def png_size(data: bytes) -> tuple[int, int]:
    assert data.startswith(b"\x89PNG")
    return int.from_bytes(data[16:20], "big"), int.from_bytes(data[20:24], "big")


def png_color_type(data: bytes) -> int:
    assert data.startswith(b"\x89PNG")
    return data[25]


def png_pixel(data: bytes, x: int, y: int) -> tuple[int, ...]:
    assert data.startswith(b"\x89PNG")
    width, height = png_size(data)
    assert 0 <= x < width
    assert 0 <= y < height
    bit_depth = data[24]
    color_type = data[25]
    assert bit_depth == 8
    channels = {2: 3, 6: 4}[color_type]
    chunks = []
    offset = 8
    while offset < len(data):
        length = int.from_bytes(data[offset : offset + 4], "big")
        kind = data[offset + 4 : offset + 8]
        if kind == b"IDAT":
            chunks.append(data[offset + 8 : offset + 8 + length])
        offset += 12 + length
    raw = zlib.decompress(b"".join(chunks))
    stride = width * channels
    previous = bytearray(stride)
    cursor = 0
    rows = []
    for _ in range(height):
        filter_type = raw[cursor]
        cursor += 1
        row = bytearray(raw[cursor : cursor + stride])
        cursor += stride
        for index in range(stride):
            left = row[index - channels] if index >= channels else 0
            up = previous[index]
            upper_left = previous[index - channels] if index >= channels else 0
            if filter_type == 1:
                row[index] = (row[index] + left) & 0xFF
            elif filter_type == 2:
                row[index] = (row[index] + up) & 0xFF
            elif filter_type == 3:
                row[index] = (row[index] + ((left + up) // 2)) & 0xFF
            elif filter_type == 4:
                predictor = left + up - upper_left
                pa = abs(predictor - left)
                pb = abs(predictor - up)
                pc = abs(predictor - upper_left)
                row[index] = (row[index] + (left if pa <= pb and pa <= pc else up if pb <= pc else upper_left)) & 0xFF
        rows.append(bytes(row))
        previous = row
    start = x * channels
    return tuple(rows[y][start : start + channels])


def jpeg_size(data: bytes) -> tuple[int, int]:
    assert data.startswith(b"\xff\xd8")
    index = 2
    sof_markers = {
        0xC0,
        0xC1,
        0xC2,
        0xC3,
        0xC5,
        0xC6,
        0xC7,
        0xC9,
        0xCA,
        0xCB,
        0xCD,
        0xCE,
        0xCF,
    }
    while index + 3 < len(data):
        if data[index] != 0xFF:
            index += 1
            continue
        while index < len(data) and data[index] == 0xFF:
            index += 1
        if index >= len(data):
            break
        marker = data[index]
        index += 1
        if marker in {0xD8, 0xD9, 0x01} or 0xD0 <= marker <= 0xD7:
            continue
        if index + 2 > len(data):
            break
        segment_length = int.from_bytes(data[index : index + 2], "big")
        if marker in sof_markers:
            height = int.from_bytes(data[index + 3 : index + 5], "big")
            width = int.from_bytes(data[index + 5 : index + 7], "big")
            return width, height
        index += segment_length
    raise AssertionError("JPEG size marker was not found")


def image_size(data: bytes) -> tuple[int, int]:
    if data.startswith(b"\x89PNG"):
        return png_size(data)
    if data.startswith(b"\xff\xd8"):
        return jpeg_size(data)
    raise AssertionError("unsupported image data")


def pdf_media_box(data: bytes) -> tuple[float, float]:
    match = re.search(rb"/MediaBox\s*\[\s*0\s+0\s+([0-9.]+)\s+([0-9.]+)\s*\]", data)
    if not match:
        raise AssertionError("PDF MediaBox was not found")
    return float(match.group(1)), float(match.group(2))


def subprocess_env(**overrides: str) -> dict[str, str]:
    env = {**os.environ}
    python_source = str(Path(__file__).resolve().parents[1] / "python")
    env["PYTHONPATH"] = python_source + (os.pathsep + env["PYTHONPATH"] if env.get("PYTHONPATH") else "")
    env.update(overrides)
    return env


def require_reference_module(module_name: str, reason: str) -> None:
    probe = subprocess.run(
        [
            sys.executable,
            "-c",
            "import importlib.util, sys; raise SystemExit(3 if importlib.util.find_spec(sys.argv[1]) is None else 0)",
            module_name,
        ],
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
        timeout=10,
    )
    if probe.returncode == 3:
        pytest.skip(reason)
    assert probe.returncode == 0, probe.stdout


def webm_size(path: Path) -> tuple[int, int]:
    ffprobe = shutil.which("ffprobe")
    if not ffprobe:
        raise AssertionError("ffprobe is required for WebM size checks")
    result = subprocess.run(
        [
            ffprobe,
            "-v",
            "error",
            "-select_streams",
            "v:0",
            "-show_entries",
            "stream=width,height",
            "-of",
            "csv=p=0:s=x",
            str(path),
        ],
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        text=True,
        check=True,
        timeout=10,
    )
    width, height = result.stdout.strip().split("x", 1)
    return int(width), int(height)


def webm_frame_count(path: Path) -> int:
    ffprobe = shutil.which("ffprobe")
    if not ffprobe:
        raise AssertionError("ffprobe is required for WebM frame-count checks")
    result = subprocess.run(
        [
            ffprobe,
            "-v",
            "error",
            "-count_frames",
            "-select_streams",
            "v:0",
            "-show_entries",
            "stream=nb_read_frames",
            "-of",
            "default=nokey=1:noprint_wrappers=1",
            str(path),
        ],
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        text=True,
        check=True,
        timeout=10,
    )
    value = result.stdout.strip()
    return int(value) if value.isdigit() else 0


def wait_until(predicate, timeout: float = 3.0):
    deadline = time.monotonic() + timeout
    while time.monotonic() < deadline:
        value = predicate()
        if value:
            return value
        time.sleep(0.02)
    raise AssertionError("condition was not met before timeout")


async def wait_until_async(predicate, timeout: float = 3.0):
    deadline = time.monotonic() + timeout
    while time.monotonic() < deadline:
        value = predicate()
        if inspect.isawaitable(value):
            value = await value
        if value:
            return value
        await asyncio.sleep(0.02)
    raise AssertionError("condition was not met before timeout")


def assert_near(value: int | float, expected: int | float, tolerance: int | float = 25) -> None:
    assert abs(value - expected) <= tolerance


def chromium_env_probe_wrapper(tmp_path: Path, real_chromium: str, env_file: Path) -> Path:
    wrapper = tmp_path / "chromium-env-probe.sh"
    wrapper.write_text(
        "\n".join(
            [
                "#!/bin/sh",
                f"printf '%s' \"$RUSTWRIGHT_ENV_PROBE\" > {shlex.quote(str(env_file))}",
                f"exec {shlex.quote(real_chromium)} \"$@\"",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    wrapper.chmod(0o755)
    return wrapper


def chromium_arg_probe_wrapper(tmp_path: Path, real_chromium: str, args_file: Path) -> Path:
    wrapper = tmp_path / "chromium-arg-probe.sh"
    wrapper.write_text(
        "\n".join(
            [
                "#!/bin/sh",
                f"printf '%s\\n' \"$@\" > {shlex.quote(str(args_file))}",
                f"exec {shlex.quote(real_chromium)} \"$@\"",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    wrapper.chmod(0o755)
    return wrapper


