@pytest.fixture()
def websocket_server():
    stop = threading.Event()
    ready = threading.Event()
    connections = []
    magic = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"

    def run_server():
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as server:
            server.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
            server.bind(("127.0.0.1", 0))
            server.listen()
            server.settimeout(0.1)
            connections.append(("port", server.getsockname()[1]))
            ready.set()
            while not stop.is_set():
                try:
                    conn, _ = server.accept()
                except socket.timeout:
                    continue
                thread = threading.Thread(target=handle_connection, args=(conn,), daemon=True)
                thread.start()

    def handle_connection(conn):
        with conn:
            conn.settimeout(2)
            request = b""
            while b"\r\n\r\n" not in request:
                chunk = conn.recv(4096)
                if not chunk:
                    return
                request += chunk
            text = request.decode("latin1")
            path = text.split(" ", 2)[1]
            key = ""
            requested_protocols = ""
            for line in text.split("\r\n"):
                if line.lower().startswith("sec-websocket-key:"):
                    key = line.split(":", 1)[1].strip()
                if line.lower().startswith("sec-websocket-protocol:"):
                    requested_protocols = line.split(":", 1)[1].strip()
            protocol_values = [item.strip() for item in requested_protocols.split(",") if item.strip()]
            selected_protocol = "chat" if "chat" in protocol_values else ""
            protocol_response = (
                f"Sec-WebSocket-Protocol: {selected_protocol}\r\n"
                if selected_protocol
                else ""
            )
            accept = base64.b64encode(hashlib.sha1((key + magic).encode("ascii")).digest()).decode("ascii")
            response = (
                "HTTP/1.1 101 Switching Protocols\r\n"
                "Upgrade: websocket\r\n"
                "Connection: Upgrade\r\n"
                f"Sec-WebSocket-Accept: {accept}\r\n"
                f"{protocol_response}"
                "\r\n"
            )
            conn.sendall(response.encode("ascii"))
            connections.append(("path", path))
            if requested_protocols:
                connections.append(("protocols", path, requested_protocols))
            while not stop.is_set():
                try:
                    frame = read_ws_frame(conn)
                except socket.timeout:
                    continue
                except OSError:
                    return
                if frame is None:
                    return
                opcode, payload = frame
                if opcode == 8:
                    code = int.from_bytes(payload[:2], "big") if len(payload) >= 2 else None
                    reason = payload[2:].decode("utf-8", errors="replace") if len(payload) > 2 else ""
                    connections.append(("close", path, code, reason))
                    return
                if opcode == 10:
                    connections.append(("pong", path, payload.decode("utf-8", errors="replace")))
                    continue
                message = payload.decode("utf-8")
                connections.append(("message", path, message))
                if message == "fragment-request":
                    send_ws_fragmented_text(conn, "fragmented:reply")
                elif message == "binary-fragment-request":
                    send_ws_fragmented_binary(conn, bytes([5, 6, 7]))
                elif message == "ping-request":
                    send_ws_ping(conn, "server-ping")
                elif message == "close-request":
                    send_ws_close(conn, 3002, "server-done")
                else:
                    send_ws_text(conn, f"echo:{message}")

    def read_exact(conn, size):
        data = b""
        while len(data) < size:
            chunk = conn.recv(size - len(data))
            if not chunk:
                return None
            data += chunk
        return data

    def read_ws_frame(conn):
        header = read_exact(conn, 2)
        if header is None:
            return None
        opcode = header[0] & 0x0F
        masked = bool(header[1] & 0x80)
        length = header[1] & 0x7F
        if length == 126:
            extended = read_exact(conn, 2)
            if extended is None:
                return None
            length = int.from_bytes(extended, "big")
        elif length == 127:
            extended = read_exact(conn, 8)
            if extended is None:
                return None
            length = int.from_bytes(extended, "big")
        mask = read_exact(conn, 4) if masked else b""
        payload = read_exact(conn, length)
        if payload is None:
            return None
        if masked:
            payload = bytes(byte ^ mask[index % 4] for index, byte in enumerate(payload))
        return opcode, payload

    def send_ws_text(conn, message):
        payload = message.encode("utf-8")
        if len(payload) > 125:
            raise ValueError("test websocket payload is too large")
        conn.sendall(bytes([0x81, len(payload)]) + payload)

    def send_ws_fragmented_text(conn, message):
        payload = message.encode("utf-8")
        split = max(1, len(payload) // 2)
        first = payload[:split]
        second = payload[split:]
        if len(first) > 125 or len(second) > 125:
            raise ValueError("test websocket payload is too large")
        conn.sendall(bytes([0x01, len(first)]) + first)
        conn.sendall(bytes([0x80, len(second)]) + second)

    def send_ws_fragmented_binary(conn, payload):
        split = max(1, len(payload) // 2)
        first = payload[:split]
        second = payload[split:]
        if len(first) > 125 or len(second) > 125:
            raise ValueError("test websocket payload is too large")
        conn.sendall(bytes([0x02, len(first)]) + first)
        conn.sendall(bytes([0x80, len(second)]) + second)

    def send_ws_ping(conn, message):
        payload = message.encode("utf-8")
        if len(payload) > 125:
            raise ValueError("test websocket payload is too large")
        conn.sendall(bytes([0x89, len(payload)]) + payload)

    def send_ws_close(conn, code, reason):
        payload = int(code).to_bytes(2, "big") + reason.encode("utf-8")
        if len(payload) > 125:
            raise ValueError("test websocket payload is too large")
        conn.sendall(bytes([0x88, len(payload)]) + payload)

    thread = threading.Thread(target=run_server, daemon=True)
    thread.start()
    ready.wait(timeout=2)
    port_items = [item for item in connections if item[0] == "port"]
    if not port_items:
        raise RuntimeError("websocket test server did not start")
    try:
        yield f"ws://127.0.0.1:{port_items[0][1]}/socket", connections
    finally:
        stop.set()
        try:
            with socket.create_connection(("127.0.0.1", port_items[0][1]), timeout=1):
                pass
        except OSError:
            pass
        thread.join(timeout=2)


@pytest.fixture()
def slow_attach_cdp_server():
    stop = threading.Event()
    ready = threading.Event()
    slow_enable_started = threading.Event()
    slow_create_started = threading.Event()
    state: dict[str, Any] = {
        "commands": [],
        "port": None,
        "delay_create_target": False,
        "slow_create_started": slow_create_started,
        "slow_enable_started": slow_enable_started,
    }
    magic = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"

    def read_exact(conn, size):
        data = b""
        while len(data) < size:
            chunk = conn.recv(size - len(data))
            if not chunk:
                return None
            data += chunk
        return data

    def read_ws_frame(conn):
        header = read_exact(conn, 2)
        if header is None:
            return None
        opcode = header[0] & 0x0F
        masked = bool(header[1] & 0x80)
        length = header[1] & 0x7F
        if length == 126:
            extended = read_exact(conn, 2)
            if extended is None:
                return None
            length = int.from_bytes(extended, "big")
        elif length == 127:
            extended = read_exact(conn, 8)
            if extended is None:
                return None
            length = int.from_bytes(extended, "big")
        mask = read_exact(conn, 4) if masked else b""
        payload = read_exact(conn, length)
        if payload is None:
            return None
        if masked:
            payload = bytes(byte ^ mask[index % 4] for index, byte in enumerate(payload))
        return opcode, payload

    def ws_text_frame(message):
        payload = message.encode("utf-8")
        if len(payload) <= 125:
            header = bytes([0x81, len(payload)])
        elif len(payload) <= 0xFFFF:
            header = bytes([0x81, 126]) + len(payload).to_bytes(2, "big")
        else:
            header = bytes([0x81, 127]) + len(payload).to_bytes(8, "big")
        return header + payload

    def result_for(command, target_counter):
        method = command.get("method")
        if method == "Target.getBrowserContexts":
            return {"browserContextIds": []}
        if method == "Target.getTargets":
            return {"targetInfos": list(state.get("target_infos", []))}
        if method == "Target.createTarget":
            return {"targetId": f"target-{target_counter}"}
        if method == "Target.attachToTarget":
            target_id = command.get("params", {}).get("targetId")
            return {"sessionId": f"session-{target_id}"}
        if method == "Browser.getVersion":
            return {
                "product": "Chrome/120.0.0.0",
                "userAgent": "Mozilla/5.0 HeadlessChrome/120.0.0.0",
            }
        if method == "Page.addScriptToEvaluateOnNewDocument":
            return {"identifier": "stealth-script"}
        if method == "Page.getFrameTree":
            session_id = command.get("sessionId") or "browser"
            return {
                "frameTree": {
                    "frame": {
                        "id": f"frame-{session_id}",
                        "loaderId": f"loader-{session_id}",
                        "url": "about:blank",
                        "securityOrigin": "://",
                        "mimeType": "text/html",
                    }
                }
            }
        if method == "Target.closeTarget":
            return {"success": True}
        return {}

    def handle_connection(conn):
        with conn:
            conn.settimeout(2)
            request = b""
            while b"\r\n\r\n" not in request:
                chunk = conn.recv(4096)
                if not chunk:
                    return
                request += chunk
            text = request.decode("latin1")
            key = ""
            for line in text.split("\r\n"):
                if line.lower().startswith("sec-websocket-key:"):
                    key = line.split(":", 1)[1].strip()
            accept = base64.b64encode(hashlib.sha1((key + magic).encode("ascii")).digest()).decode("ascii")
            conn.sendall(
                (
                    "HTTP/1.1 101 Switching Protocols\r\n"
                    "Upgrade: websocket\r\n"
                    "Connection: Upgrade\r\n"
                    f"Sec-WebSocket-Accept: {accept}\r\n"
                    "\r\n"
                ).encode("ascii")
            )
            send_lock = threading.Lock()
            target_counter = 0

            def respond(command, result):
                response = json.dumps({"id": command["id"], "result": result}, separators=(",", ":"))
                try:
                    with send_lock:
                        conn.sendall(ws_text_frame(response))
                except OSError:
                    pass

            while not stop.is_set():
                try:
                    frame = read_ws_frame(conn)
                except socket.timeout:
                    continue
                except OSError:
                    return
                if frame is None:
                    return
                opcode, payload = frame
                if opcode == 8:
                    return
                if opcode != 1:
                    continue
                command = json.loads(payload.decode("utf-8"))
                state["commands"].append(command)
                if command.get("method") == "Target.createTarget":
                    target_counter += 1
                result = result_for(command, target_counter)
                if (
                    command.get("method") == "Target.createTarget"
                    and state["delay_create_target"]
                ):
                    slow_create_started.set()
                    threading.Timer(0.75, respond, args=(command, result)).start()
                elif (
                    command.get("method") == "Page.enable"
                    and command.get("sessionId") == "session-target-1"
                ):
                    slow_enable_started.set()
                    threading.Timer(0.75, respond, args=(command, result)).start()
                else:
                    respond(command, result)

    def run_server():
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as server:
            server.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
            server.bind(("127.0.0.1", 0))
            server.listen(1)
            server.settimeout(0.1)
            state["port"] = server.getsockname()[1]
            ready.set()
            while not stop.is_set():
                try:
                    conn, _ = server.accept()
                except socket.timeout:
                    continue
                handle_connection(conn)

    thread = threading.Thread(target=run_server, daemon=True)
    thread.start()
    ready.wait(timeout=2)
    if state["port"] is None:
        raise RuntimeError("mock CDP server did not start")
    try:
        yield f"ws://127.0.0.1:{state['port']}/devtools/browser/slow-attach", state
    finally:
        stop.set()
        try:
            with socket.create_connection(("127.0.0.1", state["port"]), timeout=1):
                pass
        except OSError:
            pass
        thread.join(timeout=2)


@pytest.fixture()
def secure_websocket_server(tmp_path: Path):
    cert_path = tmp_path / "wss-cert.pem"
    key_path = tmp_path / "wss-key.pem"
    proc = subprocess.run(
        [
            "openssl",
            "req",
            "-x509",
            "-newkey",
            "rsa:2048",
            "-nodes",
            "-keyout",
            str(key_path),
            "-out",
            str(cert_path),
            "-days",
            "1",
            "-subj",
            "/CN=localhost",
            "-addext",
            "subjectAltName=IP:127.0.0.1,DNS:localhost",
        ],
        text=True,
        capture_output=True,
        timeout=10,
    )
    if proc.returncode != 0:
        pytest.skip(f"openssl could not create a self-signed certificate: {proc.stderr or proc.stdout}")

    stop = threading.Event()
    ready = threading.Event()
    connections = []
    magic = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
    server_context = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
    server_context.load_cert_chain(certfile=str(cert_path), keyfile=str(key_path))

    def run_server():
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as server:
            server.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
            server.bind(("127.0.0.1", 0))
            server.listen()
            server.settimeout(0.1)
            connections.append(("port", server.getsockname()[1]))
            ready.set()
            while not stop.is_set():
                try:
                    conn, _ = server.accept()
                except socket.timeout:
                    continue
                try:
                    tls_conn = server_context.wrap_socket(conn, server_side=True)
                except OSError:
                    conn.close()
                    continue
                thread = threading.Thread(target=handle_connection, args=(tls_conn,), daemon=True)
                thread.start()

    def handle_connection(conn):
        with conn:
            conn.settimeout(2)
            request = b""
            while b"\r\n\r\n" not in request:
                chunk = conn.recv(4096)
                if not chunk:
                    return
                request += chunk
            text = request.decode("latin1")
            path = text.split(" ", 2)[1]
            key = ""
            for line in text.split("\r\n"):
                if line.lower().startswith("sec-websocket-key:"):
                    key = line.split(":", 1)[1].strip()
                    break
            accept = base64.b64encode(hashlib.sha1((key + magic).encode("ascii")).digest()).decode("ascii")
            response = (
                "HTTP/1.1 101 Switching Protocols\r\n"
                "Upgrade: websocket\r\n"
                "Connection: Upgrade\r\n"
                f"Sec-WebSocket-Accept: {accept}\r\n"
                "\r\n"
            )
            conn.sendall(response.encode("ascii"))
            connections.append(("path", path))
            while not stop.is_set():
                try:
                    message = read_ws_message(conn)
                except socket.timeout:
                    continue
                except OSError:
                    return
                if message is None:
                    return
                connections.append(("message", path, message))
                send_ws_text(conn, f"secure-echo:{message}")

    def read_exact(conn, size):
        data = b""
        while len(data) < size:
            chunk = conn.recv(size - len(data))
            if not chunk:
                return None
            data += chunk
        return data

    def read_ws_message(conn):
        header = read_exact(conn, 2)
        if header is None:
            return None
        opcode = header[0] & 0x0F
        masked = bool(header[1] & 0x80)
        length = header[1] & 0x7F
        if length == 126:
            extended = read_exact(conn, 2)
            if extended is None:
                return None
            length = int.from_bytes(extended, "big")
        elif length == 127:
            extended = read_exact(conn, 8)
            if extended is None:
                return None
            length = int.from_bytes(extended, "big")
        mask = read_exact(conn, 4) if masked else b""
        payload = read_exact(conn, length)
        if payload is None:
            return None
        if masked:
            payload = bytes(byte ^ mask[index % 4] for index, byte in enumerate(payload))
        if opcode == 8:
            return None
        return payload.decode("utf-8")

    def send_ws_text(conn, message):
        payload = message.encode("utf-8")
        if len(payload) > 125:
            raise ValueError("test websocket payload is too large")
        conn.sendall(bytes([0x81, len(payload)]) + payload)

    thread = threading.Thread(target=run_server, daemon=True)
    thread.start()
    ready.wait(timeout=2)
    port_items = [item for item in connections if item[0] == "port"]
    if not port_items:
        raise RuntimeError("secure websocket test server did not start")
    try:
        yield f"wss://127.0.0.1:{port_items[0][1]}/socket", connections
    finally:
        stop.set()
        try:
            with socket.create_connection(("127.0.0.1", port_items[0][1]), timeout=1):
                pass
        except OSError:
            pass
        thread.join(timeout=2)


