def test_patchright_alias_imports_for_skyvern_rewritten_backend():
    import patchright.async_api as patchright_async_api
    import patchright.sync_api as patchright_sync_api
    import playwright.async_api as playwright_async_api
    import playwright.sync_api as playwright_sync_api

    from patchright._impl._errors import Error as ImplError
    from patchright._impl._errors import TargetClosedError as ImplTargetClosedError
    from patchright._impl._errors import TimeoutError as ImplTimeoutError
    from patchright.async_api import Error as AsyncError
    from patchright.async_api import TimeoutError as AsyncTimeoutError
    from patchright.async_api import async_playwright as patchright_async_playwright
    from patchright.sync_api import Error as SyncError
    from patchright.sync_api import TimeoutError as SyncTimeoutError
    from patchright.sync_api import sync_playwright as patchright_sync_playwright
    from rustwright.sync_api import TargetClosedError as RustwrightTargetClosedError

    assert ImplError is SyncError
    assert ImplError is AsyncError
    assert ImplTimeoutError is SyncTimeoutError
    assert ImplTimeoutError is AsyncTimeoutError
    assert ImplTargetClosedError is RustwrightTargetClosedError
    assert patchright_sync_api.__all__ == playwright_sync_api.__all__
    assert patchright_async_api.__all__ == playwright_async_api.__all__
    assert "sync_playwright" in patchright_sync_api.__all__
    assert "async_playwright" in patchright_async_api.__all__

    with patchright_sync_playwright() as p:
        assert p.chromium.name == "chromium"

    async def run() -> None:
        async with patchright_async_playwright() as p:
            assert p.chromium.name == "chromium"

    asyncio.run(run())


def test_cloakbrowser_alias_launchers_for_skyvern_stealth_paths(tmp_path: Path):
    import cloakbrowser

    assert "launch_async" in cloakbrowser.__all__
    assert "launch_persistent_context_async" in cloakbrowser.__all__
    assert "ensure_binary" in cloakbrowser.__all__

    async def run() -> None:
        from benchmarks.automation_cases import http_proxy_case_server, proxy_seen_for_url

        with http_proxy_case_server() as (proxy_url, proxy_seen):
            browser = await cloakbrowser.launch_async(
                backend="patchright",
                geoip=True,
                headless=True,
                humanize=True,
                proxy=proxy_url,
            )
            try:
                page = await browser.new_page()
                payload = await (await page.goto("http://cloakbrowser-proxy.invalid/probe")).json()
                assert payload == {
                    "proxied": True,
                    "url": "http://cloakbrowser-proxy.invalid/probe",
                    "host": "cloakbrowser-proxy.invalid",
                }
            finally:
                await browser.close()

        assert proxy_seen_for_url(proxy_seen, "http://cloakbrowser-proxy.invalid/probe") == [
            {"url": "http://cloakbrowser-proxy.invalid/probe", "host": "cloakbrowser-proxy.invalid"}
        ]

        with http_proxy_case_server() as (persistent_proxy_url, persistent_proxy_seen):
            context = await cloakbrowser.launch_persistent_context_async(
                user_data_dir=tmp_path / "cloak-profile",
                backend="playwright",
                geoip=True,
                headless=True,
                humanize=False,
                proxy=persistent_proxy_url,
                timezone="UTC",
            )
            try:
                page = context.pages[0] if context.pages else await context.new_page()
                assert await page.evaluate("() => Intl.DateTimeFormat().resolvedOptions().timeZone") == "UTC"
                payload = await (await page.goto("http://cloakbrowser-persistent-proxy.invalid/probe")).json()
                assert payload == {
                    "proxied": True,
                    "url": "http://cloakbrowser-persistent-proxy.invalid/probe",
                    "host": "cloakbrowser-persistent-proxy.invalid",
                }
            finally:
                await context.close()

        assert proxy_seen_for_url(persistent_proxy_seen, "http://cloakbrowser-persistent-proxy.invalid/probe") == [
            {
                "url": "http://cloakbrowser-persistent-proxy.invalid/probe",
                "host": "cloakbrowser-persistent-proxy.invalid",
            }
        ]

    asyncio.run(run())


@pytest.mark.parametrize(
    ("wire_message", "expected_type", "expected_message", "expected_kind", "expected_payload"),
    [
        (
            '__rustwright_timeout__:{"ms":250}',
            TimeoutError,
            "timed out after 250 ms",
            "timeout",
            {"ms": 250},
        ),
        (
            '__rustwright_target_closed__:{"kind":"page"}',
            "TargetClosedError",
            "Target page, context or browser has been closed",
            "target_closed",
            {"kind": "page"},
        ),
        (
            '__rustwright_target_closed__:{"kind":"context"}',
            "TargetClosedError",
            "Target page, context or browser has been closed",
            "target_closed",
            {"kind": "context"},
        ),
        (
            '__rustwright_target_closed__:{"kind":"browser"}',
            "TargetClosedError",
            "Target page, context or browser has been closed",
            "target_closed",
            {"kind": "browser"},
        ),
        (
            '__rustwright_target_closed__:{"kind":"target"}',
            "TargetClosedError",
            "Target page, context or browser has been closed",
            "target_closed",
            {"kind": "target"},
        ),
        (
            "__rustwright_page_crashed__:{}",
            Error,
            "Page crashed",
            "page_crashed",
            {},
        ),
        (
            "__rustwright_disconnected__:{}",
            Error,
            "target or browser is closed",
            "disconnected",
            {},
        ),
    ],
)
def test_structured_native_error_markers_translate_without_wire_residue(
    wire_message, expected_type, expected_message, expected_kind, expected_payload
):
    import rustwright.sync_api as sync_api

    if expected_type == "TargetClosedError":
        expected_type = sync_api.TargetClosedError
    translated = sync_api._translate_error(RuntimeError(wire_message))

    assert type(translated) is expected_type
    assert str(translated) == expected_message
    assert "__rustwright_" not in str(translated)
    assert translated._rustwright_error_kind == expected_kind
    assert translated._rustwright_error_payload == expected_payload


@pytest.mark.parametrize(
    ("legacy_message", "expected_type"),
    [
        ("legacy operation timed out", TimeoutError),
        ("Target page, context or browser has been closed", "TargetClosedError"),
    ],
)
def test_unmarked_legacy_native_errors_still_use_prose_fallback(legacy_message, expected_type):
    import rustwright.sync_api as sync_api

    if expected_type == "TargetClosedError":
        expected_type = sync_api.TargetClosedError
    translated = sync_api._translate_error(RuntimeError(legacy_message))

    assert type(translated) is expected_type
    assert str(translated) == legacy_message
    assert not hasattr(translated, "_rustwright_error_kind")


def test_structured_timeout_payload_survives_playwright_method_formatting():
    import rustwright.sync_api as sync_api

    def native_timeout():
        raise RuntimeError('__rustwright_timeout__:{"ms":75}')

    with pytest.raises(TimeoutError) as exc_info:
        sync_api._call_wait_with_playwright_timeout("Page.goto", native_timeout)

    assert str(exc_info.value) == "Page.goto: Timeout 75ms exceeded."
    assert exc_info.value._rustwright_error_kind == "timeout"
    assert exc_info.value._rustwright_error_payload == {"ms": 75}


