def test_chromium_connect_over_cdp_adopts_default_context_pages_and_disconnects_only(playwright):
    launched = playwright.chromium.launch(headless=True)
    connected = None
    try:
        launched_page = launched.new_page()
        launched_page.goto(data_url("<title>Origin CDP Page</title><h1>origin</h1>"))

        connected = playwright.chromium.connect_over_cdp(launched._ws_endpoint)
        assert len(connected.contexts) == 1
        context = connected.contexts[0]
        urls = [page.url for page in context.pages]
        assert "about:blank" in urls
        assert launched_page.url in urls

        adopted = next(page for page in context.pages if page.url == launched_page.url)
        assert adopted.title() == "Origin CDP Page"

        connected.close()
        connected = None
        assert launched.is_connected()
        assert launched_page.title() == "Origin CDP Page"
    finally:
        if connected is not None:
            connected.close()
        launched.close()


