def test_chromium_connect_over_cdp_forwards_headers(playwright):
    websocket_listener = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    websocket_listener.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    websocket_listener.bind(("127.0.0.1", 0))
    websocket_listener.listen(1)
    websocket_host, websocket_port = websocket_listener.getsockname()
    http_seen: list[str | None] = []
    websocket_seen: list[str] = []

    def websocket_server():
        try:
            conn, _ = websocket_listener.accept()
        except OSError:
            return
        try:
            conn.settimeout(3)
            chunks = []
            while True:
                data = conn.recv(4096)
                if not data:
                    break
                chunks.append(data)
                if b"\r\n\r\n" in b"".join(chunks):
                    break
            websocket_seen.append(b"".join(chunks).decode("iso-8859-1"))
        finally:
            conn.close()

    class Handler(BaseHTTPRequestHandler):
        def log_message(self, *_):
            pass

        def do_GET(self):
            http_seen.append(self.headers.get("X-CDP-Test"))
            body = json.dumps(
                {
                    "webSocketDebuggerUrl": (
                        f"ws://{websocket_host}:{websocket_port}/devtools/browser/header-test"
                    )
                }
            ).encode("utf-8")
            self.send_response(200)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", str(len(body)))
            self.end_headers()
            self.wfile.write(body)

    http_server = ThreadingHTTPServer(("127.0.0.1", 0), Handler)
    http_host, http_port = http_server.server_address
    http_thread = threading.Thread(target=_serve_forever_fast, args=(http_server,), daemon=True)
    ws_thread = threading.Thread(target=websocket_server, daemon=True)
    http_thread.start()
    ws_thread.start()

    try:
        with pytest.raises(Error):
            playwright.chromium.connect_over_cdp(
                f"http://{http_host}:{http_port}",
                headers={"X-CDP-Test": "seen"},
                timeout=1_000,
            )
        assert wait_until(lambda: http_seen)[0] == "seen"
        raw_websocket_request = wait_until(lambda: websocket_seen)[0].lower()
        assert "x-cdp-test: seen" in raw_websocket_request
    finally:
        http_server.shutdown()
        http_server.server_close()
        websocket_listener.close()


def test_chromium_connect_over_cdp_option_validation_matches_playwright(playwright):
    with pytest.raises(Error) as endpoint_exc:
        playwright.chromium.connect_over_cdp(123)
    assert str(endpoint_exc.value).splitlines()[0] == (
        "BrowserType.connect_over_cdp: endpoint_url: expected string, got number"
    )

    with pytest.raises(Error) as empty_endpoint_exc:
        playwright.chromium.connect_over_cdp("")
    assert str(empty_endpoint_exc.value).splitlines()[0] == "BrowserType.connect_over_cdp: Invalid URL"

    with pytest.raises(Error) as timeout_exc:
        playwright.chromium.connect_over_cdp("ws://127.0.0.1:1/devtools/browser/test", timeout="10")
    assert str(timeout_exc.value).splitlines()[0] == (
        "BrowserType.connect_over_cdp: timeout: expected float, got string"
    )

    with pytest.raises(Error) as slow_mo_exc:
        playwright.chromium.connect_over_cdp("ws://127.0.0.1:1/devtools/browser/test", slow_mo=True)
    assert str(slow_mo_exc.value).splitlines()[0] == (
        "BrowserType.connect_over_cdp: slow_mo: expected float, got boolean"
    )

    with pytest.raises(Error) as is_local_exc:
        playwright.chromium.connect_over_cdp("ws://127.0.0.1:1/devtools/browser/test", is_local=1)
    assert str(is_local_exc.value).splitlines()[0] == (
        "BrowserType.connect_over_cdp: is_local: expected boolean, got number"
    )

    with pytest.raises(AttributeError) as headers_object_exc:
        playwright.chromium.connect_over_cdp("ws://127.0.0.1:1/devtools/browser/test", headers="x")
    assert str(headers_object_exc.value) == "'str' object has no attribute 'items'"

    with pytest.raises(Error) as header_name_exc:
        playwright.chromium.connect_over_cdp("ws://127.0.0.1:1/devtools/browser/test", headers={1: "value"})
    assert str(header_name_exc.value).splitlines()[0] == (
        "BrowserType.connect_over_cdp: headers[0].name: expected string, got number"
    )

    with pytest.raises(Error) as header_value_exc:
        playwright.chromium.connect_over_cdp("ws://127.0.0.1:1/devtools/browser/test", headers={"X-Test": 1})
    assert str(header_value_exc.value).splitlines()[0] == (
        "BrowserType.connect_over_cdp: headers[0].value: expected string, got number"
    )


