def test_chromium_connect_over_cdp_websocket_status_error_matches_playwright(playwright):
    body = b"<html><head><title>502 Bad Gateway</title></head></html>"

    class Handler(BaseHTTPRequestHandler):
        protocol_version = "HTTP/1.1"

        def log_message(self, *_):
            pass

        def do_GET(self):
            self.send_response(502, "Bad Gateway")
            self.send_header("Content-Type", "text/html")
            self.send_header("Content-Length", str(len(body)))
            self.send_header("Connection", "close")
            self.end_headers()
            self.wfile.write(body)

    http_server = ThreadingHTTPServer(("127.0.0.1", 0), Handler)
    host, port = http_server.server_address
    http_thread = threading.Thread(target=_serve_forever_fast, args=(http_server,), daemon=True)
    http_thread.start()
    endpoint = f"ws://{host}:{port}/devtools/browser/bad"

    try:
        with pytest.raises(Error) as exc:
            playwright.chromium.connect_over_cdp(endpoint, timeout=1_000)
    finally:
        http_server.shutdown()
        http_server.server_close()

    lines = str(exc.value).splitlines()
    assert lines[0] == f"BrowserType.connect_over_cdp: WebSocket error: {endpoint} 502 Bad Gateway"
    assert lines[1] == body.decode("utf-8")
    assert f"  - <ws unexpected response> {endpoint} 502 Bad Gateway" in lines


