def test_browser_close_closes_contexts_and_pages_before_disconnected(playwright):
    browser = playwright.chromium.launch(headless=True)
    context = browser.new_context()
    page = context.new_page()
    events = []

    page.on(
        "close",
        lambda closed_page: events.append(
            ("page", closed_page is page, browser.is_connected(), context.is_closed(), page.is_closed(), context in browser.contexts, page in context.pages)
        ),
    )
    context.on(
        "close",
        lambda closed_context: events.append(
            ("context", closed_context is context, browser.is_connected(), context.is_closed(), page.is_closed(), context in browser.contexts, page in context.pages)
        ),
    )
    browser.on(
        "disconnected",
        lambda: events.append(
            ("browser", browser.is_connected(), context.is_closed(), page.is_closed(), context in browser.contexts, page in context.pages)
        ),
    )

    browser.close()

    assert browser.is_connected() is False
    assert context.is_closed() is True
    assert page.is_closed() is True
    assert context not in browser.contexts
    assert page not in context.pages
    assert events == [
        ("page", True, True, False, True, True, False),
        ("context", True, True, True, True, False, False),
        ("browser", False, True, True, False, False),
    ]


