@pytest.fixture()
def authenticated_http_proxy_server():
    expected = "Basic " + base64.b64encode(b"user:pass").decode("ascii")
    seen: list[tuple[str, str | None]] = []

    class ProxyHandler(BaseHTTPRequestHandler):
        def do_GET(self):
            auth = self.headers.get("Proxy-Authorization")
            seen.append((self.path, auth))
            if auth != expected:
                body = b"proxy auth required"
                self.send_response(407, "Proxy Authentication Required")
                self.send_header("Proxy-Authenticate", 'Basic realm="rustwright-proxy"')
                self.send_header("Connection", "close")
                self.send_header("Content-Length", str(len(body)))
                self.end_headers()
                self.wfile.write(body)
                return

            body = b"<title>Auth Proxied</title><main>via authenticated proxy</main>"
            self.send_response(200, "OK")
            self.send_header("Content-Type", "text/html")
            self.send_header("Content-Length", str(len(body)))
            self.end_headers()
            self.wfile.write(body)

        def log_message(self, format, *args):
            return

    proxy = ThreadingHTTPServer(("127.0.0.1", 0), ProxyHandler)
    thread = threading.Thread(target=_serve_forever_fast, args=(proxy,), daemon=True)
    thread.start()
    try:
        yield f"http://127.0.0.1:{proxy.server_port}", seen, expected
    finally:
        proxy.shutdown()
        proxy.server_close()
        thread.join(timeout=2)


