    direct_port, direct_seen = direct_http_server
    bypass_host = "launch-bypass.rustwright.test"
    target_url = f"http://{bypass_host}:{direct_port}/direct"
    browser = playwright.chromium.launch(
        headless=True,
        args=[f"--host-resolver-rules=MAP {bypass_host} 127.0.0.1"],
        proxy={"server": proxy_url, "bypass": bypass_host},
    )
    try:
        page = browser.new_page()
        response = page.goto(target_url)

        assert response is not None
        assert response.ok
        assert page.title() == "Direct"
        assert wait_until(lambda: [item for item in direct_seen if item[0] == "/direct"])
        assert not [item for item in proxy_seen if item[0] == target_url]
    finally:
        browser.close()


