def test_launch_proxy_option_validation_matches_playwright(playwright):
    with pytest.raises(Error) as object_exc:
        playwright.chromium.launch(headless=True, proxy="bad")
    assert str(object_exc.value).splitlines()[0] == (
        "BrowserType.launch: proxy: expected object, got string"
    )

    with pytest.raises(Error) as server_exc:
        playwright.chromium.launch(headless=True, proxy={"server": 1})
    assert str(server_exc.value).splitlines()[0] == (
        "BrowserType.launch: proxy.server: expected string, got number"
    )

    with pytest.raises(Error) as bypass_exc:
        playwright.chromium.launch(headless=True, proxy={"server": "http://127.0.0.1:1", "bypass": 1})
    assert str(bypass_exc.value).splitlines()[0] == (
        "BrowserType.launch: proxy.bypass: expected string, got number"
    )

    with pytest.raises(Error) as username_exc:
        playwright.chromium.launch(headless=True, proxy={"server": "http://127.0.0.1:1", "username": 1})
    assert str(username_exc.value).splitlines()[0] == (
        "BrowserType.launch: proxy.username: expected string, got number"
    )

    with pytest.raises(Error) as password_exc:
        playwright.chromium.launch(headless=True, proxy={"server": "http://127.0.0.1:1", "password": 1})
    assert str(password_exc.value).splitlines()[0] == (
        "BrowserType.launch: proxy.password: expected string, got number"
    )

    with pytest.raises(Error) as url_exc:
        playwright.chromium.launch(headless=True, proxy={"server": ""})
    assert str(url_exc.value).splitlines()[0] == "BrowserType.launch: Invalid URL"

    with pytest.raises(Error) as socks5_exc:
        playwright.chromium.launch(headless=True, proxy={"server": "socks5://127.0.0.1:1", "username": "u"})
    assert str(socks5_exc.value).splitlines()[0] == (
        "BrowserType.launch: Browser does not support socks5 proxy authentication"
    )


