def test_default_navigation_actions_do_not_enable_runtime(playwright):
    browser = playwright.chromium.launch(headless=True)
    try:
        assert browser._core.sent_runtime_enable_count() == 0
        page = browser.new_page()
        assert browser._core.sent_runtime_enable_count() == 0

        page.goto(
            data_url(
                """
                <input id="name">
                <button id="save" onclick="document.body.dataset.saved = document.querySelector('#name').value">
                  Save
                </button>
                """
            )
        )
        page.fill("#name", "Ada")
        page.click("#save")

        assert page.evaluate("() => document.body.dataset.saved") == "Ada"
        assert page.evaluate(
            """() => {
              let getterFired = false;
              const error = new Error('cdp getter probe');
              Object.defineProperty(error, 'stack', {
                get() {
                  getterFired = true;
                  return 'synthetic stack';
                }
              });
              console.log(error);
              return getterFired;
            }"""
        ) is False
        assert browser._core.sent_runtime_enable_count() == 0
    finally:
        browser.close()


