def test_context_tracing_writes_trace_zip(browser, http_server, tmp_path: Path):
    context = browser.new_context()
    trace_path = tmp_path / "trace.zip"

    context.tracing.start(screenshots=True, snapshots=True, title="Trace Title")
    page = context.new_page()
    context.tracing.group("Outer group", location={"file": "flow.py", "line": 7, "column": 3})
    page.goto(f"{http_server}/page")
    context.tracing.group("Inner group")
    page.click("#fetch")
    context.tracing.group_end()
    assert wait_until(lambda: page.evaluate("document.body.dataset.fetchPath")) == "/json"
    context.tracing.stop(path=trace_path)

    assert zipfile.is_zipfile(trace_path)
    with zipfile.ZipFile(trace_path) as archive:
        names = set(archive.namelist())
        assert "trace.trace" in names
        assert "trace.network" in names
        assert "trace.stacks" in names
        assert "resources/rustwright-cdp-trace.json" in names
        trace_events = [
            json.loads(line)
            for line in archive.read("trace.trace").decode("utf-8").splitlines()
            if line
        ]
        metadata = trace_events[0]
        assert metadata["type"] == "context-options"
        assert metadata["version"] == 8
        assert metadata["browserName"] == "chromium"
        assert metadata["sdkLanguage"] == "python"
        assert metadata["title"] == "Trace Title"
        methods = {event["method"] for event in trace_events if event["type"] == "before"}
        assert {"goto", "click", "evaluate", "tracingGroup"} <= methods
        groups = [event for event in trace_events if event.get("method") == "tracingGroup"]
        assert [event["title"] for event in groups] == ["Outer group", "Inner group"]
        outer_group, inner_group = groups
        assert outer_group["stack"] == [{"file": "flow.py", "line": 7, "column": 3}]
        assert inner_group["parentId"] == outer_group["callId"]
        grouped_actions = [
            event
            for event in trace_events
            if event.get("method") in {"goto", "click", "evaluate"} and event.get("parentId")
        ]
        assert any(event["method"] == "goto" and event["parentId"] == outer_group["callId"] for event in grouped_actions)
        assert any(event["method"] == "click" and event["parentId"] == inner_group["callId"] for event in grouped_actions)
        before_call_ids = {event["callId"] for event in trace_events if event["type"] == "before"}
        after_call_ids = {event["callId"] for event in trace_events if event["type"] == "after"}
        assert before_call_ids <= after_call_ids
        snapshots = [event["snapshot"] for event in trace_events if event["type"] == "frame-snapshot"]
        assert snapshots
        assert any(snapshot["snapshotName"].startswith("before@") for snapshot in snapshots)
        assert any(snapshot["snapshotName"].startswith("after@") for snapshot in snapshots)
        assert any("Fetch" in snapshot["html"] for snapshot in snapshots)
        screencast_frames = [event for event in trace_events if event["type"] == "screencast-frame"]
        assert screencast_frames
        first_frame = screencast_frames[0]
        assert first_frame["width"] > 0
        assert first_frame["height"] > 0
        assert f"resources/{first_frame['sha1']}" in names
        assert archive.read(f"resources/{first_frame['sha1']}").startswith(b"\x89PNG")
        cdp_trace = json.loads(archive.read("resources/rustwright-cdp-trace.json"))
        assert "traceEvents" in cdp_trace
        network_events = [
            json.loads(line)
            for line in archive.read("trace.network").decode("utf-8").splitlines()
            if line
        ]
        matching_events = [
            event
            for event in network_events
            if event["snapshot"]["request"]["url"] == f"{http_server}/json"
        ]
        assert matching_events
        response_content = matching_events[0]["snapshot"]["response"]["content"]
        assert response_content["mimeType"] == "application/json"
        assert f"resources/{response_content['_sha1']}" in names
    context.close()


def test_context_tracing_chunks_can_be_exported_separately(browser, http_server, tmp_path: Path):
    context = browser.new_context()
    page = context.new_page()
    first_trace_path = tmp_path / "first-trace.zip"
    second_trace_path = tmp_path / "second-trace.zip"

    with pytest.raises(Error) as start_chunk_error:
        context.tracing.start_chunk(title="No Start")
    assert str(start_chunk_error.value) == "Must start tracing before starting a new chunk"

    context.tracing.start(title="First Chunk")
    page.goto(f"{http_server}/page")
    context.tracing.stop_chunk(path=first_trace_path)
    page.evaluate("() => document.body.dataset.untraced = 'yes'")
    context.tracing.start_chunk(title="Second Chunk")
    page.goto(f"{http_server}/json")
    context.tracing.stop_chunk(path=second_trace_path)
    context.tracing.stop()

    def trace_payload(path: Path) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
        with zipfile.ZipFile(path) as archive:
            trace_events = [
                json.loads(line)
                for line in archive.read("trace.trace").decode("utf-8").splitlines()
                if line
            ]
            network_events = [
                json.loads(line)
                for line in archive.read("trace.network").decode("utf-8").splitlines()
                if line
            ]
        return trace_events, network_events

    first_events, first_network = trace_payload(first_trace_path)
    second_events, second_network = trace_payload(second_trace_path)

    assert first_events[0]["title"] == "First Chunk"
    assert second_events[0]["title"] == "Second Chunk"
    assert [event["method"] for event in first_events if event["type"] == "before"] == ["goto"]
    assert [event["method"] for event in second_events if event["type"] == "before"] == ["goto"]
    assert {event["snapshot"]["request"]["url"] for event in first_network} == {f"{http_server}/page"}
    assert {event["snapshot"]["request"]["url"] for event in second_network} == {f"{http_server}/json"}
    context.close()


