def test_goto_returns_real_response_status_headers_and_body(page, http_server):
    response = page.goto(f"{http_server}/json")

    assert response is not None
    assert response.status == 201
    assert response.status_text == "Created"
    assert response.ok
    assert response.headers["content-type"] == "application/json"
    assert response.headers["x-rustwright-test"] == "yes"
    assert "Content-Type" not in response.headers
    assert {"name": "X-Rustwright-Test", "value": "yes"} in response.headers_array()
    assert response.header_value("x-rustwright-test") == "yes"
    assert response.http_version().startswith("http/")
    assert response.security_details() is None
    assert response.server_addr()["port"] > 0
    assert response.request is not None
    assert response.request.method == "GET"
    assert response.request.url == f"{http_server}/json"
    assert response.request.is_navigation_request()
    assert response.request.frame.page is page
    assert response.frame.page is page
    assert response.json() == {"ok": True, "path": "/json"}


def test_https_response_metadata_matches_playwright_shape(browser, https_server):
    context = browser.new_context(ignore_https_errors=True)
    try:
        page = context.new_page()
        response = page.goto(f"{https_server}/secure")
        assert response is not None

        assert response.http_version().startswith("http/")
        security_details = response.security_details()
        assert security_details is not None
        assert set(security_details) == {"issuer", "protocol", "subjectName", "validFrom", "validTo"}
        assert security_details["issuer"] == "localhost"
        assert security_details["subjectName"] == "localhost"
        assert security_details["protocol"].startswith("TLS ")
        assert isinstance(security_details["validFrom"], int)
        assert security_details["validTo"] > security_details["validFrom"]
        server_addr = response.server_addr()
        assert server_addr is not None
        assert server_addr["ipAddress"] == "127.0.0.1"
        assert server_addr["port"] > 0
    finally:
        context.close()


def test_network_header_maps_are_lowercase_and_arrays_preserve_original_case(page, http_server):
    page.goto(f"{http_server}/page")

    with page.expect_request("**/json") as request_info:
        with page.expect_response("**/json") as response_info:
            page.evaluate("() => fetch('/json', { headers: { 'X-Client-Mixed': 'ReqValue' } })")

    request = request_info.value
    response = response_info.value

    assert request.headers["x-client-mixed"] == "ReqValue"
    assert "X-Client-Mixed" not in request.headers
    assert {"name": "X-Client-Mixed", "value": "ReqValue"} in request.headers_array()
    assert request.all_headers()["x-client-mixed"] == "ReqValue"

    assert response.headers["content-type"] == "application/json"
    assert response.headers["x-rustwright-test"] == "yes"
    assert "X-Rustwright-Test" not in response.headers
    assert {"name": "X-Rustwright-Test", "value": "yes"} in response.headers_array()
    assert response.all_headers()["x-rustwright-test"] == "yes"


