def test_subframe_request_and_response_frame_attribution(page, http_server):
    page.goto(f"{http_server}/frame-fetch-page")
    frame = page.frame(name="child")
    assert frame is not None
    assert frame.url == f"{http_server}/frame-fetch-child"

    with page.expect_request("**/json") as request_info:
        with page.expect_response("**/json") as response_info:
            frame.click("#fetch")

    request = request_info.value
    response = response_info.value

    assert request.frame is frame
    assert response.frame is frame
    assert response.request.frame is frame
    assert request.frame.page is page
    assert request.frame.name == "child"
    assert frame.evaluate("() => document.body.dataset.fetchPath") == "/json"


def test_cross_origin_subframe_request_frame_attribution(page, http_server, cross_origin_frame_server):
    page.goto(f"{http_server}/page")
    frame_url = f"{cross_origin_frame_server}/frame-fetch-child-auto"

    with page.expect_request(f"{cross_origin_frame_server}/json", timeout=5_000) as request_info:
        with page.expect_response(f"{cross_origin_frame_server}/json", timeout=5_000) as response_info:
            page.evaluate(
                """(url) => {
                const frame = document.createElement('iframe');
                frame.name = 'child';
                frame.src = url;
                document.body.appendChild(frame);
                }""",
                frame_url,
            )

    request = request_info.value
    response = response_info.value
    frame = request.frame

    assert frame is response.frame
    assert response.request.frame is frame
    assert frame is not page.main_frame
    assert frame in page.frames
    assert frame.page is page
    assert frame.name == "child"
    assert frame.url == frame_url
    assert response.json() == {"ok": True, "path": "/json"}


def test_response_set_cookie_helpers_use_extra_info_headers(page, http_server):
    response = page.goto(f"{http_server}/set-cookies")

    assert response is not None
