def test_page_frameattached_and_framedetached_events(page):
    page.set_content("<main></main>")
    attached_seen: list[tuple[bool, bool, bool]] = []
    page.on(
        "frameattached",
        lambda frame: attached_seen.append((frame.page is page, frame.parent_frame is not None and frame.parent_frame.page is page, frame.is_detached())),
    )

    with page.expect_event("frameattached") as attached_info:
        page.evaluate(
            """() => {
            const frame = document.createElement('iframe');
            frame.name = 'child';
            frame.srcdoc = '<p>child</p>';
            document.body.appendChild(frame);
            }"""
        )

    attached = attached_info.value
    assert attached.page is page
    assert attached.parent_frame is not None
    assert attached.parent_frame.page is page
    assert attached.is_detached() is False
    wait_until(lambda: any(item[0] and item[1] and item[2] is False for item in attached_seen))

    detached_seen: list[tuple[bool, bool, bool]] = []
    page.on(
        "framedetached",
        lambda frame: detached_seen.append((frame.page is page, frame.parent_frame is not None and frame.parent_frame.page is page, frame.is_detached())),
    )

    with page.expect_event("framedetached") as detached_info:
        page.evaluate("() => document.querySelector('iframe').remove()")

    detached = detached_info.value
    assert detached.page is page
    assert detached.parent_frame is not None
    assert detached.parent_frame.page is page
    assert detached.is_detached() is True
    wait_until(lambda: any(item[0] and item[1] and item[2] is True for item in detached_seen))


def test_combined_frame_events_preserve_child_frame_identity(page, http_server):
    page.goto(f"{http_server}/page")
    attached = []
    navigated = []
    detached = []
    child_url = f"{http_server}/frame-fetch-child"
    page.on("frameattached", attached.append)
    page.on("framenavigated", navigated.append)
    page.on("framedetached", detached.append)

    page.evaluate(
        """url => {
        const frame = document.createElement('iframe');
        frame.id = 'combined-child';
        frame.src = url;
        document.body.appendChild(frame);
        }""",
        child_url,
    )

    child = wait_until(lambda: next((frame for frame in navigated if frame.url == child_url), None))
    attached_child = wait_until(
        lambda: next((frame for frame in attached if frame._frame_id == child._frame_id), None)
    )
    assert child is not page.main_frame
    assert child.url == child_url
    assert child._frame_id
    assert attached_child._frame_id == child._frame_id

    page.evaluate("() => document.querySelector('#combined-child').remove()")
    detached_child = wait_until(
        lambda: next((frame for frame in detached if frame._frame_id == child._frame_id), None)
    )
    assert detached_child._frame_id == child._frame_id
    assert detached_child.is_detached() is True


