def test_api_request_context_get_and_post(playwright, http_server):
    request = playwright.request.new_context(
        base_url=http_server,
        extra_http_headers={"X-Test-Header": "from-api"},
    )
    rooted_request = playwright.request.new_context(base_url=f"{http_server}/root/")

    get_response = request.get("/headers")
    post_response = request.post("/echo", data={"hello": "world"})
    rooted_slash_response = rooted_request.get("/headers")
    rooted_relative_response = rooted_request.get("headers")
    duplicate_headers_response = request.get("/duplicate-headers")

    assert get_response.ok
    assert get_response.status == 200
    assert get_response.status_text == "OK"
    assert get_response.headers["content-type"] == "application/json"
    assert {"name": "Content-Type", "value": "application/json"} in get_response.headers_array
    assert get_response.json() == {"x-test": "from-api"}
    get_response.dispose()
    with pytest.raises(Error, match="Response has been disposed"):
        get_response.body()
    with pytest.raises(Error, match="Response has been disposed"):
        get_response.text()
    with pytest.raises(Error, match="Response has been disposed"):
        get_response.json()
    assert get_response.headers["content-type"] == "application/json"
    assert post_response.status == 202
    assert post_response.json() == {
        "content_type": "application/json",
        "x_test": "from-api",
        "body": '{"hello": "world"}',
    }
    assert rooted_slash_response.status == 200
    assert rooted_slash_response.url == f"{http_server}/headers"
    assert rooted_relative_response.status == 404
    assert rooted_relative_response.url == f"{http_server}/root/headers"
    assert duplicate_headers_response.headers["x-dupe"] == "first, second"
    assert duplicate_headers_response.headers["set-cookie"] == "first=one; Path=/\nsecond=two; Path=/"
    assert {"name": "X-Dupe", "value": "first"} in duplicate_headers_response.headers_array
    assert {"name": "X-Dupe", "value": "second"} in duplicate_headers_response.headers_array
    assert {"name": "Set-Cookie", "value": "first=one; Path=/"} in duplicate_headers_response.headers_array
    assert {"name": "Set-Cookie", "value": "second=two; Path=/"} in duplicate_headers_response.headers_array
    request.dispose()
    rooted_request.dispose()


