def test_api_request_context_data_payload_encoding(playwright, http_server):
    request = playwright.request.new_context(base_url=http_server)

    object_response = request.post("/echo", data={"hello": "world"})
    assert object_response.json() == {
        "content_type": "application/json",
        "x_test": None,
        "body": '{"hello": "world"}',
    }

    list_response = request.post("/echo", data=[1, 2])
    assert list_response.json() == {
        "content_type": "application/json",
        "x_test": None,
        "body": "[1, 2]",
    }

    int_response = request.post("/echo", data=7)
    assert int_response.json() == {
        "content_type": "application/json",
        "x_test": None,
        "body": "7",
    }

    bool_response = request.post("/echo", data=True)
    assert bool_response.json() == {
        "content_type": "application/json",
        "x_test": None,
        "body": "true",
    }

    string_response = request.post("/echo", data="raw-body")
    assert string_response.json() == {
        "content_type": "application/octet-stream",
        "x_test": None,
        "body": "raw-body",
    }

    json_string_response = request.post("/echo", headers={"Content-Type": "application/json"}, data="raw-body")
    assert json_string_response.json() == {
        "content_type": "application/json",
        "x_test": None,
        "body": '"raw-body"',
    }

    bytes_response = request.post("/echo", data=b"bytes-body")
    assert bytes_response.json() == {
        "content_type": "application/octet-stream",
        "x_test": None,
        "body": "bytes-body",
    }
    request.dispose()


