def test_api_request_context_params_status_and_redirect_options(playwright, http_server):
    request = playwright.request.new_context(base_url=http_server)

    dict_params_response = request.get("/query?existing=1", params={"alpha": "one", "many": ["x", "y"]})
    assert dict_params_response.json() == {
        "path": "/query",
        "query": {"existing": ["1"], "alpha": ["one"], "many": ["['x', 'y']"]},
    }

    string_params_response = request.get("/query?existing=1", params="raw=yes")
    assert string_params_response.json() == {"path": "/query", "query": {"raw": ["yes"]}}

    missing_response = request.get("/missing")
    assert missing_response.status == 404
    assert missing_response.status_text == "Missing"

    with pytest.raises(Error, match="404 Missing"):
        request.get("/missing", fail_on_status_code=True)

    redirect_response = request.get("/redirect-one", max_redirects=0)
    assert redirect_response.status == 302
    assert redirect_response.url == f"{http_server}/redirect-one"

    with pytest.raises(Error, match="Max redirect count exceeded"):
        request.get("/redirect-hop-one", max_redirects=1)

    with pytest.raises(AssertionError, match="'max_redirects' must be greater than or equal to '0'"):
        request.get("/json", max_redirects=-1)
    with pytest.raises(AssertionError, match="'max_retries' must be greater than or equal to '0'"):
        request.get("/json", max_retries=-1)

    followed_response = request.get("/redirect-hop-one", max_redirects=2)
    assert followed_response.status == 201
    assert followed_response.url == f"{http_server}/json"

    request.dispose()

    strict_request = playwright.request.new_context(base_url=http_server, fail_on_status_code=True, max_redirects=0)
    with pytest.raises(Error, match="404 Missing"):
        strict_request.get("/missing")
    assert strict_request.get("/redirect-one").status == 302
    strict_request.dispose()


