def test_api_request_context_per_call_option_validation_matches_playwright(playwright, http_server):
    request = playwright.request.new_context(base_url=http_server)
    invalid_cases = [
        (
            lambda: request.get("/json", headers={1: "x"}),
            "APIRequestContext.get: headers[0].name: expected string, got number",
        ),
        (
            lambda: request.get("/json", headers={"X": 1}),
            "APIRequestContext.get: headers[0].value: expected string, got number",
        ),
        (
            lambda: request.get("/json", fail_on_status_code="bad"),
            "APIRequestContext.get: fail_on_status_code: expected boolean, got string",
        ),
        (
            lambda: request.get("/json", ignore_https_errors="bad"),
            "APIRequestContext.get: ignore_https_errors: expected boolean, got string",
        ),
        (
            lambda: request.get("/json", max_redirects=True),
            "APIRequestContext.get: max_redirects: expected integer, got boolean",
        ),
        (
            lambda: request.get("/json", max_redirects=1.5),
            "APIRequestContext.get: max_redirects: expected integer, got float 1.5",
        ),
        (
            lambda: request.get("/json", max_retries=True),
            "APIRequestContext.get: max_retries: expected integer, got boolean",
        ),
        (
            lambda: request.get("/json", max_retries=1.5),
            "APIRequestContext.get: max_retries: expected integer, got float 1.5",
        ),
        (
            lambda: request.get("/json", timeout="bad"),
            "APIRequestContext.get: timeout: expected float, got string",
        ),
        (
            lambda: request.get("/json", timeout=True),
            "APIRequestContext.get: timeout: expected float, got boolean",
        ),
        (
            lambda: request.fetch("/json", method=123),
            "APIRequestContext.fetch: method: expected string, got number",
        ),
    ]
    try:
        for call in (lambda: request.get(123), lambda: request.post(None), lambda: request.fetch(123)):
            with pytest.raises(AssertionError) as exc_info:
                call()
            assert str(exc_info.value) == "First argument must be either URL string or Request"

        for call, message in invalid_cases:
            with pytest.raises(Error) as exc_info:
                call()
            assert str(exc_info.value).splitlines()[0] == message

        for call, message in [
            (lambda: request.post("/json", form="raw=yes"), "'str' object has no attribute 'items'"),
            (lambda: request.post("/json", form=["raw"]), "'list' object has no attribute 'items'"),
            (lambda: request.post("/json", multipart="raw"), "'str' object has no attribute 'items'"),
            (lambda: request.post("/json", multipart=["raw"]), "'list' object has no attribute 'items'"),
        ]:
            with pytest.raises(AttributeError) as exc_info:
                call()
            assert str(exc_info.value) == message

        assert request.get("/json", max_redirects=1.0).ok
        assert request.get("/json", max_retries=1.0).ok
    finally:
        request.dispose()


def test_api_request_context_default_timeout_matches_playwright(playwright, http_server):
    request = playwright.request.new_context(base_url=http_server, timeout=50)
    try:
        with pytest.raises(TimeoutError) as timeout_info:
            request.get("/slow")
        assert str(timeout_info.value).splitlines()[0] == "APIRequestContext.get: Timeout 50ms exceeded."

        response = request.get("/slow", timeout=0)
        assert response.status == 200
    finally:
        request.dispose()

    negative = playwright.request.new_context(base_url=http_server, timeout=-1)
    try:
        with pytest.raises(TimeoutError) as negative_timeout:
            negative.get("/slow")
        assert str(negative_timeout.value).splitlines()[0] == "APIRequestContext.get: Timeout -1ms exceeded."
    finally:
        negative.dispose()

    invalid = playwright.request.new_context(base_url=http_server, timeout="bad")
    try:
        with pytest.raises(Error) as invalid_timeout:
            invalid.get("/json")
        assert str(invalid_timeout.value).splitlines()[0] == (
            "APIRequestContext.get: timeout: expected float, got string"
        )
    finally:
        invalid.dispose()


def test_api_request_context_raw_get_connection_errors_keep_api_prefix(playwright):
    with socket.socket() as probe:
        probe.bind(("127.0.0.1", 0))
        port = probe.getsockname()[1]

    request = playwright.request.new_context()
    try:
        with pytest.raises(Error) as exc_info:
            request.get(f"http://127.0.0.1:{port}/unreachable", timeout=250)
        first_line = str(exc_info.value).splitlines()[0]
        assert first_line.startswith("APIRequestContext.get: ")
        assert "UnboundLocalError" not in first_line
    finally:
        request.dispose()


def test_api_request_context_multipart_form_data(playwright, http_server):
    request = playwright.request.new_context(base_url=http_server)

    response = request.post(
        "/multipart",
        multipart={
            "empty": "",
            "title": "Quarterly report",
            "zero": "0",
            "count": 3,
            "enabled": True,
            "rawBytes": b"raw bytes are skipped by Playwright Python",
            "partialFile": {"name": "partial.txt", "buffer": b"ignored"},
            "attachment": {
                "name": "report.txt",
                "mimeType": "text/plain",
                "buffer": b"hello multipart",
            },
            "mimeFallback": {
                "name": "payload.bin",
                "mimeType": "",
                "buffer": b"fallback mime",
            },
        },
    )
    payload = response.json()

    assert response.status == 200
    assert payload["content_type"].startswith("multipart/form-data; boundary=")
    assert "rustwright" not in payload["content_type"].lower()
    assert "rustwright" not in payload["body"].lower()
    assert 'name="empty"' not in payload["body"]
    assert 'name="title"' in payload["body"]
    assert "Quarterly report" in payload["body"]
    assert 'name="zero"' in payload["body"]
    assert "\r\n0\r\n" in payload["body"]
    assert 'name="count"' not in payload["body"]
    assert 'name="enabled"' not in payload["body"]
    assert 'name="rawBytes"' not in payload["body"]
    assert 'name="partialFile"' not in payload["body"]
    assert 'name="attachment"; filename="report.txt"' in payload["body"]
    assert "content-type: text/plain" in payload["body"]
    assert "hello multipart" in payload["body"]
    assert 'name="mimeFallback"; filename="payload.bin"' in payload["body"]
    assert "content-type: application/octet-stream" in payload["body"]
    assert "fallback mime" in payload["body"]

    with pytest.raises(AssertionError) as invalid_buffer:
        request.post(
            "/multipart",
            multipart={
                "attachment": {
                    "name": "report.txt",
                    "mimeType": "text/plain",
                    "buffer": "not-bytes",
                }
            },
        )
    assert str(invalid_buffer.value) == "Unexpected buffer type of 'data.attachment'"
    request.dispose()


def test_api_request_context_body_option_truthiness_matches_playwright(playwright, http_server):
    request = playwright.request.new_context(base_url=http_server)
    try:
        cases = {
            "empty_multipart": {"multipart": {}},
            "empty_form": {"form": {}},
            "data_with_empty_multipart": {"data": "body", "multipart": {}},
            "data_with_empty_form": {"data": "body", "form": {}},
            "empty_data_with_form": {"data": "", "form": {"x": "y"}},
            "zero_data_with_form": {"data": 0, "form": {"x": "y"}},
        }
        results = {label: request.post("/echo", **kwargs).json() for label, kwargs in cases.items()}
    finally:
        request.dispose()

    assert results == {
        "empty_multipart": {"body": "", "content_type": None, "x_test": None},
        "empty_form": {"body": "", "content_type": None, "x_test": None},
        "data_with_empty_multipart": {
            "body": "body",
            "content_type": "application/octet-stream",
            "x_test": None,
        },
        "data_with_empty_form": {
            "body": "body",
            "content_type": "application/octet-stream",
            "x_test": None,
        },
        "empty_data_with_form": {"body": "", "content_type": None, "x_test": None},
        "zero_data_with_form": {"body": "0", "content_type": "application/json", "x_test": None},
    }


def test_api_request_context_invalid_url_errors_match_playwright(playwright):
    request = playwright.request.new_context()
    try:
        cases = [
            ("get_relative", lambda: request.get("/headers"), "APIRequestContext.get: Invalid URL"),
            ("post_relative", lambda: request.post("headers", data="x"), "APIRequestContext.post: Invalid URL"),
            ("fetch_malformed", lambda: request.fetch("http://"), "APIRequestContext.fetch: Invalid URL"),
            (
                "get_unsupported_protocol",
                lambda: request.get("ftp://example.com/file"),
                'APIRequestContext.get: Protocol "ftp:" not supported. Expected "http:"',
            ),
            (
                "fetch_unsupported_protocol",
                lambda: request.fetch("data:text/plain,hi"),
                'APIRequestContext.fetch: Protocol "data:" not supported. Expected "http:"',
            ),
            (
                "get_colon_protocol",
                lambda: request.get("localhost:1234/path"),
                'APIRequestContext.get: Protocol "localhost:" not supported. Expected "http:"',
            ),
        ]
        for label, operation, message in cases:
            with pytest.raises(Error) as exc_info:
                operation()
            assert str(exc_info.value).splitlines()[0] == message, label
    finally:
        request.dispose()


def test_api_request_context_dispose_reason_and_header_errors_match_playwright(playwright, http_server):
    request = playwright.request.new_context(base_url=http_server)
    try:
        with pytest.raises(Error) as header_error:
            request.get("/headers", headers={None: "x"})
        assert str(header_error.value).splitlines()[0] == (
            "APIRequestContext.get: headers[0].name: expected string, got object"
        )
    finally:
        request.dispose()

    truthy_reason = playwright.request.new_context(base_url=http_server)
    try:
        with pytest.raises(Error) as reason_error:
            truthy_reason.dispose(reason=123)
        assert str(reason_error.value).splitlines()[0] == (
            "APIRequestContext.dispose: reason: expected string, got number"
        )
        with pytest.raises(Error) as closed_error:
            truthy_reason.get("/headers")
        assert str(closed_error.value).splitlines()[0] == "123"
    finally:
        try:
            truthy_reason.dispose()
        except Error:
            pass

    false_reason = playwright.request.new_context(base_url=http_server)
    try:
        with pytest.raises(Error) as false_reason_error:
            false_reason.dispose(reason=False)
        assert str(false_reason_error.value).splitlines()[0] == (
            "APIRequestContext.dispose: reason: expected string, got boolean"
        )
        assert false_reason.get("/headers").status == 200
    finally:
        false_reason.dispose()


def test_api_request_context_cookie_storage_state(playwright, http_server, tmp_path: Path):
    request = playwright.request.new_context(base_url=http_server)

    request.get("/set-cookie")
    assert request.get("/cookie-echo").json() == {"cookie": "session=abc123"}

    state = request.storage_state()
    assert state["origins"] == []
    assert any(cookie["name"] == "session" and cookie["value"] == "abc123" for cookie in state["cookies"])

    state_path = tmp_path / "api-storage-state.json"
    assert request.storage_state(path=str(state_path)) == state
    assert json.loads(state_path.read_text()) == state
    for value, message in [
        ("bad", "APIRequestContext.storage_state: indexed_db: expected boolean, got string"),
        (1, "APIRequestContext.storage_state: indexed_db: expected boolean, got number"),
    ]:
        with pytest.raises(Error) as exc_info:
            request.storage_state(indexed_db=value)
        assert str(exc_info.value).splitlines()[0] == message
    request.storage_state(indexed_db=True)
    request.dispose()

    replay_request = playwright.request.new_context(base_url=http_server, storage_state=str(state_path))
    assert replay_request.get("/cookie-echo").json() == {"cookie": "session=abc123"}
    replay_request.dispose()


def test_api_request_context_dispose_closes_context_with_reason(playwright, http_server):
    request = playwright.request.new_context(base_url=http_server)
    request.dispose()
    with pytest.raises(Error) as closed_get:
        request.get("/json")
    assert str(closed_get.value).splitlines()[0] == (
        "APIRequestContext.get: Target page, context or browser has been closed"
    )
    with pytest.raises(Error) as closed_storage:
        request.storage_state()
    assert str(closed_storage.value).splitlines()[0] == (
        "APIRequestContext.storage_state: Target page, context or browser has been closed"
    )

    reason_request = playwright.request.new_context(base_url=http_server)
    reason_request.dispose(reason="api request shutdown")
    with pytest.raises(Error) as reason_error:
        reason_request.get("/json")
    assert str(reason_error.value).splitlines()[0] == "api request shutdown"
    with pytest.raises(Error) as reason_storage:
        reason_request.storage_state()
    assert str(reason_storage.value).splitlines()[0] == (
        "APIRequestContext.storage_state: Target page, context or browser has been closed"
    )
    reason_request.dispose(reason="second shutdown")
    with pytest.raises(Error) as second_reason_error:
        reason_request.get("/json")
    assert str(second_reason_error.value).splitlines()[0] == "second shutdown"


def test_context_request_shares_cookies_with_browser_context(browser, http_server):
    context = browser.new_context(base_url=http_server)
    try:
        context.add_cookies([{"name": "from_browser", "value": "yes", "url": http_server}])
        assert context.request.get("/cookie-echo").json() == {"cookie": "from_browser=yes"}

        context.request.get("/set-cookie")
        response = context.new_page().goto(f"{http_server}/cookie-echo")

        assert response is not None
        cookie_header = response.json()["cookie"]
        assert "from_browser=yes" in cookie_header
        assert "session=abc123" in cookie_header
        assert any(cookie["name"] == "session" and cookie["value"] == "abc123" for cookie in context.cookies(http_server))
    finally:
        context.close()


