def test_context_request_skips_blank_context_cookie_sync_until_page_can_mutate_cookies(browser, http_server, monkeypatch):
    context = browser.new_context(base_url=http_server)
    try:
        page = context.new_page()
        cookie_sync_calls = 0
        original_cookies = context.cookies

        def counted_cookies(*args, **kwargs):
            nonlocal cookie_sync_calls
            cookie_sync_calls += 1
            return original_cookies(*args, **kwargs)

        monkeypatch.setattr(context, "cookies", counted_cookies)

        assert context.request.get("/headers").status == 200
        assert cookie_sync_calls == 0

        page.evaluate("() => { document.body.dataset.cookieSyncRisk = '1'; }")
        assert context.request.get("/headers").status == 200
        assert cookie_sync_calls == 1
    finally:
        context.close()


