def test_api_request_context_proxy_bypass_uses_direct_connection(playwright, browser, http_proxy_server, direct_http_server):
    proxy_url, proxy_seen = http_proxy_server
    direct_port, direct_seen = direct_http_server
    target_url = f"http://localhost:{direct_port}/direct"

    request = playwright.request.new_context(proxy={"server": proxy_url, "bypass": "<local>"})
    try:
        response = request.get(target_url)
        assert response.status == 200
        assert response.text() == "<title>Direct</title><main>direct target</main>"
    finally:
        request.dispose()

    context = browser.new_context(proxy={"server": proxy_url, "bypass": "<local>"})
    try:
        context_response = context.request.get(target_url)
        assert context_response.status == 200
    finally:
        context.close()

    assert wait_until(lambda: [item for item in direct_seen if item[0] == "/direct"])
    assert not [item for item in proxy_seen if item[0] == target_url]


def test_api_request_new_context_option_validation_matches_playwright(playwright):
    invalid_cases = [
        ({"base_url": 123}, "APIRequest.new_context: base_url: expected string, got number"),
        ({"user_agent": 123}, "APIRequest.new_context: user_agent: expected string, got number"),
        ({"proxy": "bad"}, "APIRequest.new_context: proxy: expected object, got string"),
        ({"proxy": {"username": "u"}}, "APIRequest.new_context: proxy.server: expected string, got undefined"),
        ({"proxy": {"server": 1}}, "APIRequest.new_context: proxy.server: expected string, got number"),
        (
            {"proxy": {"server": "http://127.0.0.1:1", "username": 1}},
            "APIRequest.new_context: proxy.username: expected string, got number",
        ),
        (
            {"proxy": {"server": "http://127.0.0.1:1", "password": 1}},
            "APIRequest.new_context: proxy.password: expected string, got number",
        ),
        (
            {"proxy": {"server": "http://127.0.0.1:1", "bypass": 1}},
            "APIRequest.new_context: proxy.bypass: expected string, got number",
        ),
        ({"extra_http_headers": {1: "x"}}, "APIRequest.new_context: extraHTTPHeaders[0].name: expected string, got number"),
        ({"extra_http_headers": {"X": 1}}, "APIRequest.new_context: extraHTTPHeaders[0].value: expected string, got number"),
        ({"http_credentials": "bad"}, "APIRequest.new_context: http_credentials: expected object, got string"),
        ({"http_credentials": {"username": "u"}}, "APIRequest.new_context: httpCredentials.password: expected string, got undefined"),
        ({"http_credentials": {"password": "p"}}, "APIRequest.new_context: httpCredentials.username: expected string, got undefined"),
        (
            {"http_credentials": {"username": 1, "password": "p"}},
            "APIRequest.new_context: httpCredentials.username: expected string, got number",
        ),
        (
            {"http_credentials": {"username": "u", "password": 1}},
            "APIRequest.new_context: httpCredentials.password: expected string, got number",
        ),
        (
            {"http_credentials": {"username": "u", "password": "p", "origin": 1}},
            "APIRequest.new_context: httpCredentials.origin: expected string, got number",
        ),
        (
            {"http_credentials": {"username": "u", "password": "p", "send": "bad"}},
            "APIRequest.new_context: httpCredentials.send: expected one of (always|unauthorized)",
        ),
        ({"ignore_https_errors": "bad"}, "APIRequest.new_context: ignore_https_errors: expected boolean, got string"),
        ({"fail_on_status_code": "bad"}, "APIRequest.new_context: fail_on_status_code: expected boolean, got string"),
        ({"max_redirects": "bad"}, "APIRequest.new_context: max_redirects: expected integer, got string"),
        ({"max_redirects": True}, "APIRequest.new_context: max_redirects: expected integer, got boolean"),
        ({"max_redirects": 1.5}, "APIRequest.new_context: max_redirects: expected integer, got float 1.5"),
        ({"client_certificates": "bad"}, "APIRequest.new_context: client_certificates: expected array, got string"),
        (
            {"client_certificates": [{"origin": "https://example.com"}]},
            "APIRequest.new_context: None of cert, key, passphrase or pfx is specified",
        ),
        (
            {"client_certificates": [{"origin": "https://example.com", "certPath": "cert.pem"}]},
            "APIRequest.new_context: cert is specified without key",
        ),
        (
            {"client_certificates": [{"origin": "https://example.com", "keyPath": "key.pem"}]},
            "APIRequest.new_context: key is specified without cert",
        ),
        (
            {"client_certificates": [{"origin": "https://example.com", "certPath": "cert.pem", "pfxPath": "client.pfx"}]},
            "APIRequest.new_context: pfx is specified together with cert, key or passphrase",
        ),
    ]
    for kwargs, message in invalid_cases:
        with pytest.raises(Error) as exc_info:
            playwright.request.new_context(**kwargs)
        assert str(exc_info.value).splitlines()[0] == message
    with pytest.raises(AttributeError) as headers_container_error:
        playwright.request.new_context(extra_http_headers=[])
    assert str(headers_container_error.value).splitlines()[0] == "'list' object has no attribute 'items'"

    request = playwright.request.new_context(
        extra_http_headers={"X-Optional": None},
        http_credentials={"username": "u", "password": "p", "send": None},
        max_redirects=1.0,
        client_certificates=[],
    )
    request.dispose()


def test_api_request_context_client_certificates_authenticate_with_matching_origin(playwright, mtls_server):
    request = playwright.request.new_context(
        ignore_https_errors=True,
        client_certificates=[
            {
                "origin": mtls_server["origin"],
                "certPath": mtls_server["client_cert"],
                "keyPath": mtls_server["client_key"],
            }
        ],
    )
    try:
        response = request.get(mtls_server["url"])
        assert response.ok
        payload = response.json()
        assert payload["path"] == "/secure"
        assert "commonName=Rustwright Client" in payload["client_subject"]
    finally:
        request.dispose()


