def test_api_request_context_http_credentials(playwright, browser, http_server):
    request = playwright.request.new_context(
        base_url=http_server,
        http_credentials={"username": "user", "password": "pass"},
    )
    assert request.get("/basic-auth").status == 200
    request.dispose()

    wrong_request = playwright.request.new_context(
        base_url=http_server,
        http_credentials={"username": "wrong", "password": "pass"},
    )
    assert wrong_request.get("/basic-auth").status == 401
    wrong_request.dispose()

    context = browser.new_context(
        base_url=http_server,
        http_credentials={"username": "user", "password": "pass"},
    )
    try:
        assert context.request.get("/basic-auth").json() == {
            "authorization": "Basic " + base64.b64encode(b"user:pass").decode("ascii")
        }
    finally:
        context.close()


