def test_expect_response_captures_fetch_response(page, http_server):
    page.goto(f"{http_server}/page")

    with page.expect_response("**/json") as response_info:
        page.click("#fetch")

    response = response_info.value
    assert response.status == 201
    assert response.request is not None
    assert response.request.method == "GET"
    assert response.request.url.endswith("/json")
    assert response.request.frame.page is page
    assert response.frame.page is page
    assert response.json() == {"ok": True, "path": "/json"}


def test_expect_response_records_linked_request_in_history(page, http_server):
    page.goto(f"{http_server}/page")

    with page.expect_response(lambda response: response.url.endswith("/headers"), timeout=3_000) as response_info:
        page.evaluate("() => fetch('/headers')")

    response = response_info.value
    assert response.request is not None
    assert response.request.url == f"{http_server}/headers"
    assert any(request.url == f"{http_server}/headers" for request in page.requests())


