def test_post_request_body_helpers_and_response_link(page, http_server):
    page.goto(f"{http_server}/page")

    with page.expect_request(lambda request: request.url.endswith("/echo")) as request_info:
        with page.expect_response(lambda response: response.url.endswith("/echo")) as response_info:
            page.evaluate(
                """() => fetch('/echo', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'X-Test-Header': 'from-page' },
                body: JSON.stringify({ hello: 'browser' }),
                })"""
            )

    request = request_info.value
    response = response_info.value

    assert request.method == "POST"
    assert request.url == f"{http_server}/echo"
    assert request.header_value("content-type") == "application/json"
    assert request.post_data == '{"hello":"browser"}'
    assert request.post_data_buffer == b'{"hello":"browser"}'
    assert request.post_data_json == {"hello": "browser"}
    request_sizes = request.sizes()
    assert request_sizes["requestBodySize"] == len(b'{"hello":"browser"}')
    assert request_sizes["requestHeadersSize"] > 0

    assert response.status == 202
    assert request is response.request
    assert response.request is not None
    assert response.request.post_data_json == {"hello": "browser"}
    assert request.response() is response
    assert response.request.response() is response
    response_request_sizes = response.request.sizes()
    assert response_request_sizes["requestBodySize"] == len(b'{"hello":"browser"}')
    assert response_request_sizes["requestHeadersSize"] > 0
    assert response_request_sizes["responseHeadersSize"] > 0
    assert response.request.timing["startTime"] > 0
    assert response.request.timing["requestStart"] >= -1
    assert response.request.frame.page is page
    assert response.frame.page is page
    assert response.header_value("content-type") == "application/json"
    assert response.header_values("content-type") == ["application/json"]
    assert {"name": "Content-Type", "value": "application/json"} in response.headers_array()
    assert response.finished() is None
    assert request.sizes()["responseBodySize"] == len(response.body())


def test_binary_post_request_preserves_post_data_buffer(page):
    body = b"\x00\xffA"
    routed_buffers = []

    def handler(route):
        routed_buffers.append(route.request.post_data_buffer)
        route.fulfill(status=200, body="ok")

    page.route("**/binary-post", handler)
    page.goto("about:blank")

    with page.expect_request("**/binary-post") as request_info:
        page.evaluate(
            """() => fetch('https://example.com/binary-post', {
            method: 'POST',
            mode: 'no-cors',
            headers: { 'content-type': 'application/octet-stream' },
            body: new Uint8Array([0, 255, 65]).buffer,
            }).catch(() => {})"""
        )

    request = request_info.value
    assert routed_buffers == [body]
    assert request.post_data_buffer == body
    assert request.sizes()["requestBodySize"] == len(body)
    with pytest.raises(UnicodeDecodeError, match="utf-8"):
        request.post_data
    with pytest.raises(UnicodeDecodeError, match="utf-8"):
        request.post_data_json


def test_request_post_data_json_parses_form_urlencoded(page, http_server):
    page.goto(f"{http_server}/page")

    with page.expect_request(lambda request: request.url.endswith("/echo")) as request_info:
        page.evaluate(
            """() => fetch('/echo', {
            method: 'POST',
            body: new URLSearchParams({ hello: 'form', number: '7', multi: 'one' }),
            })"""
        )

    request = request_info.value
    assert request.header_value("content-type").startswith("application/x-www-form-urlencoded")
    assert request.post_data == "hello=form&number=7&multi=one"
    assert request.post_data_json == {"hello": "form", "number": "7", "multi": "one"}


def test_response_finished_waits_for_slow_body(page, http_server):
    page.goto(f"{http_server}/page")
    started = time.monotonic()
    with page.expect_response("**/slow-body") as response_info:
        page.evaluate("() => { fetch('/slow-body').then(response => response.text()); }")

    response = response_info.value
    assert response.finished() is None
    elapsed = time.monotonic() - started

    assert elapsed >= 0.15
    assert response.text().startswith("<title>Slow Body</title>")


def test_redirect_request_chain_helpers(page, http_server):
    listener_requests = []
    page.on("request", listener_requests.append)
    with page.expect_request(lambda request: request.url.endswith("/json")) as request_info:
        page.goto(f"{http_server}/redirect-hop-one")

    final_request = request_info.value
    redirected_from = final_request.redirected_from
    listener_final = wait_until(
        lambda: next((request for request in listener_requests if request.url.endswith("/json")), None)
    )

    assert final_request.url == f"{http_server}/json"
    assert final_request.is_navigation_request()
    assert redirected_from is not None
    assert redirected_from.url == f"{http_server}/redirect-hop-two"
    assert redirected_from.redirected_from is not None
    assert redirected_from.redirected_from.url == f"{http_server}/redirect-hop-one"
    assert redirected_from.redirected_from.redirected_from is None
    assert redirected_from.redirected_from.redirected_to is redirected_from
    assert redirected_from.redirected_to is final_request
    assert final_request.redirected_to is None
    assert listener_final.redirected_from is not None
    assert listener_final.redirected_from.url == f"{http_server}/redirect-hop-two"
    assert listener_final.redirected_from.redirected_from is not None
    assert listener_final.redirected_from.redirected_from.url == f"{http_server}/redirect-hop-one"


def test_expect_download_captures_file(page, http_server, tmp_path: Path):
    page.set_content(f"<a id='download' href='{http_server}/download'>Download</a>")

    with page.expect_download() as download_info:
        page.click("#download")

    download = download_info.value
    saved_path = download.path()
    assert isinstance(saved_path, Path)
    copied_path = tmp_path / "copy.txt"
    download.save_as(str(copied_path))

    assert download.suggested_filename == "report.txt"
    assert download.failure() is None
    assert saved_path.read_bytes() == b"download-body"
    assert copied_path.read_bytes() == b"download-body"
    download.cancel()
    assert download.failure() is None
    assert saved_path.exists()
    download.delete()
    assert not saved_path.exists()


def test_download_save_as_fetches_when_cdp_path_is_not_local(page, http_server, tmp_path: Path):
    from playwright.sync_api import Download

    remote_only_path = tmp_path / "remote-browser-download-guid"
    copy_path = tmp_path / "remote-copy.txt"
    download = Download(
        page,
        {
            "url": f"{http_server}/download",
            "suggested_filename": "report.txt",
            "path": str(remote_only_path),
        },
    )

    download.save_as(copy_path)

    assert not remote_only_path.exists()
    assert copy_path.read_bytes() == b"download-body"


def test_page_download_waiters_ignore_other_pages(browser, http_server):
    context = browser.new_context()
    first = context.new_page()
    second = context.new_page()
    try:
        first.set_content(f"<a id='download' href='{http_server}/download'>First</a>")
        second.set_content(f"<a id='download' href='{http_server}/download'>Second</a>")

        with pytest.raises(TimeoutError):
            with first.expect_download(timeout=500):
                second.evaluate("() => document.querySelector('#download').click()")

        with first.expect_download(timeout=3_000) as download_info:
            first.evaluate("() => document.querySelector('#download').click()")

        assert download_info.value.url == f"{http_server}/download"
    finally:
        context.close()


