def test_async_skyvern_browser_cdp_download_behavior_allow_writes_suggested_file():
    async def run() -> None:
        import inspect

        from playwright.async_api import async_playwright
        from benchmarks.automation_cases import header_case_server

        with tempfile.TemporaryDirectory() as directory, header_case_server() as base_url:
            downloads_dir = Path(directory) / "async-browser-cdp-downloads"
            downloads_dir.mkdir()
            async with async_playwright() as p:
                browser = await p.chromium.launch(headless=True)
                try:
                    session = await browser.new_browser_cdp_session()
                    await session.send(
                        "Browser.setDownloadBehavior",
                        {
                            "behavior": "allow",
                            "downloadPath": str(downloads_dir),
                            "eventsEnabled": True,
                        },
                    )
                    await session.detach()

                    context = await browser.new_context()
                    try:
                        download_page = await context.new_page()
                        await download_page.set_content(
                            f"<a id='large' href='{base_url}/download-large-slow'>Large</a>"
                        )
                        await download_page.evaluate("() => document.querySelector('#large').click()")

                        saw_partial = False
                        observed_files = []
                        deadline = time.monotonic() + 8.0
                        while time.monotonic() < deadline:
                            files = sorted(path.name for path in downloads_dir.iterdir())
                            observed_files.append(files)
                            if any(name.endswith(".crdownload") for name in files):
                                saw_partial = True
                            if "large-report.bin" in files:
                                break
                            await asyncio.sleep(0.05)

                        final_path = downloads_dir / "large-report.bin"
                        assert saw_partial, f"expected suggested-name .crdownload file, observed {observed_files[-10:]}"
                        assert final_path.exists(), f"expected suggested-name final file, observed {observed_files[-10:]}"
                        assert final_path.stat().st_size == 2 * 1024 * 1024
                        assert not list(downloads_dir.glob("*.crdownload"))
                    finally:
                        await context.close()
                finally:
                    await browser.close()

    asyncio.run(run())


def test_async_skyvern_browser_cdp_download_monitor_deny_event_and_context_request():
    async def run() -> None:
        from playwright.async_api import async_playwright
        from benchmarks.automation_cases import header_case_server

        with header_case_server() as base_url:
            async with async_playwright() as p:
                browser = await p.chromium.launch(headless=True)
                try:
                    context = await browser.new_context()
                    session = await browser.new_browser_cdp_session()
                    try:
                        download_page = await context.new_page()
                        await download_page.goto(f"{base_url}/set-cookies")
                        done = asyncio.Event()
                        events: list[dict[str, Any]] = []
                        errors: list[str] = []

                        async def handle_download(event: dict[str, Any]) -> None:
                            events.append(event)
                            done.set()

                        def callback(event: dict[str, Any]) -> None:
                            try:
                                asyncio.ensure_future(handle_download(event))
                            except BaseException as exc:
                                errors.append(f"{type(exc).__name__}: {exc}")
                                done.set()

                        session.on("Browser.downloadWillBegin", callback)
                        await session.send(
                            "Browser.setDownloadBehavior",
                            {
                                "behavior": "deny",
                                "eventsEnabled": True,
                            },
                        )

                        await download_page.set_content(
                            f"<a id='protected' href='{base_url}/protected-download'>Protected</a>"
                        )
                        await download_page.evaluate("() => document.querySelector('#protected').click()")

                        await asyncio.wait_for(done.wait(), timeout=3)
                        assert errors == []
                        assert events
                        event = events[0]
                        assert event["url"].endswith("/protected-download")
                        assert event["suggestedFilename"] == "protected.txt"
                        response = await context.request.get(event["url"])
                        try:
                            assert response.status == 200
                            assert await response.body() == b"protected-download-body"
                        finally:
                            await response.dispose()
                    finally:
                        await session.detach()
                        await context.close()
                finally:
                    await browser.close()

    asyncio.run(run())


