def test_accept_downloads_false_matches_playwright_error_shape(browser, http_server, tmp_path: Path):
    context = browser.new_context(accept_downloads=False)
    page = context.new_page()
    page.set_content(f"<a id='download' href='{http_server}/download'>Download</a>")

    with page.expect_download() as download_info:
        page.click("#download")

    download = download_info.value
    assert download.suggested_filename == "report.txt"
    assert download.failure() == "Pass 'accept_downloads=True' when you are creating your browser context."
    with pytest.raises(Error, match="Download\\.path: Pass 'accept_downloads=True'"):
        download.path()
    with pytest.raises(Error, match="Download\\.save_as: Pass 'accept_downloads=True'"):
        download.save_as(str(tmp_path / "copy.txt"))
    context.close()


