def test_launch_env_is_passed_to_chromium_process(playwright, tmp_path: Path):
    env_file = tmp_path / "launch-env.txt"
    wrapper = chromium_env_probe_wrapper(tmp_path, playwright.chromium.executable_path, env_file)

