def test_launch_args_validation_matches_playwright(playwright, tmp_path: Path):
    with pytest.raises(Error) as string_exc:
        playwright.chromium.launch(headless=True, args="--mute-audio")
    assert str(string_exc.value).splitlines()[0] == (
        "BrowserType.launch: args: expected array, got string"
    )

    with pytest.raises(Error) as scalar_exc:
        playwright.chromium.launch(headless=True, args=123)
    assert str(scalar_exc.value).splitlines()[0] == (
        "BrowserType.launch: args: expected array, got number"
    )

    with pytest.raises(Error) as item_exc:
        playwright.chromium.launch(headless=True, args=["--mute-audio", 123])
    assert str(item_exc.value).splitlines()[0] == (
        "BrowserType.launch: args[1]: expected string, got number"
    )

    expected_page_arg_error = "BrowserType.launch: Arguments can not specify page to be opened"
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as probe:
        probe.bind(("127.0.0.1", 0))
        port = int(probe.getsockname()[1])

    with pytest.raises(Error) as page_arg_exc:
        playwright.chromium.launch(headless=True, args=["about:blank"], timeout=1_000)
    assert str(page_arg_exc.value).splitlines()[0] == expected_page_arg_error

    with pytest.raises(Error) as split_flag_arg_exc:
        playwright.chromium.launch(
            headless=True,
            args=["--host-resolver-rules", "MAP example.com 127.0.0.1"],
            timeout=1_000,
        )
    assert str(split_flag_arg_exc.value).splitlines()[0] == expected_page_arg_error

    with pytest.raises(Error) as split_remote_debugging_port_exc:
        playwright.chromium.launch(
            headless=True,
            args=["--remote-debugging-port", str(port)],
            timeout=1_000,
        )
    assert str(split_remote_debugging_port_exc.value).splitlines()[0] == expected_page_arg_error

    expected_user_data_dir_error = (
        "BrowserType.launch: Pass user_data_dir parameter to "
        "'browser_type.launch_persistent_context(user_data_dir, **kwargs)' "
        "instead of specifying '--user-data-dir' argument"
    )
    with pytest.raises(Error) as user_data_dir_exc:
        playwright.chromium.launch(
            headless=True,
            args=[f"--user-data-dir={tmp_path / 'launch-profile'}"],
            timeout=1_000,
        )
    assert str(user_data_dir_exc.value).splitlines()[0] == expected_user_data_dir_error

    with pytest.raises(Error) as user_data_dir_split_exc:
        playwright.chromium.launch(
            headless=True,
            args=["--user-data-dir", str(tmp_path / "launch-profile-split")],
            timeout=1_000,
        )
    assert str(user_data_dir_split_exc.value).splitlines()[0] == expected_user_data_dir_error

    with pytest.raises(Error) as remote_debugging_pipe_exc:
        playwright.chromium.launch(
            headless=True,
            args=["--remote-debugging-pipe"],
            timeout=1_000,
        )
    assert str(remote_debugging_pipe_exc.value).splitlines()[0] == (
        "BrowserType.launch: Playwright manages remote debugging connection itself."
    )

    with pytest.raises(Error) as remote_debugging_pipe_value_exc:
        playwright.chromium.launch(
            headless=True,
            args=["--remote-debugging-pipe=1"],
            timeout=1_000,
        )
    assert str(remote_debugging_pipe_value_exc.value).splitlines()[0] == (
        "BrowserType.launch: Playwright manages remote debugging connection itself."
    )


