def test_launch_hidden_pipe_transport_opt_in(playwright, monkeypatch):
    if sys.platform == "win32":
        pytest.skip("Chromium remote-debugging pipe fd wiring is Unix-only")
    monkeypatch.setenv("RUSTWRIGHT_CDP_TRANSPORT", "pipe")
    browser = playwright.chromium.launch(headless=True)
    try:
        assert browser._ws_endpoint == "pipe://chromium"
        assert "Chrome" in browser.version
        page = browser.new_page()
        page.set_content("<button id='go'>Go</button>")
        assert page.locator("#go").text_content() == "Go"
        assert page.evaluate("() => 2 + 3") == 5
        assert page.screenshot().startswith(b"\x89PNG")
    finally:
        browser.close()


def test_launch_hidden_pipe_transport_repeated_response_waits(playwright, http_server, monkeypatch):
    if sys.platform == "win32":
        pytest.skip("Chromium remote-debugging pipe fd wiring is Unix-only")
    monkeypatch.setenv("RUSTWRIGHT_CDP_TRANSPORT", "pipe")
    browser = playwright.chromium.launch(headless=True)
    try:
        for _ in range(12):
            page = browser.new_page()
            try:
                page.goto(f"{http_server}/page")
                with page.expect_response(lambda response: response.url.endswith("/headers"), timeout=3_000) as response_info:
                    page.evaluate("() => fetch('/headers')")
                assert response_info.value.status == 200
            finally:
                page.close()
    finally:
        browser.close()


