def test_persistent_context_context_options_validate_before_launch(playwright, tmp_path: Path):
    marker = tmp_path / "chromium-launched"
    real_chromium = playwright.chromium.executable_path
    wrapper = tmp_path / "chromium-launch-probe.py"
    wrapper.write_text(
        "\n".join(
            [
                f"#!{sys.executable}",
                "import os",
                "from pathlib import Path",
                f"Path({str(marker)!r}).write_text('launched', encoding='utf-8')",
                f"os.execv({real_chromium!r}, [{real_chromium!r}] + os.sys.argv[1:])",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    wrapper.chmod(0o755)

    with pytest.raises(Error) as exc_info:
        playwright.chromium.launch_persistent_context(
            str(tmp_path / "profile-context-option"),
            headless=True,
            executable_path=str(wrapper),
            java_script_enabled="bad",
        )

    assert str(exc_info.value).splitlines()[0] == (
        "BrowserType.launch_persistent_context: java_script_enabled: expected boolean, got string"
    )
    assert not marker.exists()


