    assert str(user_data_dir_exc.value) == (
        "argument should be a str or an os.PathLike object where __fspath__ returns a str, not 'int'"
    )

    with pytest.raises(TypeError) as executable_exc:
        playwright.chromium.launch_persistent_context(
            str(tmp_path / "profile-executable-path"),
            headless=True,
            executable_path=123,
        )
    assert str(executable_exc.value) == (
        "argument should be a str or an os.PathLike object where __fspath__ returns a str, not 'int'"
    )

    with pytest.raises(TypeError) as downloads_exc:
        playwright.chromium.launch_persistent_context(
            str(tmp_path / "profile-downloads-path"),
            headless=True,
            downloads_path=[],
        )
    assert str(downloads_exc.value) == (
        "argument should be a str or an os.PathLike object where __fspath__ returns a str, not 'list'"
    )

    with pytest.raises(TypeError) as traces_exc:
        playwright.chromium.launch_persistent_context(
            str(tmp_path / "profile-traces-dir"),
            headless=True,
            traces_dir={},
        )
    assert str(traces_exc.value) == (
        "argument should be a str or an os.PathLike object where __fspath__ returns a str, not 'dict'"
    )

    with pytest.raises(TypeError) as artifacts_exc:
        playwright.chromium.launch_persistent_context(
            str(tmp_path / "profile-artifacts-dir"),
            headless=True,
            artifacts_dir=True,
        )
    assert str(artifacts_exc.value) == (
        "argument should be a str or an os.PathLike object where __fspath__ returns a str, not 'bool'"
    )


