def test_launch_reports_chromium_stderr_when_process_exits(playwright, tmp_path: Path):
    wrapper = tmp_path / "chromium-fails.sh"
    wrapper.write_text(
        "#!/bin/sh\n"
        "echo 'synthetic chromium stderr failure' >&2\n"
        "exit 86\n",
        encoding="utf-8",
    )
    wrapper.chmod(0o755)

    with pytest.raises(Error) as exc_info:
        playwright.chromium.launch(headless=True, executable_path=str(wrapper), timeout=1_000)

    message = str(exc_info.value)
    assert "Failed to launch chromium" in message
    assert "Chromium process exited before CDP endpoint became available" in message
    assert "synthetic chromium stderr failure" in message
    assert "status:" in message


