def test_page_request_and_response_events_are_dispatched(page, http_server):
    page.goto(f"{http_server}/page")
    requests = []
    responses = []

    page.on("request", lambda request: requests.append((request.method, request.url)))
    page.on("response", lambda response: responses.append((response.status, response.url)))
    page.click("#fetch")

    assert wait_until(lambda: [item for item in requests if item[1].endswith("/json")])[0] == (
        "GET",
        f"{http_server}/json",
    )
