def test_page_requestfailed_event_captures_aborted_request(page, http_server):
    page.goto(f"{http_server}/page")
    failures = []

    page.route("**/json", lambda route: route.abort("failed"))
    page.on("requestfailed", lambda request: failures.append((request.url, request.failure)))
    with page.expect_event("requestfailed", lambda request: request.url.endswith("/json")) as request_info:
        page.evaluate(
            """() => fetch('/json').then(
              () => document.body.dataset.failed = 'no',
              () => document.body.dataset.failed = 'yes'
            )"""
        )

    assert request_info.value.url == f"{http_server}/json"
    assert request_info.value.failure
    assert wait_until(lambda: page.evaluate("document.body.dataset.failed")) == "yes"
    assert wait_until(lambda: failures)[0][0] == f"{http_server}/json"


def test_route_abort_option_validation_matches_playwright(page, http_server):
    errors = []

    def handler(route):
        invalid_cases = [
            ("number", lambda: route.abort(123), "Route.abort: error_code: expected string, got number"),
            ("boolean", lambda: route.abort(True), "Route.abort: error_code: expected string, got boolean"),
            ("empty", lambda: route.abort(""), "Route.abort: Unknown error code: "),
            (
                "underscore",
                lambda: route.abort("connection_failed"),
                "Route.abort: Unknown error code: connection_failed",
            ),
        ]
        for label, call, expected in invalid_cases:
            with pytest.raises(Error) as exc_info:
                call()
            errors.append([label, str(exc_info.value).splitlines()[0]])
            assert str(exc_info.value).splitlines()[0] == expected
        route.fulfill(status=200, json={"errors": errors})

    page.route("**/route-abort-validation", handler)
    response = page.goto(f"{http_server}/route-abort-validation")

    assert response.json()["errors"] == [
        ["number", "Route.abort: error_code: expected string, got number"],
        ["boolean", "Route.abort: error_code: expected string, got boolean"],
        ["empty", "Route.abort: Unknown error code: "],
        ["underscore", "Route.abort: Unknown error code: connection_failed"],
    ]


