def test_page_unroute_all_wait_behavior_waits_for_active_handler(page, http_server):
    entered = threading.Event()
    release = threading.Event()
    completed = threading.Event()

    def handler(route):
        entered.set()
        release.wait(timeout=3)
        route.fulfill(status=200, body="waited")
        completed.set()

    page.route("**/query?unroute=wait", handler)
    page.goto(f"{http_server}/headers")
    page.evaluate(
        """() => {
        window.unrouteWaitResult = "";
        fetch('/query?unroute=wait')
          .then(response => response.text())
          .then(text => window.unrouteWaitResult = text)
          .catch(error => window.unrouteWaitResult = String(error));
        }"""
    )

    assert entered.wait(timeout=3)
    timer = threading.Timer(0.2, release.set)
    timer.start()
    started = time.monotonic()
    page.unroute_all(behavior="wait")
    elapsed = time.monotonic() - started
    timer.cancel()

    assert elapsed >= 0.15
    assert completed.is_set()
    assert wait_until(lambda: page.evaluate("() => window.unrouteWaitResult")) == "waited"
    assert page.goto(f"{http_server}/query?unroute=wait").json() == {"path": "/query", "query": {"unroute": ["wait"]}}


