def test_route_continue_option_validation_matches_playwright(page, http_server):
    errors = []

    def handler(route, request):
        invalid_cases = [
            ("url", lambda: route.continue_(url=123), "Route.continue_: url: expected string, got number"),
            ("method", lambda: route.continue_(method=123), "Route.continue_: method: expected string, got number"),
            (
                "headers_name",
                lambda: route.continue_(headers={1: "x"}),
                "Route.continue_: headers[0].name: expected string, got number",
            ),
            (
                "headers_value",
                lambda: route.continue_(headers={"X": 1}),
                "Route.continue_: headers[0].value: expected string, got number",
            ),
        ]
        for label, call, expected in invalid_cases:
            with pytest.raises(Error) as exc_info:
                call()
            errors.append([label, str(exc_info.value).splitlines()[0]])
            assert str(exc_info.value).splitlines()[0] == expected
        route.fulfill(status=200, json={"errors": errors})

    page.route("**/route-continue-validation", handler)
    response = page.goto(f"{http_server}/route-continue-validation")

    assert response.json()["errors"] == [
        ["url", "Route.continue_: url: expected string, got number"],
        ["method", "Route.continue_: method: expected string, got number"],
        ["headers_name", "Route.continue_: headers[0].name: expected string, got number"],
        ["headers_value", "Route.continue_: headers[0].value: expected string, got number"],
    ]


