def test_page_route_structured_post_data_matches_playwright_encoding(page, http_server):
    page.goto(f"{http_server}/page")

    class Unserializable:
        pass

    page.route(
        "**/echo",
        lambda route: route.continue_(
            headers={"Content-Type": "application/json"},
            post_data={"patched": True},
        ),
    )
    continued = page.evaluate(
        """() => fetch('/echo', {
            method: 'POST',
            headers: { 'Content-Type': 'text/plain' },
            body: 'base'
        }).then(response => response.json())"""
    )

    page.unroute("**/echo")
    fetched = []

    def fetch_handler(route):
        upstream = route.fetch(
            headers={"Content-Type": "application/json"},
            post_data={"fetch": 7},
        )
        fetched.append(upstream.json())
        route.fulfill(response=upstream)

    page.route("**/echo", fetch_handler)
    fulfilled = page.evaluate(
        """() => fetch('/echo', {
            method: 'POST',
            headers: { 'Content-Type': 'text/plain' },
            body: 'base'
        }).then(response => response.json())"""
    )

    page.unroute("**/echo")
    fallback_requests = []

    def terminal(route, request):
        fallback_requests.append((request.post_data, request.post_data_json))
        route.continue_()

    page.route("**/echo", terminal)
    page.route(
        "**/echo",
        lambda route: route.fallback(
            headers={"Content-Type": "application/json"},
            post_data={"fallback": 3},
        ),
    )
    fallback_continued = page.evaluate(
        """() => fetch('/echo', {
            method: 'POST',
            headers: { 'Content-Type': 'text/plain' },
            body: 'base'
        }).then(response => response.json())"""
    )

    assert continued == {
        "content_type": "application/json",
        "x_test": None,
        "body": '{"patched": true}',
    }
    assert fetched == [
        {
            "content_type": "application/json",
            "x_test": None,
            "body": '{"fetch": 7}',
        }
    ]
    assert fulfilled == fetched[0]
    assert fallback_requests == [('{"fallback": 3}', {"fallback": 3})]
    assert fallback_continued == {
        "content_type": "application/json",
        "x_test": None,
        "body": '{"fallback": 3}',
    }

    errors = []

    def invalid_override_handler(route, request):
        for label, call in (
            ("continue", lambda: route.continue_(method="POST", post_data=Unserializable())),
            ("fallback", lambda: route.fallback(method="POST", post_data=Unserializable())),
        ):
            with pytest.raises(TypeError) as exc_info:
                call()
            errors.append([label, str(exc_info.value)])
        route.fulfill(status=200, json={"errors": errors})

    page.route("**/route-post-data-validation", invalid_override_handler)
    validation_response = page.goto(f"{http_server}/route-post-data-validation")

    assert validation_response.json()["errors"] == [
        ["continue", "Object of type Unserializable is not JSON serializable"],
        ["fallback", "Object of type Unserializable is not JSON serializable"],
    ]


def test_page_route_fallback_invokes_next_matching_handler(page, http_server):
    calls = []
    page.goto(f"{http_server}/page")

    def terminal(route, request):
        calls.append(("terminal", request.url))
        route.fulfill(json={"ok": True, "path": "/fallback-chain"})

    def first(route, request):
        calls.append(("first", request.url))
        route.fallback()

    page.route("**/json", terminal)
    page.route("**/json", first)
    page.click("#fetch")

    assert wait_until(lambda: page.evaluate("document.body.dataset.fetchPath")) == "/fallback-chain"
    assert calls == [
        ("first", f"{http_server}/json"),
        ("terminal", f"{http_server}/json"),
    ]


