def test_page_route_terminal_actions_mark_route_handled_like_playwright(page, http_server):
    errors = []

    def continue_handler(route, request):
        route.continue_()
        with pytest.raises(Error) as handled_error:
            route.fulfill(json={"unexpected": True})
        errors.append(["continue", str(handled_error.value).splitlines()[0]])

    def fulfill_handler(route, request):
        route.fulfill(json={"ok": True})
        with pytest.raises(Error) as handled_error:
            route.continue_()
        errors.append(["fulfill", str(handled_error.value).splitlines()[0]])

    page.route("**/route-continue-handled", continue_handler)
    continued = page.goto(f"{http_server}/route-continue-handled")
    page.route("**/route-fulfill-handled", fulfill_handler)
    fulfilled = page.goto(f"{http_server}/route-fulfill-handled")

    assert continued.status == 404
    assert fulfilled.json() == {"ok": True}
    assert errors == [
        ["continue", "Route is already handled!"],
        ["fulfill", "Route is already handled!"],
    ]


