def test_route_fetch_honors_skyvern_local_proxy_bypass_token(page):
    from benchmarks.automation_cases import header_case_server, http_proxy_case_server, proxy_seen_for_url

    browser = page.context.browser
    assert browser is not None
    with header_case_server() as http_base, http_proxy_case_server() as (proxy_url, proxy_seen):
        local_http_base = http_base.replace("127.0.0.1", "localhost")
        context = browser.new_context(proxy={"server": proxy_url, "bypass": "<local>"})
        try:
            context_page = context.new_page()
            result: dict[str, object] = {}

            def handler(route):
                bypassed = route.fetch(url=f"{local_http_base}/headers")
                proxied = route.fetch(url="http://route-fetch-local-bypass-proxy.invalid/proxied")
                result["bypassed"] = bypassed.json()
                result["proxied"] = proxied.json()
                route.fulfill(status=200, json=result)

            context_page.route("**/route-fetch-local-bypass-trigger", handler)
            response = context_page.goto("http://route-fetch-trigger.invalid/route-fetch-local-bypass-trigger")
            assert response is not None
            payload = response.json()
        finally:
            context.close()

    assert payload == {
        "bypassed": {"ok": True},
        "proxied": {
            "proxied": True,
            "url": "http://route-fetch-local-bypass-proxy.invalid/proxied",
            "host": "route-fetch-local-bypass-proxy.invalid",
        },
    }
    assert proxy_seen_for_url(proxy_seen, "http://route-fetch-local-bypass-proxy.invalid/proxied") == [
        {
            "url": "http://route-fetch-local-bypass-proxy.invalid/proxied",
            "host": "route-fetch-local-bypass-proxy.invalid",
        }
    ]


