def test_route_fetch_honors_max_redirects(page, http_server):
    seen = []

    def no_redirect_handler(route):
        upstream = route.fetch(url=f"{http_server}/redirect-one", max_redirects=0)
        seen.append(("no-redirect", upstream.status, upstream.url))
        route.fulfill(status=200, json={"status": upstream.status, "url": upstream.url})

    page.route("**/route-fetch-no-redirect", no_redirect_handler)
    response = page.goto(f"{http_server}/route-fetch-no-redirect")

    errors = []

    def limited_redirect_handler(route):
        try:
            route.fetch(url=f"{http_server}/redirect-hop-one", max_redirects=1)
        except Error as exc:
            errors.append(str(exc))
            route.fulfill(status=200, json={"error": str(exc)})
            return
        raise AssertionError("route.fetch(max_redirects=1) should fail after one redirect")

    page.route("**/route-fetch-limited-redirect", limited_redirect_handler)
    limited_response = page.goto(f"{http_server}/route-fetch-limited-redirect")

    assert seen == [("no-redirect", 302, f"{http_server}/redirect-one")]
    assert response.json() == {"status": 302, "url": f"{http_server}/redirect-one"}
    assert "Max redirect count exceeded" in limited_response.json()["error"]
    assert any("Max redirect count exceeded" in error for error in errors)

    validation_errors = []

    def negative_option_handler(route):
        for option_name in ("max_redirects", "max_retries"):
            try:
                route.fetch(url=f"{http_server}/json", **{option_name: -1})
            except AssertionError as exc:
                validation_errors.append((option_name, str(exc)))
        route.fulfill(status=200, json={"errors": validation_errors})

    page.route("**/route-fetch-negative-options", negative_option_handler)
    validation_response = page.goto(f"{http_server}/route-fetch-negative-options")

    assert validation_response.json()["errors"] == [
        ["max_redirects", "Route.fetch: 'max_redirects' must be greater than or equal to '0'"],
        ["max_retries", "Route.fetch: 'max_retries' must be greater than or equal to '0'"],
    ]


def test_route_fetch_option_validation_matches_playwright(page, http_server):
    errors = []
    accepted = []

    def handler(route):
        invalid_cases = [
            (
                "headers_name",
                lambda: route.fetch(url=f"{http_server}/json", headers={1: "x"}),
                "Route.fetch: headers[0].name: expected string, got number",
            ),
            (
                "headers_value",
                lambda: route.fetch(url=f"{http_server}/json", headers={"X": 1}),
                "Route.fetch: headers[0].value: expected string, got number",
            ),
            ("url", lambda: route.fetch(url=123), "Route.fetch: url: expected string, got number"),
            ("method", lambda: route.fetch(method=123), "Route.fetch: method: expected string, got number"),
            (
                "max_redirects_bool",
                lambda: route.fetch(url=f"{http_server}/json", max_redirects=True),
                "Route.fetch: max_redirects: expected integer, got boolean",
            ),
            (
                "max_redirects_float",
                lambda: route.fetch(url=f"{http_server}/json", max_redirects=1.5),
                "Route.fetch: max_redirects: expected integer, got float 1.5",
            ),
            (
                "max_retries_bool",
                lambda: route.fetch(url=f"{http_server}/json", max_retries=True),
                "Route.fetch: max_retries: expected integer, got boolean",
            ),
            (
                "max_retries_float",
                lambda: route.fetch(url=f"{http_server}/json", max_retries=1.5),
                "Route.fetch: max_retries: expected integer, got float 1.5",
            ),
            (
                "timeout_string",
                lambda: route.fetch(url=f"{http_server}/json", timeout="bad"),
                "Route.fetch: timeout: expected float, got string",
            ),
            (
                "timeout_bool",
                lambda: route.fetch(url=f"{http_server}/json", timeout=True),
                "Route.fetch: timeout: expected float, got boolean",
            ),
        ]
        for label, call, expected in invalid_cases:
            with pytest.raises(Error) as exc_info:
                call()
            errors.append([label, str(exc_info.value).splitlines()[0]])
            assert str(exc_info.value).splitlines()[0] == expected
        accepted.append(route.fetch(url=f"{http_server}/json", max_redirects=1.0, max_retries=1.0).ok)
        route.fulfill(status=200, json={"errors": errors, "accepted": accepted})

    page.route("**/route-fetch-validation", handler)
    response = page.goto(f"{http_server}/route-fetch-validation")

    assert response.json()["errors"] == [
        ["headers_name", "Route.fetch: headers[0].name: expected string, got number"],
        ["headers_value", "Route.fetch: headers[0].value: expected string, got number"],
        ["url", "Route.fetch: url: expected string, got number"],
        ["method", "Route.fetch: method: expected string, got number"],
        ["max_redirects_bool", "Route.fetch: max_redirects: expected integer, got boolean"],
        ["max_redirects_float", "Route.fetch: max_redirects: expected integer, got float 1.5"],
        ["max_retries_bool", "Route.fetch: max_retries: expected integer, got boolean"],
        ["max_retries_float", "Route.fetch: max_retries: expected integer, got float 1.5"],
        ["timeout_string", "Route.fetch: timeout: expected float, got string"],
        ["timeout_bool", "Route.fetch: timeout: expected float, got boolean"],
    ]
    assert response.json()["accepted"] == [True]


