def test_route_fulfill_option_validation_matches_playwright(page, http_server):
    errors = []

    def handler(route):
        invalid_cases = [
            ("status_str", lambda: route.fulfill(status="200"), "Route.fulfill: status: expected integer, got string"),
            ("status_bool", lambda: route.fulfill(status=True), "Route.fulfill: status: expected integer, got boolean"),
            (
                "status_float",
                lambda: route.fulfill(status=200.5),
                "Route.fulfill: status: expected integer, got float 200.5",
            ),
            (
                "content_type",
                lambda: route.fulfill(content_type=123, body="x"),
                "Route.fulfill: headers[0].value: expected string, got number",
            ),
            ("body_int", lambda: route.fulfill(body=123), "Route.fulfill: body: expected string, got number"),
            ("body_bool", lambda: route.fulfill(body=True), "Route.fulfill: body: expected string, got boolean"),
            (
                "body_json",
                lambda: route.fulfill(body="x", json={"ok": True}),
                "Can specify either body or json parameters",
            ),
        ]
        for label, call, expected in invalid_cases:
            with pytest.raises(Error) as exc_info:
                call()
            errors.append([label, str(exc_info.value).splitlines()[0]])
            assert str(exc_info.value).splitlines()[0] == expected
        invalid_header_cases = [
            ("headers_list", lambda: route.fulfill(headers=[("X", "1")], body="x"), "'list' object has no attribute 'items'"),
            ("headers_string", lambda: route.fulfill(headers="bad", body="x"), "'str' object has no attribute 'items'"),
            ("headers_name", lambda: route.fulfill(headers={1: "x"}, body="x"), "'int' object has no attribute 'lower'"),
            ("headers_bool_name", lambda: route.fulfill(headers={True: "x"}, body="x"), "'bool' object has no attribute 'lower'"),
        ]
        for label, call, expected in invalid_header_cases:
            with pytest.raises(AttributeError) as exc_info:
                call()
            errors.append([label, str(exc_info.value)])
            assert str(exc_info.value) == expected
        route.fulfill(
            status=200.0,
            headers={"X-Number": 7, "X-Flag": True, "X-None": None},
            body=b"bytes-ok",
            content_type="text/plain",
        )

    page.route("**/route-fulfill-validation", handler)
    response = page.goto(f"{http_server}/route-fulfill-validation")

    assert response.status == 200
    assert response.text() == "bytes-ok"
    assert errors == [
        ["status_str", "Route.fulfill: status: expected integer, got string"],
        ["status_bool", "Route.fulfill: status: expected integer, got boolean"],
        ["status_float", "Route.fulfill: status: expected integer, got float 200.5"],
        ["content_type", "Route.fulfill: headers[0].value: expected string, got number"],
        ["body_int", "Route.fulfill: body: expected string, got number"],
        ["body_bool", "Route.fulfill: body: expected string, got boolean"],
        ["body_json", "Can specify either body or json parameters"],
        ["headers_list", "'list' object has no attribute 'items'"],
        ["headers_string", "'str' object has no attribute 'items'"],
        ["headers_name", "'int' object has no attribute 'lower'"],
        ["headers_bool_name", "'bool' object has no attribute 'lower'"],
    ]
    assert response.headers["x-number"] == "7"
    assert response.headers["x-flag"] == "True"
    assert "x-none" not in response.headers


def test_route_fulfill_path_infers_content_type(page, http_server, tmp_path: Path):
    files = [
        ("data.json", '{"ok":true}', "application/json"),
        ("page.html", "<main>hi</main>", "text/html"),
        ("plain.txt", "hello", "text/plain"),
        ("style.css", "body{}", "text/css"),
    ]
    for name, text, content_type in files:
        (tmp_path / name).write_text(text, encoding="utf-8")

    def handler(route, request):
        name = request.url.rsplit("/", 1)[-1]
        route.fulfill(path=str(tmp_path / name))

    page.route("**/*", handler)
    for name, text, content_type in files:
        response = page.goto(f"{http_server}/{name}")
        assert response.status == 200
        assert response.header_value("content-type") == content_type
        assert response.text() == text

    page.unroute("**/*", handler)
    page.route("**/override", lambda route: route.fulfill(path=str(tmp_path / "data.json"), content_type="text/custom"))
    response = page.goto(f"{http_server}/override")
    assert response.header_value("content-type") == "text/custom"
    assert response.text() == '{"ok":true}'


