def test_async_route_from_har_update_path_scalar_coercion():
    async def run() -> None:
        from benchmarks.automation_cases import header_case_server
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            try:
                for scope in ("context", "page"):
                    for raw_path in (123, False, 0):
                        with tempfile.TemporaryDirectory() as directory, header_case_server() as base_url:
                            root = Path(directory)
                            previous = os.getcwd()
                            os.chdir(root)
                            context = await browser.new_context()
                            closed = False
                            try:
                                routed_page = await context.new_page()
                                if scope == "context":
                                    await context.route_from_har(
                                        raw_path,
                                        url="**/headers",
                                        update=True,
                                        update_content="embed",
                                        update_mode="minimal",
                                    )
                                else:
                                    await routed_page.route_from_har(
                                        raw_path,
                                        url="**/headers",
                                        update=True,
                                        update_content="embed",
                                        update_mode="minimal",
                                    )
                                response = await routed_page.goto(f"{base_url}/headers")
                                assert response is not None
                                await response.finished()
                                await context.close()
                                closed = True
                            finally:
                                if not closed:
                                    try:
                                        await context.close()
                                    except Exception:
                                        pass
                                os.chdir(previous)

                            har_path = root / str(raw_path)
                            assert har_path.exists()
                            har = json.loads(har_path.read_text(encoding="utf-8"))
                            entries = har["log"]["entries"]
                            assert len(entries) == 1
                            assert json.loads(entries[0]["response"]["content"]["text"]) == {"ok": True}
            finally:
                await browser.close()

    asyncio.run(run())


