def test_evaluate_can_reinject_declaration_helper_script(page):
    script = """
    // Skyvern helper prelude comment
    let browserNameForWorkarounds = "chromium";
    class __RustwrightSmokeCounter {
        constructor() {
            this.value = browserNameForWorkarounds;
        }
    }
    function __rustwrightSmokeHelper() {
        return new __RustwrightSmokeCounter().value;
    }
    // comment with punctuation, matching Skyvern helper comments,
    async function __rustwrightAsyncSmokeHelper() {
        return new __RustwrightSmokeCounter().value;
    }
    /*
     * block comment before a top-level helper
     */
    function __rustwrightOuterSmokeHelper() {
        function __rustwrightNestedSmokeHelper() {
            return "nested";
        }
        return __rustwrightNestedSmokeHelper();
    }
    """

    assert page.evaluate("let localValue = 1; localValue") == 1
    page.evaluate("() => { globalThis.eval = () => { throw new Error('eval disabled'); }; }")
    assert page.evaluate(script) is None
    assert page.evaluate("() => typeof browserNameForWorkarounds") == "undefined"
    assert page.evaluate("() => __rustwrightSmokeHelper()") == "chromium"
    assert page.evaluate("async () => await __rustwrightAsyncSmokeHelper()") == "chromium"
    assert page.evaluate("() => __rustwrightOuterSmokeHelper()") == "nested"
    assert page.evaluate("() => typeof __rustwrightNestedSmokeHelper") == "undefined"
    assert page.evaluate(script) is None
    assert page.evaluate("() => __rustwrightSmokeHelper()") == "chromium"
    assert page.evaluate("async () => await __rustwrightAsyncSmokeHelper()") == "chromium"
    assert page.evaluate("() => __rustwrightOuterSmokeHelper()") == "nested"
    assert page.evaluate("() => typeof __rustwrightNestedSmokeHelper") == "undefined"


def test_frame_evaluate_can_reinject_declaration_helper_script(page):
    page.set_content("<iframe name='child' srcdoc='<main>child</main>'></iframe>")
    frame = wait_until(lambda: page.frame(name="child"))
    script = """
    // Skyvern helper prelude comment
    let browserNameForWorkarounds = "chromium";
    class __RustwrightFrameSmokeCounter {
        constructor() {
            this.value = browserNameForWorkarounds;
        }
    }
    function __rustwrightFrameSmokeHelper() {
        return new __RustwrightFrameSmokeCounter().value;
    }
    // comment with punctuation, matching Skyvern helper comments,
    async function __rustwrightAsyncFrameSmokeHelper() {
        return new __RustwrightFrameSmokeCounter().value;
    }
    /*
     * block comment before a top-level helper
     */
    function __rustwrightOuterFrameSmokeHelper() {
        function __rustwrightNestedFrameSmokeHelper() {
            return "nested";
        }
        return __rustwrightNestedFrameSmokeHelper();
    }
    """

    frame.evaluate("() => { globalThis.eval = () => { throw new Error('eval disabled'); }; }")
    assert frame.evaluate(script) is None
    assert frame.evaluate("() => __rustwrightFrameSmokeHelper()") == "chromium"
    assert frame.evaluate("async () => await __rustwrightAsyncFrameSmokeHelper()") == "chromium"
    assert frame.evaluate("() => __rustwrightOuterFrameSmokeHelper()") == "nested"
    assert frame.evaluate("() => typeof __rustwrightNestedFrameSmokeHelper") == "undefined"
    assert frame.evaluate(script) is None
    assert frame.evaluate("() => __rustwrightFrameSmokeHelper()") == "chromium"
    assert frame.evaluate("async () => await __rustwrightAsyncFrameSmokeHelper()") == "chromium"
    assert frame.evaluate("() => __rustwrightOuterFrameSmokeHelper()") == "nested"
    assert frame.evaluate("() => typeof __rustwrightNestedFrameSmokeHelper") == "undefined"


def test_evaluate_unserializable_primitive_values_match_playwright(page):
    nan_value = page.evaluate("() => Number.NaN")
    assert isinstance(nan_value, float)
    assert math.isnan(nan_value)
    assert page.evaluate("() => Infinity") == float("inf")
    assert page.evaluate("() => -Infinity") == float("-inf")
    neg_zero = page.evaluate("() => -0")
    assert neg_zero == 0
    assert math.copysign(1, neg_zero) == -1

    values = page.evaluate(
        "() => ({ nan: Number.NaN, inf: Infinity, negInf: -Infinity, negZero: -0, nested: [Number.NaN, -0] })"
    )
    assert math.isnan(values["nan"])
    assert values["inf"] == float("inf")
    assert values["negInf"] == float("-inf")
    assert values["negZero"] == 0
    assert math.copysign(1, values["negZero"]) == -1
    assert math.isnan(values["nested"][0])
    assert values["nested"][1] == 0
    assert math.copysign(1, values["nested"][1]) == -1

    serialized = page.evaluate(
        """() => ({
        date: new Date('2020-01-02T03:04:05.678Z'),
        regex: /abc/gi,
        url: new URL('https://example.com/a?b=1'),
        big: 42n,
        error: new TypeError('boom'),
        symbol: Symbol('ignored'),
        array: [new Date('2021-02-03T04:05:06Z'), /x/m, -3n, new Error('nested')]
        })"""
    )
    error_value = serialized["error"]
    nested_error = serialized["array"][3]
    assert serialized == {
        "date": datetime(2020, 1, 2, 3, 4, 5, 678000, tzinfo=timezone.utc),
        "regex": {"r": {"p": "abc", "f": "gi"}},
        "url": urlparse("https://example.com/a?b=1"),
        "big": 42,
        "error": error_value,
        "symbol": None,
        "array": [
            datetime(2021, 2, 3, 4, 5, 6, tzinfo=timezone.utc),
            {"r": {"p": "x", "f": "m"}},
            -3,
            nested_error,
        ],
    }
    assert isinstance(error_value, Error)
    assert error_value.name == "TypeError"
    assert error_value.message == "boom"
    assert "TypeError: boom" in error_value.stack
    assert isinstance(nested_error, Error)
    assert nested_error.message == "nested"

    page.set_content("<div id='box'></div>")
    assert math.isnan(page.locator("#box").evaluate("(element) => Number.NaN"))

    handle = page.evaluate_handle("() => Number.NaN")
    assert math.isnan(handle.json_value())
    assert math.isnan(handle.evaluate("(value) => value"))
    handle.dispose()

    object_handle = page.evaluate_handle(
        "() => ({ nested: [Number.NaN, -0, 4n], date: new Date('2020-01-02T03:04:05.678Z'), regex: /abc/gi, url: new URL('https://example.com/a?b=1') })"
    )
    nested = object_handle.get_property("nested").json_value()
    assert math.isnan(nested[0])
    assert nested[1] == 0
    assert math.copysign(1, nested[1]) == -1
    assert nested[2] == 4
    assert object_handle.get_property("date").json_value() == datetime(
        2020, 1, 2, 3, 4, 5, 678000, tzinfo=timezone.utc
    )
    assert object_handle.get_property("regex").json_value() == {"r": {"p": "abc", "f": "gi"}}
    assert object_handle.get_property("url").json_value() == urlparse("https://example.com/a?b=1")
    evaluated_nested = object_handle.evaluate("(value) => value.nested")
    assert math.isnan(evaluated_nested[0])
    assert evaluated_nested[1] == 0
    assert math.copysign(1, evaluated_nested[1]) == -1
    object_handle.dispose()


def test_evaluate_handle_json_property_evaluate_and_dispose(page):
    handle = page.evaluate_handle("() => ({ name: 'Ada', nested: { count: 2 }, items: [1, 2, 3] })")

    assert handle.json_value() == {"name": "Ada", "nested": {"count": 2}, "items": [1, 2, 3]}
    assert handle.get_property("nested").json_value() == {"count": 2}
    assert handle.evaluate("(value) => value.items.length") == 3
    mapped = handle.evaluate_handle("(value) => value.items.map(item => item * 2)")
    assert mapped.json_value() == [2, 4, 6]
    mapped.dispose()
    handle.dispose()

    assert mapped._disposed
    assert handle._disposed
    for operation in (
        handle.json_value,
        lambda: handle.get_property("name"),
        lambda: handle.evaluate("(value) => value"),
        lambda: handle.evaluate_handle("(value) => value"),
    ):
        with pytest.raises(Error, match="Target page, context or browser has been closed"):
            operation()


def test_evaluation_expression_validation_and_error_prefixes_match_playwright(page):
    page.set_content("<body><section id='root'><div id='one'>Hi</div><div>Two</div></section></body>")

    def expect_error(operation, expected_message: str, error_type: type[BaseException] = Error) -> None:
        with pytest.raises(error_type) as exc_info:
            operation()
        assert str(exc_info.value).splitlines()[0] == expected_message

    expect_error(lambda: page.evaluate(None), "Page.evaluate: expression: expected string, got undefined")
    expect_error(lambda: page.evaluate(123), "Page.evaluate: expression: expected string, got number")
    expect_error(lambda: page.evaluate_handle(None), "Page.evaluate_handle: expression: expected string, got undefined")
    expect_error(
        lambda: page.wait_for_function(None, timeout=100),
        "Frame.wait_for_function() missing 1 required positional argument: 'expression'",
        TypeError,
    )
    expect_error(
        lambda: page.wait_for_function(123, timeout=100),
        "Page.wait_for_function: expression: expected string, got number",
    )
    expect_error(
        lambda: page.wait_for_function("() => { throw 'bad'; }", timeout=100),
        "Page.wait_for_function: bad",
    )

    frame = page.main_frame
    expect_error(lambda: frame.evaluate(None), "Frame.evaluate: expression: expected string, got undefined")
    expect_error(lambda: frame.evaluate("() => { throw 'bad'; }"), "Frame.evaluate: bad")
    expect_error(lambda: frame.evaluate_handle("() => { throw 'bad'; }"), "Frame.evaluate_handle: bad")
    expect_error(
        lambda: frame.wait_for_function(None, timeout=100),
        "Frame.wait_for_function: expression: expected string, got undefined",
    )
    expect_error(
        lambda: frame.wait_for_function(123, timeout=100),
        "Frame.wait_for_function: expression: expected string, got number",
    )
    expect_error(
        lambda: frame.wait_for_function("() => { throw 'bad'; }", timeout=100),
        "Frame.wait_for_function: bad",
    )

    locator = page.locator("body")
    expect_error(lambda: locator.evaluate(None), "Locator.evaluate: expression: expected string, got undefined")
    expect_error(lambda: locator.evaluate("() => { throw 'bad'; }"), "Locator.evaluate: bad")
    expect_error(
        lambda: locator.evaluate_handle(None),
        "Locator.evaluate_handle: expression: expected string, got undefined",
    )
    expect_error(lambda: locator.evaluate_handle("() => { throw 'bad'; }"), "Locator.evaluate_handle: bad")
    expect_error(
        lambda: page.locator("div").evaluate_all(None),
        "Frame.eval_on_selector_all() missing 1 required positional argument: 'expression'",
        TypeError,
    )
    expect_error(
        lambda: page.locator("div").evaluate_all(123),
        "Locator.evaluate_all: expression: expected string, got number",
    )

    element = page.query_selector("body")
    assert element is not None
    expect_error(lambda: element.evaluate(None), "ElementHandle.evaluate: expression: expected string, got undefined")
    expect_error(lambda: element.evaluate("() => { throw 'bad'; }"), "ElementHandle.evaluate: bad")
    expect_error(lambda: element.evaluate_handle("() => { throw 'bad'; }"), "ElementHandle.evaluate_handle: bad")

    expect_error(
        lambda: page.eval_on_selector("#one", None),
        "Page.eval_on_selector: expression: expected string, got undefined",
    )
    expect_error(
        lambda: page.eval_on_selector("#one", 123),
        "Page.eval_on_selector: expression: expected string, got number",
    )
    expect_error(lambda: page.eval_on_selector("#one", "() => { throw 'bad'; }"), "Page.eval_on_selector: bad")
    expect_error(
        lambda: page.eval_on_selector_all("div", None),
        "Page.eval_on_selector_all: expression: expected string, got undefined",
    )
    expect_error(
        lambda: page.eval_on_selector_all("div", 123),
        "Page.eval_on_selector_all: expression: expected string, got number",
    )
    expect_error(
        lambda: page.eval_on_selector_all("div", "() => { throw 'bad'; }"),
        "Page.eval_on_selector_all: bad",
    )
    expect_error(
        lambda: frame.eval_on_selector("#one", None),
        "Frame.eval_on_selector: expression: expected string, got undefined",
    )
    expect_error(lambda: frame.eval_on_selector("#one", "() => { throw 'bad'; }"), "Frame.eval_on_selector: bad")
    expect_error(
        lambda: frame.eval_on_selector_all("div", 123),
        "Frame.eval_on_selector_all: expression: expected string, got number",
    )

    root_handle = page.query_selector("#root")
    assert root_handle is not None
    try:
        expect_error(
            lambda: root_handle.eval_on_selector("#one", None),
            "ElementHandle.eval_on_selector: expression: expected string, got undefined",
        )
        expect_error(
            lambda: root_handle.eval_on_selector("#one", "() => { throw 'bad'; }"),
            "ElementHandle.eval_on_selector: bad",
        )
        expect_error(
            lambda: root_handle.eval_on_selector_all("div", 123),
            "ElementHandle.eval_on_selector_all: expression: expected string, got number",
        )
    finally:
        root_handle.dispose()

    object_handle = page.evaluate_handle("() => ({ x: 1 })")
    primitive_handle = page.evaluate_handle("() => 1")
    try:
        expect_error(
            lambda: object_handle.evaluate(None),
            "JSHandle.evaluate: expression: expected string, got undefined",
        )
        expect_error(
            lambda: object_handle.evaluate_handle(None),
            "JSHandle.evaluate_handle: expression: expected string, got undefined",
        )
        expect_error(lambda: primitive_handle.evaluate("() => { throw 'bad'; }"), "JSHandle.evaluate: bad")
        mapped = primitive_handle.evaluate_handle("(value, arg) => value + arg", 2)
        try:
            assert mapped.json_value() == 3
        finally:
            mapped.dispose()
    finally:
        object_handle.dispose()
        primitive_handle.dispose()


def test_js_handle_string_previews_match_playwright(page):
    page.set_content("<button>Hi</button>")
    cases = [
        ("() => ({ a: 1 })", "Object"),
        ("() => 42", "42"),
        ("() => undefined", "undefined"),
        ("() => null", "null"),
        ("() => true", "true"),
        ("() => false", "false"),
        ("() => 'abc'", "abc"),
        ("() => Symbol('x')", "Symbol(x)"),
        ("() => Number.NaN", "NaN"),
        ("() => -0", "0"),
        ("() => Infinity", "Infinity"),
        ("() => [1, 2]", "Array(2)"),
        ("() => /a/g", "/a/g"),
        ("() => function f(){}", "function f(){}"),
        ("() => document.querySelector('button')", "JSHandle@node"),
    ]

    for expression, preview in cases:
        handle = page.evaluate_handle(expression)
        try:
            assert str(handle) == preview
            assert repr(handle) == f"<JSHandle preview={preview}>"
        finally:
            handle.dispose()
        assert str(handle) == preview
        assert repr(handle) == f"<JSHandle preview={preview}>"


def test_js_handle_get_properties_uses_remote_property_enumeration(page):
    handle = page.evaluate_handle(
        """() => {
            const obj = { a: 1, b: undefined };
            obj.self = obj;
            return obj;
        }"""
    )
    try:
        properties = handle.get_properties()
        assert sorted(properties) == ["a", "b", "self"]
        assert properties["a"].json_value() == 1
        assert properties["b"].json_value() is None
        assert properties["self"].evaluate("(value) => value === value.self") is True
    finally:
        handle.dispose()

    array_handle = page.evaluate_handle("() => { const arr = [10]; arr.extra = 20; return arr; }")
    try:
        properties = array_handle.get_properties()
        assert sorted(properties) == ["0", "extra"]
        assert properties["0"].json_value() == 10
        assert properties["extra"].json_value() == 20
    finally:
        array_handle.dispose()


