def test_json_value_serializes_typed_arrays_and_dom_geometry(page):
    assert page.evaluate("() => new Uint8Array([1, 2, 255])") == [1, 2, 255]
    floats = page.evaluate("() => new Float32Array([1.5, -0])")
    assert floats[0] == 1.5
    assert floats[1] == 0 and math.copysign(1, floats[1]) == -1
    assert page.evaluate("() => new BigInt64Array([1n, -2n])") == [1, -2]

    rect = page.evaluate("() => new DOMRect(1, 2, 3, 4)")
    assert rect == {
        "x": 1,
        "y": 2,
        "width": 3,
        "height": 4,
        "top": 2,
        "right": 4,
        "bottom": 6,
        "left": 1,
    }
    assert page.evaluate("() => new DOMPoint(1, 2, 3, 4)") == {"x": 1, "y": 2, "z": 3, "w": 4}
    matrix = page.evaluate("() => new DOMMatrix([1, 2, 3, 4, 5, 6])")
    assert matrix["a"] == 1
    assert matrix["f"] == 6
    assert matrix["m33"] == 1
    assert matrix["is2D"] is True
    assert matrix["isIdentity"] is False

    handle = page.evaluate_handle(
        """() => ({
            bytes: new Uint8ClampedArray([1, 260]),
            quad: new DOMQuad(
                new DOMPoint(1, 2),
                new DOMPoint(3, 4),
                new DOMPoint(5, 6),
                new DOMPoint(7, 8)
            ),
        })"""
    )
    try:
        value = handle.json_value()
        assert value["bytes"] == [1, 255]
        assert value["quad"]["p1"] == {"x": 1, "y": 2, "z": 0, "w": 1}
        assert value["quad"]["p4"] == {"x": 7, "y": 8, "z": 0, "w": 1}
    finally:
        handle.dispose()


def test_js_handle_json_value_skips_throwing_getters_and_error_prefixes(page):
    handle = page.evaluate_handle(
        """() => {
            const obj = { a: 1 };
            Object.defineProperty(obj, "ok", { enumerable: true, get() { return 2; } });
            Object.defineProperty(obj, "boom", { enumerable: true, get() { throw "bad json"; } });
            return obj;
        }"""
    )
    try:
        assert handle.json_value() == {"a": 1, "ok": 2}
    finally:
        handle.dispose()

    error_handle = page.evaluate_handle(
        """() => {
            const obj = {};
            Object.defineProperty(obj, "boom", { get() { throw new Error("bad getter"); } });
            return obj;
        }"""
    )
    try:
        with pytest.raises(Error) as exc_info:
            error_handle.get_property("boom")
        assert str(exc_info.value).splitlines()[0] == "JSHandle.get_property: Error: bad getter"

        with pytest.raises(Error) as exc_info:
            error_handle.evaluate("() => { throw 'bad'; }")
        assert str(exc_info.value).splitlines()[0] == "JSHandle.evaluate: bad"

        with pytest.raises(Error) as exc_info:
            error_handle.evaluate_handle("() => { throw 'bad'; }")
        assert str(exc_info.value).splitlines()[0] == "JSHandle.evaluate_handle: bad"
    finally:
        error_handle.dispose()


def test_evaluate_primitive_throw_messages_match_playwright(page):
    for thrown, expected in (
        ("'sync'", "sync"),
        ("42", "42"),
        ("null", "null"),
        ("undefined", "undefined"),
        ("{a: 1}", "Object"),
    ):
        with pytest.raises(Error) as exc_info:
            page.evaluate(f"() => {{ throw {thrown}; }}")
        assert str(exc_info.value).splitlines()[0] == f"Page.evaluate: {expected}"

    with pytest.raises(Error) as exc_info:
        page.evaluate_handle("async () => { throw 'oops'; }")
    assert str(exc_info.value).splitlines()[0] == "Page.evaluate_handle: oops"


def test_evaluate_handle_can_wrap_primitive(page):
    handle = page.evaluate_handle("() => 42")

    assert handle.json_value() == 42
    assert handle.evaluate("(value) => value + 1") == 43
    handle.dispose()
    assert handle._disposed
    for operation in (
        handle.json_value,
        lambda: handle.get_property("x"),
        lambda: handle.evaluate("(value) => value"),
        lambda: handle.evaluate_handle("(value) => value"),
    ):
        with pytest.raises(Error, match="Target page, context or browser has been closed"):
            operation()


def test_page_evaluate_accepts_js_handle_argument(page):
    handle = page.evaluate_handle("() => ({ count: 4, nested: { label: 'ok' } })")

    assert page.evaluate("(value) => value.count + 1", handle) == 5

    mapped = page.evaluate_handle("(value) => ({ doubled: value.count * 2, label: value.nested.label })", handle)
    assert mapped.json_value() == {"doubled": 8, "label": "ok"}


def test_page_evaluate_accepts_element_handle_argument(page):
    page.set_content("<button id='go' data-kind='primary'>Go</button>")
    element = page.query_selector("#go")
    assert element is not None

    assert page.evaluate("(element) => element.dataset.kind", element) == "primary"

    mapped = page.evaluate_handle("(element) => ({ id: element.id, text: element.textContent })", element)
    assert mapped.json_value() == {"id": "go", "text": "Go"}


def test_page_evaluate_accepts_nested_handle_arguments(page):
    page.set_content("<button id='go' data-kind='primary'>Go</button>")
    element = page.query_selector("#go")
    assert element is not None
    data = page.evaluate_handle("() => ({ count: 4, suffix: '!' })")

    result = page.evaluate(
        "(arg) => ({ text: arg.node.textContent + arg.data.suffix, total: arg.items[0].count + arg.items[1].id.length })",
        {"node": element, "data": data, "items": [data, element]},
    )

    assert result == {"text": "Go!", "total": 6}

    mapped = page.evaluate_handle(
        "(arg) => ({ kind: arg.node.dataset.kind, count: arg.data.count })",
        {"node": element, "data": data},
    )
    assert mapped.json_value() == {"kind": "primary", "count": 4}


def test_js_handle_evaluate_accepts_nested_handle_arguments(page):
    page.set_content("<button id='go' data-kind='primary'>Go</button>")
    element = page.query_selector("#go")
    assert element is not None
    receiver = page.evaluate_handle("() => ({ prefix: 'Hello ', count: 3 })")
    extra = page.evaluate_handle("() => ({ suffix: '!' })")

    result = receiver.evaluate(
        "(value, arg) => value.prefix + arg.node.textContent + arg.extra.suffix + ':' + (value.count + arg.items[0].id.length)",
        {"node": element, "extra": extra, "items": [element]},
    )

    assert result == "Hello Go!:5"

    mapped = receiver.evaluate_handle(
        "(value, arg) => ({ text: arg.node.textContent, suffix: arg.extra.suffix, total: value.count + arg.items[0].id.length })",
        {"node": element, "extra": extra, "items": [element]},
    )
    assert mapped.json_value() == {"text": "Go", "suffix": "!", "total": 5}


def test_wait_for_function_and_add_tags(page, http_server):
    page.set_content("<html><head></head><body><div id='box'>Box</div></body></html>")

    page.add_script_tag(content="window.__tagValue = 7")
    page.add_style_tag(content="#box { color: rgb(1, 2, 3); }")
    page.evaluate("() => setTimeout(() => { window.__ready = true }, 100)")

    assert page.evaluate("window.__tagValue") == 7
    ready = page.wait_for_function("() => window.__ready === true", timeout=3_000)
    try:
        assert ready.json_value() is True
    finally:
        ready.dispose()
    assert page.evaluate("getComputedStyle(document.querySelector('#box')).color") == "rgb(1, 2, 3)"

    page.add_script_tag(url=f"{http_server}/delayed-script.js")
    page.add_style_tag(url=f"{http_server}/delayed-style.css")

    assert page.evaluate("window.__delayedScriptTag") == "loaded"
    assert page.evaluate("getComputedStyle(document.querySelector('#box')).backgroundColor") == "rgb(4, 5, 6)"


def test_add_script_and_style_tag_option_parity(page, tmp_path):
    script_path = tmp_path / "tag.js"
    script_path.write_text("window.__pathScript = 11", encoding="utf-8")
    style_path = tmp_path / "tag.css"
    style_path.write_text("body { --path-style: 22; }", encoding="utf-8")
    page.set_content("<iframe></iframe>")
    frame = wait_until(lambda: page.frames[1] if len(page.frames) > 1 else None)

    for target, prefix in [(page, "Page"), (frame, "Frame")]:
        with pytest.raises(Error) as missing_script:
            target.add_script_tag()
        assert (
            str(missing_script.value).splitlines()[0]
            == f"{prefix}.add_script_tag: Provide an object with a `url`, `path` or `content` property"
        )

        with pytest.raises(Error) as missing_style:
            target.add_style_tag()
        assert (
            str(missing_style.value).splitlines()[0]
            == f"{prefix}.add_style_tag: Provide an object with a `url`, `path` or `content` property"
        )

        script = target.add_script_tag(content="window.__contentScript = 1", path=script_path)
        try:
            assert script.evaluate("node => node.textContent") == f"window.__pathScript = 11\n//# sourceURL={script_path}"
        finally:
            script.dispose()
        assert target.evaluate("() => window.__pathScript") == 11
        assert target.evaluate("() => window.__contentScript") is None

        url_script = target.add_script_tag(
            content="window.__ignoredContentScript = 1",
            path=script_path,
            url="data:text/javascript,window.__urlScript=31",
        )
        try:
            assert url_script.evaluate("node => node.src") == "data:text/javascript,window.__urlScript=31"
            assert url_script.evaluate("node => node.textContent") == ""
        finally:
            url_script.dispose()
        assert target.evaluate("() => window.__urlScript") == 31
        assert target.evaluate("() => window.__ignoredContentScript") is None

        style = target.add_style_tag(content="body { --content-style: 1; }", path=style_path)
        try:
            assert style.evaluate("node => node.textContent") == f"body {{ --path-style: 22; }}\n/*# sourceURL={style_path}*/"
        finally:
            style.dispose()
        assert target.evaluate("() => getComputedStyle(document.body).getPropertyValue('--path-style').trim()") == "22"

        url_style = target.add_style_tag(
            content="body { --ignored-content-style: 1; }",
            path=style_path,
            url="data:text/css,body%7B--url-style:32%7D",
        )
        try:
            assert url_style.evaluate("node => node.tagName") == "LINK"
            assert url_style.evaluate("node => node.href") == "data:text/css,body%7B--url-style:32%7D"
        finally:
            url_style.dispose()
        assert target.evaluate("() => getComputedStyle(document.body).getPropertyValue('--url-style').trim()") == "32"
        assert target.evaluate("() => getComputedStyle(document.body).getPropertyValue('--ignored-content-style').trim()") == ""

    with pytest.raises(TypeError) as unknown_page_script:
        page.add_script_tag(foo="bar")
    assert str(unknown_page_script.value) == "Page.add_script_tag() got an unexpected keyword argument 'foo'"

    with pytest.raises(TypeError) as unknown_frame_script:
        frame.add_script_tag(foo="bar")
    assert str(unknown_frame_script.value) == "Frame.add_script_tag() got an unexpected keyword argument 'foo'"

    with pytest.raises(TypeError) as unknown_page_style:
        page.add_style_tag(type="text/css")
    assert str(unknown_page_style.value) == "Page.add_style_tag() got an unexpected keyword argument 'type'"

    with pytest.raises(TypeError) as unknown_frame_style:
        frame.add_style_tag(type="text/css")
    assert str(unknown_frame_style.value) == "Frame.add_style_tag() got an unexpected keyword argument 'type'"


def test_add_script_and_style_tag_option_validation_matches_playwright(page):
    page.set_content("<iframe></iframe>")
    frame = wait_until(lambda: page.frames[1] if len(page.frames) > 1 else None)

    invalid_cases = [
        (
            lambda: page.add_script_tag(content=123),
            "Page.add_script_tag: content: expected string, got number",
        ),
        (
            lambda: page.add_script_tag(content=True),
            "Page.add_script_tag: content: expected string, got boolean",
        ),
        (
            lambda: page.add_script_tag(url=123),
            "Page.add_script_tag: url: expected string, got number",
        ),
        (
            lambda: page.add_script_tag(content="window.__badType = 1", type=123),
            "Page.add_script_tag: type: expected string, got number",
        ),
        (
            lambda: page.add_script_tag(content="window.__badType = 1", type=True),
            "Page.add_script_tag: type: expected string, got boolean",
        ),
        (
            lambda: page.add_style_tag(content=123),
            "Page.add_style_tag: content: expected string, got number",
        ),
        (
            lambda: page.add_style_tag(content=True),
            "Page.add_style_tag: content: expected string, got boolean",
        ),
        (
            lambda: page.add_style_tag(url=123),
            "Page.add_style_tag: url: expected string, got number",
        ),
        (
            lambda: frame.add_script_tag(content=123),
            "Frame.add_script_tag: content: expected string, got number",
        ),
        (
            lambda: frame.add_script_tag(content="window.__frameBadType = 1", type=123),
            "Frame.add_script_tag: type: expected string, got number",
        ),
        (
            lambda: frame.add_style_tag(content=123),
            "Frame.add_style_tag: content: expected string, got number",
        ),
    ]
    for operation, message in invalid_cases:
        with pytest.raises(Error) as exc_info:
            operation()
        assert str(exc_info.value).splitlines()[0] == message


def test_wait_for_function_polling_option_validation(page):
    raf_handle = page.wait_for_function("() => true", polling="raf", timeout=500)
    raf_handle.dispose()
    interval_handle = page.wait_for_function("() => true", polling=1.5, timeout=500)
    interval_handle.dispose()

    with pytest.raises(Error) as unknown_page:
        page.wait_for_function("() => true", polling="mutation", timeout=100)
    assert str(unknown_page.value).splitlines()[0] == "Unknown polling option: mutation"

    with pytest.raises(Error) as zero_page:
        page.wait_for_function("() => true", polling=0, timeout=100)
    assert str(zero_page.value).splitlines()[0] == "Page.wait_for_function: Cannot poll with non-positive interval: 0"

    with pytest.raises(Error) as bool_page:
        page.wait_for_function("() => true", polling=True, timeout=100)
    assert str(bool_page.value).splitlines()[0] == "Page.wait_for_function: polling_interval: expected float, got boolean"

    with pytest.raises(Error) as unknown_frame:
        page.main_frame.wait_for_function("() => true", polling="mutation", timeout=100)
    assert str(unknown_frame.value).splitlines()[0] == "Unknown polling option: mutation"

    with pytest.raises(Error) as zero_frame:
        page.main_frame.wait_for_function("() => true", polling=0, timeout=100)
    assert str(zero_frame.value).splitlines()[0] == "Frame.wait_for_function: Cannot poll with non-positive interval: 0"

    with pytest.raises(Error) as bool_frame:
        page.main_frame.wait_for_function("() => true", polling=True, timeout=100)
    assert str(bool_frame.value).splitlines()[0] == "Frame.wait_for_function: polling_interval: expected float, got boolean"


def test_wait_for_function_timeout_option_validation(page):
    page.set_content("<iframe srcdoc='<main>ready</main>'></iframe>")
    page.set_default_timeout(1)

    page.evaluate("() => { window.__delayed = false; setTimeout(() => window.__delayed = true, 20); }")
    handle = page.evaluate_handle("() => ({ value: 7 })")
    assert handle.evaluate("(value) => value.value") == 7
    nested_handle = handle.evaluate_handle("(value) => value")
    nested_handle.dispose()
    handle.dispose()
    no_timeout_page = page.wait_for_function("() => window.__delayed", timeout=0, polling=1)
    no_timeout_page.dispose()

    frame = wait_until(lambda: page.frames[1] if len(page.frames) > 1 else None)
    assert frame is not None
    frame.evaluate("() => { window.__delayed = false; setTimeout(() => window.__delayed = true, 20); }")
    no_timeout_frame = frame.wait_for_function("() => window.__delayed", timeout=0, polling=1)
    no_timeout_frame.dispose()

    for bad_timeout, type_name in [("100", "string"), (True, "boolean"), ({}, "object")]:
        with pytest.raises(Error) as page_error:
            page.wait_for_function("() => true", timeout=bad_timeout)
        assert str(page_error.value).splitlines()[0] == f"Page.wait_for_function: timeout: expected float, got {type_name}"

        with pytest.raises(Error) as frame_error:
            frame.wait_for_function("() => true", timeout=bad_timeout)
        assert str(frame_error.value).splitlines()[0] == f"Frame.wait_for_function: timeout: expected float, got {type_name}"

    with pytest.raises(TimeoutError) as page_timeout:
        page.wait_for_function("() => false", timeout=-1, polling=1)
    assert str(page_timeout.value).splitlines()[0] == "Page.wait_for_function: Timeout -1ms exceeded."

    with pytest.raises(TimeoutError) as frame_timeout:
        frame.wait_for_function("() => false", timeout=-1, polling=1)
    assert str(frame_timeout.value).splitlines()[0] == "Frame.wait_for_function: Timeout -1ms exceeded."


