def test_expect_locator_state_attribute_css_and_js_property(page):
    page.set_content(
        """
        <input id="name" value="Ada">
        <button id="disabled" disabled>Disabled</button>
        <fieldset disabled>
          <button id="fieldset-disabled">Fieldset Disabled</button>
          <input id="fieldset-editable">
        </fieldset>
        <div aria-disabled="true">
          <button id="aria-disabled-child">Aria Disabled Child</button>
          <span id="aria-disabled-plain">Aria Disabled Plain</span>
        </div>
        <input id="check" type="checkbox" checked>
        <input id="mixed" type="checkbox">
        <div id="aria-true" role="checkbox" aria-checked="true"></div>
        <div id="aria-mixed" role="checkbox" aria-checked="mixed"></div>
        <input id="readonly" value="Read only" readonly>
        <div id="box" data-state="ready" style="color: rgb(1, 2, 3); width: 20px; height: 20px">Hello Alpha</div>
        <div id="hidden" hidden>Hidden</div>
        <div id="space">   </div>
        <div id="empty-child"><span></span></div>
        <input id="empty-input" value="">
        <input id="space-input" value="   ">
        <textarea id="space-textarea">   </textarea>
        <div id="half" style="position: fixed; left: 0; top: 50vh; width: 100px; height: 100vh"></div>
        <div id="offscreen" style="position: fixed; left: -1000px; top: -1000px; width: 20px; height: 20px"></div>
        <script>document.getElementById("mixed").indeterminate = true;</script>
        """
    )

    expect(page.locator("#box")).to_be_attached()
    expect(page.locator("#box")).to_be_attached(attached=None)
    expect(page.locator("#missing")).to_be_attached(attached=False)
    expect(page.locator("#box")).to_be_visible(visible=True)
    expect(page.locator("#hidden")).to_be_visible(visible=False)
    expect(page.locator("#name")).to_be_editable()
    expect(page.locator("#name")).to_be_editable(editable=True)
    expect(page.locator("#name")).to_have_value("Ada")
    with pytest.raises(Error) as invalid_value_expected:
        expect(page.locator("#name")).to_have_value(True, timeout=100)
    assert str(invalid_value_expected.value).splitlines()[0] == "value must be a string or regular expression"
    expect(page.locator("#name")).to_have_js_property("value", "Ada")
    expect(page.locator("#disabled")).to_be_disabled()
    expect(page.locator("#disabled")).to_be_enabled(enabled=False)
    expect(page.locator("#fieldset-disabled")).to_be_disabled()
    expect(page.locator("#fieldset-editable")).to_be_editable(editable=False)
    expect(page.locator("#aria-disabled-child")).to_be_disabled()
    expect(page.locator("#aria-disabled-plain")).to_be_enabled()
    expect(page.locator("#check")).to_be_checked()
    with pytest.raises(AssertionError):
        expect(page.locator("#check")).to_be_checked(indeterminate="bad", timeout=100)
    expect(page.locator("#mixed")).to_be_checked(indeterminate=True)
    expect(page.locator("#mixed")).to_be_checked(indeterminate="bad")
    expect(page.locator("#mixed")).to_be_checked(checked=False, indeterminate=False)
    expect(page.locator("#aria-true")).to_be_checked()
    expect(page.locator("#aria-mixed")).to_be_checked(indeterminate=True)
    expect(page.locator("#aria-mixed")).to_be_checked(checked=False, indeterminate=False)
    assert page.locator("#aria-true").is_checked()
    assert not page.locator("#aria-mixed").is_checked()
    expect(page.locator("#readonly")).not_to_be_editable()
    expect(page.locator("#readonly")).to_be_editable(editable=False)
    expect(page.locator("#readonly")).to_have_value(value="Read only")
    expect(page.locator("#box")).to_have_attribute("data-state", "ready")
    expect(page.locator("#box")).to_have_attribute("data-state", "READY", ignore_case=True)
    with pytest.raises(Error) as invalid_attribute_expected:
        expect(page.locator("#box")).to_have_attribute("data-state", True, timeout=100)
    assert str(invalid_attribute_expected.value).splitlines()[0] == "value must be a string or regular expression"
    with pytest.raises(TypeError, match="missing .*required positional argument"):
        expect(page.locator("#box")).to_have_attribute("data-state")
    expect(page.locator("#box")).to_have_css("color", "rgb(1, 2, 3)")
    with pytest.raises(Error) as invalid_css_expected:
        expect(page.locator("#box")).to_have_css("color", True, timeout=100)
    assert str(invalid_css_expected.value).splitlines()[0] == "value must be a string or regular expression"
    expect(page.locator("#box")).to_contain_text("Alpha")
    expect(page.locator("#space")).to_be_empty()
    expect(page.locator("#empty-child")).to_be_empty()
    expect(page.locator("#empty-input")).to_be_empty()
    expect(page.locator("#space-input")).not_to_be_empty()
    expect(page.locator("#space-textarea")).not_to_be_empty()
    expect(page.locator("#box")).to_be_in_viewport()
    expect(page.locator("#half")).to_be_in_viewport(ratio=0.5)
    expect(page.locator("#half")).to_be_in_viewport(ratio=None)
    with pytest.raises(Error) as invalid_ratio_string:
        expect(page.locator("#half")).to_be_in_viewport(ratio="bad", timeout=100)
    assert (
        str(invalid_ratio_string.value).splitlines()[0]
        == "LocatorAssertions.to_be_in_viewport: expected_number: expected float, got string"
    )
    with pytest.raises(Error) as invalid_ratio_bool:
        expect(page.locator("#half")).to_be_in_viewport(ratio=True, timeout=100)
    assert (
        str(invalid_ratio_bool.value).splitlines()[0]
        == "LocatorAssertions.to_be_in_viewport: expected_number: expected float, got boolean"
    )
    expect(page.locator("#offscreen")).not_to_be_in_viewport(ratio=0)


def test_expect_locator_text_use_inner_text_option(page):
    page.set_content(
        """
        <div id="box">Visible<span style="display:none"> Hidden</span></div>
        <div id="spaced">  Hello
          world <span> now</span></div>
        <ul>
          <li>One<span style="display:none"> Hidden</span></li>
          <li>Two</li>
          <li>Three</li>
          <li>Four</li>
        </ul>
        """
    )

    expect(page.locator("#box")).to_have_text("Visible Hidden")
    expect(page.locator("#box")).to_have_text("Visible", use_inner_text=True)
    expect(page.locator("#box")).to_contain_text("Hidden")
    expect(page.locator("#box")).not_to_contain_text("Hidden", use_inner_text=True)
    expect(page.locator("#spaced")).to_have_text("Hello world now")
    expect(page.locator("#spaced")).to_contain_text("world now")
    expect(page.locator("#spaced")).to_have_text(re.compile(r"^  Hello\s+world  now$"))
    expect(page.locator("li")).to_have_text(["One Hidden", "Two", "Three", "Four"])
    expect(page.locator("li")).to_have_text(["One", "Two", "Three", "Four"], use_inner_text=True)
    expect(page.locator("li")).to_contain_text(["Hidden", "Two"])
    expect(page.locator("li")).to_contain_text(["Two", "Four"])
    expect(page.locator("li")).to_contain_text([re.compile("Tw"), "Four"])
    expect(page.locator("li")).not_to_contain_text(["Hidden", "Two"], use_inner_text=True)
    expect(page.locator("li")).not_to_contain_text(["Four", "Two"])


