def test_expect_is_playwright_style_callable_object(page):
    from playwright.sync_api import Expect, PlaywrightContextManager, expect as compat_expect, sync_playwright

    assert isinstance(compat_expect, Expect)
    assert isinstance(sync_playwright(), PlaywrightContextManager)
    page.set_content(
        """
        <title>Loading</title>
        <script>setTimeout(() => { document.title = 'Object Expect'; }, 50)</script>
        """
    )

    compat_expect.set_options(timeout=3_000)
    try:
        with pytest.raises(TypeError, match="unexpected keyword argument"):
            compat_expect.set_options(unknown_option=True)
        compat_expect(page).to_have_title("Object Expect")
        compat_expect.set_options(timeout="bad")
        with pytest.raises(Error) as invalid_global_timeout:
            compat_expect(page.locator("body")).to_have_text("Missing")
        assert (
            str(invalid_global_timeout.value).splitlines()[0]
            == "LocatorAssertions.to_have_text: timeout: expected float, got string"
        )
        compat_expect.set_options(timeout=True)
        with pytest.raises(Error) as invalid_boolean_timeout:
            compat_expect(page.locator("body")).to_have_text("Missing")
        assert (
            str(invalid_boolean_timeout.value).splitlines()[0]
            == "LocatorAssertions.to_have_text: timeout: expected float, got boolean"
        )
        compat_expect.set_options(timeout=3_000)
        with pytest.raises(AssertionError) as custom_message_error:
            compat_expect(page, "custom title failed").to_have_title("Missing", timeout=100)
        assert str(custom_message_error.value).splitlines()[0] == "custom title failed"
        assert "expected: title 'Missing'" in str(custom_message_error.value)
    finally:
        compat_expect.set_options(timeout=None)


def test_public_type_shape_exports_are_importable():
    import playwright.async_api as async_api
    import playwright.sync_api as sync_api

    assert hasattr(sync_api, "__all__")
    assert hasattr(async_api, "__all__")
    assert "sync_playwright" in sync_api.__all__
    assert "async_playwright" in async_api.__all__
    assert "Error" in sync_api.__all__
    assert "TimeoutError" in sync_api.__all__
    assert "Error" in async_api.__all__
    assert "TimeoutError" in async_api.__all__

    names = [
        "BrowserBindResult",
        "ChromiumBrowserContext",
        "Cookie",
        "DebuggerLocation",
        "DebuggerPausedDetails",
        "FilePayload",
        "FloatRect",
        "Geolocation",
        "HttpCredentials",
        "PdfMargins",
        "Position",
        "ProxySettings",
        "ResourceTiming",
        "SourceLocation",
        "StorageState",
        "StorageStateCookie",
        "ViewportSize",
        "APIResponseAssertionsImpl",
        "LocatorAssertionsImpl",
        "PageAssertionsImpl",
    ]
    for module in (sync_api, async_api):
        for name in names:
            assert hasattr(module, name), f"{module.__name__}.{name}"

    assert sync_api.ViewportSize.__annotations__ == {"width": int, "height": int}
    assert async_api.ViewportSize.__annotations__ == {"width": int, "height": int}
    assert "server" in sync_api.ProxySettings.__annotations__
    assert "server" in async_api.ProxySettings.__annotations__


def test_public_class_like_import_surface_matches_reference():
    root = Path(__file__).resolve().parents[1]
    audit_path = str(root / ".audit-playwright")
    if not Path(audit_path).exists():
        pytest.skip("reference Playwright package is not installed in .audit-playwright")

    def load_reference(module_name: str):
        saved_modules = {
            name: sys.modules.pop(name)
            for name in list(sys.modules)
            if name == "playwright" or name.startswith("playwright.")
        }
        sys.path.insert(0, audit_path)
        try:
            return importlib.import_module(module_name)
        finally:
            sys.path.remove(audit_path)
            for name in list(sys.modules):
                if name == "playwright" or name.startswith("playwright."):
                    sys.modules.pop(name)
            sys.modules.update(saved_modules)

    import rustwright.async_api as async_candidate
    import rustwright.sync_api as sync_candidate

    for reference, candidate in [
        (load_reference("playwright.sync_api"), sync_candidate),
        (load_reference("playwright.async_api"), async_candidate),
    ]:
        reference_names = [
            name
            for name in dir(reference)
            if not name.startswith("_") and inspect.isclass(getattr(reference, name))
        ]
        missing = [name for name in reference_names if not hasattr(candidate, name)]
        assert not missing


