def test_simple_css_count_fast_path_covers_indexed_and_shadow_fallback(page):
    from rustwright.sync_api import _MISSING

    page.set_content("<ul><li>One</li><li>Two</li><li>Three</li></ul>")

    items = page.locator("li")
    assert items._try_fast_simple_css_count(timeout=500) == 3
    assert items.first._try_fast_simple_css_count(timeout=500) == 1
    assert items.last._try_fast_simple_css_count(timeout=500) == 1
    assert items.nth(5)._try_fast_simple_css_count(timeout=500) == 0
    assert page.locator(".missing")._try_fast_simple_css_count(timeout=500) == 0

    page.evaluate(
        """() => {
        const host = document.createElement('div');
        document.body.appendChild(host);
        host.attachShadow({ mode: 'open' }).innerHTML = '<span class="shadow-count">Shadow</span>';
        }"""
    )
    assert page.locator(".shadow-count")._try_fast_simple_css_count(timeout=500) is _MISSING
    assert page.locator(".shadow-count").count() == 1


