def test_simple_css_enabled_fast_paths_cover_first_last_and_role_aware_disabled(page):
    from rustwright.sync_api import _MISSING

    page.set_content(
        """
        <button class="state" id="enabled">Enabled</button>
        <button class="state" id="disabled" disabled>Disabled</button>
        <fieldset disabled><button class="state" id="fieldset-disabled">Fieldset Disabled</button></fieldset>
        <div aria-disabled="true">
          <button class="state" id="aria-disabled-child">Aria Disabled Child</button>
          <span class="state" id="aria-plain">Aria Plain</span>
        </div>
        <span class="state" id="aria-role-disabled" role="button" aria-disabled="true">Role Disabled</span>
        """
    )

    states = page.locator(".state")
    assert states.first._try_fast_simple_css_enabled_state(timeout=500) is True
    assert states.nth(1).is_enabled() is False
    assert states.nth(2).is_disabled()
    assert states.nth(3).is_disabled()
    assert states.nth(4)._try_fast_simple_css_enabled_state(timeout=500) is True
    assert states.last.is_disabled()
    assert page.locator("#missing")._try_fast_simple_css_enabled_state(timeout=500) is _MISSING
    with pytest.raises(TimeoutError):
        page.locator("#missing").is_enabled(timeout=100)

    with pytest.raises(Error, match="strict mode violation"):
        states._try_fast_simple_css_enabled_state(timeout=500)
    with pytest.raises(Error, match="Locator.is_enabled: timeout: expected float"):
        states.first.is_enabled(timeout="bad")

    page.evaluate(
        """() => {
        const host = document.createElement('div');
        document.body.appendChild(host);
        host.attachShadow({ mode: 'open' }).innerHTML = '<button id="shadow-state">Shadow</button>';
        }"""
    )
    assert states.first._try_fast_simple_css_enabled_state(timeout=500) is _MISSING
    assert states.first.is_enabled()


def test_simple_role_count_and_attribute_fast_paths(page):
    page.set_content(
        """
        <header id="banner">Header</header>
        <button id="save" aria-label="Save record">Save</button>
        <button id="image-button"><img alt="Search"></button>
        <button id="hidden-name">Visible<span aria-hidden="true"> Hidden</span></button>
        <button id="disabled" disabled>Disabled</button>
        """
    )

    assert page.get_by_role("banner")._try_fast_simple_role_attribute("id", timeout=500) == "banner"
    assert page.get_by_role("button", name="Search")._try_fast_simple_role_attribute("id", timeout=500) == "image-button"
    assert page.get_by_role("button", name="Hidden")._try_fast_simple_role_count(timeout=500) == 0
    assert page.get_by_role("button", name="Save")._try_fast_simple_role_visibility(timeout=500) is True
    assert page.get_by_role("button", name="Hidden")._try_fast_simple_role_visibility(timeout=500) is False
    assert page.get_by_role("button")._try_fast_simple_role_evaluate_all(
        "(els) => els.map(el => el.id)",
        None,
        method="Locator.evaluate_all",
    ) == ["save", "image-button", "hidden-name", "disabled"]
    assert page.get_by_role("button", name="Save record").get_attribute("id") == "save"
    assert page.get_by_role("button", name="Hidden").count() == 0
    assert page.get_by_role("button", name="Save").evaluate_all(
        "(els, arg) => els.map(el => `${el.id}:${arg}`)",
        "matched",
    ) == ["save:matched"]

    with pytest.raises(Error, match="strict mode violation"):
        page.get_by_role("button")._try_fast_simple_role_attribute("id", timeout=500)
    with pytest.raises(Error, match="strict mode violation"):
        page.get_by_role("button")._try_fast_simple_role_visibility(timeout=500)

    assert page.get_by_role("button", name=re.compile("Search"))._try_fast_simple_role_count(timeout=500) == 1
    assert page.get_by_role("button", name=re.compile("Search"))._try_fast_simple_role_visibility(timeout=500) is True
    assert page.get_by_role("button", name=re.compile("Search"))._try_fast_simple_role_evaluate_all(
        "(els) => els.map(el => el.id)",
        None,
        method="Locator.evaluate_all",
    ) == ["image-button"]
    assert page.get_by_role("button", disabled=False)._try_fast_simple_role_count(timeout=500) == 3


