    assert page.get_by_role("button", name="Send").evaluate_all("(els) => els.map(el => el.id)") == ["submit-value"]
    assert page.get_by_role("button", name="Clear").evaluate_all("(els) => els.map(el => el.id)") == ["reset-value"]
