def test_skyvern_accessibility_snapshot_extension(page):
    page.set_content(
        """
        <main id="root" aria-label="Observe root">
          <button id="save">Save</button>
          <input id="email" aria-label="Email" value="ada@example.com">
          <div aria-hidden="true"><button id="hidden">Hidden</button></div>
        </main>
        """
    )

    def flattened(node):
        nodes = [node]
        for child in node.get("children", []):
            nodes.extend(flattened(child))
        return nodes

    snapshot = page.accessibility.snapshot()
    assert snapshot is not None
    assert snapshot["role"] == "WebArea"
    roles_and_names = {(node.get("role"), node.get("name")) for node in flattened(snapshot)}
    assert ("main", "Observe root") in roles_and_names
    assert ("button", "Save") in roles_and_names
    assert ("textbox", "Email") in roles_and_names
    assert ("button", "Hidden") not in roles_and_names

    root = page.query_selector("#root")
    scoped = page.accessibility.snapshot(root=root)
    assert scoped is not None
    assert scoped["role"] == "main"
    assert scoped["name"] == "Observe root"
    scoped_roles_and_names = {(node.get("role"), node.get("name")) for node in flattened(scoped)}
    assert ("button", "Save") in scoped_roles_and_names
    assert ("textbox", "Email") in scoped_roles_and_names

    ignored_snapshot = page.accessibility.snapshot(root=root, interesting_only=False)
    assert ignored_snapshot is not None
    assert any(node.get("role") == "none" for node in flattened(ignored_snapshot))


def test_aria_snapshot_covers_common_roles_names_and_states(page):
    page.set_content(
        """
        <main aria-label="Checkout">
          <h1>Order</h1>
          <button aria-expanded="false">Pay now</button>
          <label>Email <input value="a@example.com"></label>
          <label>Phone <input value="555" placeholder="Phone number"></label>
          <input title="Website" placeholder="URL hint" value="https://example.com">
          <ul><li>First</li><li><a href="/two">Second</a></li></ul>
          <img alt="Logo" src="data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///ywAAAAAAQABAAACAUwAOw==">
          <input type="checkbox" checked aria-label="Accept">
          <select aria-label="Plan"><option selected>Pro</option></select>
        </main>
        """
    )

    assert page.aria_snapshot() == (
        '- main "Checkout":\n'
        '  - heading "Order" [level=1]\n'
        '  - button "Pay now"\n'
        '  - text: Email\n'
        '  - textbox "Email": a@example.com\n'
        '  - text: Phone\n'
        '  - textbox "Phone":\n'
        '    - /placeholder: Phone number\n'
        '    - text: 555\n'
        '  - textbox "Website":\n'
        '    - /placeholder: URL hint\n'
        '    - text: https://example.com\n'
        '  - list:\n'
        '    - listitem: First\n'
        '    - listitem:\n'
        '      - link "Second":\n'
        '        - /url: /two\n'
        '  - img "Logo"\n'
        '  - checkbox "Accept" [checked]\n'
        '  - combobox "Plan":\n'
        '    - option "Pro" [selected]'
    )
    assert page.locator("button").aria_snapshot(mode="ai").startswith('- button "Pay now" [ref=e')
    with pytest.raises(Error, match="mode"):
        page.locator("main").aria_snapshot(mode="compact")

    page.set_content("<main></main>")
    page.evaluate(
        """() => setTimeout(() => {
          const button = document.createElement('button');
          button.id = 'late';
          button.textContent = 'Late';
          document.body.appendChild(button);
        }, 50)"""
    )
    assert page.locator("#late").aria_snapshot(timeout=2_000) == '- button "Late"'

    page.set_content("<button>One</button><button>Two</button>")
    with pytest.raises(Error, match="strict mode violation: locator resolved to 2 elements while trying to aria snapshot"):
        page.locator("button").aria_snapshot(timeout=1_000)

    page.set_content(
        """
        <main>
          <div id="multi" role="button link">Multi</div>
          <div id="fallback" role="unknown button">Fallback</div>
          <div id="none-button" role="none button">None Button</div>
          <div id="presentation-button" role="presentation button">Presentation Button</div>
          <div id="upper" role="BUTTON">Upper</div>
          <button id="native">Native</button>
        </main>
        """
    )
    assert page.locator("#multi").aria_snapshot() == '- button "Multi"'
    assert page.locator("#fallback").aria_snapshot() == '- button "Fallback"'
    assert page.locator("#none-button").aria_snapshot() == "- text: None Button"
    assert page.locator("#presentation-button").aria_snapshot() == "- text: Presentation Button"
    assert page.locator("#upper").aria_snapshot() == "- text: Upper"
    assert page.locator("main").aria_snapshot() == (
        "- main:\n"
        '  - button "Multi"\n'
        '  - button "Fallback"\n'
        "  - text: None Button Presentation Button Upper\n"
        '  - button "Native"'
    )

    page.set_content(
        """
        <main aria-label="App">
          <header>Header</header>
          <footer>Footer</footer>
          <aside>Aside</aside>
          <article>Article</article>
          <form aria-label="Signup"><input></form>
          <section aria-label="Featured">Featured</section>
          <hr>
          <details><summary>More</summary><p>Body</p></details>
          <fieldset><legend>Choice Group</legend><input></fieldset>
          <dialog open>Dialog</dialog>
          <table><tr><th scope="col">Col</th><th scope="row">Row</th><td>Cell</td></tr></table>
          <input type="search" aria-label="Find">
          <input type="number" aria-label="Qty" value="3">
          <input type="range" aria-label="Volume" value="40">
          <input id="image-alt" type="image" alt="Image Submit">
          <input id="image-value" type="image" value="Image Value">
          <input id="image-empty" type="image">
          <progress value="1" max="2" aria-label="Loading"></progress>
          <meter value="0.5" aria-label="Fuel">half</meter>
          <output>7</output>
          <select multiple aria-label="Many"><option selected>One</option><option>Two</option></select>
        </main>
        """
    )
    assert page.locator("main").aria_snapshot() == (
        '- main "App":\n'
        "  - text: Header Footer\n"
        "  - complementary: Aside\n"
        "  - article: Article\n"
        '  - form "Signup":\n'
        "    - textbox\n"
        '  - region "Featured"\n'
        "  - separator\n"
        "  - group: More\n"
        '  - group "Choice Group":\n'
        "    - text: Choice Group\n"
        "    - textbox\n"
        "  - dialog: Dialog\n"
        "  - table:\n"
        "    - rowgroup:\n"
        '      - row "Col Row Cell":\n'
        '        - columnheader "Col"\n'
        '        - rowheader "Row"\n'
        '        - cell "Cell"\n'
        '  - searchbox "Find"\n'
        '  - spinbutton "Qty": "3"\n'
        '  - slider "Volume": "40"\n'
        '  - button "Image Submit"\n'
        '  - button "Submit": Image Value\n'
        '  - button "Submit"\n'
        '  - progressbar "Loading"\n'
        '  - meter "Fuel": half\n'
        '  - status: "7"\n'
        '  - listbox "Many":\n'
        '    - option "One" [selected]\n'
        '    - option "Two"'
    )


