def test_locator_evaluate_and_evaluate_all(page):
    page.set_content("<ul><li data-id='a'>One</li><li data-id='b'>Two</li><li data-id='c'>Three</li></ul>")

    items = page.locator("li")

    assert items.nth(1).evaluate("(element) => element.dataset.id") == "b"
    assert items.nth(0).evaluate("(element, suffix) => element.textContent + suffix", "!") == "One!"
    assert items.evaluate_all("(elements) => elements.map(element => element.textContent)") == [
        "One",
        "Two",
        "Three",
    ]


def test_locator_evaluate_handle_returns_js_handle(page):
    page.set_content("<div id='box' data-kind='primary'>Box</div>")

    handle = page.locator("#box").evaluate_handle(
        "(element) => ({ text: element.textContent, kind: element.dataset.kind })"
    )

    assert handle.get_property("text").json_value() == "Box"
    assert handle.get_property(property_name="text").json_value() == "Box"
    assert handle.evaluate("(value) => value.kind") == "primary"
    nested = handle.evaluate_handle("(value) => ({ label: value.text + ':' + value.kind })")
    assert nested.get_property("label").json_value() == "Box:primary"
    nested.dispose()
    handle.dispose()

    assert nested._disposed
    assert handle._disposed


def test_locator_and_element_handle_evaluate_accept_nested_handle_arguments(page):
    page.set_content("<button id='go' data-kind='primary'>Go</button><span id='tail'>Tail</span>")
    button = page.query_selector("#go")
    tail = page.query_selector("#tail")
    assert button is not None
    assert tail is not None
    data = page.evaluate_handle("() => ({ count: 4, suffix: '!' })")

    assert page.locator("#go").evaluate(
        "(node, arg) => node.textContent + arg.data.suffix + ':' + arg.tail.textContent",
        {"data": data, "tail": tail},
    ) == "Go!:Tail"

    assert page.locator("button, span").evaluate_all(
        "(nodes, arg) => nodes.map(node => arg.data.suffix + node.textContent + ':' + arg.tail.id)",
        {"data": data, "tail": tail},
    ) == ["!Go:tail", "!Tail:tail"]

    locator_handle = page.locator("#go").evaluate_handle(
        "(node, arg) => ({ text: node.textContent, total: arg.data.count + arg.tail.id.length })",
        {"data": data, "tail": tail},
    )
    assert locator_handle.json_value() == {"text": "Go", "total": 8}
    locator_handle.dispose()

    assert button.evaluate(
        "(node, arg) => node.dataset.kind + ':' + arg.data.suffix + arg.tail.id",
        {"data": data, "tail": tail},
    ) == "primary:!tail"

    element_handle = button.evaluate_handle(
        "(node, arg) => ({ id: node.id, label: arg.tail.textContent, total: arg.data.count + node.id.length })",
        {"data": data, "tail": tail},
    )
    assert element_handle.json_value() == {"id": "go", "label": "Tail", "total": 6}
    element_handle.dispose()
    data.dispose()


