def test_expect_file_chooser_honors_predicate(page):
    page.set_content(
        """
        <input id="single" type="file">
        <input id="multi" type="file" multiple>
        """
    )

    with pytest.raises(TimeoutError):
        with page.expect_file_chooser(lambda chooser: chooser.is_multiple(), timeout=250):
            page.click("#single")

    with page.expect_file_chooser(lambda chooser: chooser.is_multiple()) as chooser_info:
        page.click("#multi")

    chooser = chooser_info.value
    assert chooser.page is page
    assert chooser.is_multiple() is True


def test_file_chooser_event_listener_sets_files(page, tmp_path: Path):
    upload = tmp_path / "listener.txt"
    upload.write_text("from-listener", encoding="utf-8")
    seen = []
    page.set_content(
        """
        <input id="file" type="file">
        <script>
        document.querySelector('#file').addEventListener('change', event => {
          document.body.dataset.listenerFile = event.target.files[0].name;
        });
        </script>
        """
    )
    page.on("filechooser", lambda chooser: (seen.append((chooser.page is page, chooser.is_multiple())), chooser.set_files(str(upload))))

    page.click("#file")

    assert wait_until(lambda: page.evaluate("document.body.dataset.listenerFile")) == "listener.txt"
    assert seen == [(True, False)]


def test_file_chooser_listener_dedupes_immediate_duplicate_payload():
    from rustwright.sync_api import FileChooser, Page

    page = object.__new__(Page)
    page._file_chooser_last_dispatch_key = None
    page._file_chooser_last_dispatch_at = 0.0
    payload = {"frame_id": "main", "backend_node_id": 7, "mode": "selectSingle"}

    first = FileChooser(page, payload)
    duplicate = FileChooser(page, payload)
    later = FileChooser(page, payload)

    assert page._should_dispatch_file_chooser_listener_event(first)
    assert not page._should_dispatch_file_chooser_listener_event(duplicate)
    page._file_chooser_last_dispatch_at -= 1
    assert page._should_dispatch_file_chooser_listener_event(later)


def test_expect_popup_captures_window_open(page):
    page.set_content(
        """
        <button id="open" onclick="
          const popup = window.open();
          popup.document.write('<title>Popup</title><main>Opened</main>');
          popup.document.close();
        ">Open</button>
        """
    )

    with page.expect_popup() as popup_info:
        page.click("#open")

    popup = popup_info.value
    try:
        assert popup.opener() is page
        handle = popup.wait_for_function("() => document.querySelector('main')?.textContent === 'Opened'", timeout=3_000)
        handle.dispose()
        assert popup.title() == "Popup"
        assert popup.text_content("main") == "Opened"
    finally:
        popup.close()


def test_context_expect_page_captures_popup(browser):
    context = browser.new_context()
    page = context.new_page()
    try:
        page.set_content(
            """
            <button id="open" onclick="
              const popup = window.open();
              popup.document.write('<title>Context Popup</title><main>Opened from context</main>');
              popup.document.close();
            ">Open</button>
            """
        )

        with context.expect_page(lambda popup: popup.title() == "Context Popup") as popup_info:
            page.click("#open")

        popup = popup_info.value
        assert popup.context is context
        assert popup in context.pages
        assert popup.opener() is page
        assert popup.text_content("main") == "Opened from context"
    finally:
        context.close()


def test_context_init_script_and_binding_apply_to_popup_pages(browser):
    context = browser.new_context()
    context.add_init_script("window.__popupContextInit = 42")
    context.expose_function("fromContextPopup", lambda value: value + 1)
    page = context.new_page()
    try:
        page.set_content("<button id='open' onclick=\"window.open('about:blank')\">Open</button>")

        with context.expect_page() as popup_info:
            page.click("#open")

        popup = popup_info.value
        try:
            assert popup.evaluate("window.__popupContextInit") == 42
            assert popup.evaluate("async () => await window.fromContextPopup(8)") == 9
            popup.goto(data_url("<title>Popup Setup</title><main>popup</main>"))
            assert popup.evaluate("window.__popupContextInit") == 42
            assert popup.evaluate("async () => await window.fromContextPopup(8)") == 9
            assert popup.opener() is page
        finally:
            popup.close()
    finally:
        context.close()


