def test_websocket_frame_events(page, websocket_server):
    ws_url, connections = websocket_server

    with page.expect_websocket() as websocket_info:
        page.evaluate("(url) => { window.__frameSocket = new WebSocket(url + '?frames'); }", ws_url)

    websocket = websocket_info.value
    handle = page.wait_for_function("() => window.__frameSocket.readyState === WebSocket.OPEN")
    handle.dispose()

    with websocket.expect_event("framereceived") as received_client_info:
        with websocket.expect_event("framesent") as sent_info:
            page.evaluate("() => window.__frameSocket.send('client-ping')")
    assert sent_info.value == "client-ping"
    assert received_client_info.value == "echo:client-ping"
    assert wait_until(lambda: [item for item in connections if item == ("message", "/socket?frames", "client-ping")])

    with websocket.expect_event("framereceived") as received_info:
        page.evaluate("() => window.__frameSocket.send('server-ping')")
    assert received_info.value == "echo:server-ping"

    with page.expect_websocket() as closing_websocket_info:
        page.evaluate("(url) => { window.__closingSocket = new WebSocket(url + '?closing'); }", ws_url)
    closing_websocket = closing_websocket_info.value
    closing_handle = page.wait_for_function("() => window.__closingSocket.readyState === WebSocket.OPEN")
    closing_handle.dispose()
    with pytest.raises(Error, match="Socket closed"):
        with closing_websocket.expect_event("framereceived", timeout=3_000):
            page.evaluate("() => window.__closingSocket.close()")
    assert closing_websocket.is_closed()

    with websocket.expect_event("close") as close_info:
        page.evaluate("() => window.__frameSocket.close()")
    assert close_info.value is websocket
    assert websocket.is_closed()
    with pytest.raises(TimeoutError, match='Timeout 10ms exceeded while waiting for event "close"'):
        websocket.wait_for_event("close", timeout=10)


