def test_page_route_web_socket_mocks_browser_socket(page):
    received = []
    closed = []

    def handler(route):
        assert route.url == "ws://example.test/mock"
        route.send("server-ready")

        def on_message(message):
            received.append(message)
            route.send(f"echo:{message}")
            route.close(code=1001, reason="done")

        route.on_message(on_message)
        route.on_close(lambda code, reason: closed.append((code, reason)))

    page.route_web_socket("**/mock", handler)
    page.set_content("<main>route websocket</main>")
    page.evaluate(
        """() => {
        window.messages = [];
        window.routeClosed = "";
        const ws = new WebSocket("ws://example.test/mock");
        ws.onmessage = event => window.messages.push(event.data);
        ws.onopen = () => ws.send("client-ping");
        ws.onclose = event => window.routeClosed = `${event.code}:${event.reason}`;
        }"""
    )

    assert wait_until(lambda: page.evaluate("() => window.messages.length >= 2")) is True
    assert page.evaluate("() => window.messages") == ["server-ready", "echo:client-ping"]
    assert wait_until(lambda: received) == ["client-ping"]
    assert page.evaluate("() => window.routeClosed") == "1001:done"


def test_page_route_web_socket_binary_messages_follow_binary_type(page):
    received = []

    def handler(route):
        route.send(bytes([1, 2, 255]))

        def on_message(message):
            received.append(message)
            if message == "next":
                route.send(bytes([3, 4]))
            if message == bytes([7, 6, 5]):
                route.send("blob-ok")

        route.on_message(on_message)

    page.route_web_socket("**/binary", handler)
    page.set_content("<main>binary websocket route</main>")
    page.evaluate(
        """() => {
        window.binaryResults = [];
        window.blobAck = "";
        const ws = new WebSocket("ws://example.test/binary");
        ws.onmessage = async event => {
          if (typeof event.data === "string") {
            window.blobAck = event.data;
            return;
          }
          const kind = event.data instanceof Blob
            ? "blob"
            : event.data instanceof ArrayBuffer
              ? "arraybuffer"
              : typeof event.data;
          const buffer = kind === "blob" ? await event.data.arrayBuffer() : event.data;
          window.binaryResults.push({ kind, values: Array.from(new Uint8Array(buffer)) });
          if (window.binaryResults.length === 1) {
            ws.binaryType = "arraybuffer";
            ws.send("next");
          }
          if (window.binaryResults.length === 2) {
            ws.send(new Blob([new Uint8Array([7, 6, 5]).buffer]));
          }
        };
        ws.onopen = () => ws.send(new Uint8Array([9, 8]).buffer);
        }"""
    )

    assert wait_until(lambda: page.evaluate("() => window.binaryResults.length === 2 && window.blobAck === 'blob-ok'")) is True
    assert page.evaluate("() => window.binaryResults") == [
        {"kind": "blob", "values": [1, 2, 255]},
        {"kind": "arraybuffer", "values": [3, 4]},
    ]
    assert page.evaluate("() => window.blobAck") == "blob-ok"
    assert wait_until(lambda: bytes([9, 8]) in received and "next" in received and bytes([7, 6, 5]) in received)


def test_route_web_socket_validation_matches_playwright_routed_shim(page):
    created = []
    closes = []

    def handler(route):
        created.append(route.url)
        route.on_close(lambda code, reason: closes.append((code, reason)))

    page.route_web_socket("**/validation", handler)
    page.set_content("<main>websocket validation</main>")

    result = page.evaluate(
        """async () => {
        const result = {};
        try {
          new WebSocket("ws://example.test/validation", ["chat", "chat"]);
          result.duplicateProtocol = "none";
        } catch (error) {
          result.duplicateProtocol = error.name;
        }
        try {
          new WebSocket("ws://example.test/validation", "not valid");
          result.invalidProtocol = "none";
        } catch (error) {
          result.invalidProtocol = error.name;
        }
        const ws = new WebSocket("ws://example.test/validation", "chat");
        await new Promise(resolve => ws.onopen = resolve);
        try {
          ws.close(1001);
          result.invalidClose = "none";
        } catch (error) {
          result.invalidClose = error.name;
        }
        const closePromise = new Promise(resolve => ws.onclose = resolve);
        ws.close(3001, "done");
        await closePromise;
        return result;
        }"""
    )

    assert result == {
        "duplicateProtocol": "none",
        "invalidProtocol": "none",
        "invalidClose": "Error",
    }
    assert created == [
        "ws://example.test/validation",
        "ws://example.test/validation",
        "ws://example.test/validation",
    ]
    assert wait_until(lambda: closes) == [(3001, "done")]


