def test_route_web_socket_connect_to_server_proxies_messages(page, websocket_server):
    ws_url, connections = websocket_server

    def handler(route):
        route.connect_to_server()

    page.route_web_socket("**/socket?proxy", handler)
    page.set_content("<main>proxy websocket</main>")
    page.evaluate(
        f"""() => {{
        window.messages = [];
        window.protocol = "";
        window.proxyClosed = "";
        const ws = new WebSocket({json.dumps(ws_url + '?proxy')}, ['fallback', 'chat']);
        ws.onmessage = event => {{
          if (event.data instanceof ArrayBuffer) {{
            window.messages.push(`binary:${{Array.from(new Uint8Array(event.data)).join(',')}}`);
            ws.send('ping-request');
            ws.send('close-request');
            return;
          }}
          window.messages.push(event.data);
          if (window.messages.length === 1) ws.send('fragment-request');
          if (window.messages.length === 2) {{
            ws.binaryType = 'arraybuffer';
            ws.send('binary-fragment-request');
          }}
        }};
        ws.onopen = () => {{
          window.protocol = ws.protocol;
          ws.send('proxied-ping');
        }};
        ws.onclose = event => window.proxyClosed = `${{event.code}}:${{event.reason}}`;
        }}"""
    )

    assert wait_until(lambda: page.evaluate("() => window.messages.length === 3")) is True
    assert page.evaluate("() => window.messages") == ["echo:proxied-ping", "fragmented:reply", "binary:5,6,7"]
    assert wait_until(lambda: page.evaluate("() => window.proxyClosed")) == "3002:server-done"
    assert page.evaluate("() => window.protocol") == "chat"
    assert wait_until(lambda: [item for item in connections if item == ("protocols", "/socket?proxy", "fallback, chat")])
    assert wait_until(lambda: [item for item in connections if item == ("message", "/socket?proxy", "proxied-ping")])
    assert wait_until(lambda: [item for item in connections if item == ("message", "/socket?proxy", "fragment-request")])
    assert wait_until(lambda: [item for item in connections if item == ("message", "/socket?proxy", "binary-fragment-request")])
    assert wait_until(lambda: [item for item in connections if item == ("pong", "/socket?proxy", "server-ping")])
    assert wait_until(lambda: [item for item in connections if item == ("message", "/socket?proxy", "close-request")])


def test_route_web_socket_connect_to_server_handlers_disable_default_forwarding(page, websocket_server):
    ws_url, _ = websocket_server
    client_messages = []
    server_messages = []

    def handler(route):
        server = route.connect_to_server()

        def from_client(message):
            client_messages.append(message)
            server.send(message)

        def from_server(message):
            server_messages.append(message)
            route.send(f"manual:{message}")

        route.on_message(from_client)
        server.on_message(from_server)

    page.route_web_socket("**/socket?manual-proxy", handler)
    page.set_content("<main>manual websocket proxy</main>")
    page.evaluate(
        f"""() => {{
        window.manualMessages = [];
        const ws = new WebSocket({json.dumps(ws_url + '?manual-proxy')});
        ws.onmessage = event => window.manualMessages.push(event.data);
        ws.onopen = () => ws.send('manual-ping');
        }}"""
    )

    assert wait_until(lambda: page.evaluate("() => window.manualMessages.length === 1")) is True
    assert page.evaluate("() => window.manualMessages") == ["manual:echo:manual-ping"]
    assert wait_until(lambda: client_messages) == ["manual-ping"]
    assert wait_until(lambda: server_messages) == ["echo:manual-ping"]


