def test_expect_worker_captures_and_evaluates_dedicated_worker(page):
    with page.expect_worker() as worker_info:
        page.evaluate(
            """() => {
            const source = `
              self.answer = 41;
              self.addEventListener('message', event => self.postMessage(event.data + 1));
            `;
            const url = URL.createObjectURL(new Blob([source], { type: 'text/javascript' }));
            window.__worker = new Worker(url);
            }"""
        )

    worker = worker_info.value

    assert worker.url.startswith("blob:")
    assert wait_until(lambda: worker.evaluate("() => self.answer === 41 ? self.answer + 1 : null")) == 42
    handle = worker.evaluate_handle("() => ({ answer: self.answer, nested: { ok: true } })")
    assert handle.json_value() == {"answer": 41, "nested": {"ok": True}}
    assert handle.get_property("nested").json_value() == {"ok": True}
    assert handle.evaluate("(value) => value.answer + 1") == 42
    mapped = handle.evaluate_handle("(value) => ({ doubled: value.answer * 2 })")
    assert mapped.json_value() == {"doubled": 82}
    extra = worker.evaluate_handle("() => ({ add: 5 })")
    assert worker.evaluate("(arg) => arg.base.answer + arg.extra.add", {"base": handle, "extra": extra}) == 46
    nested = handle.evaluate_handle("(value, arg) => ({ total: value.answer + arg.extra.add })", {"extra": extra})
    assert nested.json_value() == {"total": 46}
    nested.dispose()
    extra.dispose()
    mapped.dispose()
    handle.dispose()
    assert any(existing.url == worker.url for existing in page.workers)
    with worker.expect_event("close") as close_info:
        page.evaluate("() => window.__worker.terminate()")
    assert close_info.value is worker
    assert worker._closed
    with pytest.raises(TimeoutError, match='Timeout 10ms exceeded while waiting for event "close"'):
        with worker.expect_event("close", timeout=10):
            pass


