def test_worker_close_waiter_survives_background_closed_state():
    from rustwright.sync_api import Worker

    class CloseWaiter:
        def __init__(self):
            self.calls = 0

        def wait(self, timeout):
            self.calls += 1

    worker = Worker("blob://worker")
    worker._closed = True
    waiter = CloseWaiter()

    assert worker._wait_for_event("close", waiter=waiter, timeout=10) is worker
    assert waiter.calls == 1
    assert worker._closed


def test_worker_console_events(page):
    with page.expect_worker() as worker_info:
        page.evaluate(
            """() => {
            const url = URL.createObjectURL(new Blob(['self.ready = true; setInterval(() => {}, 1000);'], { type: 'text/javascript' }));
            window.__consoleWorker = new Worker(url);
            }"""
        )
    worker = worker_info.value
    assert wait_until(lambda: worker.evaluate("() => self.ready === true"))

    with worker.expect_event("console", lambda message: message.text == "worker hello 7") as message_info:
        worker.evaluate("() => console.log('worker hello', 7)")
    message = message_info.value
    assert message.type == "log"
    assert message.page is page
    assert message.worker is worker

    with worker.expect_event("console", lambda message: message.type == "error") as later_info:
        worker.evaluate("() => setTimeout(() => console.error('worker later'), 20)")
    later = later_info.value
    assert later.text == "worker later"
    assert later.worker is worker

    page_seen = []
    page.on("console", page_seen.append)
    worker.evaluate("() => console.info('worker page listener')")
    page_message = wait_until(lambda: [message for message in page_seen if message.text == "worker page listener"])[0]
    assert page_message.worker is worker

    with page.expect_event("console", lambda message: message.text == "worker page expect") as page_info:
        worker.evaluate("() => console.log('worker page expect')")
    assert page_info.value.worker is worker

    worker.evaluate("() => setTimeout(() => console.log('worker page wait'), 20)")
    waited = page.wait_for_event("console", lambda message: message.text == "worker page wait")
    assert waited.worker is worker

    seen = []
    worker.on("console", seen.append)
    page.wait_for_timeout(100)
    worker.evaluate("() => console.warn('worker listener')")
    assert wait_until(lambda: seen)[0].text == "worker listener"

    with worker.expect_event("close"):
        page.evaluate("() => window.__consoleWorker.terminate()")


