def test_context_service_worker_event_and_listing(browser, http_server):
    context = browser.new_context()
    try:
        page = context.new_page()

        with context.expect_event("serviceworker") as worker_info:
            page.goto(f"{http_server}/service-worker-page")

        worker = worker_info.value
        assert worker.url.endswith("/sw.js")
        handle = page.wait_for_function("() => document.body.dataset.sw === 'ready'")
        handle.dispose()
        assert wait_until(lambda: worker.evaluate("() => self.__rustwrightServiceWorkerValue")) == 73

        workers = wait_until(lambda: context.service_workers)
        assert any(existing.url.endswith("/sw.js") for existing in workers)
    finally:
        context.close()


def test_persistent_context_service_worker_event_and_listing(playwright, http_server, tmp_path: Path):
    context = playwright.chromium.launch_persistent_context(str(tmp_path / "profile"), headless=True)
    try:
        page = context.new_page()

        with context.expect_event("serviceworker") as worker_info:
            page.goto(f"{http_server}/service-worker-page")

        worker = worker_info.value
        assert worker.url.endswith("/sw.js")
        handle = page.wait_for_function("() => document.body.dataset.sw === 'ready'")
        handle.dispose()
        assert wait_until(lambda: worker.evaluate("() => self.__rustwrightServiceWorkerValue")) == 73

        workers = wait_until(lambda: context.service_workers)
        assert any(existing.url.endswith("/sw.js") for existing in workers)
    finally:
        context.close()


def test_service_worker_fulfilled_response_reports_from_service_worker(browser, http_server):
    context = browser.new_context()
    try:
        page = context.new_page()
        page.goto(f"{http_server}/service-worker-page")
        handle = page.wait_for_function("() => document.body.dataset.sw === 'ready'")
        handle.dispose()
        page.reload()
        handle = page.wait_for_function("() => navigator.serviceWorker.controller !== null")
        handle.dispose()

        with page.expect_response("**/sw-controlled") as response_info:
            page.evaluate(
                """
                () => fetch('/sw-controlled')
                  .then(response => response.json())
                  .then(data => { document.body.dataset.swFetch = data.source; })
                """
            )

        response = response_info.value
        assert response.status == 203
        assert response.from_service_worker is True
        assert response.headers["x-sw"] == "yes"
        assert response.json() == {"source": "service-worker"}
        assert response.request.service_worker is None
        assert response.request.frame.page is page
        assert page.evaluate("() => document.body.dataset.swFetch") == "service-worker"
    finally:
        context.close()


def test_context_service_worker_event_is_dispatched_to_listener(browser, http_server):
    context = browser.new_context()
    try:
        seen = []
        context.on("serviceworker", seen.append)
        page = context.new_page()
        page.goto(f"{http_server}/service-worker-page")

        worker = wait_until(lambda: seen)[0]
        assert worker.url.endswith("/sw.js")
        handle = page.wait_for_function("() => document.body.dataset.sw === 'ready'")
        handle.dispose()
        assert wait_until(lambda: worker.evaluate("() => self.__rustwrightServiceWorkerValue")) == 73
    finally:
        context.close()


def test_context_service_workers_block_prevents_registration(browser, http_server):
    context = browser.new_context(service_workers="block")
    try:
        seen = []
        context.on("serviceworker", seen.append)
        page = context.new_page()

        page.goto(f"{http_server}/service-worker-page")
        page.wait_for_timeout(500)

        assert page.evaluate("() => document.body.dataset.sw || null") is None
        assert page.evaluate("async () => (await navigator.serviceWorker.getRegistrations()).length") == 0
        assert context.service_workers == []
        assert seen == []
    finally:
        context.close()


def test_focus_press_keyboard_and_hover(page):
    page.set_content(
        """
        <input id="name">
        <button id="hover" onmouseenter="this.dataset.hovered='yes'">Hover</button>
        <button id="dbl" ondblclick="this.dataset.double='yes'">Double</button>
        <script>
        document.querySelector('#name').addEventListener('keydown', event => {
          if (event.key === 'Enter') document.body.dataset.entered = 'yes';
        });
        </script>
        """
    )

    page.focus("#name")
    page.keyboard.type("Ada")
    page.press("#name", "Enter")
    page.hover("#hover")
    page.dblclick("#dbl")

    assert page.input_value("#name") == "Ada"
    assert page.evaluate("document.body.dataset.entered") == "yes"
    assert page.evaluate("document.querySelector('#hover').dataset.hovered") == "yes"
    assert page.evaluate("document.querySelector('#dbl').dataset.double") == "yes"


