def test_keyboard_press_supports_shift_shortcut(page):
    page.set_content(
        """
        <input id="name">
        <script>
        window.keyEvents = [];
        document.querySelector('#name').addEventListener('keydown', event => {
          window.keyEvents.push({
            key: event.key,
            altKey: event.altKey,
            ctrlKey: event.ctrlKey,
            metaKey: event.metaKey,
            shiftKey: event.shiftKey,
          });
        });
        </script>
        """
    )

    page.focus("#name")
    page.keyboard.press("Shift+A")

    assert page.input_value("#name") == "A"
    events = page.evaluate("() => window.keyEvents")
    assert any(event["key"] == "Shift" and event["shiftKey"] for event in events)
    assert any(event["key"] == "A" and event["shiftKey"] for event in events)


