def test_keyboard_rejects_unknown_keys_like_playwright(page):
    page.set_content(
        """
        <input id="name">
        <script>
        window.keyEvents = [];
        document.querySelector('#name').addEventListener('keydown', event => {
          window.keyEvents.push(event.key);
        });
        </script>
        """
    )
    page.focus("#name")

    with pytest.raises(Error, match=re.escape('Keyboard.press: Unknown key: "Esc"')):
        page.keyboard.press("Esc")
    with pytest.raises(Error, match=re.escape('Keyboard.press: Unknown key: "é"')):
        page.keyboard.press("é")
    with pytest.raises(Error, match=re.escape('Keyboard.press: Unknown key: "Ctrl"')):
        page.keyboard.press("Ctrl+A")
    with pytest.raises(Error, match=re.escape('Keyboard.down: Unknown key: "NoSuchKey"')):
        page.keyboard.down("NoSuchKey")
    with pytest.raises(Error, match=re.escape('Keyboard.up: Unknown key: "NoSuchKey"')):
        page.keyboard.up("NoSuchKey")

    assert page.evaluate("() => window.keyEvents") == []


def test_direct_keyboard_option_validation_matches_playwright(page):
    page.set_content("<input id='name'>")
    page.focus("#name")

    invalid_cases = [
        (lambda: page.keyboard.type(123), "Keyboard.type: text: expected string, got number"),
        (lambda: page.keyboard.type(True), "Keyboard.type: text: expected string, got boolean"),
        (lambda: page.keyboard.type(None), "Keyboard.type: text: expected string, got undefined"),
        (lambda: page.keyboard.type("a", delay=True), "Keyboard.type: delay: expected float, got boolean"),
        (lambda: page.keyboard.type("a", delay="bad"), "Keyboard.type: delay: expected float, got string"),
        (lambda: page.keyboard.insert_text(123), "Keyboard.insert_text: text: expected string, got number"),
        (lambda: page.keyboard.insert_text(True), "Keyboard.insert_text: text: expected string, got boolean"),
        (lambda: page.keyboard.insert_text(None), "Keyboard.insert_text: text: expected string, got undefined"),
        (lambda: page.keyboard.press(123), "Keyboard.press: key: expected string, got number"),
        (lambda: page.keyboard.press(True), "Keyboard.press: key: expected string, got boolean"),
        (lambda: page.keyboard.press(None), "Keyboard.press: key: expected string, got undefined"),
        (lambda: page.keyboard.press("a", delay=True), "Keyboard.press: delay: expected float, got boolean"),
        (lambda: page.keyboard.press("a", delay="bad"), "Keyboard.press: delay: expected float, got string"),
        (lambda: page.keyboard.down(123), "Keyboard.down: key: expected string, got number"),
        (lambda: page.keyboard.down(True), "Keyboard.down: key: expected string, got boolean"),
        (lambda: page.keyboard.down(None), "Keyboard.down: key: expected string, got undefined"),
        (lambda: page.keyboard.up(123), "Keyboard.up: key: expected string, got number"),
        (lambda: page.keyboard.up(True), "Keyboard.up: key: expected string, got boolean"),
        (lambda: page.keyboard.up(None), "Keyboard.up: key: expected string, got undefined"),
    ]
    for action, message in invalid_cases:
        with pytest.raises(Error) as exc_info:
            action()
        assert str(exc_info.value).splitlines()[0] == message

    page.keyboard.type("a", delay=1.0)
    page.keyboard.press("b", delay=1.0)
    assert page.input_value("#name") == "ab"


