def test_keyboard_type_press_and_locator_paths_respect_delay(page):
    page.set_content("<input id='name'>")
    page.focus("#name")

    start = time.monotonic()
    page.keyboard.type("ab", delay=25)
    assert time.monotonic() - start >= 0.04

    start = time.monotonic()
    page.keyboard.press("c", delay=25)
    assert time.monotonic() - start >= 0.02

    page.locator("#name").fill("")
    start = time.monotonic()
    page.type("#name", "de", delay=25)
    assert time.monotonic() - start >= 0.04

    start = time.monotonic()
    page.locator("#name").press_sequentially("fg", delay=25)
    assert time.monotonic() - start >= 0.04
    assert page.input_value("#name") == "defg"


def test_mouse_click_and_dblclick_respect_delay(page):
    page.set_content(
        """
        <button id="target" style="margin: 20px; width: 80px; height: 40px">Hit</button>
        <script>
        window.mouseEvents = [];
        const target = document.querySelector('#target');
        for (const type of ['mousedown', 'mouseup', 'dblclick']) {
          target.addEventListener(type, event => window.mouseEvents.push(type));
        }
        </script>
        """
    )

    box = page.locator("#target").bounding_box()
    assert box is not None
    x = box["x"] + box["width"] / 2
    y = box["y"] + box["height"] / 2

    start = time.monotonic()
    page.mouse.click(x, y, delay=25)
    assert time.monotonic() - start >= 0.02

    start = time.monotonic()
    page.mouse.dblclick(x, y, delay=25)
    assert time.monotonic() - start >= 0.04

    assert page.evaluate("() => window.mouseEvents") == [
        "mousedown",
        "mouseup",
        "mousedown",
        "mouseup",
        "mousedown",
        "mouseup",
        "dblclick",
    ]


def test_mouse_move_supports_steps(page):
    page.set_content(
        """
        <div id="area" style="width: 300px; height: 220px; background: #eee"></div>
        <script>
        window.moves = [];
        document.addEventListener('mousemove', event => {
          window.moves.push({ x: Math.round(event.clientX), y: Math.round(event.clientY) });
        });
        </script>
        """
    )

    page.mouse.move(10, 20)
    page.evaluate("window.moves = []")
    page.mouse.move(110, 120, steps=4)

    assert page.evaluate("() => window.moves") == [
        {"x": 35, "y": 45},
        {"x": 60, "y": 70},
        {"x": 85, "y": 95},
        {"x": 110, "y": 120},
    ]


