def test_async_locator_drag_to_force_and_positions():
    async def run() -> None:
        from playwright.async_api import async_playwright, expect as async_expect

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <style>
                #source { position: absolute; left: 20px; top: 20px; width: 80px; height: 40px; }
                #target { position: absolute; left: 150px; top: 20px; width: 100px; height: 60px; }
                #overlay { position: absolute; left: 150px; top: 20px; width: 100px; height: 60px; }
                </style>
                <div id="source" draggable="true">Item</div>
                <div id="target">Target</div>
                <div id="overlay">Overlay</div>
                <script>
                document.querySelector('#source').addEventListener('dragstart', event => {
                  document.body.dataset.start = `${Math.round(event.clientX)},${Math.round(event.clientY)}`;
                  event.dataTransfer.setData('text/plain', 'Item');
                });
                for (const id of ['target', 'overlay']) {
                  const node = document.querySelector('#' + id);
                  node.addEventListener('dragover', event => event.preventDefault());
                  node.addEventListener('drop', event => {
                    event.preventDefault();
                    document.body.dataset.drop = id;
                    document.body.dataset.point = `${Math.round(event.clientX)},${Math.round(event.clientY)}`;
                  });
                }
                </script>
                """
            )

            await page.locator("#source").drag_to(
                page.locator("#target"),
                force=True,
                source_position={"x": 10, "y": 15},
                target_position={"x": 20, "y": 25},
            )

            assert await page.evaluate("document.body.dataset.drop") == "overlay"
            assert await page.evaluate("document.body.dataset.start") == "30,35"
            assert await page.evaluate("document.body.dataset.point") == "170,45"
            await browser.close()

    asyncio.run(run())


def test_dialog_event_accepts_prompt(page):
    page.set_content(
        """
        <button id="prompt" onclick="document.body.dataset.answer = prompt('Name?', 'Ada')">Prompt</button>
        """
    )
    seen = []

    def handle(dialog):
        seen.append((dialog.type, dialog.message, dialog.default_value))
        dialog.accept("Grace")

    page.on("dialog", handle)
    page.click("#prompt")

    assert seen == [("prompt", "Name?", "Ada")]
    assert page.evaluate("document.body.dataset.answer") == "Grace"


