def test_console_messages_support_navigation_filter(page):
    before = "sync console before navigation filter"
    after = "sync console after navigation filter"
    page.set_content("<main>console filter</main>")
    page.evaluate("(text) => console.log(text)", before)
    wait_until(lambda: before in [message.text for message in page.console_messages(filter="all")])

    page.goto(data_url(f"<script>console.log({json.dumps(after)})</script><main>after</main>"))
    def current_console_texts():
        texts = [message.text for message in page.console_messages()]
        return texts if after in texts else None

    current = wait_until(current_console_texts)

    all_messages = [message.text for message in page.console_messages(filter="all")]
    since_messages = [message.text for message in page.console_messages(filter="since-navigation")]
    assert before in all_messages
    assert after in all_messages
    assert before not in current
    assert since_messages == current
    with pytest.raises(Error, match="expected one of"):
        page.console_messages(filter="bogus")


