def test_page_pick_locator_returns_clicked_locator(page):
    page.set_content(
        """
        <main>
          <button id="picked" data-state="ready">Pick me</button>
        </main>
        """
    )
    result = {}

    thread = threading.Thread(target=lambda: result.setdefault("locator", page.pick_locator()))
    thread.start()
    wait_until(lambda: page.evaluate("(key) => !!window[key]?.active", page._pick_locator_state_name))
    page.mouse.move(20, 20)
    page.click("#picked")
    thread.join(timeout=3)

