def test_page_pick_locator_can_be_cancelled(page):
    page.set_default_timeout(3_000)
    page.set_content("<button>Cancel pick</button>")
    errors = {}

    def run_picker() -> None:
        try:
            page.pick_locator()
        except Error as exc:
            errors["message"] = str(exc)

    thread = threading.Thread(target=run_picker)
    thread.start()
    wait_until(lambda: page.evaluate("(key) => !!window[key]?.active", page._pick_locator_state_name))
    page.cancel_pick_locator()
    thread.join(timeout=3)

    assert not thread.is_alive()
    assert "canceled" in errors["message"]


def test_page_crash_event_for_chromium_target_crash(browser):
    page = browser.new_page()
    seen = []

    page.on("crash", lambda crashed_page: seen.append(crashed_page is page))
    with page.expect_event("crash", timeout=7_000) as crash_info:
        with pytest.raises(Error):
            page.goto("chrome://crash", timeout=5_000)

    assert crash_info.value is page
    assert seen == [True]
    with pytest.raises(TimeoutError, match='Timeout 10ms exceeded while waiting for event "crash"'):
        page.wait_for_event("crash", timeout=10)


def test_page_event_waiters_reject_on_page_crash(browser):
    page = browser.new_page()
    result = {}

    def wait_for_console() -> None:
        try:
            page.wait_for_event("console", timeout=7_000)
        except Exception as exc:
            result["waiter"] = (exc.__class__.__name__, str(exc).splitlines()[0])
        else:
            result["waiter"] = ("resolved", "")

    thread = threading.Thread(target=wait_for_console)
    try:
        thread.start()
        time.sleep(0.1)
        with pytest.raises(Error, match="Page crashed"):
            page.goto("chrome://crash", timeout=5_000)
        thread.join(timeout=8)
        assert not thread.is_alive()
        assert result.get("waiter") == ("Error", "Page crashed")
    finally:
        if not page.is_closed():
            page.close()


