def test_mouse_and_touchscreen_click(browser, page):
    page.set_content(
        """
        <button id="target" style="position:absolute;left:20px;top:20px;width:100px;height:40px"
                onclick="document.body.dataset.clicked='yes'">Target</button>
        <script>
        const target = document.querySelector('#target');
        target.addEventListener('pointerdown', event => {
          document.body.dataset.pointerType = event.pointerType;
        });
        target.addEventListener('mousedown', () => {
          document.body.dataset.mouseDown = 'yes';
        });
        </script>
        """
    )

    page.mouse.click(40, 40)
    assert page.evaluate("document.body.dataset.clicked") == "yes"

    context = browser.new_context(has_touch=True)
    touch_page = context.new_page()
    try:
        touch_page.set_content(
            """
            <button id="target" style="position:absolute;left:20px;top:20px;width:100px;height:40px"
                    onclick="document.body.dataset.clicked='yes'">Target</button>
            <script>
            const target = document.querySelector('#target');
            target.addEventListener('pointerdown', event => {
              document.body.dataset.pointerType = event.pointerType;
              document.body.dataset.pointerTrusted = String(event.isTrusted);
            });
            target.addEventListener('mousedown', event => {
              document.body.dataset.mouseDown = 'yes';
              document.body.dataset.mouseTrusted = String(event.isTrusted);
            });
            </script>
            """
        )
        touch_page.touchscreen.tap(40, 40)
        assert touch_page.evaluate("document.body.dataset.clicked") == "yes"
        assert touch_page.evaluate("document.body.dataset.pointerType") == "touch"
        assert touch_page.evaluate("document.body.dataset.mouseDown") == "yes"
        assert touch_page.evaluate("document.body.dataset.pointerTrusted") == "true"
        assert touch_page.evaluate("document.body.dataset.mouseTrusted") == "true"
    finally:
        context.close()


