def test_tap_has_touch_and_touchscreen_validation_matches_playwright(browser, page):
    page.set_content("<button id='target' style='width:80px;height:40px'>Target</button>")

    for action, message in [
        (
            lambda: page.tap("#target", timeout=100),
            "Page.tap: The page does not support tap. Use hasTouch context option to enable touch support.",
        ),
        (
            lambda: page.locator("#target").tap(timeout=100),
            "Locator.tap: The page does not support tap. Use hasTouch context option to enable touch support.",
        ),
        (
            lambda: page.main_frame.tap("#target", timeout=100),
            "Frame.tap: The page does not support tap. Use hasTouch context option to enable touch support.",
        ),
        (
            lambda: page.touchscreen.tap(1, 1),
            "Touchscreen.tap: hasTouch must be enabled on the browser context before using the touchscreen.",
        ),
    ]:
        with pytest.raises(Error) as exc_info:
            action()
        assert str(exc_info.value).splitlines()[0] == message

    invalid_cases = [
        (lambda: page.touchscreen.tap("x", 1), "Touchscreen.tap: x: expected float, got string"),
        (lambda: page.touchscreen.tap(True, 1), "Touchscreen.tap: x: expected float, got boolean"),
        (lambda: page.touchscreen.tap(None, 1), "Touchscreen.tap: x: expected float, got undefined"),
        (lambda: page.touchscreen.tap(1, "y"), "Touchscreen.tap: y: expected float, got string"),
    ]
    for action, message in invalid_cases:
        with pytest.raises(Error) as exc_info:
            action()
        assert str(exc_info.value).splitlines()[0] == message

    context = browser.new_context(has_touch=True)
    touch_page = context.new_page()
    try:
        touch_page.set_content(
            """
            <button id="target" style="position:absolute;left:0;top:0;width:80px;height:80px">Target</button>
            <script>
            window.events = [];
            for (const type of ['pointerdown', 'touchstart', 'mousedown', 'click']) {
              document.querySelector('#target').addEventListener(type, event => {
                window.events.push({
                  type,
                  pointerType: event.pointerType || '',
                  shiftKey: event.shiftKey,
                  isTrusted: event.isTrusted,
                  touches: event.touches ? event.touches.length : null,
                });
              });
            }
            </script>
            """
        )
        touch_page.keyboard.down("Shift")
        touch_page.touchscreen.tap(1.5, 2.5)
        touch_page.keyboard.up("Shift")
        assert touch_page.evaluate("() => window.events") == [
            {"type": "pointerdown", "pointerType": "touch", "shiftKey": True, "isTrusted": True, "touches": None},
            {"type": "touchstart", "pointerType": "", "shiftKey": True, "isTrusted": True, "touches": 1},
            {"type": "mousedown", "pointerType": "", "shiftKey": True, "isTrusted": True, "touches": None},
            {"type": "click", "pointerType": "touch", "shiftKey": True, "isTrusted": True, "touches": None},
        ]
    finally:
        context.close()


def test_mouse_down_up_and_wheel_dispatch_events(page):
    page.set_content(
        """
        <style>body { margin: 0; height: 2000px; } #area { width: 200px; height: 120px; }</style>
        <div id="area">Scroll target</div>
        <script>
        document.addEventListener('mousedown', () => document.body.dataset.mouseDown = 'yes');
        document.addEventListener('mouseup', () => document.body.dataset.mouseUp = 'yes');
        document.addEventListener('wheel', event => document.body.dataset.wheelDelta = String(event.deltaY));
        </script>
        """
    )

    page.mouse.down()
    page.mouse.up()
    page.mouse.move(50, 50)
    page.mouse.wheel(0, 120)
    page.wait_for_timeout(100)

    assert page.evaluate("document.body.dataset.mouseDown") == "yes"
    assert page.evaluate("document.body.dataset.mouseUp") == "yes"
    assert page.evaluate("document.body.dataset.wheelDelta") == "120"
    assert page.evaluate("window.scrollY") > 0


