def test_expose_binding_option_validation_matches_playwright(browser):
    def expect_error(operation, expected):
        context = browser.new_context()
        page = context.new_page()
        try:
            with pytest.raises(Error) as exc_info:
                operation(page, context)
            assert str(exc_info.value).splitlines()[0] == expected
        finally:
            context.close()

    expect_error(
        lambda page, context: page.expose_binding("badHandle", lambda source: None, handle="bad"),
        "Page.expose_binding: needs_handle: expected boolean, got string",
    )
    expect_error(
        lambda page, context: page.expose_binding("badHandleNumber", lambda source: None, handle=1),
        "Page.expose_binding: needs_handle: expected boolean, got number",
    )
    expect_error(
        lambda page, context: page.expose_binding(123, lambda source: None),
        "Page.expose_binding: name: expected string, got number",
    )
    expect_error(
        lambda page, context: page.expose_function(True, lambda: None),
        "Page.expose_function: name: expected string, got boolean",
    )
    expect_error(
        lambda page, context: context.expose_binding("badHandle", lambda source: None, handle="bad"),
        "BrowserContext.expose_binding: needs_handle: expected boolean, got string",
    )
    expect_error(
        lambda page, context: context.expose_binding("badHandleNumber", lambda source: None, handle=1),
        "BrowserContext.expose_binding: needs_handle: expected boolean, got number",
    )
    expect_error(
        lambda page, context: context.expose_binding(123, lambda source: None),
        "BrowserContext.expose_binding: name: expected string, got number",
    )
    expect_error(
        lambda page, context: context.expose_function(123, lambda: None),
        "BrowserContext.expose_function: name: expected string, got number",
    )
    duplicate_cases = [
        (
            lambda page, context: (page.expose_function("dupPageFunction", lambda: None), page.expose_function("dupPageFunction", lambda: None)),
            'Function "dupPageFunction" has been already registered',
        ),
        (
            lambda page, context: (page.expose_binding("dupPageBinding", lambda source: None), page.expose_binding("dupPageBinding", lambda source: None)),
            'Function "dupPageBinding" has been already registered',
        ),
        (
            lambda page, context: (page.expose_function("dupPageMixed", lambda: None), page.expose_binding("dupPageMixed", lambda source: None)),
            'Function "dupPageMixed" has been already registered',
        ),
        (
            lambda page, context: (context.expose_function("dupContextFunction", lambda: None), context.expose_function("dupContextFunction", lambda: None)),
            'Function "dupContextFunction" has been already registered',
        ),
        (
            lambda page, context: (context.expose_binding("dupContextBinding", lambda source: None), context.expose_binding("dupContextBinding", lambda source: None)),
            'Function "dupContextBinding" has been already registered',
        ),
        (
            lambda page, context: (context.expose_function("dupContextMixed", lambda: None), context.expose_binding("dupContextMixed", lambda source: None)),
            'Function "dupContextMixed" has been already registered',
        ),
        (
            lambda page, context: (context.expose_function("contextThenPage", lambda: None), page.expose_function("contextThenPage", lambda: None)),
            'Function "contextThenPage" has been already registered in the browser context',
        ),
        (
            lambda page, context: (page.expose_function("pageThenContext", lambda: None), context.expose_function("pageThenContext", lambda: None)),
            'Function "pageThenContext" has been already registered in one of the pages',
        ),
    ]
    for operation, message in duplicate_cases:
        expect_error(operation, message)


