def test_viewport_screen_and_device_scale_option_validation_matches_playwright(browser):
    invalid_context_cases = [
        ({"viewport": "bad"}, "Browser.new_context: viewport: expected object, got string"),
        ({"viewport": {"height": 100}}, "Browser.new_context: viewport.width: expected integer, got undefined"),
        (
            {"viewport": {"width": True, "height": 100}},
            "Browser.new_context: viewport.width: expected integer, got boolean",
        ),
        (
            {"viewport": {"width": 100.5, "height": 100}},
            "Browser.new_context: viewport.width: expected integer, got float 100.5",
        ),
        ({"screen": "bad"}, "Browser.new_context: screen: expected object, got string"),
        ({"screen": {"height": 100}}, "Browser.new_context: screen.width: expected integer, got undefined"),
        (
            {"device_scale_factor": "2"},
            "Browser.new_context: device_scale_factor: expected float, got string",
        ),
        (
            {"no_viewport": True, "device_scale_factor": 2},
            'Browser.new_context: "deviceScaleFactor" option is not supported with null "viewport"',
        ),
        (
            {"no_viewport": True, "is_mobile": True},
            'Browser.new_context: "isMobile" option is not supported with null "viewport"',
        ),
    ]
    for kwargs, message in invalid_context_cases:
        with pytest.raises(Error) as exc_info:
            browser.new_context(**kwargs)
        assert str(exc_info.value).splitlines()[0] == message

    with pytest.raises(Error) as page_error:
        browser.new_page(viewport={"width": "100", "height": 100})
    assert str(page_error.value).splitlines()[0] == "Browser.new_page: viewport.width: expected integer, got string"
    with pytest.raises(Error) as no_viewport_scale_error:
        browser.new_page(no_viewport=True, device_scale_factor=2)
    assert (
        str(no_viewport_scale_error.value).splitlines()[0]
        == 'Browser.new_page: "deviceScaleFactor" option is not supported with null "viewport"'
    )
    with pytest.raises(Error) as no_viewport_mobile_error:
        browser.new_page(no_viewport=True, is_mobile=True)
    assert (
        str(no_viewport_mobile_error.value).splitlines()[0]
        == 'Browser.new_page: "isMobile" option is not supported with null "viewport"'
    )

    page = browser.new_page()
    try:
        invalid_set_cases = [
            ("bad", "Page.set_viewport_size: viewport_size: expected object, got string"),
            ({"height": 100}, "Page.set_viewport_size: viewportSize.width: expected integer, got undefined"),
            (
                {"width": "100", "height": 100},
                "Page.set_viewport_size: viewportSize.width: expected integer, got string",
            ),
        ]
        for value, message in invalid_set_cases:
            with pytest.raises(Error) as exc_info:
                page.set_viewport_size(value)
            assert str(exc_info.value).splitlines()[0] == message

        page.set_viewport_size({"width": 0, "height": 100})
        assert page.viewport_size == {"width": 0, "height": 100}

        with pytest.raises(Error) as protocol_error:
            page.set_viewport_size({"width": 100, "height": -1})
        protocol_message = str(protocol_error.value).splitlines()[0]
        assert (
            protocol_message
            == "Page.set_viewport_size: Protocol error (Emulation.setDeviceMetricsOverride): "
            "Screen width and height values must be positive, not greater than 10000000"
        )
    finally:
        page.close()

    negative_context = browser.new_context(viewport={"width": 100, "height": -1})
    try:
        with pytest.raises(Error) as context_protocol_error:
            negative_context.new_page()
        context_protocol_message = str(context_protocol_error.value).splitlines()[0]
        assert (
            context_protocol_message
            == "BrowserContext.new_page: Protocol error (Emulation.setDeviceMetricsOverride): "
            "Screen width and height values must be positive, not greater than 10000000"
        )
    finally:
        negative_context.close()

    context = browser.new_context(
        viewport={"width": 100.0, "height": 100},
        screen={"width": 0, "height": 100},
        device_scale_factor=0,
    )
    try:
        valid_page = context.new_page()
        assert valid_page.viewport_size == {"width": 100, "height": 100}
        assert valid_page.evaluate("({ width: innerWidth, height: innerHeight })") == {"width": 100, "height": 100}
    finally:
        context.close()


