def test_close_event_handlers_accept_zero_or_value_callbacks_like_playwright(browser):
    context = browser.new_context()
    page = context.new_page()
    seen: list[object] = []

    def page_zero_arg() -> None:
        seen.append("page-zero")

    def page_value_arg(closed_page) -> None:
        seen.append(("page-value", closed_page is page))

    def context_zero_arg() -> None:
        seen.append("context-zero")

    def context_value_arg(closed_context) -> None:
        seen.append(("context-value", closed_context is context))

    page.on("close", page_zero_arg)
    page.on("close", page_value_arg)
    context.on("close", context_zero_arg)
    context.on("close", context_value_arg)

    page.close()
    context.close()

    assert seen == [
        "page-zero",
        ("page-value", True),
        "context-zero",
        ("context-value", True),
    ]


def test_context_pageload_and_pageclose_events(browser, http_server):
    context = browser.new_context()
    page = context.new_page()
    loaded = []
    closed = []

    context.on("pageload", lambda loaded_page: loaded.append(loaded_page))
    context.on("pageclose", lambda closed_page: closed.append(closed_page))

    with context.expect_event("pageload", lambda loaded_page: loaded_page is page) as load_info:
        page.goto(f"{http_server}/page")
