def test_context_pageload_predicate_can_accept_second_delivery_of_same_page(browser, http_server):
    context = browser.new_context()
    page = context.new_page()
    predicate_calls = 0

    def accepts_second_load(loaded_page) -> bool:
        nonlocal predicate_calls
        assert loaded_page is page
        predicate_calls += 1
        return predicate_calls == 2

    with context.expect_event("pageload", accepts_second_load, timeout=5_000) as load_info:
        page.goto(f"{http_server}/page")
        page.reload()

    assert load_info.value is page
    assert predicate_calls == 2
    context.close()


def test_context_pageload_and_pageclose_events_cover_new_pages_and_listener_removal(browser, http_server):
    context = browser.new_context()
    loaded = []
    closed = []

    def on_load(page):
        loaded.append(page)

    def on_close(page):
        closed.append(page)

    context.on("pageload", on_load)
    context.on("pageclose", on_close)
    first = context.new_page()
    first.goto(f"{http_server}/page")
    first.close()

    assert wait_until(lambda: loaded) == [first]
    assert closed == [first]

    context.remove_listener("pageload", on_load)
    context.remove_listener("pageclose", on_close)
    second = context.new_page()
    second.goto(f"{http_server}/page")
    second.close()
    time.sleep(0.1)

    assert loaded == [first]
    assert closed == [first]
    context.close()


def test_closed_page_and_context_are_removed_from_owner_lists(browser):
    context = browser.new_context()
    page = context.new_page()
    page_close_seen = []
    context_close_seen = []

    page.on("close", lambda closed_page: page_close_seen.append((closed_page is page, page in context.pages)))
    context.on("close", lambda closed_context: context_close_seen.append((closed_context is context, context in browser.contexts)))
    assert page in context.pages
    assert context in browser.contexts

    page.close()
    assert page not in context.pages
    assert page_close_seen == [(True, False)]

    context.close()
    assert context not in browser.contexts
    assert context_close_seen == [(True, False)]


