def test_page_extra_http_headers_merge_with_context_headers(browser, http_server):
    context = browser.new_context(extra_http_headers={"X-Context": "initial", "X-Shared": "context"})
    page = context.new_page()
    try:
        page.set_extra_http_headers({"X-Page": "page", "X-Shared": "page"})
        first = page.goto(f"{http_server}/request-headers")
        assert first is not None
        first_headers = first.json()
        assert first_headers["x-context"] == "initial"
        assert first_headers["x-page"] == "page"
        assert first_headers["x-shared"] == "page"

        context.set_extra_http_headers({"X-Context": "updated", "X-After": "context"})
        second = page.goto(f"{http_server}/request-headers")
        assert second is not None
        second_headers = second.json()
        assert second_headers["x-context"] == "updated"
        assert second_headers["x-after"] == "context"
        assert second_headers["x-page"] == "page"
        assert second_headers["x-shared"] == "page"

        page.set_extra_http_headers({})
        third = page.goto(f"{http_server}/request-headers")
        assert third is not None
        third_headers = third.json()
        assert third_headers["x-context"] == "updated"
        assert third_headers["x-after"] == "context"
        assert "x-page" not in third_headers
        assert "x-shared" not in third_headers
    finally:
        context.close()


def test_set_extra_http_headers_validation_matches_playwright(browser):
    context = browser.new_context()
    page = context.new_page()
    try:
        context_invalid_cases = [
            ({1: "x"}, "BrowserContext.set_extra_http_headers: headers[0].name: expected string, got number"),
            ({"X": 1}, "BrowserContext.set_extra_http_headers: headers[0].value: expected string, got number"),
            ({"X": True}, "BrowserContext.set_extra_http_headers: headers[0].value: expected string, got boolean"),
        ]
        for value, message in context_invalid_cases:
            with pytest.raises(Error) as exc_info:
                context.set_extra_http_headers(value)
            assert str(exc_info.value).splitlines()[0] == message
        for value, message in [
            (None, "'NoneType' object has no attribute 'items'"),
            ("bad", "'str' object has no attribute 'items'"),
            ([("X", "Y")], "'list' object has no attribute 'items'"),
            ((("X", "Y"),), "'tuple' object has no attribute 'items'"),
        ]:
            with pytest.raises(AttributeError) as exc_info:
                context.set_extra_http_headers(value)
            assert str(exc_info.value).splitlines()[0] == message

        page_invalid_cases = [
            ({1: "x"}, "Page.set_extra_http_headers: headers[0].name: expected string, got number"),
            ({"X": 1}, "Page.set_extra_http_headers: headers[0].value: expected string, got number"),
            ({"X": True}, "Page.set_extra_http_headers: headers[0].value: expected string, got boolean"),
        ]
        for value, message in page_invalid_cases:
            with pytest.raises(Error) as exc_info:
                page.set_extra_http_headers(value)
            assert str(exc_info.value).splitlines()[0] == message
        for value, message in [
            (None, "'NoneType' object has no attribute 'items'"),
            ("bad", "'str' object has no attribute 'items'"),
            ([("X", "Y")], "'list' object has no attribute 'items'"),
            ((("X", "Y"),), "'tuple' object has no attribute 'items'"),
        ]:
            with pytest.raises(AttributeError) as exc_info:
                page.set_extra_http_headers(value)
            assert str(exc_info.value).splitlines()[0] == message

        context.set_extra_http_headers({"X-Optional": None})
        page.set_extra_http_headers({"X-Optional": None})
    finally:
        context.close()


def test_context_bypass_csp_allows_inline_script_injection(browser, http_server):
    normal_context = browser.new_context()
    normal_page = normal_context.new_page()
    normal_page.goto(f"{http_server}/csp")
    with pytest.raises(Error, match="Content Security Policy"):
        normal_page.add_script_tag(content="window.__rustwrightCspProbe = 'blocked';")
    assert normal_page.evaluate("window.__rustwrightCspProbe") is None
    normal_context.close()

    bypass_context = browser.new_context(bypass_csp=True)
    bypass_page = bypass_context.new_page()
    bypass_page.goto(f"{http_server}/csp")
    bypass_page.add_script_tag(content="window.__rustwrightCspProbe = 'allowed';")
    assert bypass_page.evaluate("window.__rustwrightCspProbe") == "allowed"
    bypass_context.close()


def test_context_java_script_enabled_false_prevents_page_scripts(browser, http_server):
    disabled_context = browser.new_context(java_script_enabled=False)
    disabled_page = disabled_context.new_page()
    disabled_page.goto(f"{http_server}/scripted")
    disabled_html = disabled_page.content()
    assert 'data-script="ran"' not in disabled_html
    assert '<main id="probe">Initial</main>' in disabled_html
    disabled_context.close()

    enabled_context = browser.new_context(java_script_enabled=True)
    enabled_page = enabled_context.new_page()
    enabled_page.goto(f"{http_server}/scripted")
    enabled_html = enabled_page.content()
    assert 'data-script="ran"' in enabled_html
    assert '<main id="probe">Ran</main>' in enabled_html
    enabled_context.close()


def test_context_geolocation_permissions_and_environment_options(browser, http_server):
    context = browser.new_context(
        geolocation={"latitude": 37.5, "longitude": -122.5, "accuracy": 7},
        permissions=["geolocation"],
        timezone_id="America/Los_Angeles",
        locale="fr-FR",
        color_scheme="dark",
        reduced_motion="reduce",
        forced_colors="active",
        contrast="more",
    )
    page = context.new_page()
    page.goto(f"{http_server}/page")

    position = page.evaluate(
        """async () => await new Promise((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(
          position => resolve({
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
            accuracy: position.coords.accuracy,
          }),
          error => reject(new Error(error.message))
        );
        })"""
    )

    assert position == {"latitude": 37.5, "longitude": -122.5, "accuracy": 7}
    assert page.evaluate("Intl.DateTimeFormat().resolvedOptions().timeZone") == "America/Los_Angeles"
    assert page.evaluate("Intl.DateTimeFormat().resolvedOptions().locale") == "fr-FR"
    assert page.evaluate("navigator.language") == "fr-FR"
    assert page.evaluate("navigator.languages") == ["fr-FR"]
    assert page.evaluate("matchMedia('(prefers-color-scheme: dark)').matches")
    assert page.evaluate("matchMedia('(prefers-reduced-motion: reduce)').matches")
    assert page.evaluate("matchMedia('(forced-colors: active)').matches")
    assert page.evaluate("matchMedia('(prefers-contrast: more)').matches")
    assert page.goto(f"{http_server}/request-headers").json()["accept-language"] == "fr-FR"
    context.close()


def test_context_environment_option_validation_matches_playwright(browser):
    invalid_context_cases = [
        ({"color_scheme": "bad"}, "Browser.new_context: color_scheme: expected one of (dark|light|no-preference|no-override)"),
        ({"color_scheme": "none"}, "Browser.new_context: color_scheme: expected one of (dark|light|no-preference|no-override)"),
        ({"reduced_motion": "bad"}, "Browser.new_context: reduced_motion: expected one of (reduce|no-preference|no-override)"),
        ({"forced_colors": "bad"}, "Browser.new_context: forced_colors: expected one of (active|none|no-override)"),
        ({"contrast": "bad"}, "Browser.new_context: contrast: expected one of (no-preference|more|no-override)"),
        ({"service_workers": "bad"}, "Browser.new_context: service_workers: expected one of (allow|block)"),
        ({"java_script_enabled": "bad"}, "Browser.new_context: java_script_enabled: expected boolean, got string"),
        ({"is_mobile": "bad"}, "Browser.new_context: is_mobile: expected boolean, got string"),
        ({"has_touch": "bad"}, "Browser.new_context: has_touch: expected boolean, got string"),
        ({"offline": "bad"}, "Browser.new_context: offline: expected boolean, got string"),
        ({"ignore_https_errors": "bad"}, "Browser.new_context: ignore_https_errors: expected boolean, got string"),
        ({"bypass_csp": "bad"}, "Browser.new_context: bypass_csp: expected boolean, got string"),
        ({"strict_selectors": "bad"}, "Browser.new_context: strict_selectors: expected boolean, got string"),
    ]
    for kwargs, message in invalid_context_cases:
        with pytest.raises(Error) as exc_info:
            browser.new_context(**kwargs)
        assert str(exc_info.value).splitlines()[0] == message

    with pytest.raises(Error) as page_bool_error:
        browser.new_page(java_script_enabled="bad")
    assert str(page_bool_error.value).splitlines()[0] == (
        "Browser.new_page: java_script_enabled: expected boolean, got string"
    )

    with pytest.raises(Error) as page_enum_error:
        browser.new_page(color_scheme="bad")
    assert str(page_enum_error.value).splitlines()[0] == (
        "Browser.new_page: color_scheme: expected one of (dark|light|no-preference|no-override)"
    )

    context = browser.new_context(
        color_scheme="no-override",
        reduced_motion="null",
        forced_colors="no-override",
        contrast="null",
    )
    context.close()


