def test_context_device_identity_options_apply_to_pages(browser):
    mobile_user_agent = (
        "Mozilla/5.0 (Linux; Android 11; Pixel 5) AppleWebKit/537.36 "
        "(KHTML, like Gecko) Chrome/120.0.0.0 Mobile Safari/537.36"
    )
    context = browser.new_context(
        viewport={"width": 390, "height": 844},
        screen={"width": 414, "height": 896},
        user_agent=mobile_user_agent,
        device_scale_factor=2,
        is_mobile=True,
        has_touch=True,
    )
    page = context.new_page()
    page.set_content("<meta name='viewport' content='width=device-width,initial-scale=1'><main>Device</main>")

    assert page.viewport_size == {"width": 390, "height": 844}
    assert page.evaluate("navigator.userAgent") == mobile_user_agent
    assert page.evaluate("window.devicePixelRatio") == 2
    assert page.evaluate("navigator.maxTouchPoints") > 0
    assert page.evaluate("() => ({ type: screen.orientation.type, angle: screen.orientation.angle })") == {
        "type": "portrait-primary",
        "angle": 0,
    }
    assert page.evaluate("() => navigator.userAgentData ? navigator.userAgentData.mobile : true")
    assert page.evaluate("() => navigator.userAgentData ? navigator.userAgentData.platform : 'Android'") == "Android"
    assert page.evaluate("window.innerWidth") == 390
    assert page.evaluate("({ width: window.screen.width, height: window.screen.height })") == {
        "width": 414,
        "height": 896,
    }
    context.close()


def test_device_descriptor_can_create_context(playwright, browser):
    descriptor = dict(playwright.devices["Pixel 7"])
    expected_viewport = descriptor["viewport"]

    context = browser.new_context(**descriptor)
    try:
        page = context.new_page()
        page.set_content("<meta name='viewport' content='width=device-width,initial-scale=1'><main>Device</main>")

        assert page.viewport_size == expected_viewport
        assert page.evaluate("({ width: innerWidth, height: innerHeight })") == expected_viewport
        assert_near(page.evaluate("window.devicePixelRatio"), descriptor["device_scale_factor"], 0.01)
        assert page.evaluate("navigator.userAgent") == descriptor["user_agent"]
        assert page.evaluate("navigator.maxTouchPoints") > 0
        assert page.evaluate("() => ({ type: screen.orientation.type, angle: screen.orientation.angle })") == {
            "type": "portrait-primary",
            "angle": 0,
        }
        assert page.evaluate("'ontouchstart' in window") is False
    finally:
        context.close()


def test_desktop_hidpi_device_descriptor_can_create_context(playwright, browser):
    descriptor = dict(playwright.devices["Desktop Chrome HiDPI"])
    expected_viewport = descriptor["viewport"]
    expected_screen = descriptor.get("screen") or expected_viewport

    context = browser.new_context(**descriptor)
    try:
        page = context.new_page()
        page.set_content("<main>Desktop Device</main>")

        assert page.viewport_size == expected_viewport
        assert page.evaluate("({ width: innerWidth, height: innerHeight })") == expected_viewport
        assert page.evaluate("({ width: screen.width, height: screen.height })") == expected_screen
        assert_near(page.evaluate("window.devicePixelRatio"), descriptor["device_scale_factor"], 0.01)
        assert page.evaluate("navigator.userAgent") == descriptor["user_agent"]
        assert page.evaluate("navigator.maxTouchPoints") == 0
        assert page.evaluate("'ontouchstart' in window") is False
        assert page.evaluate("() => ({ type: screen.orientation.type, angle: screen.orientation.angle })") == {
            "type": "landscape-primary",
            "angle": 0,
        }
    finally:
        context.close()


def expected_screen_orientation(screen: dict[str, int], *, mobile: bool) -> dict[str, Any]:
    if mobile and screen["width"] > screen["height"]:
        return {"type": "landscape-primary", "angle": 90}
    if mobile:
        return {"type": "portrait-primary", "angle": 0}
    return {"type": "landscape-primary", "angle": 0}


def test_all_device_descriptors_apply_core_browser_visible_metrics(playwright, browser):
    for name, raw_descriptor in sorted(playwright.devices.items()):
        descriptor = dict(raw_descriptor)
        expected_viewport = descriptor["viewport"]
        expected_screen = descriptor.get("screen") or expected_viewport

        context = browser.new_context(**descriptor)
        try:
            page = context.new_page()
            page.set_content("<meta name='viewport' content='width=device-width,initial-scale=1'><main>Device</main>")

            assert page.viewport_size == expected_viewport, name
            assert page.evaluate("({ width: innerWidth, height: innerHeight })") == expected_viewport, name
            assert page.evaluate("({ width: screen.width, height: screen.height })") == expected_screen, name
            assert_near(page.evaluate("window.devicePixelRatio"), descriptor["device_scale_factor"], 0.01)
            assert page.evaluate("navigator.userAgent") == descriptor["user_agent"], name
            touch_points = page.evaluate("navigator.maxTouchPoints")
            assert (touch_points > 0) == bool(descriptor.get("has_touch")), name
            assert page.evaluate("'ontouchstart' in window") is False, name
            assert page.evaluate("() => ({ type: screen.orientation.type, angle: screen.orientation.angle })") == (
                expected_screen_orientation(expected_screen, mobile=bool(descriptor.get("is_mobile")))
            ), name
        finally:
            context.close()


def test_mobile_landscape_device_metrics_update_screen_orientation(browser):
    context = browser.new_context(
        viewport={"width": 844, "height": 390},
        screen={"width": 896, "height": 414},
        is_mobile=True,
    )
    try:
        page = context.new_page()
        page.set_content("<meta name='viewport' content='width=device-width,initial-scale=1'><main>Landscape</main>")

        assert page.viewport_size == {"width": 844, "height": 390}
        assert page.evaluate("() => ({ type: screen.orientation.type, angle: screen.orientation.angle })") == {
            "type": "landscape-primary",
            "angle": 90,
        }
    finally:
        context.close()


def test_devices_match_playwright_reference_descriptor_set(playwright):
    source_path = (
        Path(__file__).resolve().parents[1]
        / ".audit-playwright"
        / "playwright"
        / "driver"
        / "package"
        / "lib"
        / "server"
        / "deviceDescriptorsSource.json"
    )
    if not source_path.exists():
        pytest.skip("real Playwright reference package is not installed in .audit-playwright")

    raw_reference = json.loads(source_path.read_text(encoding="utf-8"))
    key_map = {
        "userAgent": "user_agent",
        "viewport": "viewport",
        "deviceScaleFactor": "device_scale_factor",
        "isMobile": "is_mobile",
        "hasTouch": "has_touch",
        "defaultBrowserType": "default_browser_type",
    }
    reference = {
        name: {key_map[key]: value for key, value in descriptor.items() if key in key_map}
        for name, descriptor in raw_reference.items()
    }

    devices = playwright.devices

    assert len(devices) == 143
    assert set(devices) == set(reference)
    for name in ["Desktop Chrome", "Desktop Firefox", "Desktop Safari", "iPhone 13", "Pixel 7", "Galaxy S24"]:
        assert devices[name] == reference[name]

    devices["Desktop Chrome"]["viewport"]["width"] = 1
    assert playwright.devices["Desktop Chrome"]["viewport"]["width"] == reference["Desktop Chrome"]["viewport"]["width"]


def test_context_set_offline_toggles_network(browser, http_server):
    context = browser.new_context()
    page = context.new_page()
    page.goto(f"{http_server}/page")

    invalid_cases = [
        ("bad", "BrowserContext.set_offline: offline: expected boolean, got string"),
        (1, "BrowserContext.set_offline: offline: expected boolean, got number"),
        (None, "BrowserContext.set_offline: offline: expected boolean, got undefined"),
    ]
    for value, message in invalid_cases:
        with pytest.raises(Error) as exc_info:
            context.set_offline(value)
        assert str(exc_info.value).splitlines()[0] == message

    context.set_offline(True)
    assert page.evaluate("async () => fetch('/headers').then(() => 'ok').catch(() => 'failed')") == "failed"
    context.set_offline(False)
    page2 = context.new_page()
    assert page2.goto(f"{http_server}/headers").ok
    context.close()


def test_context_cookies_roundtrip(browser):
    context = browser.new_context()

    context.add_cookies([{"name": "sid", "value": "abc", "url": "https://example.com"}])
    cookies = context.cookies("https://example.com")

    assert any(cookie["name"] == "sid" and cookie["value"] == "abc" for cookie in cookies)
    context.clear_cookies()
    assert not any(cookie["name"] == "sid" for cookie in context.cookies("https://example.com"))
    context.close()


def test_context_add_cookies_validation_matches_playwright(browser):
    context = browser.new_context()
    try:
        invalid_cases = [
            ("bad", "BrowserContext.add_cookies: cookies: expected array, got string"),
            ([1], "BrowserContext.add_cookies: cookies[0]: expected object, got number"),
            ([{}], "BrowserContext.add_cookies: cookies[0].name: expected string, got undefined"),
            (
                [{"name": "sid", "value": "v"}],
                "BrowserContext.add_cookies: Cookie should have a url or a domain/path pair",
            ),
            (
                [{"name": "sid", "url": "https://example.com"}],
                "BrowserContext.add_cookies: cookies[0].value: expected string, got undefined",
            ),
            (
                [{"value": "v", "url": "https://example.com"}],
                "BrowserContext.add_cookies: cookies[0].name: expected string, got undefined",
            ),
            (
                [{"name": 1, "value": "v", "url": "https://example.com"}],
                "BrowserContext.add_cookies: cookies[0].name: expected string, got number",
            ),
            (
                [{"name": "sid", "value": 1, "url": "https://example.com"}],
                "BrowserContext.add_cookies: cookies[0].value: expected string, got number",
            ),
            (
                [{"name": "sid", "value": "v", "url": 1}],
                "BrowserContext.add_cookies: cookies[0].url: expected string, got number",
            ),
            (
                [{"name": "sid", "value": "v", "url": "https://example.com", "domain": "example.com"}],
                "BrowserContext.add_cookies: Cookie should have either url or domain",
            ),
            (
                [{"name": "sid", "value": "v", "domain": "example.com"}],
                "BrowserContext.add_cookies: Cookie should have a url or a domain/path pair",
            ),
            (
                [{"name": "sid", "value": "v", "url": "https://example.com", "path": 1}],
                "BrowserContext.add_cookies: cookies[0].path: expected string, got number",
            ),
            (
                [{"name": "sid", "value": "v", "url": "https://example.com", "expires": "bad"}],
                "BrowserContext.add_cookies: cookies[0].expires: expected float, got string",
            ),
            (
                [{"name": "sid", "value": "v", "url": "https://example.com", "expires": True}],
                "BrowserContext.add_cookies: cookies[0].expires: expected float, got boolean",
            ),
            (
                [{"name": "sid", "value": "v", "url": "https://example.com", "httpOnly": "bad"}],
                "BrowserContext.add_cookies: cookies[0].httpOnly: expected boolean, got string",
            ),
            (
                [{"name": "sid", "value": "v", "url": "https://example.com", "secure": "bad"}],
                "BrowserContext.add_cookies: cookies[0].secure: expected boolean, got string",
            ),
            (
                [{"name": "sid", "value": "v", "url": "https://example.com", "sameSite": "Bad"}],
                "BrowserContext.add_cookies: cookies[0].sameSite: expected one of (Strict|Lax|None)",
            ),
            (
                [{"name": "sid", "value": "v", "url": "https://example.com", "sameSite": 1}],
                "BrowserContext.add_cookies: cookies[0].sameSite: expected one of (Strict|Lax|None)",
            ),
        ]
        for value, message in invalid_cases:
            with pytest.raises(Error) as exc_info:
                context.add_cookies(value)
            assert str(exc_info.value).splitlines()[0] == message

        context.add_cookies(
            (
                {
                    "name": "tuple_cookie",
                    "value": "ok",
                    "domain": "example.com",
                    "path": "/",
                    "expires": 2147483647.5,
                    "httpOnly": False,
                    "secure": False,
                    "sameSite": "Lax",
                },
            )
        )
        assert any(cookie["name"] == "tuple_cookie" for cookie in context.cookies("https://example.com"))
    finally:
        context.close()


