def test_context_cookies_filter_urls_and_clear_with_filters(browser, http_server):
    context = browser.new_context()
    context.add_cookies(
        [
            {"name": "sid", "value": "abc", "url": http_server},
            {"name": "theme", "value": "dark", "url": http_server},
            {"name": "remote", "value": "yes", "url": "https://example.com"},
        ]
    )

    local_cookies = context.cookies(http_server)
    assert {cookie["name"] for cookie in local_cookies} == {"sid", "theme"}
    assert {cookie["name"] for cookie in context.cookies(["https://example.com"])} == {"remote"}

    context.clear_cookies(name="sid")
    assert {cookie["name"] for cookie in context.cookies(http_server)} == {"theme"}

    context.clear_cookies(domain=re.compile("example\\.com"))
    assert {cookie["name"] for cookie in context.cookies()} == {"theme"}
    context.close()


def test_context_storage_state_includes_cookies_and_local_storage(browser, http_server, tmp_path: Path):
    context = browser.new_context()
    page = context.new_page()
    page.goto(f"{http_server}/page")
    page.evaluate("localStorage.setItem('token', 'abc')")
    context.add_cookies([{"name": "sid", "value": "123", "url": http_server}])
    path = tmp_path / "state.json"

    state = context.storage_state(path=str(path))

    assert any(cookie["name"] == "sid" and cookie["value"] == "123" for cookie in state["cookies"])
    assert state["origins"] == [
        {
            "origin": http_server,
            "localStorage": [{"name": "token", "value": "abc"}],
        }
    ]
    assert json.loads(path.read_text(encoding="utf-8")) == state
    for value, message in [
        ("bad", "BrowserContext.storage_state: indexed_db: expected boolean, got string"),
        (1, "BrowserContext.storage_state: indexed_db: expected boolean, got number"),
    ]:
        with pytest.raises(Error) as exc_info:
            context.storage_state(indexed_db=value)
        assert str(exc_info.value).splitlines()[0] == message
    context.close()


def test_new_context_applies_storage_state_to_navigated_pages(browser, http_server):
    source = browser.new_context()
    source_page = source.new_page()
    source_page.goto(f"{http_server}/page")
    source_page.evaluate("localStorage.setItem('token', 'abc')")
    source.add_cookies([{"name": "sid", "value": "123", "url": http_server}])
    state = source.storage_state()
    source.close()

    restored = browser.new_context(storage_state=state)
    restored_page = restored.new_page()
    restored_page.goto(f"{http_server}/page")

    assert restored_page.evaluate("localStorage.getItem('token')") == "abc"
    assert "sid=123" in restored_page.evaluate("document.cookie")
    restored.close()


def test_storage_state_payload_validation_matches_playwright(browser, playwright, http_server, tmp_path: Path):
    state_path = tmp_path / "empty-storage-state.json"
    state_path.write_text(json.dumps({"cookies": [], "origins": []}), encoding="utf-8")
    try:
        request_from_bytes = playwright.request.new_context(storage_state=bytes(str(state_path), "utf-8"))
        request_from_bytes.dispose()

        context_from_bytes = browser.new_context(storage_state=bytes(str(state_path), "utf-8"))
        context_from_bytes.close()
    finally:
        state_path.unlink(missing_ok=True)

    for value, message in [
        ([], "expected str, bytes or os.PathLike object, not list"),
        ((), "expected str, bytes or os.PathLike object, not tuple"),
    ]:
        with pytest.raises(TypeError) as exc_info:
            browser.new_context(storage_state=value)
        assert str(exc_info.value).splitlines()[0] == message

    for value in ([], ()):
        request = playwright.request.new_context(storage_state=value)
        request.dispose()

    with pytest.raises(Error) as request_error:
        playwright.request.new_context(storage_state="")
    assert str(request_error.value).splitlines()[0] == (
        "APIRequest.new_context: storage_state: expected object, got string"
    )

    for value, message in [
        (["state.json"], "expected str, bytes or os.PathLike object, not list"),
        (("state.json",), "expected str, bytes or os.PathLike object, not tuple"),
    ]:
        with pytest.raises(TypeError) as exc_info:
            playwright.request.new_context(storage_state=value)
        assert str(exc_info.value).splitlines()[0] == message

    invalid_context_cases = [
        ({"cookies": "bad"}, "Browser.new_context: storageState.cookies: expected array, got string"),
        ({"cookies": [1]}, "Browser.new_context: storageState.cookies[0]: expected object, got number"),
        ({"cookies": [{}]}, "Browser.new_context: storageState.cookies[0].name: expected string, got undefined"),
        ({"origins": "bad"}, "Browser.new_context: storageState.origins: expected array, got string"),
        ({"origins": [1]}, "Browser.new_context: storageState.origins[0]: expected object, got number"),
        ({"origins": [{}]}, "Browser.new_context: storageState.origins[0].origin: expected string, got undefined"),
        (
            {"origins": [{"origin": 1, "localStorage": []}]},
            "Browser.new_context: storageState.origins[0].origin: expected string, got number",
        ),
        (
            {"origins": [{"origin": "https://example.com", "localStorage": "bad"}]},
            "Browser.new_context: storageState.origins[0].localStorage: expected array, got string",
        ),
        (
            {"origins": [{"origin": "https://example.com", "localStorage": [1]}]},
            "Browser.new_context: storageState.origins[0].localStorage[0]: expected object, got number",
        ),
        (
            {"origins": [{"origin": "https://example.com", "localStorage": [{}]}]},
            "Browser.new_context: storageState.origins[0].localStorage[0].name: expected string, got undefined",
        ),
        (
            {"origins": [{"origin": "https://example.com", "localStorage": [{"name": 1, "value": "v"}]}]},
            "Browser.new_context: storageState.origins[0].localStorage[0].name: expected string, got number",
        ),
        (
            {"origins": [{"origin": "https://example.com", "localStorage": [{"name": "n", "value": 1}]}]},
            "Browser.new_context: storageState.origins[0].localStorage[0].value: expected string, got number",
        ),
    ]
    for value, message in invalid_context_cases:
        with pytest.raises(Error) as exc_info:
            browser.new_context(storage_state=value)
        assert str(exc_info.value).splitlines()[0] == message

    with pytest.raises(Error) as page_error:
        browser.new_page(storage_state={"cookies": [1]})
    assert str(page_error.value).splitlines()[0] == (
        "Browser.new_page: storageState.cookies[0]: expected object, got number"
    )

    context = browser.new_context()
    try:
        invalid_set_cases = [
            ({"cookies": "bad"}, "BrowserContext.set_storage_state: storageState.cookies: expected array, got string"),
            (
                {"origins": [{"origin": "https://example.com", "localStorage": [{"name": "n", "value": 1}]}]},
                "BrowserContext.set_storage_state: storageState.origins[0].localStorage[0].value: expected string, got number",
            ),
        ]
        for value, message in invalid_set_cases:
            with pytest.raises(Error) as exc_info:
                context.set_storage_state(value)
            assert str(exc_info.value).splitlines()[0] == message
    finally:
        context.close()

    origin_state_path = tmp_path / "origin-storage-state.json"
    origin_state_path.write_text(
        json.dumps(
            {
                "cookies": [],
                "origins": [
                    {
                        "origin": http_server,
                        "localStorage": [{"name": "token", "value": "from-file"}],
                    }
                ],
            }
        ),
        encoding="utf-8",
    )
    loaded_context = browser.new_context()
    try:
        loaded_context.set_storage_state(str(origin_state_path))
        loaded_page = loaded_context.new_page()
        loaded_page.goto(f"{http_server}/page")
        assert loaded_page.evaluate("localStorage.getItem('token')") == "from-file"
    finally:
        loaded_context.close()

    noop_cases = [
        bytes(str(origin_state_path), "utf-8"),
        [],
        (),
        ["state.json"],
        None,
    ]
    for value in noop_cases:
        noop_context = browser.new_context()
        try:
            noop_context.set_storage_state(value)
            noop_page = noop_context.new_page()
            noop_page.goto(f"{http_server}/page")
            assert noop_page.evaluate("localStorage.getItem('token')") is None
        finally:
            noop_context.close()

    for value, message in [
        (123, "BrowserContext.set_storage_state: storage_state: expected object, got number"),
        (True, "BrowserContext.set_storage_state: storage_state: expected object, got boolean"),
    ]:
        invalid_context = browser.new_context()
        try:
            with pytest.raises(Error) as exc_info:
                invalid_context.set_storage_state(value)
            assert str(exc_info.value).splitlines()[0] == message
        finally:
            invalid_context.close()

    invalid_request_cases = [
        ({"cookies": "bad"}, "APIRequest.new_context: storageState.cookies: expected array, got string"),
        ({"origins": [1]}, "APIRequest.new_context: storageState.origins[0]: expected object, got number"),
    ]
    for value, message in invalid_request_cases:
        with pytest.raises(Error) as exc_info:
            playwright.request.new_context(storage_state=value)
        assert str(exc_info.value).splitlines()[0] == message


def test_context_storage_state_includes_and_replays_indexed_db(browser, http_server):
    create_indexed_db = """async () => {
    const request = indexedDB.open('auth-db', 1);
    request.onupgradeneeded = () => {
      request.result.createObjectStore('tokens', { keyPath: 'id' });
    };
    const db = await new Promise((resolve, reject) => {
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
    const tx = db.transaction('tokens', 'readwrite');
    tx.objectStore('tokens').put({ id: 'primary', token: 'secret', nested: { ok: true } });
    await new Promise((resolve, reject) => {
      tx.oncomplete = resolve;
      tx.onerror = () => reject(tx.error);
    });
    db.close();
    }"""
    read_indexed_db = """async () => {
    const request = indexedDB.open('auth-db');
    const db = await new Promise((resolve, reject) => {
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
    const tx = db.transaction('tokens', 'readonly');
    const value = await new Promise((resolve, reject) => {
      const get = tx.objectStore('tokens').get('primary');
      get.onsuccess = () => resolve(get.result);
      get.onerror = () => reject(get.error);
    });
    db.close();
    return value;
    }"""

    source = browser.new_context()
    source_page = source.new_page()
    source_page.goto(f"{http_server}/page")
    source_page.evaluate(create_indexed_db)
    state = source.storage_state(indexed_db=True)
    source.close()

    origin_state = next(item for item in state["origins"] if item["origin"] == http_server)
    assert origin_state["indexedDB"][0]["name"] == "auth-db"
    assert origin_state["indexedDB"][0]["stores"][0]["records"] == [
        {"value": {"id": "primary", "nested": {"ok": True}, "token": "secret"}}
    ]

    restored = browser.new_context(storage_state=state)
    restored_page = restored.new_page()
    restored_page.goto(f"{http_server}/page")

    assert restored_page.evaluate(read_indexed_db) == {"id": "primary", "nested": {"ok": True}, "token": "secret"}
    restored.close()


