def test_persistent_context_supports_basic_http_proxy(playwright, http_proxy_server, tmp_path: Path):
    proxy_url, seen = http_proxy_server
    target_url = "http://persistent-proxy.invalid/proxied"

    context = playwright.chromium.launch_persistent_context(
        str(tmp_path / "profile"),
        headless=True,
        proxy={"server": proxy_url},
    )
    try:
        page = context.new_page()
        response = page.goto(target_url)

        assert response is not None
        assert response.ok
        assert page.title() == "Proxied"
        assert wait_until(lambda: [item for item in seen if item[0] == target_url])
    finally:
        context.close()


def test_persistent_context_supports_http_proxy_credentials(
    playwright,
    authenticated_http_proxy_server,
    tmp_path: Path,
):
    proxy_url, seen, expected = authenticated_http_proxy_server
    target_url = "http://persistent-proxy-auth.invalid/proxied"

    context = playwright.chromium.launch_persistent_context(
        str(tmp_path / "profile"),
        headless=True,
        proxy={"server": proxy_url, "username": "user", "password": "pass"},
    )
    try:
        page = context.new_page()
        response = page.goto(target_url)

        assert response is not None
        assert response.ok
        assert page.title() == "Auth Proxied"
        assert wait_until(lambda: [item for item in seen if item == (target_url, expected)])
    finally:
        context.close()


def test_wait_for_selector(page):
    page.set_content(
        """
        <div id='root'>
          <div id='hidden' style='display:none'>Hidden</div>
          <div id='gone'>Gone</div>
          <iframe srcdoc='<span id="frame-hidden" style="display:none">Hidden</span>'></iframe>
        </div>
        """
    )
    page.evaluate(
        """() => {
        setTimeout(() => {
          const child = document.createElement('span');
          child.id = 'late';
          child.textContent = 'Loaded';
          document.querySelector('#root').appendChild(child);
          document.querySelector('#gone').remove();
        }, 100);
        }"""
    )

    handle = page.wait_for_selector("#late", timeout=3_000)

    assert handle is not None
    assert handle.text_content() == "Loaded"
    assert page.wait_for_selector("#hidden", state="hidden", timeout=500) is None
    assert page.wait_for_selector("#missing", state="hidden", timeout=500) is None
    assert page.wait_for_selector("#missing", state="detached", timeout=500) is None
    assert page.locator("#hidden").wait_for(state="hidden", timeout=500) is None
    assert page.locator("#missing").wait_for(state="detached", timeout=500) is None
    root = page.query_selector("#root")
    assert root.wait_for_selector("#hidden", state="hidden", timeout=500) is None
    assert root.wait_for_selector("#gone", state="detached", timeout=500) is None
    assert root.wait_for_selector("#missing", state="hidden", timeout=500) is None
    frame = page.frames[1]
    assert frame.wait_for_selector("#frame-hidden", state="hidden", timeout=500) is None
    with pytest.raises(Error, match="Page\\.wait_for_selector: state: expected one of"):
        page.wait_for_selector("#late", state="enabled", timeout=500)
    with pytest.raises(Error, match="Locator\\.wait_for: state: expected one of"):
        page.locator("#late").wait_for(state="enabled", timeout=500)
    with pytest.raises(Error, match="ElementHandle\\.wait_for_selector: state: expected one of"):
        root.wait_for_selector("#hidden", state="enabled", timeout=500)
    with pytest.raises(Error, match="Frame\\.wait_for_selector: state: expected one of"):
        frame.wait_for_selector("#frame-hidden", state="enabled", timeout=500)


