def test_async_locator_wait_for_survives_navigation_mid_wait(http_server):
    async def run() -> None:
        from rustwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.goto(f"{http_server}/wait-for-navigation-visible-a")
            target = page.locator("#target")

            assert await target.wait_for(state="visible", timeout=10_000) is None
            assert await target.inner_text() == "hello"
            assert page.url == f"{http_server}/wait-for-navigation-visible-b"
            await browser.close()

    asyncio.run(run())


def test_locator_wait_for_navigation_preserves_timeout_budget(page, http_server):
    page.goto(f"{http_server}/wait-for-navigation-timeout-a")
    started = time.monotonic()

    with pytest.raises(TimeoutError, match=r"Locator\.wait_for: Timeout 2000ms exceeded\."):
        page.locator("#target").wait_for(state="visible", timeout=2_000)

    assert time.monotonic() - started < 4.5


def test_locator_wait_for_fails_fast_when_page_closes(http_server):
    # The sync API serializes commands on the calling thread, so a concurrent
    # close must come from the async API to reach the browser mid-wait.
    async def run() -> None:
        from rustwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content("<main>Waiting for target</main>")
            waiter = asyncio.create_task(
                page.locator("#target").wait_for(state="visible", timeout=10_000)
            )
            await asyncio.sleep(0.2)
            started = time.monotonic()
            await page.close()
            with pytest.raises(Exception, match=r"(?i)closed"):
                await waiter
            assert time.monotonic() - started < 5
            await browser.close()

    asyncio.run(run())


def test_wait_for_selector_timeout_messages_match_playwright(page):
    page.set_content("<main id='root'><div>Ready</div></main>")
    root = page.query_selector("#root")
    assert root is not None

    checks = [
        (lambda: page.wait_for_selector("#missing", timeout=120), "Page.wait_for_selector: Timeout 120ms exceeded."),
        (lambda: page.main_frame.wait_for_selector("#missing", timeout=120), "Frame.wait_for_selector: Timeout 120ms exceeded."),
        (lambda: page.locator("#missing").wait_for(timeout=120), "Locator.wait_for: Timeout 120ms exceeded."),
        (lambda: root.wait_for_selector("#missing", timeout=120), "ElementHandle.wait_for_selector: Timeout 120ms exceeded."),
    ]
    for operation, expected in checks:
        with pytest.raises(TimeoutError) as exc_info:
            operation()
        assert str(exc_info.value).splitlines()[0] == expected


def test_wait_for_selector_strict_violations_for_all_states(page):
    page.set_content(
        """
        <main id='root'>
          <button style='display:none'>A</button>
          <button style='display:none'>B</button>
          <iframe srcdoc='<span style="display:none">One</span><span style="display:none">Two</span>'></iframe>
        </main>
        """
    )
    root = page.query_selector("#root")
    assert root is not None
    frame = page.frames[1]

    for state in ("attached", "visible", "hidden", "detached"):
        with pytest.raises(Error, match="strict mode violation"):
            page.wait_for_selector("button", state=state, strict=True, timeout=500)
        with pytest.raises(Error, match="strict mode violation"):
            frame.wait_for_selector("span", state=state, strict=True, timeout=500)
        with pytest.raises(Error, match="strict mode violation"):
            page.locator("button").wait_for(state=state, timeout=500)
        with pytest.raises(Error, match="strict mode violation"):
            root.wait_for_selector("button", state=state, strict=True, timeout=500)

    assert root.wait_for_selector("button", state="attached", timeout=500).text_content() == "A"
    assert page.locator("button").first.wait_for(state="attached", timeout=500) is None


