def test_xpath_selectors_work_for_core_queries_and_actions(page):
    page.set_content(
        """
        <section id="outer">
          <button id="outside">Outside</button>
          <div id="root">
            <button data-action="save" onclick="document.body.dataset.saved='yes'">Save</button>
            <input name="email">
            <ul><li>One</li><li>Two</li></ul>
          </div>
        </section>
        """
    )

    assert page.locator("xpath=//button[@data-action='save']").inner_text() == "Save"
    assert page.query_selector("//input[@name='email']") is not None
    assert [item.inner_text() for item in page.query_selector_all("xpath=//li")] == ["One", "Two"]

    page.fill("xpath=//input[@name='email']", "ada@example.test")
    assert page.input_value("//input[@name='email']") == "ada@example.test"

    page.locator("#root").locator("xpath=.//button").click()
    assert page.evaluate("document.body.dataset.saved") == "yes"


def test_css_visible_pseudo_selector_matches_visible_elements(page):
    page.set_content(
        """
        <section id="root">
          <button id="shown">Shown</button>
          <button id="hidden" style="display:none">Hidden</button>
          <button id="transparent" style="visibility:hidden">Transparent</button>
          <article id="alpha"><h2>Alpha</h2><span style="display:none">Secret Token</span><p>Quarterly Revenue</p></article>
          <article id="beta"><h2>Beta</h2><p>Costs</p></article>
          <article id="mixed"><h2>Mixed</h2><p>revenue and costs</p></article>
        </section>
        """
    )

    assert page.locator("button:visible").evaluate_all("(els) => els.map(el => el.id)") == ["shown"]
    assert page.locator("css=button:visible").count() == 1
    assert page.locator("#root").locator("button:visible").get_attribute("id") == "shown"
    assert page.query_selector("button:visible").get_attribute("id") == "shown"
    assert page.locator('article:has-text("Revenue")').evaluate_all("(els) => els.map(el => el.id)") == [
        "alpha",
        "mixed",
    ]
    assert page.locator('css=article:has-text("quarterly revenue")').get_attribute("id") == "alpha"
    assert page.locator("#root").locator('article:has-text("costs")').evaluate_all("(els) => els.map(el => el.id)") == [
        "beta",
        "mixed",
    ]
    assert page.locator('article:has-text("Secret Token")').get_attribute("id") == "alpha"
    assert page.query_selector('#root:has-text("Costs")').get_attribute("id") == "root"


