def test_page_screencast_streams_frames_and_writes_latest_frame(page, tmp_path: Path):
    page.set_content("<body><h1>Frame one</h1></body>")
    output = tmp_path / "latest.jpg"
    frames = []

    page.screencast.start(on_frame=lambda frame: frames.append(frame), path=output, quality=50)
    try:
        page.evaluate("() => { document.body.dataset.changed = 'yes'; document.body.append(' updated'); }")
        wait_until(lambda: len(frames) > 0)
    finally:
        page.screencast.stop()

    assert frames[0].data.startswith(b"\xff\xd8")
    assert frames[0].width > 0
    assert frames[0].height > 0
    assert frames[0].timestamp is not None
    assert output.read_bytes().startswith(b"\xff\xd8")
    assert page.evaluate("() => document.body.dataset.changed") == "yes"


