def test_context_record_video_dir_exposes_basic_video_artifact(browser, tmp_path: Path):
    context = browser.new_context(record_video_dir=str(tmp_path / "videos"))
    page = context.new_page()
    video = page.video

    assert video is not None
    page.set_content("<main style='width:120px;height:80px;background:red'>Video</main>")
    for index in range(3):
        page.evaluate(
            "index => { document.querySelector('main').textContent = `Video ${index}`; document.body.dataset.frame = String(index); }",
            index,
        )
        page.wait_for_timeout(120)
    page.close()

    video_path = Path(video.path())
    assert video_path.is_file()
    if shutil.which("ffmpeg"):
        assert video_path.suffix == ".webm"
        assert video_path.read_bytes().startswith(b"\x1a\x45\xdf\xa3")
        assert webm_frame_count(video_path) >= 2
    else:
        assert video_path.read_bytes().startswith((b"\xff\xd8", b"\x89PNG"))

    copy_path = tmp_path / f"copy{video_path.suffix}"
    video.save_as(copy_path)
    assert copy_path.read_bytes() == video_path.read_bytes()

    video.delete()
    assert not video_path.exists()
    context.close()


