def test_record_video_size_option_validation_matches_playwright(browser, tmp_path: Path):
    video_dir = str(tmp_path / "videos")
    invalid_context_cases = [
        ("bad", "Browser.new_context: recordVideo.size: expected object, got string"),
        ({"height": 100}, "Browser.new_context: recordVideo.size.width: expected integer, got undefined"),
        ({"width": 100}, "Browser.new_context: recordVideo.size.height: expected integer, got undefined"),
        ({"width": True, "height": 100}, "Browser.new_context: recordVideo.size.width: expected integer, got boolean"),
        ({"width": "100", "height": 100}, "Browser.new_context: recordVideo.size.width: expected integer, got string"),
        ({"width": 100.5, "height": 100}, "Browser.new_context: recordVideo.size.width: expected integer, got float 100.5"),
    ]
    for value, message in invalid_context_cases:
        with pytest.raises(Error) as exc_info:
            browser.new_context(record_video_dir=video_dir, record_video_size=value)
        assert str(exc_info.value).splitlines()[0] == message

    with pytest.raises(Error) as page_error:
        browser.new_page(record_video_dir=video_dir, record_video_size={"width": "100", "height": 100})
    assert (
        str(page_error.value).splitlines()[0]
        == "Browser.new_page: recordVideo.size.width: expected integer, got string"
    )

    for value in (
        {"width": 100.0, "height": 100},
        {"width": 0, "height": 100},
        {"width": 100, "height": -1},
    ):
        context = browser.new_context(record_video_dir=video_dir, record_video_size=value)
        context.close()


