def test_common_automation_signals_are_suppressed(page):
    page.set_content("<main>Signals</main>")

    assert page.evaluate("navigator.webdriver") is None
    assert not page.evaluate("() => 'webdriver' in navigator")
    assert "HeadlessChrome" not in page.evaluate("navigator.userAgent")
    assert page.evaluate("() => !!window.chrome")
    page.set_content("<iframe srcdoc='<main>child</main>'></iframe>")
    assert page.evaluate("() => !!document.querySelector('iframe').contentWindow.chrome")
    worker_signals = page.evaluate(
        """() => new Promise(resolve => {
            const source = `postMessage({
                userAgent: navigator.userAgent,
                webdriverType: typeof navigator.webdriver,
                webdriverInNavigator: 'webdriver' in navigator,
                language: navigator.language,
                languages: Array.from(navigator.languages || []),
                brands: navigator.userAgentData
                    ? Array.from(navigator.userAgentData.brands || []).map(brand => brand.brand).join(' ')
                    : ''
            })`;
            const url = URL.createObjectURL(new Blob([source], { type: 'text/javascript' }));
            const worker = new Worker(url);
            worker.onmessage = event => {
                worker.terminate();
                URL.revokeObjectURL(url);
                resolve(event.data);
            };
        })"""
    )
    assert "HeadlessChrome" not in worker_signals["userAgent"]
    assert "HeadlessChrome" not in worker_signals["brands"]
    assert worker_signals["webdriverType"] == "undefined"
    assert not worker_signals["webdriverInNavigator"]
    assert worker_signals["language"] == "en-US"
    assert worker_signals["languages"] == ["en-US", "en"]


def test_service_worker_automation_signals_are_suppressed(browser, http_server):
    context = browser.new_context()
    try:
        page = context.new_page()
        with context.expect_event("serviceworker") as worker_info:
            page.goto(f"{http_server}/service-worker-page")
        worker = worker_info.value
        signals = wait_until(
            lambda: worker.evaluate(
                """() => self.__rustwrightServiceWorkerValue === 73 ? {
                initialUserAgent: self.__rustwrightInitialServiceWorkerUserAgent,
                initialBrands: self.__rustwrightInitialServiceWorkerBrands,
                userAgent: navigator.userAgent,
                appVersion: navigator.appVersion,
                webdriverType: typeof navigator.webdriver,
                webdriverInNavigator: 'webdriver' in navigator,
                brands: navigator.userAgentData
                    ? Array.from(navigator.userAgentData.brands || []).map(brand => brand.brand).join(' ')
                    : '',
                fullVersionBrands: navigator.userAgentData
                    ? navigator.userAgentData.getHighEntropyValues(['fullVersionList'])
                        .then(values => Array.from(values.fullVersionList || []).map(brand => brand.brand).join(' '))
                    : Promise.resolve('')
                } : null"""
            )
        )

        assert "HeadlessChrome" not in signals["initialUserAgent"]
        assert "HeadlessChrome" not in signals["initialBrands"]
        assert "HeadlessChrome" not in signals["userAgent"]
        assert "HeadlessChrome" not in signals["appVersion"]
        assert "HeadlessChrome" not in signals["brands"]
        assert "HeadlessChrome" not in signals["fullVersionBrands"]
        assert signals["webdriverType"] == "undefined"
        assert not signals["webdriverInNavigator"]
    finally:
        context.close()


def test_internal_shims_do_not_expose_rustwright_named_window_globals(page):
    page.set_content("<main>Signals</main>")
    page.clock.install()
    page.expose_function("addValues", lambda left, right: left + right)
    page.expose_binding("handleTag", lambda source, handle: handle.evaluate("node => node.tagName"), handle=True)
    page.route_web_socket("**/mock-socket", lambda route: route.send("ready"))

    assert page.evaluate("async () => await addValues(2, 3)") == 5
    assert page.evaluate("async () => await handleTag(document.body)") == "BODY"
    assert (
        page.evaluate(
            """() => new Promise(resolve => {
            const socket = new WebSocket('ws://example.test/mock-socket');
            socket.onmessage = event => resolve(event.data);
            })"""
        )
        == "ready"
    )
    assert (
        page.evaluate(
            "() => Object.getOwnPropertyNames(window).filter(name => name.toLowerCase().includes('rustwright')).sort()"
        )
        == []
    )
    assert page.evaluate("() => !addValues.toString().toLowerCase().includes('rustwright')")
    assert page.evaluate("() => !handleTag.toString().toLowerCase().includes('rustwright')")


def test_default_request_headers_do_not_expose_headless_chrome(page, http_server):
    response = page.goto(f"{http_server}/request-headers")
    headers = response.json()
    combined_headers = json.dumps(headers)

    assert "HeadlessChrome" not in headers.get("user-agent", "")
    assert "HeadlessChrome" not in headers.get("sec-ch-ua", "")
    assert "HeadlessChrome" not in combined_headers
    assert headers.get("accept-language") == "en-US,en;q=0.9"
    assert page.evaluate("navigator.languages") == ["en-US", "en"]
    brands = page.evaluate(
        "() => navigator.userAgentData ? navigator.userAgentData.brands.map(brand => brand.brand).join(' ') : ''"
    )
    assert "HeadlessChrome" not in brands


