def test_context_base_url_resolves_relative_page_goto(browser, http_server):
    context = browser.new_context(base_url=f"{http_server}/root/")
    page = context.new_page()

    response = page.goto("/page")

    assert response is not None
    assert response.url == f"{http_server}/page"
    assert page.url == f"{http_server}/page"
    page.wait_for_url("/page")
    page.wait_for_url("**/page")
    expect(page).to_have_url("/page")
    with pytest.raises(AssertionError) as glob_assertion:
        expect(page).to_have_url("**/page", timeout=100)
    assert f"{http_server}/root/**/page" in str(glob_assertion.value)
    with page.expect_request("/json") as request_info:
        with page.expect_response("/json") as response_info:
            page.locator("#fetch").click()
    assert request_info.value.url == f"{http_server}/json"
    assert response_info.value.url == f"{http_server}/json"
    page.route("/headers", lambda route: route.fulfill(status=203, body="routed"))
    routed_response = page.goto("/headers")
    assert routed_response is not None
    assert routed_response.status == 203
    assert routed_response.text() == "routed"
    relative_response = page.goto("page")
    assert relative_response is not None
    assert relative_response.status == 404
    assert relative_response.url == f"{http_server}/root/page"
    context.close()


