def test_cli_screenshot_and_pdf_use_headless_cdp_capture(monkeypatch, tmp_path: Path, capsys):
    from rustwright import cli

    class FakePage:
        def __init__(self):
            self.waited_selector = None
            self.waited_timeout = None
            self.screenshot_options = None
            self.pdf_options = None
            self.closed = False

        def wait_for_selector(self, selector: str):
            self.waited_selector = selector

        def wait_for_timeout(self, timeout: float):
            self.waited_timeout = timeout

        def screenshot(self, **options):
            self.screenshot_options = options

        def pdf(self, **options):
            self.pdf_options = options

        def close(self):
            self.closed = True

    class FakeContext:
        def __init__(self):
            self.storage_state_path = None
            self.closed = False

        def storage_state(self, *, path: str):
            self.storage_state_path = path

        def close(self):
            self.closed = True

    class FakeBrowser:
        def __init__(self):
            self.closed = False

        def close(self):
            self.closed = True

    class FakeSyncPlaywright:
        def __enter__(self):
            return object()

        def __exit__(self, exc_type, exc, tb):
            return None

    browser = FakeBrowser()
    context = FakeContext()
    screenshot_page = FakePage()
    pdf_page = FakePage()
    opened_urls = []
    launch_headless_values = []
    pages = [screenshot_page, pdf_page]

    def fake_launch_context(args, playwright, *, headless):
        launch_headless_values.append(headless)
        return browser, context

    def fake_open_page(context_arg, url):
        opened_urls.append(url)
        return pages.pop(0)

    monkeypatch.setattr(cli, "sync_playwright", lambda: FakeSyncPlaywright())
    monkeypatch.setattr(cli, "_launch_cli_context", fake_launch_context)
    monkeypatch.setattr(cli, "_open_page", fake_open_page)

    screenshot_path = tmp_path / "capture.png"
    storage_path = tmp_path / "state.json"
    har_path = tmp_path / "capture.har"
    assert (
        cli.screenshot(
            [
                "example.test",
                str(screenshot_path),
                "--wait-for-selector",
                "main",
                "--wait-for-timeout",
                "25",
                "--full-page",
                "--save-storage",
                str(storage_path),
                "--save-har",
                str(har_path),
            ]
        )
        == 0
    )
    assert screenshot_page.waited_selector == "main"
    assert screenshot_page.waited_timeout == 25
    assert screenshot_page.screenshot_options == {"path": str(screenshot_path), "full_page": True}
    assert screenshot_page.closed is True
    assert context.storage_state_path == str(storage_path)
    assert context.closed is True
    assert browser.closed is True

    pdf_path = tmp_path / "capture.pdf"
    assert cli.pdf(["https://example.test", str(pdf_path), "--paper-format", "A4"]) == 0
    assert pdf_page.pdf_options == {"path": str(pdf_path), "format": "A4"}
    assert pdf_page.closed is True
    assert opened_urls == ["example.test", "https://example.test"]
    assert launch_headless_values == [True, True]
    output = capsys.readouterr().out
    assert "Capturing screenshot into" in output
    assert "Saving as pdf into" in output


