def test_cli_install_deps_dry_run_prints_linux_apt_commands(monkeypatch, capsys):
    from rustwright import cli

    monkeypatch.setattr(cli.sys, "platform", "linux")
    monkeypatch.setattr(cli, "_read_linux_os_release", lambda: {"ID": "ubuntu", "VERSION_ID": "24.04"})
    monkeypatch.setattr(cli.os, "geteuid", lambda: 1000, raising=False)

    result = cli.install_deps(["chromium", "--dry-run"])

    output = capsys.readouterr().out
    assert result == 0
    assert "sudo apt-get update" in output
    assert "sudo apt-get install -y --no-install-recommends" in output
    assert "libnss3" in output
    assert "libasound2t64" in output


