def test_chromium_executable_path_uses_rustwright_browser_cache(monkeypatch, tmp_path: Path):
    if sys.platform == "darwin":
        relative = Path(
            "chromium-123/chrome-mac-arm64/Google Chrome for Testing.app/Contents/MacOS/Google Chrome for Testing"
        )
    elif sys.platform == "win32":
        relative = Path("chromium-123/chrome-win64/chrome.exe")
    else:
        relative = Path("chromium-123/chrome-linux64/chrome")
    executable = tmp_path / "browsers" / relative
    executable.parent.mkdir(parents=True)
    executable.write_text("chrome", encoding="utf-8")
    if os.name != "nt":
        executable.chmod(0o755)

    monkeypatch.setenv("RUSTWRIGHT_BROWSERS_PATH", str(tmp_path / "browsers"))
    monkeypatch.delenv("RUSTWRIGHT_CHROMIUM", raising=False)
    monkeypatch.delenv("CHROME", raising=False)
    monkeypatch.delenv("CHROMIUM", raising=False)

    with sync_playwright() as playwright:
        assert playwright.chromium.executable_path == str(executable)


