def test_api_surface_audit_reports_missing_and_classified_members(tmp_path: Path):
    reference_module = tmp_path / "reference_api.py"
    candidate_module = tmp_path / "candidate_api.py"
    classifications = tmp_path / "classifications.json"
    report_path = tmp_path / "surface.json"
    reference_module.write_text(
        """
class Page:
    @property
    def url(self):
        return ""

    def goto(self):
        pass

    def pause(self):
        pass

    def screenshot(self):
        pass

class Browser:
    def close(self):
        pass

def sync_playwright():
    pass
""",
        encoding="utf-8",
    )
    candidate_module.write_text(
        """
class Page:
    @property
    def url(self):
        return ""

    def goto(self):
        pass

class Browser:
    def close(self):
        pass

    def new_page(self):
        pass
""",
        encoding="utf-8",
    )
    classifications.write_text(
        json.dumps(
            {
                "Page.pause": {"status": "pending", "reason": "debug API not implemented"},
                "Page.screenshot": {"status": "implemented", "reason": "implemented as an instance attribute"},
            }
        ),
        encoding="utf-8",
    )

    tool = Path(__file__).resolve().parents[1] / "tools" / "api_surface_audit.py"
    result = subprocess.run(
        [
            sys.executable,
            str(tool),
            "--reference-module",
            "reference_api",
            "--candidate-module",
            "candidate_api",
            "--pythonpath",
            str(tmp_path),
            "--classes",
            "Page,Browser",
            "--module-members",
            "sync_playwright",
            "--classifications",
            str(classifications),
            "--format",
            "json",
            "--output",
            str(report_path),
            "--fail-on-missing",
        ],
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
    )

    assert result.returncode == 1
    report = json.loads(report_path.read_text(encoding="utf-8"))
    assert report["summary"]["missing_members"] == 2
    assert report["summary"]["extra_members"] == 1
    assert report["summary"]["unclassified_missing_members"] == 1
    assert report["classes"]["Page"]["missing"]["Page.pause"]["status"] == "pending"
    assert report["classes"]["Page"]["missing"]["Page.screenshot"]["status"] == "implemented"
    assert report["module"]["missing"]["module.sync_playwright"]["status"] == "unclassified"
    assert report["classes"]["Browser"]["extra"] == ["new_page"]


