def test_jshandle_and_assertion_methods_reject_unknown_keywords():
    from playwright.sync_api import APIResponse, JSHandle, Locator, Page, expect

    js_handle = object.__new__(JSHandle)
    locator = object.__new__(Locator)
    page = object.__new__(Page)
    response = object.__new__(APIResponse)

    with pytest.raises(ValueError, match="Unsupported type"):
        expect(object())

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        js_handle.evaluate("value => value", unknown_option=True)

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        js_handle.evaluate_handle("value => value", unknown_option=True)

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        expect(locator).to_have_text("value", unknown_option=True)

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        expect(locator).to_be_visible(unknown_option=True)

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        expect(page).to_have_url("about:blank", unknown_option=True)

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        expect(response).to_be_ok(unknown_option=True)

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        expect(response).to_be_ok(timeout=1)

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        expect(locator).not_to_be_checked(checked=False)

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        expect(locator).not_to_be_checked(indeterminate=True)

    for method_name in [
        "to_have_accessible_description",
        "to_have_attribute",
        "to_have_count",
        "to_have_id",
        "to_have_role",
        "to_have_value",
        "to_have_values",
        "to_have_title",
        "to_have_url",
    ]:
        with pytest.raises(TypeError, match="missing .*required positional argument"):
            target = page if method_name in {"to_have_title", "to_have_url"} else locator
            getattr(expect(target), method_name)()


