    with pytest.raises(TypeError, match="unexpected keyword argument"):
        browser.new_page(noDefaultViewport=True)

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        browser.start_tracing(unknown_option=True)

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        browser.stop_tracing(unknown_option=True)

    with pytest.raises(TypeError, match="unexpected keyword argument"):
        browser.close(unknown_option=True)

    context = browser.new_context()
    try:
        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.close(unknown_option=True)

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.expose_binding("probe", lambda: None, unknown_option=True)

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.grant_permissions(["geolocation"], unknown_option=True)

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.route("**/*", lambda route: route.continue_(), unknown_option=True)

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.route_from_har("missing.har", unknown_option=True)

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.route_web_socket("**/*", lambda route: None, unknown_option=True)

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.storage_state(unknown_option=True)

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.set_storage_state({}, unknown_option=True)

        with pytest.raises(TypeError, match="missing .*required positional argument"):
            context.set_storage_state()

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.set_storage_state(path="state.json")

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.clear_cookies(unknown_option=True)

        with pytest.raises(TypeError, match="missing .*required positional argument"):
            context.new_cdp_session()

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.expect_page(unknown_option=True)

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.expect_console_message(unknown_option=True)

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.expect_event("page", unknown_option=True)

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.wait_for_event("close", unknown_option=True)

        with pytest.raises(TypeError, match="unexpected keyword argument"):
            context.unroute_all(unknown_option=True)
    finally:
        context.close()


