def test_launch_persistent_context_client_certificate_validation_matches_playwright(playwright, tmp_path: Path):
    with pytest.raises(Error) as exc_info:
        playwright.chromium.launch_persistent_context(
            str(tmp_path / "profile"),
            headless=True,
            client_certificates=[{"origin": "https://example.com"}],
        )
    assert str(exc_info.value).splitlines()[0] == (
        "BrowserType.launch_persistent_context: None of cert, key, passphrase or pfx is specified"
    )


def test_launch_persistent_context_request_client_certificates_authenticate(playwright, tmp_path: Path, mtls_server):
    context = playwright.chromium.launch_persistent_context(
        str(tmp_path / "profile"),
        headless=True,
        ignore_https_errors=True,
        client_certificates=[
            {
                "origin": mtls_server["origin"],
                "certPath": mtls_server["client_cert"],
                "keyPath": mtls_server["client_key"],
            }
        ],
    )
    try:
        response = context.request.get(mtls_server["url"])
        assert response.ok
        assert "commonName=Rustwright Client" in response.json()["client_subject"]
    finally:
        context.close()


