def test_async_skyvern_lifecycle_tooling_helpers_yield_event_loop():
    class SlowMethods:
        def __init__(self, prefix, calls, results=None):
            self.prefix = prefix
            self.calls = calls
            self.results = results or {}

        def _record(self, call_name, *args, **kwargs):
            time.sleep(0.08)
            self.calls.append((f"{self.prefix}.{call_name}", args, kwargs, threading.current_thread().ident))
            return self.results.get(call_name)

        def __getattr__(self, name):
            return lambda *args, **kwargs: self._record(name, *args, **kwargs)

