def test_async_launch_persistent_context_adopts_initial_page(tmp_path: Path):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            context = await p.chromium.launch_persistent_context(str(tmp_path / "profile"), headless=True)
            persistent_browser = context.browser
            closed = False
            try:
                assert persistent_browser is not None
                assert context in persistent_browser.contexts
                assert len(context.pages) == 1
                page = context.pages[0]
                assert page.url == "about:blank"
                await page.set_content("<title>Async Persistent</title>")
                assert await page.title() == "Async Persistent"
                await context.close()
                closed = True
                assert not persistent_browser.is_connected()
                assert persistent_browser.contexts == []
            finally:
                if not closed:
                    await context.close()

    asyncio.run(run())


def test_async_launch_user_remote_debugging_port():
    async def run() -> None:
        from benchmarks.automation_cases import unused_tcp_port
        from playwright.async_api import async_playwright

        port = unused_tcp_port()

        async with async_playwright() as p:
            browser = await p.chromium.launch(
                headless=True,
                args=[f"--remote-debugging-port={port}"],
                timeout=10_000,
            )
            try:
                page = await browser.new_page()
                await page.set_content("<title>Async Launch User CDP Port</title>")
                assert await page.title() == "Async Launch User CDP Port"

                def read_version() -> dict[str, Any]:
                    with urlopen(f"http://127.0.0.1:{port}/json/version", timeout=2) as response:
                        return json.loads(response.read().decode("utf-8"))

                payload = await asyncio.to_thread(read_version)
                assert payload["webSocketDebuggerUrl"].startswith(f"ws://127.0.0.1:{port}/")
            finally:
                await browser.close()

    asyncio.run(run())


