def test_async_launch_persistent_context_dynamic_remote_debugging_port(tmp_path: Path):
    async def run() -> None:
        from playwright.async_api import async_playwright

        profile = tmp_path / "profile-dynamic-cdp-port"

        async with async_playwright() as p:
            context = await p.chromium.launch_persistent_context(
                str(profile),
                headless=True,
                args=["--remote-debugging-port=0"],
                timeout=10_000,
            )
            try:
                page = context.pages[0] if context.pages else await context.new_page()
                await page.set_content("<title>Async Dynamic CDP Port</title>")
                assert await page.title() == "Async Dynamic CDP Port"

                lines = (profile / "DevToolsActivePort").read_text(encoding="utf-8").splitlines()
                port = int(lines[0])
                browser_path = lines[1]

                def read_version() -> dict[str, Any]:
                    with urlopen(f"http://127.0.0.1:{port}/json/version", timeout=2) as response:
                        return json.loads(response.read().decode("utf-8"))

                payload = await asyncio.to_thread(read_version)
                assert payload["webSocketDebuggerUrl"] == f"ws://127.0.0.1:{port}{browser_path}"
            finally:
                await context.close()

    asyncio.run(run())


def test_async_connect_over_cdp_adopts_default_context_pages_and_disconnects_only():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            launched = await p.chromium.launch(headless=True)
            connected = None
            try:
                launched_page = await launched.new_page()
                await launched_page.goto(data_url("<title>Async Origin CDP Page</title><h1>origin</h1>"))

                connected = await p.chromium.connect_over_cdp(launched._ws_endpoint)
                assert len(connected.contexts) == 1
                context = connected.contexts[0]
                urls = [page.url for page in context.pages]
                assert "about:blank" in urls
                assert launched_page.url in urls

                adopted = next(page for page in context.pages if page.url == launched_page.url)
                assert await adopted.title() == "Async Origin CDP Page"

                await connected.close()
                connected = None
                assert launched.is_connected()
                assert await launched_page.title() == "Async Origin CDP Page"
            finally:
                if connected is not None:
                    await connected.close()
                await launched.close()

    asyncio.run(run())


def test_async_connect_over_cdp_context_request_syncs_remote_cookies_for_download(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            launched = await p.chromium.launch(headless=True)
            connected = None
            try:
                page = await launched.new_page()
                await page.goto(f"{http_server}/set-cookies")

                connected = await p.chromium.connect_over_cdp(launched._ws_endpoint)
                context = connected.contexts[0]
                cookie_names = {cookie["name"] for cookie in await context.cookies([http_server])}
                assert {"first", "second"} <= cookie_names

                response = await context.request.get(f"{http_server}/protected-download")
                assert response.status == 200
                assert await response.body() == b"protected-download-body"
            finally:
                if connected is not None:
                    await connected.close()
                await launched.close()

    asyncio.run(run())


def test_event_emitter_methods_exist_on_helper_classes(page):
    handle = page.evaluate_handle("() => ({ ok: true })")
    calls = []

    handle.on("custom", lambda value: calls.append(("on", value)))
    handle.once("custom", lambda value: calls.append(("once", value)))
    handle._emit_local_event("custom", 1)
    handle._emit_local_event("custom", 2)

    assert calls == [("on", 1), ("once", 1), ("on", 2)]

    def listener(value):
        calls.append(("removed", value))

    handle.on("custom", listener)
    handle.remove_listener("custom", listener)
    handle._emit_local_event("custom", 3)

    assert calls == [("on", 1), ("once", 1), ("on", 2), ("on", 3)]


