def test_playwright_shaped_dom_convenience_helpers(browser):
    page = browser.new_page(viewport={"width": 640, "height": 480})
    try:
        page.set_content(
            """
            <button id="go" data-state="idle" onclick="this.dataset.state='clicked'"><span>Go</span></button>
            <input id="name" value="Ada">
            <input id="check" type="checkbox">
            <section id="box"><b>Nested</b></section>
            """
        )

        assert page.context is not None
        assert page.request is page.context.request
        assert page.viewport_size == {"width": 640, "height": 480}
        assert not page.is_closed()
        assert page.get_attribute("#go", "data-state") == "idle"
        assert page.inner_html("#box") == "<b>Nested</b>"
        assert page.eval_on_selector("#go", "(el) => el.textContent.trim()") == "Go"
        assert page.eval_on_selector_all("input", "(nodes) => nodes.length") == 2

        page.dispatch_event("#go", "click")
        assert page.get_attribute("#go", "data-state") == "clicked"

        locator = page.locator("#name")
        locator.clear()
        locator.press_sequentially("Grace")
        assert locator.input_value() == "Grace"
        assert locator.get_attribute("id") == "name"
        assert not locator.is_hidden()

        page.set_checked("#check", True)
        assert page.locator("#check").is_checked()
        page.locator("#check").set_checked(False)
        assert not page.locator("#check").is_checked()

        handles = page.locator("input").element_handles()
        assert len(handles) == 2
        assert handles[0].as_element() is handles[0]
        assert handles[0].get_attribute("id") == "name"
        tag_name = handles[0].get_property(property_name="tagName")
        assert tag_name.json_value() == "INPUT"
        tag_name.dispose()
        assert handles[0].bounding_box()["width"] > 0
        handles[0].dispose()
    finally:
        page.close()


def test_context_event_and_api_surface_helpers(browser):
    context = browser.new_context()
    try:
        context.set_default_timeout(3_000)
        with context.expect_page() as page_info:
            page = context.new_page()
        assert page_info.value is page

        result = {}
        thread = threading.Thread(target=lambda: result.setdefault("page", context.wait_for_event("page", timeout=3_000)))
        thread.start()
        second = context.new_page()
        thread.join(timeout=3)
        assert result["page"] is second
    finally:
        context.close()


