def test_specialized_event_waiters_reject_when_owner_closes(browser):
    def expect_target_closed(operation) -> None:
        with pytest.raises(Error, match="Target page, context or browser has been closed"):
            operation()

    page_events = [
        "request",
        "response",
        "requestfinished",
        "requestfailed",
        "console",
        "dialog",
        "pageerror",
        "download",
        "filechooser",
        "popup",
        "websocket",
        "worker",
        "load",
        "domcontentloaded",
        "framenavigated",
        "frameattached",
        "framedetached",
    ]
    for event in page_events:
        page = browser.new_page()
        try:
            def close_inside_waiter(event=event, page=page) -> None:
                with page.expect_event(event, timeout=3_000):
                    page.close()

            expect_target_closed(close_inside_waiter)
        finally:
            if not page.is_closed():
                page.close()

    context_events = [
        "page",
        "request",
        "response",
        "requestfinished",
        "requestfailed",
        "console",
        "dialog",
        "weberror",
        "pageload",
        "backgroundpage",
        "serviceworker",
    ]
    for event in context_events:
        context = browser.new_context()
        context.new_page()
        try:
            def close_context_inside_waiter(event=event, context=context) -> None:
                with context.expect_event(event, timeout=3_000):
                    context.close()

            expect_target_closed(close_context_inside_waiter)
        finally:
            if not context.is_closed():
                context.close()


