def test_specialized_event_timeout_messages_match_playwright(page, browser):
    def expect_event_timeout(event: str, operation) -> None:
        with pytest.raises(TimeoutError) as exc_info:
            operation()
        assert str(exc_info.value).splitlines()[0] == f'Timeout 5ms exceeded while waiting for event "{event}"'

    for event in [
        "request",
        "response",
        "requestfinished",
        "requestfailed",
        "console",
        "dialog",
        "pageerror",
        "download",
        "filechooser",
        "popup",
        "websocket",
        "worker",
        "load",
        "domcontentloaded",
        "framenavigated",
        "frameattached",
        "framedetached",
    ]:
        expect_event_timeout(event, lambda event=event: page.wait_for_event(event, timeout=5))

    context = browser.new_context()
    try:
        context.new_page()
        for event in [
            "page",
            "request",
            "response",
            "requestfinished",
            "requestfailed",
            "console",
            "dialog",
            "weberror",
            "pageload",
            "pageclose",
            "backgroundpage",
            "serviceworker",
        ]:
            expect_event_timeout(event, lambda event=event: context.wait_for_event(event, timeout=5))
    finally:
        context.close()


