def test_context_debugger_basic_pause_resume_state(browser):
    context = browser.new_context()
    debugger = context.debugger
    seen = []

    debugger.on("pausedstatechanged", lambda: seen.append(debugger.paused_details))
    assert debugger.paused_details is None

    debugger.request_pause()
    assert debugger.paused_details == {"location": {}, "title": "Paused"}
    debugger.resume()
    assert debugger.paused_details is None
    debugger.request_pause()
    debugger.run_to({"file": "test.py", "line": 1, "column": 1})
    assert debugger.paused_details is None
    debugger.request_pause()
    debugger.next()
    assert debugger.paused_details is None
    assert seen == [
        {"location": {}, "title": "Paused"},
        None,
        {"location": {}, "title": "Paused"},
        None,
        {"location": {}, "title": "Paused"},
        None,
    ]
    context.close()


