def test_context_console_event_applies_to_existing_and_new_pages(browser):
    context = browser.new_context()
    page = context.new_page()
    seen = []

    context.on("console", lambda message: seen.append((message.page, message.text)))
    page.evaluate("() => console.log('existing-context-console')")
    second = context.new_page()
    second.evaluate("() => console.info('new-context-console')")

    assert wait_until(lambda: [item for item in seen if item[1] == "existing-context-console"])[0][0] is page
    assert wait_until(lambda: [item for item in seen if item[1] == "new-context-console"])[0][0] is second
    context.close()


def test_remove_listener_cancels_page_and_context_once_by_original_callback(page):
    page_seen: list[str] = []

    def page_console(message):
        page_seen.append(message.text)

    page.once("console", page_console)
    page.remove_listener("console", page_console)
    page.evaluate("() => console.log('removed-page-once')")
    page.wait_for_timeout(100)
    assert page_seen == []

    page.once("console", page_console)
    page.evaluate("() => console.log('kept-page-once')")
    assert wait_until(lambda: page_seen) == ["kept-page-once"]
    page.evaluate("() => console.log('ignored-page-once')")
    page.wait_for_timeout(100)
    assert page_seen == ["kept-page-once"]

    context_seen: list[str] = []

    def context_console(message):
        context_seen.append(message.text)

    page.context.once("console", context_console)
    page.context.remove_listener("console", context_console)
    page.evaluate("() => console.log('removed-context-once')")
    page.wait_for_timeout(100)
    assert context_seen == []

    page.context.once("console", context_console)
    page.evaluate("() => console.log('kept-context-once')")
    assert wait_until(lambda: context_seen) == ["kept-context-once"]
    page.evaluate("() => console.log('ignored-context-once')")
    page.wait_for_timeout(100)
    assert context_seen == ["kept-context-once"]

    duplicate_page_seen: list[str] = []

    def duplicate_page_console(message):
        duplicate_page_seen.append(message.text)

    page.on("console", duplicate_page_console)
    page.on("console", duplicate_page_console)
    page.evaluate("() => console.log('deduped-page-listener')")
    assert wait_until(lambda: duplicate_page_seen) == ["deduped-page-listener"]

    duplicate_context_seen: list[str] = []

    def duplicate_context_console(message):
        duplicate_context_seen.append(message.text)

    page.context.on("console", duplicate_context_console)
    page.context.on("console", duplicate_context_console)
    page.evaluate("() => console.log('deduped-context-listener')")
    assert wait_until(lambda: duplicate_context_seen) == ["deduped-context-listener"]


def test_context_dialog_event_can_accept_prompt(browser):
    context = browser.new_context()
    page = context.new_page()
    seen = []

    context.on("dialog", lambda dialog: (seen.append((dialog.page, dialog.type, dialog.message)), dialog.accept("Context")))
    page.set_content("<button onclick=\"document.body.dataset.answer = prompt('Context name?', 'Ada')\">Prompt</button>")
