def test_context_expect_event_captures_dialog(browser):
    context = browser.new_context()
    page = context.new_page()
    page.set_content(
        """
        <script>
        window.showPrompt = () => setTimeout(() => {
          document.body.dataset.answer = prompt('Generic context?', 'Ada');
        }, 0);
        </script>
        """
    )

    with context.expect_event("dialog", lambda dialog: dialog.message == "Generic context?") as dialog_info:
        page.evaluate("() => window.showPrompt()")

    dialog = dialog_info.value
    assert dialog.page is page
    assert (dialog.type, dialog.default_value) == ("prompt", "Ada")
    dialog.accept("Generic")
    assert wait_until(lambda: page.evaluate("document.body.dataset.answer")) == "Generic"
    context.close()


def test_context_weberror_event_wraps_page_error(browser):
    context = browser.new_context()
    page = context.new_page()
    seen = []

    context.on("weberror", lambda web_error: seen.append(web_error))
    with context.expect_event("weberror", lambda web_error: "context boom" in str(web_error.error)) as error_info:
        page.evaluate("() => setTimeout(() => { throw new Error('context boom'); }, 0)")

    web_error = error_info.value
    assert web_error.error.args == ("context boom",)
    assert web_error.page is page
    assert wait_until(lambda: [item for item in seen if "context boom" in str(item.error)])[0].page is page
    context.close()


