def test_async_wait_for_url_argument_validation_matches_playwright():
    async def run() -> None:
        from playwright.async_api import Error as AsyncError
        from playwright.async_api import TimeoutError as AsyncTimeoutError
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.goto(data_url("<title>Async URL Validation</title><main>Ready</main>"))

            async def expect_error(operation, expected_message: str, error_type: type[BaseException] = AsyncError) -> None:
                with pytest.raises(error_type) as exc_info:
                    await operation()
                assert str(exc_info.value).splitlines()[0] == expected_message

            await expect_error(
                lambda: page.wait_for_url(None, timeout=50),
                "Frame.wait_for_url() missing 1 required positional argument: 'url'",
                TypeError,
            )
            await expect_error(lambda: page.wait_for_url(123, timeout=50), "'int' object is not callable", TypeError)
            await expect_error(lambda: page.wait_for_url(lambda url: False, timeout=50), "Timeout 50ms exceeded.", AsyncTimeoutError)
            await expect_error(
                lambda: page.wait_for_url(lambda url: (_ for _ in ()).throw(ValueError("bad predicate")), timeout=50),
                "bad predicate",
                ValueError,
            )

            assert await page.main_frame.wait_for_url(None, timeout=50) is None
            await expect_error(lambda: page.main_frame.wait_for_url(123, timeout=50), "'int' object is not callable", TypeError)
            await expect_error(
                lambda: page.main_frame.wait_for_url(lambda url: False, timeout=50),
                "Timeout 50ms exceeded.",
                AsyncTimeoutError,
            )
            await browser.close()

    asyncio.run(run())


def test_async_navigation_argument_validation_matches_playwright():
    async def run() -> None:
        from playwright.async_api import Error as AsyncError
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.goto("about:blank")

            async def expect_error(operation, expected_message: str, error_type: type[BaseException] = AsyncError) -> None:
                with pytest.raises(error_type) as exc_info:
                    await operation()
                assert str(exc_info.value).splitlines()[0] == expected_message

            await expect_error(
                lambda: page.goto(None, timeout=50),
                "Frame.goto() missing 1 required positional argument: 'url'",
                TypeError,
            )
            await expect_error(lambda: page.goto(123, timeout=50), "Page.goto: url: expected string, got number")
            await expect_error(lambda: page.main_frame.goto(None, timeout=50), "Frame.goto: url: expected string, got undefined")
            await expect_error(lambda: page.main_frame.goto(123, timeout=50), "Frame.goto: url: expected string, got number")
            await expect_error(
                lambda: page.goto("about:blank", referer=123, timeout=50),
                "Page.goto: referer: expected string, got number",
            )
            await expect_error(
                lambda: page.main_frame.goto("about:blank", referer=123, timeout=50),
                "Frame.goto: referer: expected string, got number",
            )
            await expect_error(lambda: page.goto("about:blank", timeout="bad"), "Page.goto: timeout: expected float, got string")
            await expect_error(
                lambda: page.main_frame.goto("about:blank", timeout="bad"),
                "Frame.goto: timeout: expected float, got string",
            )
            await expect_error(lambda: page.reload(timeout="bad"), "Page.reload: timeout: expected float, got string")
            await expect_error(lambda: page.go_back(timeout="bad"), "Page.go_back: timeout: expected float, got string")
            await expect_error(lambda: page.go_forward(timeout="bad"), "Page.go_forward: timeout: expected float, got string")
            await browser.close()

    asyncio.run(run())


