def test_async_goto_timeout_message_matches_playwright(http_server):
    async def run() -> None:
        from playwright.async_api import TimeoutError as AsyncTimeoutError
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async def expect_timeout(operation, expected_message: str) -> None:
                with pytest.raises(AsyncTimeoutError) as exc_info:
                    await operation()
                assert str(exc_info.value).splitlines()[0] == expected_message

            async def cleanup(pattern, handler, expected_message: str) -> None:
                try:
                    await page.unroute(pattern, handler)
                except Exception as exc:
                    assert str(exc).splitlines()[0] == expected_message
                    return
                raise AssertionError(f"expected cleanup error {expected_message!r}")

            async def page_handler(route):
                raise RuntimeError("async page goto timeout boom")

            await page.route("**/async-goto-timeout-page", page_handler)
            await expect_timeout(
                lambda: page.goto(f"{http_server}/async-goto-timeout-page", timeout=50),
                "Page.goto: Timeout 50ms exceeded.",
            )
            await cleanup("**/async-goto-timeout-page", page_handler, "Page.unroute: async page goto timeout boom")

            async def frame_handler(route):
                raise RuntimeError("async frame goto timeout boom")

            await page.route("**/async-goto-timeout-frame", frame_handler)
            await expect_timeout(
                lambda: page.main_frame.goto(f"{http_server}/async-goto-timeout-frame", timeout=50),
                "Frame.goto: Timeout 50ms exceeded.",
            )
            await cleanup("**/async-goto-timeout-frame", frame_handler, "Page.unroute: async frame goto timeout boom")
            await browser.close()

    asyncio.run(run())


def test_async_reload_and_history_timeout_messages_match_playwright(http_server):
    async def run() -> None:
        from playwright.async_api import TimeoutError as AsyncTimeoutError
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async def expect_timeout(operation, expected_message: str) -> None:
                with pytest.raises(AsyncTimeoutError) as exc_info:
                    await operation()
                assert str(exc_info.value).splitlines()[0] == expected_message

            async def cleanup(pattern, handler, expected_message: str) -> None:
                try:
                    await page.unroute(pattern, handler)
                except Exception as exc:
                    assert str(exc).splitlines()[0] == expected_message
                    return

            await page.goto(f"{http_server}/headers?async-reload-timeout")

            async def reload_handler(route):
                raise RuntimeError("async reload timeout boom")

            await page.route("**/headers?async-reload-timeout", reload_handler)
            await expect_timeout(lambda: page.reload(timeout=50), "Page.reload: Timeout 50ms exceeded.")
            await cleanup("**/headers?async-reload-timeout", reload_handler, "Page.unroute: async reload timeout boom")

            await page.goto(f"{http_server}/headers?async-back-timeout")
            await page.goto(f"{http_server}/headers?async-middle")

            async def back_handler(route):
                raise RuntimeError("async back timeout boom")

            await page.route("**/headers?async-back-timeout", back_handler)
            await expect_timeout(lambda: page.go_back(timeout=50), "Page.go_back: Timeout 50ms exceeded.")
            await cleanup("**/headers?async-back-timeout", back_handler, "Page.unroute: async back timeout boom")

            await page.goto(f"{http_server}/headers?async-forward-start")
            await page.goto(f"{http_server}/headers?async-forward-timeout")
            await page.go_back()

            async def forward_handler(route):
                raise RuntimeError("async forward timeout boom")

            await page.route("**/headers?async-forward-timeout", forward_handler)
            await expect_timeout(lambda: page.go_forward(timeout=50), "Page.go_forward: Timeout 50ms exceeded.")
            await cleanup(
                "**/headers?async-forward-timeout",
                forward_handler,
                "Page.unroute: async forward timeout boom",
            )
            await browser.close()

    asyncio.run(run())


def test_async_set_content_and_load_state_timeout_messages_match_playwright():
    async def run() -> None:
        from playwright.async_api import TimeoutError as AsyncTimeoutError
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async def expect_timeout(operation, expected_message: str) -> None:
                with pytest.raises(AsyncTimeoutError) as exc_info:
                    await operation()
                assert str(exc_info.value).splitlines()[0] == expected_message

            async def slow_asset(route):
                await asyncio.sleep(0.3)
                try:
                    await route.abort()
                except Exception:
                    pass

            await page.route("**/async-set-content-slow.png", slow_asset)
            await expect_timeout(
                lambda: page.set_content(
                    "<img src='http://example.test/async-set-content-slow.png'>",
                    wait_until="load",
                    timeout=50,
                ),
                "Page.set_content: Timeout 50ms exceeded.",
            )
            await page.unroute("**/async-set-content-slow.png", slow_asset)

            await page.route("**/async-frame-set-content-slow.png", slow_asset)
            await expect_timeout(
                lambda: page.main_frame.set_content(
                    "<img src='http://example.test/async-frame-set-content-slow.png'>",
                    wait_until="load",
                    timeout=50,
                ),
                "Frame.set_content: Timeout 50ms exceeded.",
            )
            await page.unroute("**/async-frame-set-content-slow.png", slow_asset)

            await expect_timeout(
                lambda: page.wait_for_load_state("networkidle", timeout=50),
                "Timeout 50ms exceeded.",
            )
            await expect_timeout(
                lambda: page.main_frame.wait_for_load_state("networkidle", timeout=50),
                "Timeout 50ms exceeded.",
            )
            await browser.close()

    asyncio.run(run())


