def test_async_frame_goto_special_scheme_responses_match_playwright():
    async def run() -> None:
        from playwright.async_api import Error as AsyncError
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content('<iframe name="child" srcdoc="<main>old</main>"></iframe>')
            frame = page.frame(name="child")
            assert frame is not None

            assert await frame.goto("about:blank") is None
            assert frame.url == "about:blank"

            data_target = data_url("<title>Async Frame Data</title><main>data</main>")
            assert await frame.goto(data_target) is None
            assert frame.url == data_target
            assert await frame.title() == "Async Frame Data"

            before = frame.url
            javascript_target = "javascript:void(document.body.dataset.changed='yes')"
            with pytest.raises(AsyncError) as exc_info:
                await frame.goto(javascript_target, timeout=2_000)

            assert type(exc_info.value) is AsyncError
            assert str(exc_info.value).splitlines()[0] == f"Frame.goto: net::ERR_ABORTED at {javascript_target}"
            assert frame.url == before
            assert await frame.evaluate("() => document.body.dataset.changed") == "yes"

            string_target = "javascript:'<h1>async frame replacement</h1>'"
            with pytest.raises(AsyncError) as string_exc_info:
                await frame.goto(string_target, timeout=2_000)

            assert type(string_exc_info.value) is AsyncError
            assert str(string_exc_info.value).splitlines()[0] == f"Frame.goto: net::ERR_ABORTED at {string_target}"
            assert frame.url == before
            assert await frame.title() == ""
            assert await frame.evaluate("() => document.body.innerText") == "async frame replacement"
            assert await frame.content() == "<html><head></head><body><h1>async frame replacement</h1></body></html>"
            await browser.close()

    asyncio.run(run())


