def test_async_wait_helper_timeout_messages_preserve_playwright_prefixes():
    async def run() -> None:
        from playwright.async_api import TimeoutError as AsyncTimeoutError
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content("<main id='root'><div>Ready</div></main>")
            root = await page.query_selector("#root")
            assert root is not None

            checks = [
                (lambda: page.wait_for_url(lambda url: False, timeout=120), "Timeout 120ms exceeded."),
                (lambda: page.wait_for_selector("#missing", timeout=120), "Page.wait_for_selector: Timeout 120ms exceeded."),
                (lambda: page.main_frame.wait_for_selector("#missing", timeout=120), "Frame.wait_for_selector: Timeout 120ms exceeded."),
                (lambda: page.locator("#missing").wait_for(timeout=120), "Locator.wait_for: Timeout 120ms exceeded."),
                (lambda: root.wait_for_selector("#missing", timeout=120), "ElementHandle.wait_for_selector: Timeout 120ms exceeded."),
                (lambda: page.wait_for_function("() => false", timeout=120, polling=10), "Page.wait_for_function: Timeout 120ms exceeded."),
                (
                    lambda: page.main_frame.wait_for_function("() => false", timeout=120, polling=10),
                    "Frame.wait_for_function: Timeout 120ms exceeded.",
                ),
            ]
            for operation, expected in checks:
                with pytest.raises(AsyncTimeoutError) as exc_info:
                    await operation()
                assert str(exc_info.value).splitlines()[0] == expected
            await browser.close()

    asyncio.run(run())


