def test_async_action_argument_validation_matches_playwright():
    async def run() -> None:
        from playwright.async_api import Error as AsyncError
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content("<input id='field'><button id='go'>Go</button>")
            locator = page.locator("#field")
            element = await page.query_selector("#field")
            assert element is not None

            async def expect_error(operation, expected_message: str, error_type: type[BaseException] = AsyncError) -> None:
                with pytest.raises(error_type) as exc_info:
                    await operation()
                assert str(exc_info.value).splitlines()[0] == expected_message

            await expect_error(
                lambda: page.type(None, "x"),
                "Frame.type() missing 1 required positional argument: 'selector'",
                TypeError,
            )
            await expect_error(lambda: page.type("#field", 123), "Page.type: text: expected string, got number")
            await expect_error(
                lambda: locator.type(None),
                "Frame.type() missing 1 required positional argument: 'text'",
                TypeError,
            )
            await expect_error(lambda: element.type(123), "ElementHandle.type: text: expected string, got number")
            await expect_error(
                lambda: page.press("#field", None),
                "Frame.press() missing 1 required positional argument: 'key'",
                TypeError,
            )
            await expect_error(lambda: locator.press(123), "Locator.press: key: expected string, got number")
            await expect_error(lambda: element.press(None), "ElementHandle.press: key: expected string, got undefined")
            await browser.close()

    asyncio.run(run())


