            await expect_error(lambda: page.locator("section").filter(has="button").count(), "'str' object has no attribute '_impl_obj'")
            await expect_error(lambda: page.locator("section", has_not="button").count(), "'str' object has no attribute '_impl_obj'")
            await expect_error(lambda: page.locator("button").and_("button").count(), "'str' object has no attribute '_impl_obj'")
            await expect_error(lambda: page.locator("button").or_("button").count(), "'str' object has no attribute '_impl_obj'")
            await expect_error(lambda: page.locator("section").locator(None).count(), "'NoneType' object has no attribute '_frame'")
