def test_async_close_event_handlers_accept_zero_or_value_callbacks_like_playwright():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()
            seen: list[object] = []

            async def page_zero_arg() -> None:
                await asyncio.sleep(0)
                seen.append("page-zero")

            async def page_value_arg(closed_page) -> None:
                await asyncio.sleep(0)
                seen.append(("page-value", closed_page is page))

            async def context_zero_arg() -> None:
                await asyncio.sleep(0)
                seen.append("context-zero")

            async def context_value_arg(closed_context) -> None:
                await asyncio.sleep(0)
                seen.append(("context-value", closed_context is context))

            page.on("close", page_zero_arg)
            page.on("close", page_value_arg)
            context.on("close", context_zero_arg)
            context.on("close", context_value_arg)

            await page.close()
            await context.close()

            assert await wait_until_async(lambda: len(seen) == 4 and seen) == [
                "page-zero",
                ("page-value", True),
                "context-zero",
                ("context-value", True),
            ]
            await browser.close()

    asyncio.run(run())


