def test_async_specialized_event_timeout_messages_match_playwright():
    async def run() -> None:
        from playwright.async_api import async_playwright

        def assert_timeout_message(event: str, exc: BaseException) -> None:
            assert str(exc).splitlines()[0] == f'Timeout 5ms exceeded while waiting for event "{event}"'

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            for event in [
                "request",
                "response",
                "requestfinished",
                "requestfailed",
                "console",
                "dialog",
                "pageerror",
                "download",
                "filechooser",
                "popup",
                "websocket",
                "worker",
                "load",
                "domcontentloaded",
                "framenavigated",
                "frameattached",
                "framedetached",
            ]:
                with pytest.raises(TimeoutError) as exc_info:
                    await page.wait_for_event(event, timeout=5)
                assert_timeout_message(event, exc_info.value)

            context = await browser.new_context()
            try:
                await context.new_page()
                for event in [
                    "page",
                    "request",
                    "response",
                    "requestfinished",
                    "requestfailed",
                    "console",
                    "dialog",
                    "weberror",
                    "pageload",
                    "pageclose",
                    "backgroundpage",
                    "serviceworker",
                ]:
                    with pytest.raises(TimeoutError) as exc_info:
                        await context.wait_for_event(event, timeout=5)
                    assert_timeout_message(event, exc_info.value)
            finally:
                await context.close()
            await browser.close()

    asyncio.run(run())


