def test_async_expect_dialog_download_and_file_chooser_wrappers(http_server, tmp_path: Path):
    async def run() -> None:
        from playwright.async_api import async_playwright

        upload = tmp_path / "async-chooser.txt"
        upload.write_text("async chosen", encoding="utf-8")
        copied_download = tmp_path / "async-download-copy.txt"

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            await page.set_content(
                f"""
                <a id="download" href="{http_server}/download">Download</a>
                <input id="file" type="file" multiple>
                <script>
                window.showAsyncPrompt = () => setTimeout(() => {{
                  document.body.dataset.answer = prompt('Async name?', 'Ada');
                }}, 0);
                document.querySelector('#file').addEventListener('change', event => {{
                  document.body.dataset.chosen = event.target.files[0].name;
                }});
                </script>
                """
            )

            async def matches_prompt(dialog):
                return dialog.message == "Async name?"

            async with page.expect_event("dialog", matches_prompt) as dialog_info:
                await page.evaluate("() => window.showAsyncPrompt()")

            assert inspect.isawaitable(dialog_info.value)
            dialog = await dialog_info.value
            assert dialog_info.value is dialog
            assert dialog.page is page
            assert (dialog.type, dialog.default_value) == ("prompt", "Ada")
            await dialog.accept("Grace")
            assert await page.evaluate("document.body.dataset.answer") == "Grace"

            async with page.expect_download(lambda download: download.suggested_filename == "report.txt") as download_info:
                await page.click("#download")

            assert inspect.isawaitable(download_info.value)
            download = await download_info.value
            assert download_info.value is download
            assert download.page is page
            assert download.url == f"{http_server}/download"
            assert await download.failure() is None
            downloaded_path = await download.path()
            assert isinstance(downloaded_path, Path)
            await download.save_as(str(copied_download))
            assert downloaded_path.read_bytes() == b"download-body"
            assert copied_download.read_bytes() == b"download-body"

            async with page.expect_file_chooser() as chooser_info:
                await page.click("#file")

            assert inspect.isawaitable(chooser_info.value)
            chooser = await chooser_info.value
            assert chooser_info.value is chooser
            assert chooser.page is page
            assert chooser.is_multiple()
            assert await chooser.element.get_attribute("type") == "file"
            await chooser.set_files(str(upload))
            assert await page.evaluate("document.body.dataset.chosen") == "async-chooser.txt"
            assert await page.evaluate("async () => await document.querySelector('#file').files[0].text()") == "async chosen"

            async with page.expect_file_chooser(lambda chooser: chooser.page is page and chooser.is_multiple()) as predicate_info:
                await page.click("#file")
            predicate_chooser = await predicate_info.value
            assert predicate_chooser.page is page
            assert predicate_chooser.is_multiple()
            await browser.close()

    asyncio.run(run())


def test_async_dialog_accept_dismiss_validation_matches_playwright():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async def capture_prompt(page, key):
            async with page.expect_event("dialog") as dialog_info:
                await page.evaluate("key => window.showPrompt(key)", key)
            return dialog_info.value

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <script>
                window.showPrompt = key => setTimeout(() => {
                  document.body.dataset[key] = prompt('Async question?', 'default') ?? 'null';
                }, 0);
                </script>
                """
            )

            first = await capture_prompt(page, "first")
            with pytest.raises(Error) as exc_info:
                await first.accept(prompt_text=123)
            assert str(exc_info.value).splitlines()[0] == "Dialog.accept: prompt_text: expected string, got number"
            await first.dismiss()
            handle = await page.wait_for_function("() => document.body.dataset.first === 'null'", timeout=3_000)
            await handle.dispose()

            second = await capture_prompt(page, "second")
            await second.accept("Grace")
            handle = await page.wait_for_function("() => document.body.dataset.second === 'Grace'", timeout=3_000)
            await handle.dispose()
            with pytest.raises(Error) as exc_info:
                await second.dismiss()
            assert str(exc_info.value).splitlines()[0] == (
                "Dialog.dismiss: Cannot dismiss dialog which is already handled!"
            )

            third = await capture_prompt(page, "third")
            await third.dismiss()
            handle = await page.wait_for_function("() => document.body.dataset.third === 'null'", timeout=3_000)
            await handle.dispose()
            with pytest.raises(Error) as exc_info:
                await third.accept("Grace")
            assert str(exc_info.value).splitlines()[0] == (
                "Dialog.accept: Cannot accept dialog which is already handled!"
            )
            await browser.close()

    asyncio.run(run())


def test_async_dialog_listener_can_schedule_dismiss_like_skyvern_mcp():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            seen = []
            dismiss_errors = []

            def on_dialog(dialog):
                seen.append((dialog.type, dialog.message))
                task = asyncio.create_task(dialog.dismiss())

                def record_error(done):
                    if done.cancelled():
                        dismiss_errors.append("cancelled")
                        return
                    error = done.exception()
                    if error is not None:
                        dismiss_errors.append(str(error).splitlines()[0])

                task.add_done_callback(record_error)

            page.on("dialog", on_dialog)
            await page.set_content(
                """
                <button id="alert" onclick="alert('Skyvern dialog'); document.body.dataset.done = 'yes'">
                  Alert
                </button>
                """
            )

            await page.click("#alert")
            await page.wait_for_function("() => document.body.dataset.done === 'yes'", timeout=3_000)
            await asyncio.sleep(0.05)

            assert seen == [("alert", "Skyvern dialog")]
            assert dismiss_errors == []
            await browser.close()

    asyncio.run(run())


