def test_async_single_file_inputs_reject_multiple_files(tmp_path: Path):
    async def run() -> None:
        from playwright.async_api import async_playwright

        first_path = tmp_path / "async-first.txt"
        second_path = tmp_path / "async-second.txt"
        first_path.write_text("first", encoding="utf-8")
        second_path.write_text("second", encoding="utf-8")
        paths = [str(first_path), str(second_path)]

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <input id="chooser" type="file">
                <input id="locator" type="file">
                <script>
                for (const input of document.querySelectorAll('input[type=file]')) {
                  input.addEventListener('change', event => {
                    document.body.dataset[event.target.id] =
                      Array.from(event.target.files).map(file => file.name).join(',');
                  });
                }
                </script>
                """
            )

            async with page.expect_file_chooser() as chooser_info:
                await page.click("#chooser")

            with pytest.raises(Error) as exc_info:
                await chooser_info.value.set_files(paths)
            assert str(exc_info.value).splitlines()[0] == (
                "FileChooser.set_files: Error: Non-multiple file input can only accept single file"
            )
            assert await page.evaluate("document.body.dataset.chooser") is None

            with pytest.raises(Error) as exc_info:
                await page.locator("#locator").set_input_files(paths)
            assert str(exc_info.value).splitlines()[0] == (
                "Locator.set_input_files: Error: Non-multiple file input can only accept single file"
            )
            assert await page.evaluate("document.body.dataset.locator") is None
            await browser.close()

    asyncio.run(run())


def test_async_expect_download_allows_scheduled_trigger(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(f"<a id='download' href='{http_server}/download'>Download</a>")

            trigger_task = None
            async with page.expect_download(timeout=3_000) as download_info:
                async def trigger_download() -> None:
                    await asyncio.sleep(0.05)
                    await page.click("#download")

                trigger_task = asyncio.create_task(trigger_download())

            await trigger_task
            download = download_info.value
            assert download.suggested_filename == "report.txt"
