def test_async_download_event_handler_can_await_path_and_save_as(http_server, tmp_path: Path):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            done = asyncio.get_running_loop().create_future()
            copy_path = tmp_path / "listener-copy.txt"

            async def on_download(download):
                try:
                    downloaded_path = await download.path()
                    assert isinstance(downloaded_path, Path)
                    await download.save_as(copy_path)
                    done.set_result((download.suggested_filename, downloaded_path.read_bytes(), copy_path.read_bytes()))
                except BaseException as exc:
                    done.set_exception(exc)
                    raise

            page.on("download", on_download)
            await page.set_content(f"<a id='download' href='{http_server}/download'>Download</a>")
            await page.click("#download")

            assert await asyncio.wait_for(done, timeout=3) == ("report.txt", b"download-body", b"download-body")
            await browser.close()

    asyncio.run(run())


def test_async_download_delete_invalidates_artifact_and_save_as_path_validation(http_server, tmp_path: Path):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(f"<a id='download' href='{http_server}/download'>Download</a>")

            async with page.expect_download() as download_info:
                await page.click("#download")

            download = download_info.value
            downloaded_path = Path(await download.path())
            copy_path = tmp_path / "async-copy-pathlike.txt"
            await download.save_as(copy_path)
            assert copy_path.read_bytes() == b"download-body"

            with pytest.raises(TypeError) as exc_info:
                await download.save_as(123)
            assert str(exc_info.value).splitlines()[0] == "expected str, bytes or os.PathLike object, not int"

            await download.delete()
            assert not downloaded_path.exists()
            with pytest.raises(Error) as exc_info:
                await download.path()
            assert str(exc_info.value).splitlines()[0] == (
                "Download.path: Target page, context or browser has been closed"
            )
            with pytest.raises(Error) as exc_info:
                await download.save_as(str(tmp_path / "after-delete.txt"))
            assert str(exc_info.value).splitlines()[0] == (
                "Download.save_as: Target page, context or browser has been closed"
            )
            with pytest.raises(Error) as exc_info:
                await download.failure()
            assert str(exc_info.value).splitlines()[0] == (
                "Download.failure: Target page, context or browser has been closed"
            )
            with pytest.raises(Error) as exc_info:
                await download.cancel()
            assert str(exc_info.value).splitlines()[0] == (
                "Download.cancel: Target page, context or browser has been closed"
            )
            with pytest.raises(Error) as exc_info:
                await download.delete()
            assert str(exc_info.value).splitlines()[0] == (
                "Download.delete: Target page, context or browser has been closed"
            )
            await browser.close()

    asyncio.run(run())


def test_async_page_route_fetch_and_fulfill_response(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        seen = []
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async def handler(route, request):
                upstream = await route.fetch(headers={"X-Test-Header": "from-async-route-fetch"})
                seen.append((request.url, await upstream.json()))
                await route.fulfill(response=upstream)

            await page.route("**/headers", handler)
            await page.goto(f"{http_server}/page")
            await page.evaluate(
                """() => fetch('/headers').then(response => response.json()).then(data => {
                  document.body.dataset.asyncRouteFetchHeader = data['x-test'];
                })"""
            )

            deadline = time.monotonic() + 3
            while time.monotonic() < deadline:
                if await page.evaluate("() => document.body.dataset.asyncRouteFetchHeader === 'from-async-route-fetch'"):
                    break
                await asyncio.sleep(0.05)
            assert await page.evaluate("() => document.body.dataset.asyncRouteFetchHeader") == "from-async-route-fetch"
            assert seen == [(f"{http_server}/headers", {"x-test": "from-async-route-fetch"})]

            duplicate_seen = []

            async def duplicate_handler(route, request):
                upstream = await route.fetch(url=f"{http_server}/duplicate-headers")
                duplicate_seen.append({"headers": upstream.headers, "headers_array": upstream.headers_array})
                await route.fulfill(response=upstream)

            await page.route("**/async-route-fetch-duplicate-headers", duplicate_handler)
            duplicate_response = await page.goto(f"{http_server}/async-route-fetch-duplicate-headers")
            assert duplicate_response.status == 200
            assert await duplicate_response.text() == "duplicate headers"
            assert duplicate_seen[0]["headers"]["x-dupe"] == "first, second"
            assert duplicate_seen[0]["headers"]["set-cookie"] == "first=one; Path=/\nsecond=two; Path=/"
            assert {"name": "X-Dupe", "value": "first"} in duplicate_seen[0]["headers_array"]
            assert {"name": "X-Dupe", "value": "second"} in duplicate_seen[0]["headers_array"]
            assert {"name": "Set-Cookie", "value": "first=one; Path=/"} in duplicate_seen[0]["headers_array"]
            assert {"name": "Set-Cookie", "value": "second=two; Path=/"} in duplicate_seen[0]["headers_array"]
            await browser.close()

    asyncio.run(run())


def test_async_context_route_callable_url_predicate_receives_url_string(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        target_url = f"{http_server}/query?callable=1"
        seen: list[tuple[str, str]] = []
        handled: list[tuple[str, bool]] = []

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            def matcher(url):
                seen.append((type(url).__name__, str(url)))
                return str(url).endswith("/query?callable=1")

            async def handler(route):
                handled.append((route.request.url, route.request.is_navigation_request()))
                await route.fulfill(status=200, json={"matched": True})

            await page.context.route(matcher, handler)
            await page.goto(f"{http_server}/page")
            result = await page.evaluate(
                "async url => await fetch(url).then(response => response.json())",
                target_url,
            )

            assert result == {"matched": True}
            assert handled == [(target_url, False)]
            assert any(value == target_url for type_name, value in seen if type_name == "str")
            assert all(type_name == "str" for type_name, _ in seen)
            await browser.close()

    asyncio.run(run())


