def test_async_page_and_context_unroute_all_are_scoped(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()

            async def context_handler(route):
                await route.fulfill(json={"scope": "context"})

            async def page_handler(route):
                await route.fulfill(json={"scope": "page"})

            await context.route("**/query?scope=context", context_handler)
            await page.route("**/query?scope=page", page_handler)
            await page.unroute_all()

            assert getattr(page, "_route_handler_wrappers", []) == []
            response = await page.goto(f"{http_server}/query?scope=context")
            assert await response.json() == {"scope": "context"}
            response = await page.goto(f"{http_server}/query?scope=page")
            assert await response.json() == {"path": "/query", "query": {"scope": ["page"]}}

            async def page_again(route):
                await route.fulfill(json={"scope": "page-again"})

            await page.route("**/query?scope=page-again", page_again)
            await context.unroute_all()

            assert getattr(context, "_route_handler_wrappers", []) == []
            response = await page.goto(f"{http_server}/query?scope=context")
            assert await response.json() == {"path": "/query", "query": {"scope": ["context"]}}
            response = await page.goto(f"{http_server}/query?scope=page-again")
            assert await response.json() == {"scope": "page-again"}
            await browser.close()

    asyncio.run(run())


def test_async_route_handler_errors_surface_on_unroute_cleanup(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()

            async def trigger(path: str) -> None:
                try:
                    await page.goto(f"{http_server}/{path}", timeout=250)
                except Exception:
                    return
                raise AssertionError(f"expected navigation to time out for {path}")

            async def captured_error(call):
                try:
                    await call()
                except Exception as exc:
                    return [type(exc).__name__, str(exc).splitlines()[0]]
                raise AssertionError("expected route cleanup to surface the handler error")

            async def page_handler(route):
                raise TypeError("async page unroute boom")

            await page.route("**/route-handler-error-async-page", page_handler)
            await trigger("route-handler-error-async-page")
            assert await captured_error(lambda: page.unroute("**/route-handler-error-async-page", page_handler)) == [
                "TypeError",
                "Page.unroute: async page unroute boom",
            ]

            async def context_handler(route):
                raise ValueError("async context unroute_all boom")

            await context.route("**/route-handler-error-async-context", context_handler)
            await trigger("route-handler-error-async-context")
            assert await captured_error(lambda: context.unroute_all()) == [
                "ValueError",
                "BrowserContext.unroute_all: async context unroute_all boom",
            ]
            await browser.close()

    asyncio.run(run())


def test_async_page_unroute_all_wait_behavior_waits_for_active_handler(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        entered = threading.Event()
        release = threading.Event()
        completed = threading.Event()
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async def handler(route):
                entered.set()
                await asyncio.to_thread(release.wait, 3)
                await route.fulfill(status=200, body="async-waited")
                completed.set()

            await page.route("**/query?async-unroute=wait", handler)
            await page.goto(f"{http_server}/headers")
            await page.evaluate(
                """() => {
                window.asyncUnrouteWaitResult = "";
                fetch('/query?async-unroute=wait')
                  .then(response => response.text())
                  .then(text => window.asyncUnrouteWaitResult = text)
                  .catch(error => window.asyncUnrouteWaitResult = String(error));
                }"""
            )

            assert await asyncio.to_thread(entered.wait, 3)
            timer = threading.Timer(0.2, release.set)
            timer.start()
            started = time.monotonic()
            await page.unroute_all(behavior="wait")
            elapsed = time.monotonic() - started
            timer.cancel()

            assert elapsed >= 0.15
            assert completed.is_set()
            deadline = time.monotonic() + 3
            result = ""
            while time.monotonic() < deadline:
                result = await page.evaluate("() => window.asyncUnrouteWaitResult")
                if result:
                    break
                await asyncio.sleep(0.05)
            assert result == "async-waited"
            response = await page.goto(f"{http_server}/query?async-unroute=wait")
            assert await response.json() == {"path": "/query", "query": {"async-unroute": ["wait"]}}
            await browser.close()

    asyncio.run(run())


def test_async_page_route_fetch_option_validation(http_server):
    async def run() -> None:
        from playwright.async_api import TimeoutError as AsyncTimeoutError
        from playwright.async_api import async_playwright

        errors = []
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async def handler(route, request):
                with pytest.raises(Error) as invalid_url:
                    await route.fetch(url=123)
                errors.append(str(invalid_url.value).splitlines()[0])

                with pytest.raises(Error) as relative_url:
                    await route.fetch(url="/json")
                errors.append(str(relative_url.value).splitlines()[0])

                with pytest.raises(Error) as invalid_header:
                    await route.fetch(url=f"{http_server}/json", headers={1: "x"})
                errors.append(str(invalid_header.value).splitlines()[0])

                with pytest.raises(Error) as invalid_retry:
                    await route.fetch(url=f"{http_server}/json", max_retries=True)
                errors.append(str(invalid_retry.value).splitlines()[0])

                with pytest.raises(AsyncTimeoutError) as negative_timeout:
                    await route.fetch(url=f"{http_server}/json", timeout=-1)
                errors.append(str(negative_timeout.value).splitlines()[0])

                post_data_results = {}
                for label, kwargs in {
                    "empty_str": {"method": "POST", "post_data": ""},
                    "empty_bytes": {"method": "POST", "post_data": b""},
                    "zero": {"method": "POST", "post_data": 0},
                    "body": {"method": "POST", "post_data": "body"},
                }.items():
                    post_data_response = await route.fetch(url=f"{http_server}/echo", **kwargs)
                    post_data_results[label] = await post_data_response.json()

                upstream = await route.fetch(url=f"{http_server}/json", max_redirects=1.0, max_retries=1.0)
                await route.fulfill(status=200, json={"ok": upstream.ok, "post_data_results": post_data_results})

            await page.route("**/route-fetch-async-validation", handler)
            response = await page.goto(f"{http_server}/route-fetch-async-validation")

            assert await response.json() == {
                "ok": True,
                "post_data_results": {
                    "empty_str": {"body": "", "content_type": None, "x_test": None},
                    "empty_bytes": {"body": "", "content_type": None, "x_test": None},
                    "zero": {"body": "0", "content_type": "application/json", "x_test": None},
                    "body": {"body": "body", "content_type": "application/octet-stream", "x_test": None},
                },
            }
            assert errors == [
                "Route.fetch: url: expected string, got number",
                "Route.fetch: Invalid URL",
                "Route.fetch: headers[0].name: expected string, got number",
                "Route.fetch: max_retries: expected integer, got boolean",
                "Route.fetch: Timeout -1ms exceeded.",
            ]
            await browser.close()

    asyncio.run(run())


