def test_async_page_route_fetch_honors_context_base_url():
    async def run() -> None:
        from benchmarks.automation_cases import header_case_server
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            try:
                with header_case_server() as base_url:
                    context = await browser.new_context(base_url=f"{base_url}/base/")
                    try:
                        page = await context.new_page()
                        result: dict[str, object] = {}

                        async def handler(route):
                            absolute = await route.fetch(url="/headers")
                            parent = await route.fetch(url="../query?from=async-route-fetch")
                            result["absolute"] = {
                                "status": absolute.status,
                                "url": absolute.url,
                                "json": await absolute.json(),
                            }
                            result["parent"] = {
                                "status": parent.status,
                                "url": parent.url,
                                "json": await parent.json(),
                            }
                            await route.fulfill(status=200, json=result)

                        await page.route("**/route-fetch-async-base-url-trigger", handler)
                        response = await page.goto("route-fetch-async-base-url-trigger")
                        payload = await response.json()
                    finally:
                        await context.close()

                assert payload == {
                    "absolute": {"status": 200, "url": f"{base_url}/headers", "json": {"ok": True}},
                    "parent": {
                        "status": 200,
                        "url": f"{base_url}/query?from=async-route-fetch",
                        "json": {"path": "/query", "query": {"from": ["async-route-fetch"]}},
                    },
                }
            finally:
                await browser.close()

    asyncio.run(run())


