def test_async_page_route_fulfill_option_validation(http_server, tmp_path: Path):
    async def run() -> None:
        from playwright.async_api import async_playwright

        errors = []
        path_body = tmp_path / "async.json"
        path_body.write_text('{"async":true}', encoding="utf-8")
        unknown_path_body = tmp_path / "async-payload.unknownextensionforparity"
        unknown_path_body.write_text("async-unknown", encoding="utf-8")
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async def handler(route, request):
                with pytest.raises(Error) as invalid_status:
                    await route.fulfill(status=True)
                errors.append(str(invalid_status.value).splitlines()[0])

                with pytest.raises(Error) as invalid_content_type:
                    await route.fulfill(content_type=123, body="x")
                errors.append(str(invalid_content_type.value).splitlines()[0])

                with pytest.raises(Error) as invalid_body:
                    await route.fulfill(body=123)
                errors.append(str(invalid_body.value).splitlines()[0])

                with pytest.raises(Error) as invalid_body_json:
                    await route.fulfill(body="x", json={"ok": True})
                errors.append(str(invalid_body_json.value).splitlines()[0])

                with pytest.raises(AttributeError) as invalid_header_name:
                    await route.fulfill(headers={1: "x"}, body="x")
                errors.append(str(invalid_header_name.value))

                await route.fulfill(
                    status=200.0,
                    headers={"X-Number": 7, "X-None": None},
                    body=b"async-bytes",
                    content_type="text/plain",
                )

            await page.route("**/route-fulfill-async-validation", handler)
            response = await page.goto(f"{http_server}/route-fulfill-async-validation")

            assert response.status == 200
            assert await response.text() == "async-bytes"
            assert response.headers["x-number"] == "7"
            assert "x-none" not in response.headers
            assert errors == [
                "Route.fulfill: status: expected integer, got boolean",
                "Route.fulfill: headers[0].value: expected string, got number",
                "Route.fulfill: body: expected string, got number",
                "Can specify either body or json parameters",
                "'int' object has no attribute 'lower'",
            ]

            await page.unroute("**/route-fulfill-async-validation", handler)

            async def path_handler(route, request):
                with pytest.raises(TypeError) as invalid_path:
                    await route.fulfill(path=123)
                assert str(invalid_path.value).splitlines()[0] == (
                    "argument should be a str or an os.PathLike object where __fspath__ returns a str, not 'int'"
                )
                await route.fulfill(path=str(path_body))

            await page.route("**/route-fulfill-async-path", path_handler)
            path_response = await page.goto(f"{http_server}/route-fulfill-async-path")
            assert path_response.headers["content-type"] == "application/json"
            assert await path_response.text() == '{"async":true}'

            async def unknown_path_handler(route, request):
                await route.fulfill(path=unknown_path_body)

            await page.route("**/route-fulfill-async-unknown-path", unknown_path_handler)
            unknown_path_result = await page.evaluate(
                """async url => {
                    const response = await fetch(url);
                    return {
                        contentType: response.headers.get('content-type'),
                        text: await response.text(),
                    };
                }""",
                f"{http_server}/route-fulfill-async-unknown-path",
            )
            assert unknown_path_result == {
                "contentType": "application/octet-stream",
                "text": "async-unknown",
            }

            for status, expected_ok in [(42, False), (299, True), (1000, False)]:
                await page.unroute("**/route-fulfill-async-status-*")

                async def status_handler(route, request, status=status):
                    await route.fulfill(status=status, body=f"async-status-{status}")

                await page.route(f"**/route-fulfill-async-status-{status}", status_handler)
                status_response = await page.goto(f"{http_server}/route-fulfill-async-status-{status}")
                assert status_response.status == status
                assert status_response.status_text == "Unknown"
                assert status_response.ok is expected_ok
                assert await status_response.text() == f"async-status-{status}"
            await browser.close()

    asyncio.run(run())


def test_async_api_request_context_response_methods(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright, expect as async_expect

        async with async_playwright() as p:
            request = await p.request.new_context(base_url=http_server)
            response = await request.get("/json")
            duplicate_headers_response = await request.get("/duplicate-headers")

            assert response.url == f"{http_server}/json"
            assert response.status == 201
            assert response.status_text == "Created"
            assert response.ok
            assert {"name": "Content-Type", "value": "application/json"} in response.headers_array
            assert response.headers["content-type"] == "application/json"
            assert await response.json() == {"ok": True, "path": "/json"}
            assert await response.text() == '{"ok": true, "path": "/json"}'
            assert (await response.body()).startswith(b"{")
            await async_expect(response).to_be_ok()
            with pytest.raises(AssertionError, match="got status 404"):
                await async_expect(await request.get("/missing")).to_be_ok()
            await response.dispose()
            with pytest.raises(Error, match="Response has been disposed"):
                await response.body()
            with pytest.raises(Error, match="Response has been disposed"):
                await response.text()
            with pytest.raises(Error, match="Response has been disposed"):
                await response.json()
            assert response.headers["content-type"] == "application/json"
            assert duplicate_headers_response.headers["x-dupe"] == "first, second"
            assert duplicate_headers_response.headers["set-cookie"] == "first=one; Path=/\nsecond=two; Path=/"
            assert {"name": "X-Dupe", "value": "first"} in duplicate_headers_response.headers_array
            assert {"name": "X-Dupe", "value": "second"} in duplicate_headers_response.headers_array
            assert {"name": "Set-Cookie", "value": "first=one; Path=/"} in duplicate_headers_response.headers_array
            assert {"name": "Set-Cookie", "value": "second=two; Path=/"} in duplicate_headers_response.headers_array
            await request.dispose()

    asyncio.run(run())


def test_async_api_request_context_get_yields_event_loop(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            request = await p.request.new_context(base_url=http_server)
            try:
                tick = asyncio.create_task(asyncio.sleep(0.02))
                slow_request = asyncio.create_task(request.get("/slow"))
                await asyncio.sleep(0.05)

                assert tick.done()
                assert not slow_request.done()

                response = await slow_request
                assert response.status == 200
                assert await response.text() == "slow"
            finally:
                await request.dispose()

    asyncio.run(run())


def test_async_api_request_context_option_validation(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            request = await p.request.new_context(base_url=http_server)
            try:
                with pytest.raises(AssertionError) as invalid_target:
                    await request.fetch(123)
                assert str(invalid_target.value) == "First argument must be either URL string or Request"

                with pytest.raises(Error) as invalid_header:
                    await request.get("/json", headers={1: "x"})
                assert (
                    str(invalid_header.value).splitlines()[0]
                    == "APIRequestContext.get: headers[0].name: expected string, got number"
                )

                with pytest.raises(Error) as invalid_method:
                    await request.fetch("/json", method=123)
                assert (
                    str(invalid_method.value).splitlines()[0]
                    == "APIRequestContext.fetch: method: expected string, got number"
                )

                with pytest.raises(AssertionError) as invalid_multipart:
                    await request.post(
                        "/multipart",
                        multipart={
                            "attachment": {
                                "name": "report.txt",
                                "mimeType": "text/plain",
                                "buffer": "not-bytes",
                            }
                        },
                    )
                assert str(invalid_multipart.value) == "Unexpected buffer type of 'data.attachment'"

                with pytest.raises(AttributeError) as invalid_form:
                    await request.post("/json", form="raw=yes")
                assert str(invalid_form.value) == "'str' object has no attribute 'items'"

                response = await request.post(
                    "/multipart",
                    multipart={
                        "empty": "",
                        "zero": "0",
                        "rawBytes": b"raw bytes are skipped by Playwright Python",
                        "attachment": {
                            "name": "report.txt",
                            "mimeType": "",
                            "buffer": b"async multipart",
                        },
                    },
                )
                payload = await response.json()
                assert payload["content_type"].startswith("multipart/form-data; boundary=")
                assert 'name="empty"' not in payload["body"]
                assert 'name="rawBytes"' not in payload["body"]
                assert 'name="zero"' in payload["body"]
                assert "\r\n0\r\n" in payload["body"]
                assert 'name="attachment"; filename="report.txt"' in payload["body"]
                assert "content-type: application/octet-stream" in payload["body"]
                assert "async multipart" in payload["body"]

                body_option_cases = {
                    "empty_multipart": {"multipart": {}},
                    "empty_form": {"form": {}},
                    "data_with_empty_multipart": {"data": "body", "multipart": {}},
                    "data_with_empty_form": {"data": "body", "form": {}},
                    "empty_data_with_form": {"data": "", "form": {"x": "y"}},
                    "zero_data_with_form": {"data": 0, "form": {"x": "y"}},
                }
                results = {}
                for label, kwargs in body_option_cases.items():
                    option_response = await request.post("/echo", **kwargs)
                    results[label] = await option_response.json()
                assert results == {
                    "empty_multipart": {"body": "", "content_type": None, "x_test": None},
                    "empty_form": {"body": "", "content_type": None, "x_test": None},
                    "data_with_empty_multipart": {
                        "body": "body",
                        "content_type": "application/octet-stream",
                        "x_test": None,
                    },
                    "data_with_empty_form": {
                        "body": "body",
                        "content_type": "application/octet-stream",
                        "x_test": None,
                    },
                    "empty_data_with_form": {"body": "", "content_type": None, "x_test": None},
                    "zero_data_with_form": {"body": "0", "content_type": "application/json", "x_test": None},
                }
            finally:
                await request.dispose()

    asyncio.run(run())


