def test_async_api_request_context_timeout_and_proxy_bypass(http_server, http_proxy_server, direct_http_server):
    async def run() -> None:
        from playwright.async_api import TimeoutError as AsyncTimeoutError
        from playwright.async_api import async_playwright

        proxy_url, proxy_seen = http_proxy_server
        direct_port, direct_seen = direct_http_server
        target_url = f"http://localhost:{direct_port}/direct"

        async with async_playwright() as p:
            timeout_request = await p.request.new_context(base_url=http_server, timeout=50)
            try:
                with pytest.raises(AsyncTimeoutError) as timeout_info:
                    await timeout_request.get("/slow")
                assert str(timeout_info.value).splitlines()[0] == "APIRequestContext.get: Timeout 50ms exceeded."

                response = await timeout_request.get("/slow", timeout=0)
                assert response.status == 200
            finally:
                await timeout_request.dispose()

            proxy_request = await p.request.new_context(proxy={"server": proxy_url, "bypass": "<local>"})
            try:
                response = await proxy_request.get(target_url)
                assert response.status == 200
                assert await response.text() == "<title>Direct</title><main>direct target</main>"
            finally:
                await proxy_request.dispose()

        assert wait_until(lambda: [item for item in direct_seen if item[0] == "/direct"])
        assert not [item for item in proxy_seen if item[0] == target_url]

    asyncio.run(run())


def test_async_page_route_fallback_invokes_next_handler(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        calls = []
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async def terminal(route, request):
                calls.append(("terminal", request.url))
                await route.fulfill(json={"ok": True, "path": "/async-fallback-chain"})

            async def first(route, request):
                calls.append(("first", request.url))
                await route.fallback()

            await page.route("**/json", terminal)
            await page.route("**/json", first)
            await page.goto(f"{http_server}/page")
            await page.click("#fetch")

            deadline = time.monotonic() + 3
            while time.monotonic() < deadline:
                if await page.evaluate("() => document.body.dataset.fetchPath === '/async-fallback-chain'"):
                    break
                await asyncio.sleep(0.05)
            assert await page.evaluate("() => document.body.dataset.fetchPath") == "/async-fallback-chain"
            assert calls == [
                ("first", f"{http_server}/json"),
                ("terminal", f"{http_server}/json"),
            ]
            await browser.close()

    asyncio.run(run())


def test_async_page_route_fallback_url_override_rematches_next_handler():
    async def run() -> None:
        from benchmarks.automation_cases import header_case_server
        from playwright.async_api import async_playwright

        calls = []
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            with header_case_server() as base_url:
                async def terminal(route, request):
                    calls.append(("terminal", request.url, await request.header_value("x-route-header")))
                    await route.fulfill(
                        json={
                            "handler": "terminal",
                            "url": request.url,
                            "header": await request.header_value("x-route-header"),
                        }
                    )

                async def first(route, request):
                    calls.append(("first", request.url, await request.header_value("x-route-header")))
                    await route.fallback(
                        url=f"{base_url}/echo-headers",
                        headers={"X-Route-Header": "from-fallback"},
                    )

                await page.route("**/echo-headers", terminal)
                await page.route("**/headers", first)

                response = await page.goto(f"{base_url}/headers")

                assert response is not None
                assert await response.json() == {
                    "handler": "terminal",
                    "url": f"{base_url}/echo-headers",
                    "header": "from-fallback",
                }
                assert calls == [
                    ("first", f"{base_url}/headers", None),
                    ("terminal", f"{base_url}/echo-headers", "from-fallback"),
                ]

            await browser.close()

    asyncio.run(run())


