def test_async_page_route_fallback_header_override_preserves_non_string_in_headers_array():
    async def run() -> None:
        from benchmarks.automation_cases import header_case_server
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            with header_case_server() as base_url:
                async def terminal(route, request):
                    picked = [
                        header
                        for header in await request.headers_array()
                        if header["name"].lower().startswith("x-fallback")
                    ]
                    errors = []
                    try:
                        request.headers
                    except Exception as exc:
                        errors.append(["headers", type(exc).__name__, str(exc).splitlines()[0]])
                    try:
                        await request.header_value("x-fallback-number")
                    except Exception as exc:
                        errors.append(["header_value", type(exc).__name__, str(exc).splitlines()[0]])
                    await route.fulfill(json={"picked": picked, "errors": errors})

                async def first(route, request):
                    await route.fallback(headers={"X-Fallback-Number": 123, "X-Fallback-None": None})

                await page.route("**/headers", terminal)
                await page.route("**/headers", first)

                response = await page.goto(f"{base_url}/headers")

                assert response is not None
                assert await response.json() == {
                    "picked": [{"name": "X-Fallback-Number", "value": 123}],
                    "errors": [
                        ["headers", "TypeError", "sequence item 0: expected str instance, int found"],
                        ["header_value", "TypeError", "sequence item 0: expected str instance, int found"],
                    ],
                }

            await browser.close()

    asyncio.run(run())


