def test_async_page_route_fallback_empty_post_data_preserves_original_request_accessors():
    async def run() -> None:
        from benchmarks.automation_cases import header_case_server
        from playwright.async_api import async_playwright

        results = {}
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            with header_case_server() as base_url:
                await page.goto(base_url)
                for label, post_data in (
                    ("empty_string", ""),
                    ("empty_bytes", b""),
                    ("zero_int", 0),
                    ("false_bool", False),
                ):
                    async def terminal(route, request, *, label=label):
                        post_data_buffer = request.post_data_buffer
                        payload = {
                            "post_data": request.post_data,
                            "buffer_hex": None if post_data_buffer is None else post_data_buffer.hex(),
                        }
                        results[label] = payload
                        await route.fulfill(json=payload)

                    async def first(route, request, *, post_data=post_data):
                        await route.fallback(post_data=post_data)

                    await page.route("**/echo", terminal)
                    await page.route("**/echo", first)
                    response_payload = await page.evaluate(
                        """async () => {
                            const response = await fetch('/echo', { method: 'POST', body: 'base' });
                            return await response.json();
                        }"""
                    )
                    assert response_payload == results[label]
                    await page.unroute("**/echo")

            await browser.close()

        assert results == {
            "empty_string": {"post_data": "base", "buffer_hex": "62617365"},
            "empty_bytes": {"post_data": "base", "buffer_hex": "62617365"},
            "zero_int": {"post_data": "0", "buffer_hex": "30"},
            "false_bool": {"post_data": "false", "buffer_hex": "66616c7365"},
        }

    asyncio.run(run())


