def test_async_page_route_terminal_actions_mark_route_handled(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        errors = []
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async def continue_handler(route, request):
                await route.continue_()
                with pytest.raises(Error) as handled_error:
                    await route.fulfill(json={"unexpected": True})
                errors.append(["continue", str(handled_error.value).splitlines()[0]])

            async def fulfill_handler(route, request):
                await route.fulfill(json={"ok": True})
                with pytest.raises(Error) as handled_error:
                    await route.continue_()
                errors.append(["fulfill", str(handled_error.value).splitlines()[0]])

            await page.route("**/route-continue-async-handled", continue_handler)
            continued = await page.goto(f"{http_server}/route-continue-async-handled")
            await page.route("**/route-fulfill-async-handled", fulfill_handler)
            fulfilled = await page.goto(f"{http_server}/route-fulfill-async-handled")

            assert continued.status == 404
            assert await fulfilled.json() == {"ok": True}
            assert errors == [
                ["continue", "Route is already handled!"],
                ["fulfill", "Route is already handled!"],
            ]
            await browser.close()

    asyncio.run(run())


