def test_async_event_predicates_run_on_owner_loop(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()
            owner_loop = asyncio.get_running_loop()
            seen: list[str] = []

            async def accepts_response(response):
                assert asyncio.get_running_loop() is owner_loop
                accepted = await asyncio.create_task(asyncio.sleep(0, result=response.url.endswith("/json")))
                if accepted:
                    seen.append("page-response")
                return accepted

            async with page.expect_response(accepts_response) as response_info:
                await page.goto(f"{http_server}/json")

            assert response_info.value.status == 201

            async def accepts_context_response(response):
                assert asyncio.get_running_loop() is owner_loop
                accepted = await asyncio.create_task(asyncio.sleep(0, result=response.url.endswith("/echo")))
                if accepted:
                    seen.append("context-response")
                return accepted

            async with context.expect_event("response", accepts_context_response) as context_response_info:
                await page.evaluate("() => fetch('/echo', { method: 'POST', body: 'owner-loop' })")

            assert context_response_info.value.status == 202
            assert seen == ["page-response", "context-response"]
            await browser.close()

    asyncio.run(run())


