def test_async_expose_function_and_binding_callbacks_can_await():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()

            async def add_values(left, right):
                await asyncio.sleep(0)
                return left + right

            await page.expose_function("asyncAdd", add_values)
            assert await page.evaluate("async () => await window.asyncAdd(19, 23)") == 42

            seen = []
            owner_loop = asyncio.get_running_loop()

            async def inspect_handle(source, handle):
                await asyncio.sleep(0)
                assert asyncio.get_running_loop() is owner_loop
                seen.append((source, handle))
                return "async-handle-ok"

            await context.expose_binding("asyncInspectHandle", inspect_handle, handle=True)
            result = await page.evaluate("async () => await window.asyncInspectHandle({ value: 7 })")
            assert result == "async-handle-ok"
            assert len(seen) == 1
            source, handle = seen[0]
            assert source["page"] is page
            assert source["frame"] == page.main_frame
            try:
                assert await handle.json_value() == {"value": 7}
                with pytest.raises(Error) as invalid_js:
                    await handle.get_property(None)
                assert str(invalid_js.value).splitlines()[0] == (
                    "JSHandle.get_property: name: expected string, got undefined"
                )
                value_handle = await handle.get_property(property_name="value")
                try:
                    assert await value_handle.json_value() == 7
                finally:
                    await value_handle.dispose()
            finally:
                await handle.dispose()

            loop_seen = []

            async def inspect_source_loop(source, value):
                await asyncio.sleep(0)
                loop_seen.append(asyncio.get_running_loop() is owner_loop)
                assert source["page"] is page
                assert source["frame"] == page.main_frame
                assert source["context"] is context
                return f"source-loop-{value}"

            await page.expose_binding("asyncSourceLoop", inspect_source_loop)
            assert await page.evaluate("async () => await window.asyncSourceLoop('ok')") == "source-loop-ok"
            assert loop_seen == [True]
            await browser.close()

    asyncio.run(run())


def test_async_context_expose_binding_child_frame_source_and_handle():
    async def run() -> None:
        from benchmarks.automation_cases import header_case_server
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            target = await context.new_page()
            owner_loop = asyncio.get_running_loop()
            seen = []

            async def first_binding(source, value):
                await asyncio.sleep(0)
                seen.append(("first", asyncio.get_running_loop() is owner_loop, source, value))
                return f"first:{source['frame'].name}:{value}"

            async def second_binding(source, value):
                await asyncio.sleep(0)
                seen.append(("second", asyncio.get_running_loop() is owner_loop, source, value))
                return f"second:{source['frame'].name}:{value}"

            async def inspect_handle(source, handle):
                await asyncio.sleep(0)
                seen.append(("handle", asyncio.get_running_loop() is owner_loop, source, handle))
                return f"handle:{source['frame'].name}"

            await context.expose_binding("asyncContextFirstChildBinding", first_binding)
            await context.expose_binding("asyncContextSecondChildBinding", second_binding)
            await context.expose_binding("asyncContextChildHandleBinding", inspect_handle, handle=True)

            try:
                with header_case_server() as base_url:
                    await target.goto(f"{base_url}/frame-page")
                    child = target.frame(name="child")
                    assert child is not None
                    assert await child.evaluate("() => typeof window.asyncContextFirstChildBinding") == "function"
                    assert await child.evaluate("() => typeof window.asyncContextSecondChildBinding") == "function"
                    assert await child.evaluate("() => typeof window.asyncContextChildHandleBinding") == "function"
                    await target.evaluate(
                        """
                        () => {
                          const childWindow = document.querySelector('iframe').contentWindow;
                          Promise.all([
                            childWindow.asyncContextFirstChildBinding('alpha'),
                            childWindow.asyncContextSecondChildBinding('beta'),
                            childWindow.asyncContextChildHandleBinding({ value: 31, nested: { ok: true } }),
                          ]).then(values => {
                            window.__asyncContextChildBindingResults = values;
                          }).catch(error => {
                            window.__asyncContextChildBindingError = String(error);
                          });
                        }
                        """
                    )
                    waiter = await target.wait_for_function(
                        "() => window.__asyncContextChildBindingResults || window.__asyncContextChildBindingError",
                        timeout=3_000,
                    )
                    await waiter.dispose()
                    assert await target.evaluate("() => window.__asyncContextChildBindingError || null") is None
                    assert await target.evaluate("() => window.__asyncContextChildBindingResults") == [
                        "first:child:alpha",
                        "second:child:beta",
                        "handle:child",
                    ]

                assert len(seen) == 3
                assert seen[0][0:2] == ("first", True)
                assert seen[1][0:2] == ("second", True)
                assert seen[2][0:2] == ("handle", True)
                assert seen[0][2]["page"] is target
                assert seen[0][2]["context"] is context
                assert seen[0][2]["frame"].name == "child"
                assert seen[0][3] == "alpha"
                assert seen[1][2]["page"] is target
                assert seen[1][2]["context"] is context
                assert seen[1][2]["frame"].name == "child"
                assert seen[1][3] == "beta"
                assert seen[2][2]["page"] is target
                assert seen[2][2]["context"] is context
                assert seen[2][2]["frame"].name == "child"
                handle = seen[2][3]
                try:
                    assert await handle.json_value() == {"value": 31, "nested": {"ok": True}}
                    value_handle = await handle.get_property("value")
                    try:
                        assert await value_handle.json_value() == 31
                    finally:
                        await value_handle.dispose()
                finally:
                    await handle.dispose()
            finally:
                await browser.close()

    asyncio.run(run())


