def test_async_event_handlers_dedupe_and_remove_once_by_original_callback():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()

            page_seen: list[str] = []

            async def page_console(message):
                await asyncio.sleep(0)
                page_seen.append(message.text)

            page.on("console", page_console)
            page.on("console", page_console)
            await page.evaluate("() => console.log('async-deduped-page')")
            assert await wait_until_async(lambda: page_seen) == ["async-deduped-page"]
            page.remove_listener("console", page_console)

            page_once_seen: list[str] = []

            async def page_once(message):
                await asyncio.sleep(0)
                page_once_seen.append(message.text)

            page.once("console", page_once)
            page.remove_listener("console", page_once)
            await page.evaluate("() => console.log('async-removed-page-once')")
            await page.wait_for_timeout(100)
            assert page_once_seen == []

            page.once("console", page_once)
            await page.evaluate("() => console.log('async-kept-page-once')")
            assert await wait_until_async(lambda: page_once_seen) == ["async-kept-page-once"]
            await page.evaluate("() => console.log('async-ignored-page-once')")
            await page.wait_for_timeout(100)
            assert page_once_seen == ["async-kept-page-once"]

            context_seen: list[str] = []

            async def context_console(message):
                await asyncio.sleep(0)
                context_seen.append(message.text)

            context.on("console", context_console)
            context.on("console", context_console)
            await page.evaluate("() => console.log('async-deduped-context')")
            assert await wait_until_async(lambda: context_seen) == ["async-deduped-context"]
            context.remove_listener("console", context_console)

            context_once_seen: list[str] = []

            async def context_once(message):
                await asyncio.sleep(0)
                context_once_seen.append(message.text)

            context.once("console", context_once)
            context.remove_listener("console", context_once)
            await page.evaluate("() => console.log('async-removed-context-once')")
            await page.wait_for_timeout(100)
            assert context_once_seen == []

            context.once("console", context_once)
            await page.evaluate("() => console.log('async-kept-context-once')")
            assert await wait_until_async(lambda: context_once_seen) == ["async-kept-context-once"]
            await page.evaluate("() => console.log('async-ignored-context-once')")
            await page.wait_for_timeout(100)
            assert context_once_seen == ["async-kept-context-once"]

            await browser.close()

    asyncio.run(run())


def test_async_context_pageload_and_pageclose_events(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()
            closed = []

            context.on("pageclose", lambda closed_page: closed.append(closed_page))
            async with context.expect_event("pageload", lambda loaded_page: loaded_page is page) as load_info:
                await page.goto(f"{http_server}/page")
            assert load_info.value is page

            async with context.expect_event("pageclose", lambda closed_page: closed_page is page) as close_info:
                await page.close()
            assert close_info.value is page
            assert closed == [page]
            await browser.close()

    asyncio.run(run())


def test_async_context_pageload_predicate_can_accept_second_delivery_of_same_page(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()
            predicate_calls = 0

            def accepts_second_load(loaded_page) -> bool:
                nonlocal predicate_calls
                assert loaded_page is page
                predicate_calls += 1
                return predicate_calls == 2

            async with context.expect_event(
                "pageload",
                accepts_second_load,
                timeout=5_000,
            ) as load_info:
                await page.goto(f"{http_server}/page")
                await page.reload()

            assert load_info.value is page
            assert predicate_calls == 2
            await browser.close()

    asyncio.run(run())


def test_async_context_pageload_and_pageclose_events_cover_new_pages_and_listener_removal(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            loaded = []
            closed = []

            def on_load(page):
                loaded.append(page)

            def on_close(page):
                closed.append(page)

            context.on("pageload", on_load)
            context.on("pageclose", on_close)
            first = await context.new_page()
            await first.goto(f"{http_server}/page")
            await first.close()

            assert wait_until(lambda: loaded) == [first]
            assert closed == [first]

            context.remove_listener("pageload", on_load)
            context.remove_listener("pageclose", on_close)
            second = await context.new_page()
            await second.goto(f"{http_server}/page")
            await second.close()
            await asyncio.sleep(0.1)

            assert loaded == [first]
            assert closed == [first]
            await browser.close()

    asyncio.run(run())


def test_async_context_expect_event_captures_dialog():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()
            await page.set_content(
                """
                <script>
                window.showPrompt = () => setTimeout(() => {
                  document.body.dataset.answer = prompt('Async context?', 'Ada');
                }, 0);
                </script>
                """
            )

            async with context.expect_event("dialog", lambda dialog: dialog.message == "Async context?") as dialog_info:
                await page.evaluate("() => window.showPrompt()")

            dialog = dialog_info.value
            assert dialog.page is page
            assert dialog.type == "prompt"
            await dialog.accept("Async")
            deadline = time.monotonic() + 3
            while time.monotonic() < deadline:
                if await page.evaluate("() => document.body.dataset.answer === 'Async'"):
                    break
                await asyncio.sleep(0.05)
            assert await page.evaluate("() => document.body.dataset.answer") == "Async"
            await browser.close()

    asyncio.run(run())


