def test_async_expect_is_playwright_style_callable_object():
    async def run() -> None:
        from playwright.async_api import Expect, PlaywrightContextManager, async_playwright, expect as compat_expect

        assert isinstance(compat_expect, Expect)
        assert isinstance(async_playwright(), PlaywrightContextManager)
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <title>Loading</title>
                <script>setTimeout(() => { document.title = 'Async Object Expect'; }, 50)</script>
                """
            )

            compat_expect.set_options(timeout=3_000)
            try:
                with pytest.raises(TypeError, match="unexpected keyword argument"):
                    compat_expect.set_options(unknown_option=True)
                await compat_expect(page).to_have_title("Async Object Expect")
                compat_expect.set_options(timeout="bad")
                with pytest.raises(Error) as invalid_async_global_timeout:
                    await compat_expect(page.locator("body")).to_have_text("Missing")
                assert (
                    str(invalid_async_global_timeout.value).splitlines()[0]
                    == "LocatorAssertions.to_have_text: timeout: expected float, got string"
                )
                compat_expect.set_options(timeout=True)
                with pytest.raises(Error) as invalid_async_boolean_timeout:
                    await compat_expect(page.locator("body")).to_have_text("Missing")
                assert (
                    str(invalid_async_boolean_timeout.value).splitlines()[0]
                    == "LocatorAssertions.to_have_text: timeout: expected float, got boolean"
                )
                compat_expect.set_options(timeout=3_000)
                with pytest.raises(AssertionError) as custom_async_message_error:
                    await compat_expect(page, "async title failed").to_have_title("Missing", timeout=100)
                assert str(custom_async_message_error.value).splitlines()[0] == "async title failed"
                assert "expected: title 'Missing'" in str(custom_async_message_error.value)
                await page.set_content(
                    """
                    <title>Async Assertions</title>
                    <button id="go" class="primary large" aria-label="Save order" aria-describedby="hint">Go</button>
                    <button id="image-button"><img alt="Search"></button>
                    <button id="hidden-name"><span aria-hidden="true">Hidden</span>Visible</button>
                    <p id="hint">Primary checkout action</p>
                    <div id="error">Required field</div>
                    <input id="email" aria-label="Email" aria-invalid="true" aria-errormessage="error">
                    <input id="profile-name" value="Alice">
                    <div id="empty"></div>
                    <select id="choices" multiple>
                      <option value="a" selected>A</option>
                      <option value="c" selected>C</option>
                    </select>
                    """
                )
                await page.locator("#go").focus()
                await compat_expect(page).to_have_title(title_or_reg_exp="Async Assertions")
                await compat_expect(page).to_have_url(url_or_reg_exp="about:blank")
                await compat_expect(page.locator("#go")).to_be_attached()
                await compat_expect(page.locator("#go")).to_be_focused()
                await compat_expect(page.locator("#go")).to_have_id("go")
                await compat_expect(page.locator("#go")).to_have_id(id="go")
                await compat_expect(page.locator("#go")).to_have_count(count=1)
                await compat_expect(page.locator("#go")).to_have_count(count=1.0)
                with pytest.raises(Error) as invalid_count:
                    await compat_expect(page.locator("#go")).to_have_count(count="1", timeout=100)
                assert (
                    str(invalid_count.value).splitlines()[0]
                    == "LocatorAssertions.to_have_count: expected_number: expected float, got string"
                )
                await compat_expect(page.locator("#go")).to_have_class("primary large")
                await compat_expect(page.locator("#go")).to_contain_class("primary")
                await compat_expect(page.locator("#go")).to_have_role("button")
                await compat_expect(page.locator("#go")).to_have_role(role="button")
                with pytest.raises(Error) as invalid_async_role:
                    await compat_expect(page.locator("#go")).to_have_role(re.compile("button"), timeout=100)
                assert str(invalid_async_role.value).splitlines()[0] == '"role" argument in to_have_role must be a string'
                await compat_expect(page.locator("#go")).to_have_accessible_name("Save order")
                await compat_expect(page.locator("#go")).to_have_accessible_name("  Save   order  ")
                await compat_expect(page.locator("#go")).to_have_accessible_description(re.compile("checkout", re.I))
                await compat_expect(page.locator("#go")).to_have_accessible_description(" Primary   checkout action ")
                await compat_expect(page.locator("#go")).not_to_have_accessible_description(name="Secondary action")
                await compat_expect(page.locator("#image-button")).to_have_accessible_name("Search")
                await compat_expect(page.locator("#hidden-name")).to_have_accessible_name("Visible")
                await compat_expect(page.locator("#email")).to_have_accessible_error_message("Required field")
                await compat_expect(page.locator("#email")).to_have_accessible_error_message(" Required   field ")
                await compat_expect(page.locator("#go")).to_match_aria_snapshot('- button "Save order": Go')
                with pytest.raises(Error) as invalid_async_aria_snapshot_source:
                    await compat_expect(page.locator("#go")).to_match_aria_snapshot(True, timeout=100)
                assert (
                    str(invalid_async_aria_snapshot_source.value).splitlines()[0]
                    == "LocatorAssertions.to_match_aria_snapshot: source is not a string"
                )
                await compat_expect(page.locator("#empty")).to_be_empty()
                await compat_expect(page.locator("#profile-name")).to_have_value(value="Alice")
                with pytest.raises(Error) as invalid_async_value:
                    await compat_expect(page.locator("#profile-name")).to_have_value(True, timeout=100)
                assert str(invalid_async_value.value).splitlines()[0] == "value must be a string or regular expression"
                await compat_expect(page.locator("#choices")).to_have_values(["a", "c"])
                await compat_expect(page.locator("#choices")).to_have_values(values=["a", "c"])
                await compat_expect(page.locator("#choices")).to_have_values(("a", "c"))
                with pytest.raises(AssertionError):
                    await compat_expect(page.locator("#choices")).to_have_values("ac", timeout=100)
                await compat_expect(page.locator("#go")).not_to_be_empty()
                with pytest.raises(Error) as invalid_ratio:
                    await compat_expect(page.locator("#go")).to_be_in_viewport(ratio="bad", timeout=100)
                assert (
                    str(invalid_ratio.value).splitlines()[0]
                    == "LocatorAssertions.to_be_in_viewport: expected_number: expected float, got string"
                )
                await compat_expect(page.locator("#go")).not_to_have_accessible_name("Cancel")
                await compat_expect(page.locator("#go")).not_to_match_aria_snapshot('- button "Cancel"')
                await compat_expect(page).not_to_have_title("Wrong")
                await compat_expect(page).not_to_have_title(title_or_reg_exp="Wrong")
            finally:
                compat_expect.set_options(timeout=None)
            await browser.close()

    asyncio.run(run())


def test_async_context_weberror_event_wraps_page_error():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()
            seen = []

            context.on("weberror", lambda web_error: seen.append(web_error))
            async with context.expect_event(
                "weberror",
                lambda web_error: "async context boom" in str(web_error.error),
            ) as error_info:
                await page.evaluate("() => setTimeout(() => { throw new Error('async context boom'); }, 0)")

            web_error = error_info.value
            assert str(web_error.error) == "async context boom"
            assert web_error.page is page
            deadline = time.monotonic() + 3
            while time.monotonic() < deadline:
                if seen:
                    break
                await asyncio.sleep(0.05)
            assert seen[0].page is page
            await browser.close()

    asyncio.run(run())


def test_async_lifecycle_and_frame_event_values_are_async_wrappers(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async with page.expect_event("load") as load_info:
                await page.goto(f"{http_server}/slow-image-page?async-load-event")
            assert load_info.value is page

            async with page.expect_event("framenavigated") as navigated_info:
                await page.goto(f"{http_server}/slow-image-page?async-frame-navigated")
            assert navigated_info.value.page is page
            assert navigated_info.value.url.endswith("async-frame-navigated")

            attached_seen = []

            async def on_attached(frame):
                attached_seen.append((frame.page is page, frame.is_detached()))

            page.on("frameattached", on_attached)
            await page.set_content("<main></main>")
            async with page.expect_event("frameattached") as attached_info:
                await page.evaluate(
                    """() => {
                    const frame = document.createElement('iframe');
                    frame.srcdoc = '<p>async child</p>';
                    document.body.appendChild(frame);
                    }"""
                )
            assert attached_info.value.page is page
            assert attached_info.value.is_detached() is False
            for _ in range(150):
                if attached_seen:
                    break
                await asyncio.sleep(0.02)
            assert attached_seen
            assert attached_seen[-1] == (True, False)

            async with page.expect_event("framedetached") as detached_info:
                await page.evaluate("() => document.querySelector('iframe').remove()")
            assert detached_info.value.page is page
            assert detached_info.value.is_detached() is True

            await browser.close()

    asyncio.run(run())


def test_async_page_locator_and_mouse_common_wrappers():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context(has_touch=True)
            page = await context.new_page()
            await page.set_content(
                """
                <button id="page" onclick="document.body.dataset.pageTap='yes'">Page</button>
                <button id="locator" onclick="document.body.dataset.locatorTap='yes'">Locator</button>
                <input id="agree" type="checkbox">
                <select id="plan">
                  <option value="free">Free</option>
                  <option value="pro">Pro</option>
                  <option value="enterprise">Enterprise</option>
                </select>
                <select id="multi-plan" multiple>
                  <option value="free">Free</option>
                  <option value="pro">Pro</option>
                  <option value="enterprise">Enterprise</option>
                </select>
                <div style="height:2000px">Scroll target</div>
                <script>
                document.addEventListener('mousedown', () => document.body.dataset.mouseDown = 'yes');
                document.addEventListener('mouseup', () => document.body.dataset.mouseUp = 'yes');
                document.addEventListener('wheel', event => document.body.dataset.wheelDelta = String(event.deltaY));
                </script>
                """
            )

            await page.tap("#page", trial=True)
            await page.locator("#locator").tap(trial=True)
            await page.check("#agree", trial=True)
            await page.locator("#agree").set_checked(True, trial=True)
            assert await page.evaluate("document.body.dataset.pageTap || null") is None
            assert await page.evaluate("document.body.dataset.locatorTap || null") is None
            assert not await page.is_checked("#agree")

            await page.tap("#page")
            await page.locator("#locator").tap()
            await page.check("#agree")
            assert await page.is_checked("#agree")
            await page.uncheck("#agree", trial=True)
            await page.locator("#agree").set_checked(False, trial=True)
            assert await page.is_checked("#agree")
            assert await page.select_option("#plan", "pro") == ["pro"]
            assert await page.input_value("#plan") == "pro"
            assert await page.select_option("#plan", value="free") == ["free"]
            assert await page.locator("#plan").select_option(label="Enterprise") == ["enterprise"]
            assert await page.locator("#plan").select_option(index=1) == ["pro"]
            assert await page.select_option("#plan", value=["pro", "free"]) == ["free"]
            assert await page.locator("#multi-plan").select_option(label=["Enterprise", "Free"]) == [
                "free",
                "enterprise",
            ]
            assert await page.locator("button").all_inner_texts() == ["Page", "Locator"]
            await page.mouse.move(20, 20)
            await page.mouse.down()
            await page.mouse.up()
            await page.mouse.wheel(0, 90)

            assert await page.evaluate("document.body.dataset.pageTap") == "yes"
            assert await page.evaluate("document.body.dataset.locatorTap") == "yes"
            assert await page.evaluate("document.body.dataset.mouseDown") == "yes"
            assert await page.evaluate("document.body.dataset.mouseUp") == "yes"
            await page.wait_for_function("document.body.dataset.wheelDelta === '90'")
            assert await page.evaluate("document.body.dataset.wheelDelta") == "90"

            with pytest.raises(Error) as invalid_move:
                await page.mouse.move(1, 1, steps=True)
            assert str(invalid_move.value).splitlines()[0] == "Mouse.move: steps: expected integer, got boolean"

            with pytest.raises(Error) as invalid_click:
                await page.mouse.click(1, 1, button="bad")
            assert str(invalid_click.value).splitlines()[0] == "Mouse.click: button: expected one of (left|right|middle)"

            with pytest.raises(Error) as invalid_wheel:
                await page.mouse.wheel(True, 1)
            assert str(invalid_wheel.value).splitlines()[0] == "Mouse.wheel: delta_x: expected float, got boolean"

            with pytest.raises(Error) as invalid_keyboard_text:
                await page.keyboard.type(123)
            assert str(invalid_keyboard_text.value).splitlines()[0] == "Keyboard.type: text: expected string, got number"

            with pytest.raises(Error) as invalid_keyboard_delay:
                await page.keyboard.press("a", delay=True)
            assert str(invalid_keyboard_delay.value).splitlines()[0] == "Keyboard.press: delay: expected float, got boolean"

            no_touch = await browser.new_page()
            try:
                await no_touch.set_content("<button id='target'>Target</button>")
                with pytest.raises(Error) as invalid_tap:
                    await no_touch.tap("#target", timeout=100)
                assert (
                    str(invalid_tap.value).splitlines()[0]
                    == "Page.tap: The page does not support tap. Use hasTouch context option to enable touch support."
                )
                with pytest.raises(Error) as invalid_touchscreen:
                    await no_touch.touchscreen.tap(1, 1)
                assert (
                    str(invalid_touchscreen.value).splitlines()[0]
                    == "Touchscreen.tap: hasTouch must be enabled on the browser context before using the touchscreen."
                )
            finally:
                await no_touch.close()
            await context.close()
            await browser.close()

    asyncio.run(run())


def test_async_locator_last_is_dynamic_match_playwright():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content("<ul><li>One</li><li>Two</li></ul>")
            items = page.locator("li")
            first = items.first
            last = items.last

            await page.evaluate(
                """() => {
                const item = document.createElement('li');
                item.textContent = 'Three';
                document.querySelector('ul').appendChild(item);
                }"""
            )
            assert await first.text_content() == "One"
            assert await last.text_content() == "Three"

            await page.evaluate("() => document.querySelector('li:last-child').remove()")
            assert await last.text_content() == "Two"
            assert await items.nth(-1).text_content() == "Two"
            await browser.close()

    asyncio.run(run())


def test_async_locator_nth_index_coercion_matches_playwright():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <button>A</button><button>B</button>
                <iframe srcdoc="<button>Frame A</button>"></iframe>
                <iframe srcdoc="<button>Frame B</button>"></iframe>
                """
            )
            buttons = page.locator("button")

            assert await buttons.nth("1").text_content() == "B"
            assert await buttons.nth("1.2").text_content() == "B"
            assert await buttons.nth("").text_content() == "A"
            assert await buttons.nth(1.2).text_content() == "B"
            assert await buttons.nth(-1).text_content() == "B"
            for invalid_index in [True, False, None, {}, [], "abc", "True", "None", math.nan, math.inf, -math.inf]:
                assert await buttons.nth(invalid_index).count() == 0

            frames = page.frame_locator("iframe")
            assert await frames.nth("1").locator("button").all_text_contents() == ["Frame B"]
            assert await frames.nth("1.2").locator("button").all_text_contents() == ["Frame B"]
            assert await frames.nth("").locator("button").all_text_contents() == ["Frame A"]
            assert await frames.nth(1.2).locator("button").all_text_contents() == ["Frame B"]
            assert await frames.nth(-1).locator("button").all_text_contents() == ["Frame B"]
            for invalid_index in [True, False, None, {}, [], "abc", "True", "None", math.nan, math.inf, -math.inf]:
                with pytest.raises(Error) as exc_info:
                    await frames.nth(invalid_index).locator("button").all_text_contents()
                assert "Failed to find frame" in str(exc_info.value)
            await browser.close()

    asyncio.run(run())


