def test_async_actions_yield_event_loop_while_waiting_for_targets():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content("<main>async actions</main>")

            async def add_button() -> None:
                await asyncio.sleep(0.02)
                await page.evaluate(
                    """() => {
                    const button = document.createElement('button');
                    button.id = 'async-action-button';
                    button.textContent = 'Run';
                    button.onclick = () => document.body.dataset.clicked = 'yes';
                    document.body.appendChild(button);
                    }"""
                )

            button_task = asyncio.create_task(add_button())
            await page.click("#async-action-button", timeout=3_000)
            await button_task
            assert await page.evaluate("document.body.dataset.clicked") == "yes"

            async def add_input() -> None:
                await asyncio.sleep(0.02)
                await page.evaluate(
                    """() => {
                    const input = document.createElement('input');
                    input.id = 'async-action-input';
                    document.body.appendChild(input);
                    }"""
                )

            input_task = asyncio.create_task(add_input())
            await page.locator("#async-action-input").fill("ready", timeout=3_000)
            await input_task
            assert await page.locator("#async-action-input").input_value() == "ready"

            async def add_checkbox() -> None:
                await asyncio.sleep(0.02)
                await page.evaluate(
                    """() => {
                    const checkbox = document.createElement('input');
                    checkbox.id = 'async-action-checkbox';
                    checkbox.type = 'checkbox';
                    document.body.appendChild(checkbox);
                    }"""
                )

            checkbox_task = asyncio.create_task(add_checkbox())
            await page.check("#async-action-checkbox", timeout=3_000)
            await checkbox_task
            assert await page.locator("#async-action-checkbox").is_checked()

            async def add_select() -> None:
                await asyncio.sleep(0.02)
                await page.evaluate(
                    """() => {
                    const select = document.createElement('select');
                    select.id = 'async-action-select';
                    select.innerHTML = '<option value="a">A</option><option value="b">B</option>';
                    document.body.appendChild(select);
                    }"""
                )

            select_task = asyncio.create_task(add_select())
            assert await page.locator("#async-action-select").select_option("b", timeout=3_000) == ["b"]
            await select_task
            assert await page.locator("#async-action-select").input_value() == "b"

            await page.evaluate(
                """() => {
                const button = document.createElement('button');
                button.id = 'async-action-handle';
                button.textContent = 'Handle';
                button.style.display = 'none';
                button.onclick = () => document.body.dataset.handleClicked = 'yes';
                document.body.appendChild(button);
                }"""
            )
            handle = await page.query_selector("#async-action-handle")
            assert handle is not None

            async def reveal_handle_button() -> None:
                await asyncio.sleep(0.02)
                await page.evaluate("() => document.querySelector('#async-action-handle').style.display = 'block'")

            handle_task = asyncio.create_task(reveal_handle_button())
            await handle.click(timeout=3_000)
            await handle_task
            assert await page.evaluate("document.body.dataset.handleClicked") == "yes"
            await browser.close()

    asyncio.run(run())


def test_async_locator_click_force_skips_receives_events_check():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <style>
                #target { position:absolute; left:20px; top:20px; width:120px; height:40px; z-index:1; }
                #overlay { position:absolute; left:0; top:0; width:200px; height:100px; z-index:2; background:rgba(0,0,0,.1); }
                </style>
                <button id="target" onclick="document.body.dataset.clicked = 'target'">Target</button>
                <div id="overlay" onclick="document.body.dataset.overlay = 'yes'"></div>
                """
            )

            with pytest.raises(TimeoutError):
                await page.locator("#target").click(timeout=250)

            await page.locator("#target").click(force=True, timeout=1_000)

            assert await page.evaluate("document.body.dataset.clicked || null") is None
            assert await page.evaluate("document.body.dataset.overlay") == "yes"
            await browser.close()

    asyncio.run(run())


def test_async_locator_check_force_skips_receives_events_then_verifies_state():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <style>
                #agree { position:absolute; left:20px; top:20px; width:30px; height:30px; z-index:1; }
                #overlay { position:absolute; left:0; top:0; width:100px; height:80px; z-index:2; background:rgba(0,0,0,.1); }
                </style>
                <input id="agree" type="checkbox">
                <div id="overlay" onclick="document.body.dataset.overlay = 'yes'"></div>
                """
            )

            with pytest.raises(TimeoutError):
                await page.locator("#agree").check(timeout=250)

            with pytest.raises(Error, match="did not change its state"):
                await page.locator("#agree").check(force=True, timeout=1_000)

            assert await page.locator("#agree").is_checked() is False
            assert await page.evaluate("document.body.dataset.overlay") == "yes"
            await browser.close()

    asyncio.run(run())


