def test_async_locator_filter_has_and_has_not():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <section class="card"><h2>Alpha</h2><button>Open</button><span class="badge">Ready</span></section>
                <section class="card"><h2>Beta</h2><button>Open</button></section>
                <section class="card"><h2>Gamma</h2><button disabled>Open</button><span class="badge">Blocked</span></section>
                """
            )

            cards = page.locator(".card")

            assert await cards.filter(has=page.locator(".badge")).count() == 2
            assert (await cards.filter(has_not=page.locator(".badge")).inner_text()).startswith("Beta")
            assert (
                await cards.filter(has=page.locator(".badge"), has_not=page.get_by_text("Blocked")).inner_text()
            ).startswith("Alpha")
            await browser.close()

    asyncio.run(run())


def test_async_locator_filter_visible_coercion_matches_playwright():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <p id="public">Public report</p>
                <p id="draft" hidden>Draft report</p>
                <p id="archive">Archive note</p>
                """
            )

            ids = "(els) => els.map(el => el.id)"
            assert await page.locator("p").filter(visible=True).evaluate_all(ids) == ["public", "archive"]
            assert await page.locator("p").filter(visible=False).evaluate_all(ids) == ["draft"]
            assert await page.locator("p").filter(visible="false").evaluate_all(ids) == ["public", "archive"]
            assert await page.locator("p").filter(visible=1).evaluate_all(ids) == ["public", "archive"]
            assert await page.locator("p").filter(visible=0).evaluate_all(ids) == ["draft"]
            await browser.close()

    asyncio.run(run())


