def test_async_get_by_role_supports_common_state_filters():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <h2>Reports</h2>
                <button id="disabled" disabled>Disabled</button>
                <button id="hidden" style="display:none">Hidden Action</button>
                <input id="checked" type="checkbox" checked>
                <button aria-expanded="true">Details</button>
                <span id="labelled-name">Labelled Name</span>
                <button id="labelled-button" aria-labelledby="labelled-name"></button>
                <input id="search" type="search" aria-label="Find">
                <button id="image-button"><img alt="Search"></button>
                """
            )

            assert await page.get_by_role("heading", level=2).inner_text() == "Reports"
            assert await page.get_by_role("button", disabled=True).get_attribute("id") == "disabled"
            assert await page.get_by_role("button", name="Hidden Action").count() == 0
            assert await page.get_by_role("button", name="Hidden Action", include_hidden=True).get_attribute("id") == "hidden"
            assert await page.get_by_role("checkbox", checked=True).get_attribute("id") == "checked"
            assert await page.get_by_role("button", expanded=True).inner_text() == "Details"
            assert await page.get_by_role("button", name="Labelled Name").get_attribute("id") == "labelled-button"
            assert await page.get_by_role("searchbox", name="Find").get_attribute("id") == "search"
            assert await page.get_by_role("button", name="Search").get_attribute("id") == "image-button"
            await browser.close()

    asyncio.run(run())


def test_async_file_input_button_role_matches_playwright():
    async def run() -> None:
        from playwright.async_api import async_playwright
        from playwright.async_api import expect as async_expect

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <input id="file" type="file">
                <label for="label-file">Upload Avatar</label><input id="label-file" type="file">
                <input id="file-title" type="file" title="Title Upload">
                <input id="file-aria" type="file" aria-label="ARIA Upload">
                <input id="hidden-file" type="file" style="display:none">
                <input id="submit" type="submit" value="Submitter">
                """
            )

            assert await page.get_by_role("button").evaluate_all("(els) => els.map(el => el.id)") == [
                "file",
                "label-file",
                "file-title",
                "file-aria",
                "submit",
            ]
            assert await page.get_by_role("button", include_hidden=True).evaluate_all("(els) => els.map(el => el.id)") == [
                "file",
                "label-file",
                "file-title",
                "file-aria",
                "hidden-file",
                "submit",
            ]
            assert await page.get_by_role("button", name="Choose File").evaluate_all("(els) => els.map(el => el.id)") == [
                "file",
                "file-title",
            ]
            assert await page.locator('role=button[name="Choose File"]').evaluate_all("(els) => els.map(el => el.id)") == [
                "file",
                "file-title",
            ]
            assert await page.get_by_role("button", name="Title Upload").count() == 0
            assert await page.get_by_role("button", name="Upload Avatar").get_attribute("id") == "label-file"
            assert await page.get_by_role("button", name="ARIA Upload").get_attribute("id") == "file-aria"
            assert await page.get_by_role("button", name="Submitter").get_attribute("id") == "submit"
            await async_expect(page.locator("#file")).to_have_role("button")
            await async_expect(page.locator("#file")).to_have_accessible_name("Choose File")
            await browser.close()

    asyncio.run(run())


def test_async_input_role_defaults_match_playwright():
    async def run() -> None:
        from playwright.async_api import async_playwright
        from playwright.async_api import expect as async_expect

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <main aria-label="Inputs">
                  <input id="color" type="color" aria-label="Color">
                  <input id="date" type="date" aria-label="Date">
                  <input id="datetime" type="datetime-local" aria-label="Date Time">
                  <input id="month" type="month" aria-label="Month">
                  <input id="time" type="time" aria-label="Time">
                  <input id="week" type="week" aria-label="Week">
                  <input id="submit-empty" type="submit">
                  <input id="reset-empty" type="reset">
                  <input id="button-empty" type="button">
                  <input id="submit-value" type="submit" value="Send">
                  <input id="reset-value" type="reset" value="Clear">
                </main>
                """
            )

            assert await page.get_by_role("textbox").evaluate_all("(els) => els.map(el => el.id)") == [
                "color",
                "date",
                "datetime",
                "month",
                "time",
                "week",
            ]
            assert await page.get_by_role("button", name="Submit").evaluate_all("(els) => els.map(el => el.id)") == [
                "submit-empty"
            ]
            assert await page.get_by_role("button", name="Reset").evaluate_all("(els) => els.map(el => el.id)") == [
                "reset-empty"
            ]
            assert await page.get_by_role("button", name="Send").evaluate_all("(els) => els.map(el => el.id)") == [
                "submit-value"
            ]
            assert await page.get_by_role("button", name="Clear").evaluate_all("(els) => els.map(el => el.id)") == [
                "reset-value"
            ]
