def test_async_input_button_submit_text_selectors_match_playwright():
    async def run() -> None:
        from playwright.async_api import async_playwright
        from playwright.async_api import expect as async_expect

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <section id="container">
                  <input id="button-input" type="button" value="Save">
                  <input id="submit-input" type="submit" value="Send">
                  <input id="reset-input" type="reset" value="Clear">
                  <input id="submit-empty" type="submit">
                  <input id="reset-empty" type="reset">
                  <input id="text-input" value="Typed Text">
                  <button id="button">Save</button>
                  <textarea id="textarea">Area Text</textarea>
                </section>
                """
            )

            ids = "(els) => els.map(el => el.id)"
            assert await page.get_by_text("Save").evaluate_all(ids) == ["button-input", "button"]
            assert await page.get_by_text("Send").evaluate_all(ids) == ["submit-input"]
            assert await page.get_by_text("Clear").count() == 0
            assert await page.get_by_text("Submit").count() == 0
            assert await page.get_by_text("Reset").count() == 0
            assert await page.get_by_text("Typed Text").count() == 0
            assert await page.get_by_text("Area Text").evaluate_all(ids) == ["textarea"]
            assert await page.locator("text=Save").evaluate_all(ids) == ["button-input", "button"]
            assert await page.locator("text=Send").evaluate_all(ids) == ["submit-input"]
            assert await page.locator("text=Clear").count() == 0
            assert await page.locator("text=Submit").count() == 0
            assert await page.locator("text=Reset").count() == 0
            assert await page.locator('input:text("Save")').evaluate_all(ids) == ["button-input"]
            assert await page.locator('input:text("Send")').evaluate_all(ids) == ["submit-input"]
            assert await page.locator('input:text("Clear")').count() == 0
            assert await page.locator('input:text("Submit")').count() == 0
            assert await page.locator('input:text("Reset")').count() == 0
            assert await page.locator('#container:has-text("Send")').get_attribute("id") == "container"
            assert await page.locator('#container:has-text("Clear")').count() == 0
            assert await page.locator("#container").filter(has_text="Send").get_attribute("id") == "container"
            assert await page.locator("#container").filter(has_not_text="Clear").get_attribute("id") == "container"
            await async_expect(page.locator("#button-input")).to_have_text("Save")
            await async_expect(page.locator("#button-input")).to_contain_text("av")
            await async_expect(page.locator("#submit-input")).to_have_text("Send")
            await async_expect(page.locator("#submit-input")).to_contain_text("en")
            await async_expect(page.locator("#reset-input")).not_to_have_text("Clear")
            await async_expect(page.locator("#reset-input")).not_to_contain_text("le")
            await async_expect(page.locator("input")).to_have_text(["Save", "Send", "", "", "", ""])
            await async_expect(page.locator("input")).to_contain_text(["Save", "Send"])
            await browser.close()

    asyncio.run(run())


