            await page.set_content(
                """
                <section>
                  <button id="save">Save</button>
                  <button id="lower">save</button>
                  <button id="disabled" disabled>Disabled</button>
                  <button id="hidden" hidden>Hidden</button>
                  <input id="checked" type="checkbox" checked>
                  <input id="unchecked" type="checkbox">
                </section>
                """
            )

            ids = "(els) => els.map(el => el.id)"
            assert await page.locator("internal:role=button").evaluate_all(ids) == ["save", "lower", "disabled"]
            assert await page.locator('internal:role=button[name="Save"i]').evaluate_all(ids) == ["save", "lower"]
            assert await page.locator('internal:role=button[name="Save"s]').evaluate_all(ids) == ["save"]
