def test_async_get_by_label_matches_aria_sources():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <section id="scope">
                  <label for="for-input">For Label</label><input id="for-input">
                  <label>Wrapped Label <textarea id="wrapped"></textarea></label>
                  <label>Button Wrap <button id="wrapped-button">Button</button></label>
                  <input id="aria-label-input" aria-label="Aria Label">
                  <input id="aria-labelledby-input" aria-labelledby="label-one label-two">
                  <span id="label-one">Composite</span><span id="label-two">Name</span>
                  <input id="aria-labelledby-single" aria-labelledby="single-label">
                  <span id="single-label">Single Label</span>
                  <button id="aria-button" aria-label="Button Label">ignored text</button>
                  <div id="editable" contenteditable aria-label="Editable Label"></div>
                  <div id="plain" aria-label="Plain Label"></div>
                </section>
                """
            )

            assert await page.get_by_label("For Label").evaluate_all("(els) => els.map(el => el.id)") == [
                "for-input"
            ]
            assert await page.get_by_label("Wrapped Label").evaluate_all("(els) => els.map(el => el.id)") == [
                "wrapped"
            ]
            assert await page.get_by_label("Button Wrap").evaluate_all("(els) => els.map(el => el.id)") == [
                "wrapped-button"
            ]
            assert await page.get_by_label("Aria Label").evaluate_all("(els) => els.map(el => el.id)") == [
                "aria-label-input"
            ]
            assert await page.get_by_label("Composite").evaluate_all("(els) => els.map(el => el.id)") == [
                "aria-labelledby-input"
            ]
            assert await page.get_by_label("Name", exact=True).evaluate_all("(els) => els.map(el => el.id)") == [
                "aria-labelledby-input"
            ]
            assert await page.get_by_label("Composite Name").count() == 0
            assert await page.get_by_label("Single Label").evaluate_all("(els) => els.map(el => el.id)") == [
                "aria-labelledby-single"
            ]
            assert await page.get_by_label("Button Label").evaluate_all("(els) => els.map(el => el.id)") == [
                "aria-button"
            ]
            assert await page.get_by_label("Editable Label").evaluate_all("(els) => els.map(el => el.id)") == [
                "editable"
            ]
            assert await page.get_by_label("Plain Label").evaluate_all("(els) => els.map(el => el.id)") == ["plain"]
            assert await page.locator("#scope").get_by_label("Aria Label").get_attribute("id") == "aria-label-input"
            assert (
                await page.get_by_label(re.compile(r"single\s+label", re.I)).get_attribute("id")
                == "aria-labelledby-single"
            )
            await browser.close()

    asyncio.run(run())


