                "  - paragraph:\n"
                "    - text: Lead\n"
                "    - strong: Strong\n"
                "    - text: tail\n"
                "    - emphasis: Em\n"
                "  - strong:\n"
                "    - text: Strong lead\n"
                "    - emphasis: Inner em\n"
                "  - search:\n"
