            await async_expect(page.locator("#role-row-label")).to_have_accessible_name("Role row label")
            await async_expect(page.locator("#role-cell")).to_have_accessible_name("Cell label")
            await async_expect(page.locator("#role-columnheader")).to_have_accessible_name("Column label")
            await async_expect(page.locator("#role-rowheader")).to_have_accessible_name("Row label")
