def test_async_add_locator_handler_accepts_async_handler():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <style>
                  #target { position: absolute; left: 80px; top: 80px; width: 120px; height: 40px; }
                  #overlay { position: fixed; inset: 0; z-index: 20; background: rgba(0,0,0,.2); }
                  #dismiss { position: absolute; left: 20px; top: 20px; }
                </style>
                <button id="target" onclick="document.body.dataset.clicked = 'yes'">Target</button>
                <div id="overlay"><button id="dismiss" onclick="this.parentElement.remove()">Dismiss</button></div>
                """
            )
            calls: list[str] = []
            owner_loop = asyncio.get_running_loop()

            async def dismiss_overlay(locator):
                assert asyncio.get_running_loop() is owner_loop
                calls.append(await asyncio.create_task(locator.get_attribute("id")))
                await page.get_by_role("button", name="Dismiss").click()

            await page.add_locator_handler(page.locator("#overlay"), dismiss_overlay)
            await page.get_by_role("button", name="Target").click()

            assert calls == ["overlay"]
            assert await page.evaluate("document.body.dataset.clicked") == "yes"
            await browser.close()

    asyncio.run(run())


def test_async_clock_controls_time_and_timers():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content("<body></body>")
            await page.clock.install(time="2020-01-01T00:00:00Z")
            assert_near(await page.evaluate("() => Date.now()"), 1577836800000)

            await page.evaluate("() => { window.asyncClockFired = []; setTimeout(() => asyncClockFired.push(Date.now()), 500); }")
            await page.clock.fast_forward(500)
            fired = await page.evaluate("() => window.asyncClockFired")
            assert len(fired) == 1
            assert_near(fired[0], 1577836800500)

            fresh_page = await browser.new_page()
            await fresh_page.clock.resume()
            resumed = await fresh_page.evaluate(
                """() => ({
                now: Date.now(),
                perf: performance.now(),
                origin: performance.timeOrigin,
                })"""
            )
            assert 0 <= resumed["now"] < 500
            assert_near(resumed["perf"], resumed["now"], 100)
            assert_near(resumed["origin"], 0, 100)
            await fresh_page.close()

            paused_page = await browser.new_page()
            await paused_page.clock.pause_at("2020-01-01T00:00:00Z")
            paused = await paused_page.evaluate(
                """() => ({
                now: Date.now(),
                perf: performance.now(),
                origin: performance.timeOrigin,
                })"""
            )
            assert_near(paused["now"], 1577836800000, 100)
            assert_near(paused["perf"], 1577836800000, 100)
            assert_near(paused["origin"], 0, 100)
            await paused_page.close()
            await browser.close()

    asyncio.run(run())


def test_async_screencast_streams_frames():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content("<body><h1>Async frame</h1></body>")
            frames = []

            async def on_frame(frame):
                frames.append(frame)

            await page.screencast.start(on_frame=on_frame, quality=40)
            try:
                await page.evaluate("() => { document.body.dataset.changed = 'yes'; document.body.append(' async updated'); }")
                wait_until(lambda: len(frames) > 0)
            finally:
                await page.screencast.stop()

            assert frames[0].data.startswith(b"\xff\xd8")
            assert frames[0].width > 0
            assert frames[0].height > 0
            assert await page.evaluate("() => document.body.dataset.changed") == "yes"
            await browser.close()

    asyncio.run(run())


