def test_async_context_record_video_dir_exposes_basic_video_artifact(tmp_path: Path):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context(record_video_dir=str(tmp_path / "videos"))
            page = await context.new_page()
            video = page.video

            assert video is not None
            await page.set_content("<main style='width:120px;height:80px;background:blue'>Video</main>")
            await page.close()

            video_path = Path(await video.path())
            assert video_path.is_file()
            if shutil.which("ffmpeg"):
                assert video_path.suffix == ".webm"
                assert video_path.read_bytes().startswith(b"\x1a\x45\xdf\xa3")
            else:
                assert video_path.read_bytes().startswith((b"\xff\xd8", b"\x89PNG"))

            copy_path = tmp_path / f"async-copy{video_path.suffix}"
            await video.save_as(copy_path)
            assert copy_path.read_bytes() == video_path.read_bytes()

            await video.delete()
            assert not video_path.exists()
            await context.close()
            await browser.close()

    asyncio.run(run())


def test_async_context_page_event_handler_can_await_video_path(tmp_path: Path):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context(record_video_dir=str(tmp_path / "videos"))
            done = asyncio.get_running_loop().create_future()

            async def on_page(new_page):
                try:
                    assert new_page.video is not None
                    video_path = Path(await new_page.video.path())
                    assert video_path.is_file()
                    done.set_result((new_page, video_path))
                except BaseException as exc:
                    done.set_exception(exc)
                    raise

            context.on("page", on_page)
            page = await asyncio.wait_for(context.new_page(), timeout=3)
            event_page, video_path = await asyncio.wait_for(done, timeout=3)

            assert event_page is page
            assert video_path.parent == tmp_path / "videos"
            assert video_path.suffix in {".webm", ".jpg"}
            await page.close()
            await context.close()
            await browser.close()

    asyncio.run(run())


def test_async_video_delete_lifecycle_and_save_as_validation(tmp_path: Path):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context(
                record_video_dir=str(tmp_path / "videos"),
                record_video_size={"width": 160, "height": 120},
                viewport={"width": 160, "height": 120},
            )
            page = await context.new_page()
            video = page.video

            assert video is not None
            await page.set_content("<main style='width:160px;height:120px;background:navy'>Async video</main>")
            preclose_copy_path = tmp_path / "async-preclose-copy.webm"
            preclose_save = asyncio.create_task(video.save_as(preclose_copy_path))
            await asyncio.sleep(0.1)
            assert not preclose_save.done()
            await page.close()
            await asyncio.wait_for(preclose_save, timeout=3)
            assert preclose_copy_path.exists()

            video_path = Path(await video.path())
            assert video_path.is_file()
            copy_path = tmp_path / f"async-copy{video_path.suffix}"
            await video.save_as(copy_path)
            assert copy_path.read_bytes() == video_path.read_bytes()
            with pytest.raises(TypeError) as type_error:
                await video.save_as(123)
            assert str(type_error.value).splitlines()[0] == "expected str, bytes or os.PathLike object, not int"

            await video.delete()
            assert not video_path.exists()
            assert Path(await video.path()) == video_path
            with pytest.raises(Error) as save_error:
                await video.save_as(tmp_path / f"async-after-delete{video_path.suffix}")
            assert str(save_error.value).splitlines()[0] == (
                "Video.save_as: Target page, context or browser has been closed"
            )
            with pytest.raises(Error) as delete_error:
                await video.delete()
            assert str(delete_error.value).splitlines()[0] == (
                "Video.delete: Target page, context or browser has been closed"
            )

            delete_context = await browser.new_context(
                record_video_dir=str(tmp_path / "delete-videos"),
                record_video_size={"width": 160, "height": 120},
                viewport={"width": 160, "height": 120},
            )
            delete_page = await delete_context.new_page()
            delete_video = delete_page.video
            assert delete_video is not None
            await delete_page.set_content(
                "<main style='width:160px;height:120px;background:olive'>Async delete video</main>"
            )
            await delete_page.wait_for_timeout(100)
            delete_path = Path(await delete_video.path())
            preclose_delete = asyncio.create_task(delete_video.delete())
            await asyncio.sleep(0.5)
            assert not preclose_delete.done()
            await delete_page.close()
            await asyncio.wait_for(preclose_delete, timeout=3)
            assert not delete_path.exists()
            assert Path(await delete_video.path()) == delete_path
            with pytest.raises(Error) as preclose_delete_error:
                await delete_video.delete()
            assert str(preclose_delete_error.value).splitlines()[0] == (
                "Video.delete: Target page, context or browser has been closed"
            )
            await delete_context.close()
            await context.close()
            await browser.close()

    asyncio.run(run())


def test_async_request_gc_collects_unreferenced_objects():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content("<body></body>")
            await page.evaluate(
                """() => {
                window.__gcWeak = new WeakRef({ payload: new Array(1000).fill('x') });
                window.__gcCollected = () => window.__gcWeak.deref() === undefined;
                }"""
            )

            for _ in range(3):
                await page.request_gc()
                if await page.evaluate("() => window.__gcCollected()"):
                    break

            assert await page.evaluate("() => window.__gcCollected()")
            await browser.close()

    asyncio.run(run())


