def test_async_playwright_shaped_surface_wrappers():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            assert "Desktop Chrome" in p.devices
            browser = await p.chromium.launch(headless=True)
            viewport_none_context = await browser.new_context(viewport=None)
            try:
                viewport_none_page = await viewport_none_context.new_page()
                assert viewport_none_page.viewport_size == {"width": 1280, "height": 720}
            finally:
                await viewport_none_context.close()

            no_viewport_page = await browser.new_page(no_viewport=True)
            try:
                assert no_viewport_page.viewport_size is None
            finally:
                await no_viewport_page.close()

            context = await browser.new_context()
            async with context.expect_page() as page_info:
                page = await context.new_page()
            assert page_info.value is page
            assert page.context is context
            assert context.browser is browser
            assert context in browser.contexts
            assert page in context.pages
            assert context.request is context.request
            assert page.request is page.request
            assert page.request is context.request

            await page.set_viewport_size({"width": 500, "height": 400})
            assert page.viewport_size == {"width": 500, "height": 400}
            assert page.context is not None
            assert page.request is not None
            await page.set_content(
                """
                <button id="go" data-state="idle" onclick="this.dataset.state='clicked'"><span>Go</span></button>
                <input id="name" value="Ada">
                <input id="check" type="checkbox">
                <section id="box"><b>Nested</b></section>
                """
            )

            assert await page.get_attribute("#go", "data-state") == "idle"
            assert await page.inner_html("#box") == "<b>Nested</b>"
            assert await page.eval_on_selector("#go", "(el) => el.textContent.trim()") == "Go"
            assert await page.eval_on_selector_all("input", "(nodes) => nodes.length") == 2
            assert await page.locator("xpath=//button[@id='go']").inner_text() == "Go"
            await page.dispatch_event("#go", "click")
            assert await page.get_attribute("#go", "data-state") == "clicked"

            locator = page.locator("#name")
            await locator.clear()
            await locator.press_sequentially("Grace")
            assert await locator.input_value() == "Grace"
            assert await locator.get_attribute("id") == "name"
            assert not await locator.is_hidden()

            await page.set_checked("#check", True)
            assert await page.locator("#check").is_checked()
            await page.locator("#check").set_checked(False)
            assert not await page.locator("#check").is_checked()

            handles = await page.locator("input").element_handles()
            assert len(handles) == 2
            assert await handles[0].get_attribute("id") == "name"
            assert (await handles[0].bounding_box())["width"] > 0
            await handles[0].dispose()
            await context.close()
            await browser.close()

    asyncio.run(run())


def test_async_wrapper_subclasses_accept_existing_async_wrappers():
    async def run() -> None:
        from playwright.async_api import BrowserContext, ElementHandle, Frame, Locator, Page, async_playwright

        class WrappedContext(BrowserContext):
            def __init__(self, context: BrowserContext) -> None:
                super().__init__(context)
                self.context = context

        class WrappedPage(Page):
            def __init__(self, page: Page) -> None:
                super().__init__(page)
                self.page = page

        class WrappedFrame(Frame):
            def __init__(self, frame: Frame) -> None:
                super().__init__(frame)
                self.frame = frame

        class WrappedLocator(Locator):
            def __init__(self, locator: Locator) -> None:
                super().__init__(locator)
                self.locator = locator

        class WrappedElementHandle(ElementHandle):
            def __init__(self, element: ElementHandle) -> None:
                super().__init__(element)
                self.element = element

        class LazyLocator(Locator):
            def __init__(self, page: Page, selector: str) -> None:
                super().__init__(page)
                self._page = page
                self._selector = selector
                self._resolved_locator: Locator | None = None

            async def _resolve(self) -> Locator:
                if self._resolved_locator is None:
                    self._resolved_locator = self._page.locator(self._selector)
                return self._resolved_locator

            def __getattribute__(self, name: str):
                if name.startswith("_"):
                    return object.__getattribute__(self, name)

                async def async_method_wrapper(*args, **kwargs):
                    locator = await self._resolve()
                    return await getattr(locator, name)(*args, **kwargs)

                return async_method_wrapper

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()

            wrapped_context = WrappedContext(context)
            wrapped_page = WrappedPage(page)

            await wrapped_page.set_content("<title>Wrapped</title><button>Hi</button>")
            wrapped_frame = WrappedFrame(wrapped_page.main_frame)
            wrapped_locator = WrappedLocator(wrapped_page.locator("button"))
            wrapped_element = WrappedElementHandle(await wrapped_page.query_selector("button"))
            lazy_locator = LazyLocator(wrapped_page, "button")

            assert await wrapped_page.title() == "Wrapped"
            assert await wrapped_frame.text_content("button") == "Hi"
            assert await wrapped_locator.count() == 1
            assert await wrapped_element.inner_text() == "Hi"
            assert await lazy_locator.count() == 1
            assert len(wrapped_context.pages) == 1
            assert wrapped_context.pages[0] is page
            assert wrapped_page.context is context

            done = asyncio.Event()
            errors: list[str] = []
            messages: list[str] = []

            async def record_console(message) -> None:
                messages.append(message.text)
                done.set()

            def on_console(message) -> None:
                try:
                    asyncio.create_task(record_console(message))
                except BaseException as exc:
                    errors.append(f"{type(exc).__name__}: {exc}")
                    done.set()

            wrapped_page.on("console", on_console)
            await wrapped_page.evaluate("() => console.log('wrapped-console')")
            await asyncio.wait_for(done.wait(), timeout=3)
            assert errors == []
            assert messages == ["wrapped-console"]
            await browser.close()

    asyncio.run(run())


def test_async_frame_and_handle_identity_wrappers():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content(
                """
                <iframe id="child" name="child" srcdoc="<main>Frame body</main>"></iframe>
                <button id="target">Target</button>
                """
            )

            main = page.main_frame
            frames = page.frames
            child = next(frame for frame in frames if frame.name == "child")

            assert frames[0] is main
            assert page.frame(name="child") is child
            assert page.frame("child") is child
            assert child.parent_frame is main
            assert child.page is page
            assert child in main.child_frames
            assert await child.text_content("main") == "Frame body"

            frame_element = await child.frame_element()
            assert frame_element.as_element() is frame_element
            assert await frame_element.get_attribute("id") == "child"
            assert await frame_element.owner_frame() is main
            assert await frame_element.content_frame() is child

            handle = await page.evaluate_handle("() => document.querySelector('#target')")
            element = handle.as_element()
            assert element is not None
            assert await element.get_attribute("id") == "target"
            assert await element.owner_frame() is main
            await handle.dispose()

            frame_handle = await child.evaluate_handle("() => document.querySelector('main')")
            frame_element = frame_handle.as_element()
            assert frame_element is not None
            assert await frame_element.inner_text() == "Frame body"
            assert await frame_element.owner_frame() is child
            await frame_handle.dispose()
            await browser.close()

    asyncio.run(run())


def test_async_detached_frame_child_cache_and_errors_match_playwright():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            inner_doc = '<p id="inner-text">Inner</p>'
            outer_doc = f'<p id="outer-text">Outer</p><iframe id="inner" name="inner" srcdoc="{escape(inner_doc)}"></iframe>'
            await page.set_content(f'<iframe id="outer" name="outer" srcdoc="{escape(outer_doc)}"></iframe>')

            outer_element = await page.query_selector("#outer")
            assert outer_element is not None
            outer = await outer_element.content_frame()
            assert outer is not None
            inner_element = await outer.query_selector("#inner")
            assert inner_element is not None
            inner = await inner_element.content_frame()
            assert inner is not None
            assert [frame.name for frame in page.frames] == ["", "outer", "inner"]
            assert outer.child_frames == [inner]
            assert inner.child_frames == []

            await page.evaluate("() => document.querySelector('#outer').remove()")
            await page.wait_for_timeout(100)

            assert [frame.name for frame in page.frames] == [""]
            assert page.frame(name="outer") is None
            assert page.frame(name="inner") is None
            assert outer.is_detached() is True
            assert inner.is_detached() is True
            assert outer.child_frames == [inner]
            assert inner.child_frames == []
            assert outer.parent_frame is page.main_frame
            assert inner.parent_frame is outer

            for stale_frame in (outer, inner):
                with pytest.raises(Error, match=r"^Frame\.frame_element: Frame has been detached\.$"):
                    await stale_frame.frame_element()

            for stale_frame, selector in ((outer, "#outer-text"), (inner, "#inner-text")):
                with pytest.raises(Error, match=r"^Locator\.count: Frame was detached$"):
                    await stale_frame.locator(selector).count()

            await browser.close()

    asyncio.run(run())


