def test_async_browser_cdp_download_progress_events_run_on_asyncio_loop():
    async def run() -> None:
        from playwright.async_api import async_playwright
        from benchmarks.automation_cases import data_url, header_case_server

        with tempfile.TemporaryDirectory() as directory, header_case_server() as base_url:
            downloads_dir = Path(directory) / "async-cdp-progress"
            downloads_dir.mkdir()
            async with async_playwright() as p:
                browser = await p.chromium.launch(headless=True)
                try:
                    context = await browser.new_context()
                    session = await browser.new_browser_cdp_session()
                    done = asyncio.Event()
                    errors: list[str] = []
                    will_begin_events: list[dict[str, Any]] = []
                    progress_events: list[dict[str, Any]] = []

                    async def handle_begin(event: dict[str, Any]) -> None:
                        will_begin_events.append(event)

                    async def handle_progress(event: dict[str, Any]) -> None:
                        progress_events.append(event)
                        if event.get("state") == "completed":
                            done.set()

                    def begin_callback(event: dict[str, Any]) -> None:
                        try:
                            asyncio.ensure_future(handle_begin(event))
                        except BaseException as exc:
                            errors.append(f"{type(exc).__name__}: {exc}")
                            done.set()

                    def progress_callback(event: dict[str, Any]) -> None:
                        try:
                            asyncio.ensure_future(handle_progress(event))
                        except BaseException as exc:
                            errors.append(f"{type(exc).__name__}: {exc}")
                            done.set()

                    try:
                        page = await context.new_page()
                        marker_url = data_url(f"<title>async-download-progress-{time.time_ns()}</title>")
                        await page.goto(marker_url)
                        targets = (await session.send("Target.getTargets")).get("targetInfos") or []
                        matching_targets = [
                            target
                            for target in targets
                            if target.get("type") == "page" and target.get("url") == marker_url
                        ]
                        assert matching_targets, targets
                        context_id = matching_targets[0].get("browserContextId")
                        assert context_id
                        session.on("Browser.downloadWillBegin", begin_callback)
                        session.on("Browser.downloadProgress", progress_callback)
                        await session.send(
                            "Browser.setDownloadBehavior",
                            {
                                "behavior": "allow",
                                "browserContextId": context_id,
                                "downloadPath": str(downloads_dir),
                                "eventsEnabled": True,
                            },
                        )
                        await page.set_content(f"<a id='download' href='{base_url}/download'>Download</a>")
                        await page.click("#download")

                        await asyncio.wait_for(done.wait(), timeout=5)
                        assert errors == []
                        assert will_begin_events
                        assert progress_events
                        completed_event = [event for event in progress_events if event.get("state") == "completed"][-1]
                        assert completed_event["guid"] == will_begin_events[0]["guid"]
                        assert completed_event["receivedBytes"] >= len(b"download-body")
                    finally:
                        await session.detach()
                        await context.close()
                finally:
                    await browser.close()

    asyncio.run(run())


