def test_async_browser_disconnected_handler_can_schedule_close_task():
    async def run() -> None:
        from benchmarks.automation_cases import remote_debugging_chromium
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            with remote_debugging_chromium(p.chromium) as (endpoint, process):
                browser = await p.chromium.connect_over_cdp(endpoint)
                done = asyncio.Event()
                errors: list[str] = []
                states: list[bool] = []

                async def close_and_mark() -> None:
                    try:
                        await asyncio.sleep(0)
                        states.append(browser.is_connected())
                        await browser.close()
                    except BaseException as exc:
                        errors.append(f"{type(exc).__name__}: {exc}")
                    finally:
                        done.set()

                def on_disconnected() -> None:
                    try:
                        asyncio.create_task(close_and_mark())
                    except BaseException as exc:
                        errors.append(f"{type(exc).__name__}: {exc}")
                        done.set()

                browser.on("disconnected", on_disconnected)
                process.terminate()
                await asyncio.to_thread(process.wait, timeout=3)
                await asyncio.wait_for(done.wait(), timeout=5)

                assert errors == []
                assert states == [False]
                assert browser.is_connected() is False

    asyncio.run(run())


