def test_async_page_cdp_target_discovery_events(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            try:
                page = await browser.new_page()
                session = await page.context.new_cdp_session(page)
                seen_info = asyncio.Event()
                seen_destroyed = asyncio.Event()
                errors: list[str] = []
                target_events: list[tuple[str, dict[str, object]]] = []

                async def handle_target(name, event):
                    try:
                        info = event.get("targetInfo", event)
                        target_events.append((name, info))
                        if name == "info" and str(info.get("url", "")).endswith("/headers?async-page-target"):
                            seen_info.set()
                        if name == "destroyed" and info.get("targetId"):
                            seen_destroyed.set()
                    except BaseException as exc:
                        errors.append(f"{type(exc).__name__}: {exc}")
                        seen_info.set()
                        seen_destroyed.set()

                for event_name, short_name in [
                    ("Target.targetCreated", "created"),
                    ("Target.targetInfoChanged", "info"),
                    ("Target.targetDestroyed", "destroyed"),
                ]:
                    session.on(event_name, lambda event, name=short_name: asyncio.create_task(handle_target(name, event)))

                try:
                    await session.send("Target.setDiscoverTargets", {"discover": True})
                    target_page = await browser.new_page()
                    try:
                        await target_page.goto(f"{http_server}/headers?async-page-target")
                        await asyncio.wait_for(seen_info.wait(), timeout=5)
                    finally:
                        await target_page.close()
                    await asyncio.wait_for(seen_destroyed.wait(), timeout=5)
                finally:
                    await session.detach()

                assert errors == []
                assert any(name == "created" and info.get("type") == "page" for name, info in target_events)
            finally:
                await browser.close()

    asyncio.run(run())


def test_async_cdp_storage_clear_and_reset_history():
    async def run() -> None:
        from benchmarks.automation_cases import header_case_server
        from playwright.async_api import async_playwright

        with header_case_server() as base_url:
            async with async_playwright() as p:
                browser = await p.chromium.launch(headless=True)
                try:
                    page = await browser.new_page()
                    await page.goto(f"{base_url}/query?one")
                    await page.evaluate(
                        """async () => {
                        document.cookie = 'skyvern_cookie=yes; path=/';
                        localStorage.setItem('skyvern-local', '1');
                        sessionStorage.setItem('skyvern-session', '2');
                        const cache = await caches.open('skyvern-cache');
                        await cache.put('/cached-skyvern-value', new Response('cached'));
                        const db = await new Promise((resolve, reject) => {
                            const request = indexedDB.open('skyvern-db', 1);
                            request.onupgradeneeded = () => request.result.createObjectStore('store');
                            request.onsuccess = () => resolve(request.result);
                            request.onerror = () => reject(request.error);
                        });
                        const tx = db.transaction('store', 'readwrite');
                        tx.objectStore('store').put('value', 'key');
                        await new Promise((resolve, reject) => {
                            tx.oncomplete = resolve;
                            tx.onerror = () => reject(tx.error);
                        });
                        db.close();
                        }"""
                    )

                    session = await page.context.new_cdp_session(page)
                    try:
                        origin = await page.evaluate("location.origin")
                        assert await session.send(
                            "Storage.clearDataForOrigin",
                            {
                                "origin": origin,
                                "storageTypes": (
                                    "cookies,local_storage,session_storage,indexeddb,websql,"
                                    "service_workers,cache_storage,shader_cache,file_systems"
                                ),
                            },
                        ) == {}
                        await page.reload(wait_until="domcontentloaded")
                        values = await page.evaluate(
                            """async () => {
                            const dbs = indexedDB.databases ? await indexedDB.databases() : [];
                            const cacheNames = await caches.keys();
                            return {
                                cookie: document.cookie,
                                local: localStorage.getItem('skyvern-local'),
                                session: sessionStorage.getItem('skyvern-session'),
                                dbNames: dbs.map(db => db.name).sort(),
                                cacheNames: cacheNames.sort(),
                            };
                            }"""
                        )

                        await page.goto(f"{base_url}/query?two")
                        assert await session.send("Page.resetNavigationHistory") == {}
                        back_response = await page.go_back(wait_until="domcontentloaded", timeout=1000)
                    finally:
                        await session.detach()

                    assert values == {
                        "cookie": "",
                        "local": None,
                        "session": "2",
                        "dbNames": [],
                        "cacheNames": [],
                    }
                    assert back_response is None
                    assert page.url.endswith("/query?two")
                finally:
                    await browser.close()

    asyncio.run(run())


def test_async_cdp_input_dispatch_mouse_key_and_wheel():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            try:
                page = await browser.new_page(viewport={"width": 400, "height": 300})
                await page.set_content(
                    """
                    <input id="field" style="margin:20px;width:120px;height:24px">
                    <div id="scroller" style="margin:20px;width:120px;height:60px;overflow:auto;background:#eee">
                      <div style="height:500px"></div>
                    </div>
                    <script>
                    window.events = [];
                    for (const type of ['mousemove', 'mousedown', 'mouseup', 'click', 'wheel', 'keydown', 'keyup', 'input']) {
                      document.addEventListener(type, event => window.events.push({
                        type,
                        target: event.target.id || event.target.tagName,
                        key: event.key || '',
                        deltaY: event.deltaY || 0,
                        trusted: event.isTrusted
                      }));
                    }
                    </script>
                    """
                )
                session = await page.context.new_cdp_session(page)
                try:
                    field_box = await page.locator("#field").bounding_box()
                    assert field_box is not None
                    field_x = field_box["x"] + 8
                    field_y = field_box["y"] + 8
                    await session.send(
                        "Input.dispatchMouseEvent",
                        {"type": "mouseMoved", "x": field_x, "y": field_y, "button": "none"},
                    )
                    await session.send(
                        "Input.dispatchMouseEvent",
                        {"type": "mousePressed", "x": field_x, "y": field_y, "button": "left", "clickCount": 1},
                    )
                    await session.send(
                        "Input.dispatchMouseEvent",
                        {"type": "mouseReleased", "x": field_x, "y": field_y, "button": "left", "clickCount": 1},
                    )
                    await page.wait_for_function("() => document.activeElement.id === 'field'")

                    await session.send(
                        "Input.dispatchKeyEvent",
                        {"type": "keyDown", "key": "a", "code": "KeyA", "text": "a", "windowsVirtualKeyCode": 65},
                    )
                    await session.send(
                        "Input.dispatchKeyEvent",
                        {"type": "keyUp", "key": "a", "code": "KeyA", "windowsVirtualKeyCode": 65},
                    )
                    await page.wait_for_function("() => document.querySelector('#field').value === 'a'")

                    scroller_box = await page.locator("#scroller").bounding_box()
                    assert scroller_box is not None
                    wheel_x = scroller_box["x"] + 20
                    wheel_y = scroller_box["y"] + 20
                    await session.send(
                        "Input.dispatchMouseEvent",
                        {"type": "mouseMoved", "x": wheel_x, "y": wheel_y, "button": "none"},
                    )
                    await session.send(
                        "Input.dispatchMouseEvent",
                        {"type": "mouseWheel", "x": wheel_x, "y": wheel_y, "deltaX": 0, "deltaY": 120},
                    )
                    await page.wait_for_function("() => document.querySelector('#scroller').scrollTop > 0")
                finally:
                    await session.detach()

                result = await page.evaluate(
                    """() => ({
                    value: document.querySelector('#field').value,
                    scrollTop: document.querySelector('#scroller').scrollTop,
                    events: window.events
                    })"""
                )
                assert result["value"] == "a"
                assert result["scrollTop"] > 0
                assert all(event["trusted"] is True for event in result["events"])
                assert any(event["type"] == "wheel" and event["deltaY"] == 120 for event in result["events"])
            finally:
                await browser.close()

    asyncio.run(run())


def test_async_cdp_screencast_frame_stream():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            try:
                page = await browser.new_page(viewport={"width": 320, "height": 240})
                await page.set_content(
                    """
                    <main style="background:#f8f2aa;width:100%;height:100%">
                      <h1>Skyvern Screencast</h1>
                    </main>
                    """
                )
                session = await page.context.new_cdp_session(page)
                done = asyncio.Event()
                errors: list[str] = []
                frames: list[dict[str, object]] = []

                async def handle(event):
                    try:
                        frames.append(event)
                        await session.send("Page.screencastFrameAck", {"sessionId": event["sessionId"]})
                    except BaseException as exc:
                        errors.append(f"{type(exc).__name__}: {exc}")
                    finally:
                        done.set()

                session.on("Page.screencastFrame", lambda event: asyncio.ensure_future(handle(event)))
                try:
                    await session.send(
                        "Page.startScreencast",
                        {"format": "jpeg", "quality": 60, "maxWidth": 320, "maxHeight": 240},
                    )
                    await page.evaluate("() => document.body.dataset.screencast = 'running'")
                    await asyncio.wait_for(done.wait(), timeout=5)
                finally:
                    try:
                        await session.send("Page.stopScreencast", {})
                    finally:
                        await session.detach()

                assert errors == []
                assert frames
                first_frame = frames[0]
                image_bytes = base64.b64decode(first_frame["data"])
                assert image_bytes.startswith(b"\xff\xd8")
                assert sorted(first_frame.keys()) == ["data", "metadata", "sessionId"]
                metadata = first_frame["metadata"]
                assert metadata["deviceWidth"] == 320
                assert metadata["deviceHeight"] == 240
            finally:
                await browser.close()

    asyncio.run(run())


def test_async_cdp_fetch_request_paused_stream_handler_runs_on_asyncio_loop(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            try:
                page = await browser.new_page()
                session = await page.context.new_cdp_session(page)
                done = asyncio.Event()
                errors: list[str] = []
                bodies: list[bytes] = []

                async def handle(event):
                    try:
                        request_id = event["requestId"]
                        if event.get("responseStatusCode") is None:
                            await session.send("Fetch.continueRequest", {"requestId": request_id})
                            return

                        stream_result = await session.send("Fetch.takeResponseBodyAsStream", {"requestId": request_id})
                        stream_handle = stream_result["stream"]
                        chunks: list[bytes] = []
                        try:
                            while True:
                                read_result = await session.send("IO.read", {"handle": stream_handle, "size": 1024})
                                data = read_result.get("data", "")
                                if data:
                                    chunks.append(
                                        base64.b64decode(data) if read_result.get("base64Encoded") else data.encode()
                                    )
                                if read_result.get("eof"):
                                    break
                        finally:
                            await session.send("IO.close", {"handle": stream_handle})

                        body = b"".join(chunks)
                        bodies.append(body)
                        await session.send(
                            "Fetch.fulfillRequest",
                            {
                                "requestId": request_id,
                                "responseCode": event["responseStatusCode"],
                                "responseHeaders": event.get("responseHeaders", []),
                                "body": base64.b64encode(body).decode(),
                            },
                        )
                        done.set()
                    except BaseException as exc:
                        errors.append(f"{type(exc).__name__}: {exc}")
                        done.set()

                session.on("Fetch.requestPaused", lambda event: asyncio.ensure_future(handle(event)))
                await session.send(
                    "Fetch.enable",
                    {"patterns": [{"urlPattern": "*json*", "requestStage": "Response"}]},
                )

                await page.goto(f"{http_server}/page")
                await page.click("#fetch")

                await asyncio.wait_for(done.wait(), timeout=3)
                assert errors == []
                assert json.loads(bodies[0].decode("utf-8")) == {"ok": True, "path": "/json"}
                assert await wait_until_async(lambda: page.get_attribute("body", "data-fetch-path")) == "/json"
                await session.send("Fetch.disable")
                await session.detach()
            finally:
                await browser.close()

    asyncio.run(run())


def test_async_cdp_fetch_attachment_download_stream_handler_matches_skyvern_interceptor(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            try:
                page = await browser.new_page()
                session = await page.context.new_cdp_session(page)
                done = asyncio.Event()
                errors: list[str] = []
                bodies: list[bytes] = []

                async def handle(event):
                    try:
                        request_id = event["requestId"]
                        if event.get("responseStatusCode") is None:
                            await session.send("Fetch.continueRequest", {"requestId": request_id})
                            return
                        if not event["request"]["url"].endswith("/download"):
                            await session.send("Fetch.continueResponse", {"requestId": request_id})
                            return

                        stream_result = await session.send("Fetch.takeResponseBodyAsStream", {"requestId": request_id})
                        stream_handle = stream_result["stream"]
                        chunks: list[bytes] = []
                        try:
                            while True:
                                read_result = await session.send("IO.read", {"handle": stream_handle, "size": 1024})
                                data = read_result.get("data", "")
                                if data:
                                    chunks.append(
                                        base64.b64decode(data) if read_result.get("base64Encoded") else data.encode()
                                    )
                                if read_result.get("eof"):
                                    break
                        finally:
                            await session.send("IO.close", {"handle": stream_handle})

                        body = b"".join(chunks)
                        bodies.append(body)
                        await session.send(
                            "Fetch.fulfillRequest",
                            {
                                "requestId": request_id,
                                "responseCode": event["responseStatusCode"],
                                "responseHeaders": event.get("responseHeaders", []),
                                "body": base64.b64encode(body).decode(),
                            },
                        )
                        done.set()
                    except BaseException as exc:
                        errors.append(f"{type(exc).__name__}: {exc}")
                        done.set()

                session.on("Fetch.requestPaused", lambda event: asyncio.ensure_future(handle(event)))
                await session.send("Fetch.enable", {"patterns": [{"requestStage": "Response"}]})
                try:
                    await page.set_content(f"<a id='download' href='{http_server}/download'>Download</a>")
                    async with page.expect_download() as download_info:
                        await page.click("#download")
                    download = download_info.value
                    downloaded_path = Path(await download.path())
                    await asyncio.wait_for(done.wait(), timeout=3)
                    assert errors == []
                    assert bodies == [b"download-body"]
                    assert download.suggested_filename == "report.txt"
                    assert downloaded_path.read_bytes() == b"download-body"
                finally:
                    await session.send("Fetch.disable")
                    await session.detach()
            finally:
                await browser.close()

    asyncio.run(run())


def test_async_cdp_fetch_continue_request_handler_matches_skyvern_interceptor():
    async def run() -> None:
        from benchmarks.automation_cases import header_case_server
        from playwright.async_api import async_playwright

        with header_case_server() as base_url:
            async with async_playwright() as p:
                browser = await p.chromium.launch(headless=True)
                try:
                    page = await browser.new_page()
                    session = await page.context.new_cdp_session(page)
                    done = asyncio.Event()
                    errors: list[str] = []
                    paused_urls: list[str] = []

                    async def handle(event):
                        try:
                            paused_urls.append(event["request"]["url"])
                            headers = [
                                {"name": name, "value": str(value)}
                                for name, value in event.get("request", {}).get("headers", {}).items()
                            ]
                            headers.append({"name": "X-Route-Header", "value": "async-continued-by-cdp"})
                            await session.send(
                                "Fetch.continueRequest",
                                {
                                    "requestId": event["requestId"],
                                    "headers": headers,
                                },
                            )
                        except BaseException as exc:
                            errors.append(f"{type(exc).__name__}: {exc}")
                        finally:
                            done.set()

                    session.on("Fetch.requestPaused", lambda event: asyncio.ensure_future(handle(event)))
                    await session.send(
                        "Fetch.enable",
                        {
                            "patterns": [
                                {"urlPattern": "*echo-headers?async-cdp-continue-request*", "requestStage": "Request"}
                            ]
                        },
                    )
                    try:
                        first_response = await page.goto(f"{base_url}/echo-headers?async-cdp-continue-request")
                        assert first_response is not None
                        first_body = await first_response.json()
                        await asyncio.wait_for(done.wait(), timeout=3)
                        await session.send("Fetch.disable")

                        second_response = await page.goto(f"{base_url}/echo-headers?async-after-disable")
                        assert second_response is not None
                        second_body = await second_response.json()
                    finally:
                        await session.detach()

                    assert errors == []
                    assert paused_urls == [f"{base_url}/echo-headers?async-cdp-continue-request"]
                    assert first_body["x-route-header"] == "async-continued-by-cdp"
                    assert second_body["x-route-header"] is None
                finally:
                    await browser.close()

    asyncio.run(run())


def test_async_context_tracing_writes_trace_zip(tmp_path: Path):
    async def run() -> None:
        from playwright.async_api import async_playwright

        trace_path = tmp_path / "async-trace.zip"
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()

            await context.tracing.start(sources=True)
            await page.set_content("<title>Async Trace</title><main>trace</main>")
            await page.evaluate("() => document.body.dataset.traced = 'yes'")
            await context.tracing.stop(path=trace_path)

            assert zipfile.is_zipfile(trace_path)
            with zipfile.ZipFile(trace_path) as archive:
                names = set(archive.namelist())
                assert "trace.trace" in names
                assert "trace.network" in names
                assert "trace.stacks" in names
                assert "resources/rustwright-cdp-trace.json" in names
                stacks = json.loads(archive.read("trace.stacks").decode("utf-8"))
                assert stacks["files"]
                assert stacks["stacks"]
                assert any(str(file).endswith(".py") for file in stacks["files"])
                trace_events = [
                    json.loads(line)
                    for line in archive.read("trace.trace").decode("utf-8").splitlines()
                    if line
                ]
                metadata = trace_events[0]
                assert metadata["type"] == "context-options"
                assert metadata["sdkLanguage"] == "python"
                methods = {event["method"] for event in trace_events if event["type"] == "before"}
                assert {"setContent", "evaluate"} <= methods
            await browser.close()

    asyncio.run(run())


