def test_async_expect_websocket_captures_browser_socket(websocket_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        ws_url, _ = websocket_server
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            seen = []

            async def is_target_websocket(websocket):
                return websocket.url == ws_url

            page.on("websocket", lambda websocket: seen.append((websocket.url, websocket.is_closed())))
            async with page.expect_websocket(is_target_websocket) as websocket_info:
                await page.evaluate("(url) => { window.__asyncSocket = new WebSocket(url); }", ws_url)

            websocket = websocket_info.value
            assert websocket.url == ws_url
            assert not websocket.is_closed()
            assert wait_until(lambda: seen)[0] == (ws_url, False)
            handle = await page.wait_for_function("() => window.__asyncSocket.readyState === WebSocket.OPEN")
            await handle.dispose()
            async with websocket.expect_event("framereceived") as received_info:
                async with websocket.expect_event("framesent") as sent_info:
                    await page.evaluate("() => window.__asyncSocket.send('async-ping')")
            assert inspect.isawaitable(sent_info.value)
            assert inspect.isawaitable(received_info.value)
            sent_payload = await sent_info.value
            received_payload = await received_info.value
            assert sent_info.value == sent_payload == "async-ping"
            assert received_info.value == received_payload == "echo:async-ping"

            async with page.expect_websocket() as closing_websocket_info:
                await page.evaluate("(url) => { window.__asyncClosingSocket = new WebSocket(url + '?closing'); }", ws_url)
            closing_websocket = closing_websocket_info.value
            closing_handle = await page.wait_for_function("() => window.__asyncClosingSocket.readyState === WebSocket.OPEN")
            await closing_handle.dispose()
            with pytest.raises(Error, match="Socket closed"):
                async with closing_websocket.expect_event("framereceived", timeout=3_000):
                    await page.evaluate("() => window.__asyncClosingSocket.close()")
            assert closing_websocket.is_closed()

            close_seen = []

            async def on_close(closed_websocket):
                await asyncio.sleep(0)
                close_seen.append((closed_websocket is websocket, closed_websocket.is_closed()))

            websocket.on("close", on_close)
            await page.evaluate("() => window.__asyncSocket.close()")
            deadline = time.monotonic() + 3
            while time.monotonic() < deadline and not close_seen:
                await asyncio.sleep(0.02)
            assert close_seen == [(True, True)]
            with pytest.raises(TimeoutError, match='Timeout 10ms exceeded while waiting for event "close"'):
                await websocket.wait_for_event("close", timeout=10)
            await browser.close()

    asyncio.run(run())


def test_async_route_handler_runs_on_owner_loop():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            owner_loop = asyncio.get_running_loop()
            seen = []

            async def handler(route, request):
                seen.append(("handler", asyncio.get_running_loop() is owner_loop, request.url))

                async def marker() -> None:
                    await asyncio.sleep(0)
                    seen.append(("task", asyncio.get_running_loop() is owner_loop))

                asyncio.create_task(marker())
                await asyncio.sleep(0)
                await route.fulfill(status=200, body="owner-loop-ok", content_type="text/plain")

            await page.route("**/async-owner-loop-route", handler)
            response = await page.goto("http://example.test/async-owner-loop-route")
            assert response is not None
            assert await response.text() == "owner-loop-ok"

            deadline = time.monotonic() + 3
            while time.monotonic() < deadline and not any(item[0] == "task" for item in seen):
                await asyncio.sleep(0.01)
            assert seen[0] == ("handler", True, "http://example.test/async-owner-loop-route")
            assert ("task", True) in seen
            await browser.close()

    asyncio.run(run())


def test_async_page_route_web_socket_mocks_browser_socket():
    async def run() -> None:
        from playwright.async_api import async_playwright

        received = []

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            owner_loop = asyncio.get_running_loop()
            loop_seen = []

            async def handler(route):
                loop_seen.append(("handler", asyncio.get_running_loop() is owner_loop))

                async def on_message(message):
                    loop_seen.append(("message", asyncio.get_running_loop() is owner_loop))
                    received.append(message)
                    route.send(f"async-echo:{message}")
                    await route.close(code=1000, reason="async-done")

                route.on_message(on_message)
                route.send("async-ready")

            await page.route_web_socket("**/async-mock", handler)
            await page.set_content("<main>async route websocket</main>")
            await page.evaluate(
                """() => {
                window.messages = [];
                window.routeClosed = "";
                const ws = new WebSocket("ws://example.test/async-mock");
                ws.onmessage = event => window.messages.push(event.data);
                ws.onopen = () => ws.send("async-ping");
                ws.onclose = event => window.routeClosed = `${event.code}:${event.reason}`;
                }"""
            )

            deadline = time.monotonic() + 3
            while time.monotonic() < deadline:
                if await page.evaluate("() => window.messages.length >= 2"):
                    break
                await asyncio.sleep(0.05)
            assert await page.evaluate("() => window.messages.length >= 2")
            assert await page.evaluate("() => window.messages") == ["async-ready", "async-echo:async-ping"]
            assert received == ["async-ping"]
            assert await page.evaluate("() => window.routeClosed") == "1000:async-done"
            assert loop_seen == [("handler", True), ("message", True)]
            await browser.close()

    asyncio.run(run())


def test_async_route_web_socket_connect_to_server_proxies_messages(websocket_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        ws_url, connections = websocket_server
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async def handler(route):
                route.connect_to_server()

            await page.route_web_socket("**/socket?async-proxy", handler)
            await page.set_content("<main>async proxy websocket</main>")
            await page.evaluate(
                f"""() => {{
                window.messages = [];
                window.protocol = "";
                window.asyncProxyClosed = "";
                const ws = new WebSocket({json.dumps(ws_url + '?async-proxy')}, ['fallback', 'chat']);
                ws.onmessage = event => {{
                  if (event.data instanceof ArrayBuffer) {{
                    window.messages.push(`binary:${{Array.from(new Uint8Array(event.data)).join(',')}}`);
                    ws.send('ping-request');
                    ws.send('close-request');
                    return;
                  }}
                  window.messages.push(event.data);
                  if (window.messages.length === 1) ws.send('fragment-request');
                  if (window.messages.length === 2) {{
                    ws.binaryType = 'arraybuffer';
                    ws.send('binary-fragment-request');
                  }}
                }};
                ws.onopen = () => {{
                  window.protocol = ws.protocol;
                  ws.send('async-proxied-ping');
                }};
                ws.onclose = event => window.asyncProxyClosed = `${{event.code}}:${{event.reason}}`;
                }}"""
            )

            deadline = time.monotonic() + 3
            while time.monotonic() < deadline:
                if await page.evaluate("() => window.messages.length === 3"):
                    break
                await asyncio.sleep(0.05)
            assert await page.evaluate("() => window.messages") == [
                "echo:async-proxied-ping",
                "fragmented:reply",
                "binary:5,6,7",
            ]
            deadline = time.monotonic() + 3
            while time.monotonic() < deadline:
                if await page.evaluate("() => window.asyncProxyClosed"):
                    break
                await asyncio.sleep(0.05)
            assert await page.evaluate("() => window.asyncProxyClosed") == "3002:server-done"
            assert await page.evaluate("() => window.protocol") == "chat"
            assert wait_until(lambda: [item for item in connections if item == ("protocols", "/socket?async-proxy", "fallback, chat")])
            assert wait_until(lambda: [item for item in connections if item == ("message", "/socket?async-proxy", "async-proxied-ping")])
            assert wait_until(lambda: [item for item in connections if item == ("message", "/socket?async-proxy", "fragment-request")])
            assert wait_until(lambda: [item for item in connections if item == ("message", "/socket?async-proxy", "binary-fragment-request")])
            assert wait_until(lambda: [item for item in connections if item == ("pong", "/socket?async-proxy", "server-ping")])
            assert wait_until(lambda: [item for item in connections if item == ("message", "/socket?async-proxy", "close-request")])
            await browser.close()

    asyncio.run(run())


def test_async_expect_worker_captures_dedicated_worker():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()

            async def is_blob_worker(worker):
                return worker.url.startswith("blob:")

            async with page.expect_worker(is_blob_worker) as worker_info:
                await page.evaluate(
                    """() => {
                    const url = URL.createObjectURL(new Blob(['self.value = 11; setInterval(() => {}, 1000);'], { type: 'text/javascript' }));
                    window.__asyncWorker = new Worker(url);
                    }"""
                )
            worker = worker_info.value
            assert not worker._sync._closed
            assert any(existing is worker for existing in page.workers)
            deadline = time.monotonic() + 3
            value = None
            while time.monotonic() < deadline:
                value = await worker.evaluate("() => self.value ?? null")
                if value == 11:
                    break
                await asyncio.sleep(0.05)
            assert value == 11
            handle = await worker.evaluate_handle("() => ({ value: self.value })")
            assert await handle.json_value() == {"value": 11}
            await handle.dispose()

            async def has_worker_log(message):
                await asyncio.sleep(0)
                return message.worker is worker and message.text == "async worker log"

            async with worker.expect_event("console", has_worker_log) as message_info:
                await worker.evaluate("() => console.log('async worker log')")
            assert message_info.value.worker is worker

            async def has_waited_worker_log(message):
                await asyncio.sleep(0)
                return message.worker is worker and message.text == "async worker waited log"

            async with worker.expect_event("console", has_waited_worker_log, timeout=3_000) as waited_message_info:
                await worker.evaluate("() => setTimeout(() => console.log('async worker waited log'), 20)")
            waited_message = waited_message_info.value
            assert waited_message.worker is worker
            assert waited_message.text == "async worker waited log"

            async with page.expect_worker() as reject_worker_info:
                await page.evaluate(
                    """() => {
                    const url = URL.createObjectURL(new Blob(['setInterval(() => {}, 1000);'], { type: 'text/javascript' }));
                    window.__asyncRejectWorker = new Worker(url);
                    }"""
                )
            reject_worker = reject_worker_info.value
            with pytest.raises(Error, match="Target page, context or browser has been closed"):
                async with reject_worker.expect_event("console", timeout=3_000):
                    await page.evaluate("() => window.__asyncRejectWorker.terminate()")
            assert reject_worker._sync._closed

            async with worker.expect_event("close") as close_info:
                await page.evaluate("() => window.__asyncWorker.terminate()")
            assert close_info.value is worker
            assert worker._sync._closed
            with pytest.raises(TimeoutError, match='Timeout 10ms exceeded while waiting for event "close"'):
                async with worker.expect_event("close", timeout=10):
                    pass
            await browser.close()

    asyncio.run(run())


def test_async_context_service_worker_event(http_server):
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            try:
                page = await context.new_page()
                async with context.expect_event("serviceworker") as worker_info:
                    await page.goto(f"{http_server}/service-worker-page")
                worker = worker_info.value
                assert worker.url.endswith("/sw.js")
                handle = await page.wait_for_function("() => document.body.dataset.sw === 'ready'")
                await handle.dispose()
                assert await worker.evaluate("() => self.__rustwrightServiceWorkerValue") == 73
                assert any(existing is worker for existing in context.service_workers)
            finally:
                await context.close()
                await browser.close()

    asyncio.run(run())


def test_async_evaluate_handle_flow():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            page_handle = await page.wait_for_function("() => ({ ready: true })")
            assert await page_handle.json_value() == {"ready": True}
            await page_handle.dispose()
            handle = await page.evaluate_handle("() => ({ count: 4 })")
            assert str(handle) == "Object"
            assert repr(handle) == "<JSHandle preview=Object>"
            assert await handle.json_value() == {"count": 4}
            assert await handle.evaluate("(value) => value.count + 1") == 5
            await handle.dispose()
            assert str(handle) == "Object"
            await browser.close()

    asyncio.run(run())


def test_async_evaluate_unwraps_nested_handle_arguments_like_skyvern():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            child = (
                "<main id='root'>"
                "<button id='go' data-kind='primary'>Go</button>"
                "<span id='tail'>Tail</span>"
                "</main>"
            )
            await page.set_content(
                f"<button id='main'>Main</button>"
                f'<iframe name="child" srcdoc="{escape(child, quote=True)}"></iframe>'
            )
            main_button = await page.query_selector("#main")
            frame = next(existing for existing in page.frames if existing is not page.main_frame)
            button = await frame.query_selector("#go")
            tail = await frame.query_selector("#tail")
            data = await frame.evaluate_handle("() => ({ count: 4, suffix: '!' })")
            try:
                assert await page.evaluate("(element) => element.textContent", main_button) == "Main"
                assert await frame.evaluate(
                    "([element, page_by_page]) => element.textContent + ':' + page_by_page",
                    [button, True],
                ) == "Go:true"
                assert await frame.locator("#go").evaluate(
                    "(node, arg) => node.textContent + arg.data.suffix + ':' + arg.tail.textContent",
                    {"data": data, "tail": tail},
                ) == "Go!:Tail"
                assert await button.evaluate(
                    "(node, arg) => node.dataset.kind + ':' + arg.data.suffix + arg.tail.id",
                    {"data": data, "tail": tail},
                ) == "primary:!tail"
                mapped = await data.evaluate_handle(
                    "(value, arg) => ({ text: arg.node.textContent, total: value.count + arg.node.id.length })",
                    {"node": button},
                )
                try:
                    assert await mapped.json_value() == {"text": "Go", "total": 6}
                finally:
                    await mapped.dispose()
            finally:
                await data.dispose()
                await browser.close()

    asyncio.run(run())


def test_async_locator_evaluate_handle_flow():
    async def run() -> None:
        from playwright.async_api import async_playwright

        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            page = await browser.new_page()
            await page.set_content("<div id='box' data-count='5'>Box</div>")
            element = await page.query_selector("#box")
            assert element is not None
            with pytest.raises(Error) as invalid_element:
                await element.get_property(1)
            assert str(invalid_element.value).splitlines()[0] == (
                "ElementHandle.get_property: name: expected string, got number"
            )
            handle = await page.locator("#box").evaluate_handle(
                "(element) => ({ text: element.textContent, count: Number(element.dataset.count) })"
            )
            text_handle = await handle.get_property(property_name="text")
            assert await text_handle.json_value() == "Box"
            assert await handle.evaluate("(value) => value.count + 1") == 6
            await text_handle.dispose()
            await handle.dispose()
            await browser.close()

    asyncio.run(run())
